    if (method === "POST" && path === "/me/telegram/oidc/callback") return apiError("Telegram OIDC 暂未配置", 400);
    if (method === "GET" && path === "/api-credential") return apiUserApiCredential(env, user.user.id);
    if (method === "POST" && path === "/api-credential/apply") return apiUserApplyApiCredential(env, user.user.id);
    if (method === "POST" && path === "/api-credential/regenerate") return apiUserRegenerateApiCredential(env, user.user.id);
    if (method === "PUT" && path === "/api-credential/status") return apiUserUpdateApiCredentialStatus(request, env, user.user.id);
    if (method === "GET" && path === "/wallet") return apiUserWallet(env, user.user.id);
    if (method === "GET" && path === "/wallet/transactions") return apiUserWalletTransactions(env, url, user.user.id);
    if (method === "POST" && path === "/wallet/payment-channels") return apiUserWalletPaymentChannels(request, env, user.user);
    if (method === "POST" && path === "/wallet/recharge") return apiUserWalletRecharge(request, env, user.user);
    if (method === "GET" && path === "/wallet/recharges") return apiUserWalletRecharges(env, url, user.user.id);
    if (method === "GET" && path === "/wallet/recharges/stats") return apiUserWalletRechargeStats(env, url, user.user.id);
    if (method === "GET" && /^\/wallet\/recharges\/[^/]+$/.test(path)) return apiUserWalletRechargeDetail(env, user.user.id, decodeURIComponent(path.split("/").pop() || ""));
    if (method === "POST" && /^\/wallet\/recharge\/payments\/\d+\/capture$/.test(path)) {
      return apiUserCaptureWalletRechargePayment(env, user.user, Number(path.split("/").at(-2)));
    }
    if (method === "POST" && path === "/gift-cards/redeem") return apiRedeemGiftCard(request, env, user.user);
    if (method === "POST" && path === "/order/payment-channels") return apiUserOrderPaymentChannels(request, env, user.user);
    if (method === "POST" && path === "/orders/preview") return apiOrderPreview(request, env, user.user);
    if (method === "POST" && path === "/orders") return apiGuestCreateOrder(request, env, user.user);
    if (method === "POST" && path === "/orders/create-and-pay") {
      return apiGuestCreateOrder(request, env, user.user, { executionContext: ctx });
    }
    if (method === "GET" && /^\/orders\/checkout-requests\/[^/]+$/.test(path)) {
      return apiCheckoutRequestResult(
        request,
        env,
        decodeURIComponent(path.split("/").pop() || ""),
        user.user,
        url
      );
    }
    if (method === "GET" && path === "/orders") return apiUserOrders(request, env, url, user.user.id);
    if (method === "GET" && path === "/orders/stats") return apiUserOrderStats(request, env, url, user.user.id);
    if (method === "POST" && /^\/orders\/[^/]+\/cancel$/.test(path)) return apiUserCancelOrder(request, env, user.user.id, decodeURIComponent(path.split("/").at(-2) || ""));
    if (method === "GET" && /^\/orders\/[^/]+$/.test(path)) return apiUserOrderDetail(request, env, user.user.id, decodeURIComponent(path.split("/").pop() || ""));
    if (method === "GET" && /^\/orders\/[^/]+\/fulfillment\/download$/.test(path)) {
      return fulfillmentDownloadForUserOrder(request, env, user.user.id, decodeURIComponent(path.split("/").at(-3) || ""));
    }
    if (method === "POST" && path === "/payments") return apiUserCreatePayment(request, env, user.user);
    if (method === "GET" && path === "/payments/latest") return apiUserLatestPayment(request, env, url, user.user);
    if (method === "POST" && /^\/payments\/\d+\/capture$/.test(path)) {
      return apiUserCapturePayment(request, env, user.user, Number(path.split("/").at(-2)));
    }
