  if (method === "POST" && path === "/admin/login") return apiAdminLogin(request, env);
  if (method === "POST" && path === "/admin/login/verify-2fa") return apiAdminLoginVerify2FA(request, env);

  const admin = await requireAdmin(request, env);
  if (!admin.ok) return admin.response;
  if (!await canAccessAdminPath(env, admin.user, method, path)) {
    return apiError("forbidden", 403);
  }

  if (method === "GET" && path === "/admin/authz/me") return apiAdminAuthzMe(env, admin.user);
  if (method === "GET" && path === "/admin/compliance/status") return apiAdminComplianceStatus(env);
