  if (method === "GET" && path === "/admin/resellers/operations/overview") return apiAdminResellerOperationsOverview(env, url);
  if (method === "GET" && path === "/admin/resellers/operations/finance") return apiAdminResellerOperationsFinance(env, url);
  if (method === "GET" && path === "/admin/resellers/ledger-entries") return apiAdminResellerLedgerEntries(env, url);
