function buildProcurementWhere(url: URL, includeStatus: boolean): { where: string; params: unknown[] } {
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  if (includeStatus) {
    const status = clean(url.searchParams.get("status"), 40);
    if (status && status !== "__all__") {
      where += " AND po.status=?";
      params.push(status);
    }
  }
  const connectionId = toInt(url.searchParams.get("connection_id"), 0);
  const orderNo = clean(url.searchParams.get("order_no"), 120);
  const upstreamOrderNo = clean(url.searchParams.get("upstream_order_no"), 120);
  const createdFrom = clean(url.searchParams.get("created_from"), 80);
  const createdTo = clean(url.searchParams.get("created_to"), 80);
  if (connectionId > 0) {
    where += " AND po.connection_id=?";
    params.push(connectionId);
  }
  if (orderNo) {
    where += " AND po.local_order_no LIKE ?";
    params.push(`%${orderNo}%`);
  }
  if (upstreamOrderNo) {
    where += " AND po.upstream_order_no LIKE ?";
    params.push(`%${upstreamOrderNo}%`);
  }
  if (createdFrom) {
    where += " AND po.created_at>=?";
    params.push(createdFrom);
  }
  if (createdTo) {
    where += " AND po.created_at<=?";
    params.push(createdTo);
  }
  return { where, params };
}

