async function apiAdminApproveApiCredential(env: Env, id: number): Promise<Response> {
  const credential = await env.DB.prepare("SELECT id FROM api_credentials WHERE id=?")
    .bind(id)
    .first<{ id: number }>();
  if (!credential) return apiError("API 凭证不存在", 404);
  const apiKey = makeApiKey();
  const apiSecret = makeApiSecret();
  await env.DB.prepare(
    `UPDATE api_credentials
     SET api_key=?, api_secret=?, key_hash=?, secret_hash=?, secret_tail=?,
         status='approved', is_active=1, reject_reason='', approved_at=CURRENT_TIMESTAMP,
         last_used_at=NULL, updated_at=CURRENT_TIMESTAMP
     WHERE id=?`
  ).bind(
    apiKey,
    apiSecret,
    await sha256Hex(apiKey),
    await sha256Hex(apiSecret),
    apiSecret.slice(-6),
    id
  ).run();
  const row = await env.DB.prepare(
    `SELECT ac.*, u.email AS user_email, u.display_name AS user_display_name
     FROM api_credentials ac LEFT JOIN users u ON u.id=ac.user_id WHERE ac.id=?`
  ).bind(id).first<ApiCredentialRow>();
  return apiOk({ credential: row ? formatApiCredential(row) : {}, approved: true });
}

