async function apiPublicConfig(request: Request, env: Env): Promise<Response> {
  const resellerContext = await resolveResellerContextFromRequest(request, env);
  const cacheKey = resellerContext
    ? `reseller:${Number(resellerContext.profile.id || 0)}:${clean(resellerContext.domain.domain, 255)}`
    : "main";
  const cached = publicConfigCache.get(cacheKey);
  if (cached && cached.expiresAt > Date.now()) {
    return apiOk({ ...cloneJsonRecord(cached.value), server_time: Date.now() });
  }
  const publicSettingKeys = [
    "site_config",
    "registration_config",
    "captcha",
    "telegram_auth",
    "home_announcement",
    "wallet_config"
  ];
  const [settingsResult, channelsResult] = await env.DB.batch([
    env.DB.prepare(
      `SELECT key, value_json FROM settings WHERE key IN (${publicSettingKeys.map(() => "?").join(",")})`
    ).bind(...publicSettingKeys),
    env.DB.prepare("SELECT * FROM payment_channels WHERE is_active=1 ORDER BY sort_order ASC, id ASC")
  ]);
  const publicSettings = new Map(
    ((settingsResult.results || []) as Array<{ key: string; value_json: string }>)
      .map((row) => [row.key, row.value_json] as const)
  );
  const settingsExpiresAt = Date.now() + SETTING_CACHE_TTL_MS;
  for (const key of publicSettingKeys) {
    if (CACHEABLE_SETTING_KEYS.has(key)) {
      settingCache.set(key, { raw: publicSettings.get(key) ?? null, expiresAt: settingsExpiresAt });
    }
  }
  const readPublicSetting = <T>(key: string, fallback: T): T => {
    const raw = publicSettings.get(key);
    return raw === undefined ? fallback : jsonParse(raw, fallback);
  };

  let value = cloneJsonRecord(readPublicSetting("site_config", {}));
  normalizePublicSiteName(value);
  if (resellerContext) value = applyResellerPublicConfig(value, resellerContext);
  const registrationRaw = jsonObject(readPublicSetting("registration_config", {}));
  const registration = {
    registration_enabled: registrationRaw.registration_enabled !== false,
    email_verification_enabled: registrationRaw.email_verification_enabled !== false,
    email_domain_allowlist_enabled: registrationRaw.email_domain_allowlist_enabled === true,
    allowed_email_domains: normalizeEmailDomainList(registrationRaw.allowed_email_domains)
  };
  value.registration_enabled = registration.registration_enabled !== false;
  value.email_verification_enabled = registration.email_verification_enabled !== false;
  value.email_domain_allowlist_enabled = registration.email_domain_allowlist_enabled === true;
  value.allowed_email_domains = normalizeEmailDomainList(registration.allowed_email_domains);
  value.captcha = publicCaptchaSettings(normalizeCaptchaSettings(
    readPublicSetting("captcha", defaultCaptchaSettings()),
    defaultCaptchaSettings()
  ));
  value.telegram_auth = publicTelegramAuthSettings(normalizeTelegramAuthSettings(
    readPublicSetting("telegram_auth", defaultTelegramAuthSettings())
  ));
  const resellerAnnouncement = resellerContext
    ? normalizePublicHomeAnnouncement(jsonParse(resellerContext.siteConfig.announcement_json || "{}", {}), Date.now())
    : null;
  const homeAnnouncement = resellerAnnouncement || normalizePublicHomeAnnouncement(
    readPublicSetting("home_announcement", {}),
    Date.now()
  );
  if (homeAnnouncement) value.announcement = homeAnnouncement;
  const channels = (channelsResult.results || []) as PaymentChannelRow[];
  activePaymentChannelCache = {
    rows: channels,
    expiresAt: Date.now() + PAYMENT_CHANNEL_CACHE_TTL_MS
  };
  value.payment_channels = channels.map(formatPublicPaymentChannel);
  const wallet = jsonObject(readPublicSetting("wallet_config", {}));
  value.wallet_recharge_channel_ids = arrayNumbers(wallet.recharge_channel_ids);
  value.wallet_only_payment = wallet.wallet_only_payment === true;
  publicConfigCache.set(cacheKey, {
    value: cloneJsonRecord(value),
    expiresAt: Date.now() + PUBLIC_CONFIG_CACHE_TTL_MS
  });
  value.server_time = Date.now();
  return apiOk(value);
}

function defaultTelegramAuthSettings(): AnyRecord {
  return {
    enabled: false,
    bot_username: "",
    bot_token: "",
    client_secret: "",
    oidc_redirect_uri: "",
    mini_app_url: "",
    login_expire_seconds: 300,
    replay_ttl_seconds: 300
  };
}

function normalizeTelegramAuthSettings(value: unknown): AnyRecord {
  const input = { ...defaultTelegramAuthSettings(), ...jsonObject(value) };
  const loginExpireSeconds = clampInteger(input.login_expire_seconds, 30, 86400, 300);
  return {
    enabled: input.enabled === true,
    bot_username: clean(input.bot_username, 120).replace(/^@/, ""),
    bot_token: clean(input.bot_token, 500),
    client_secret: clean(input.client_secret, 500),
    oidc_redirect_uri: clean(input.oidc_redirect_uri, 1000).replace(/\/+$/, ""),
    mini_app_url: clean(input.mini_app_url, 1000),
    login_expire_seconds: loginExpireSeconds,
    replay_ttl_seconds: clampInteger(input.replay_ttl_seconds, 60, 86400, loginExpireSeconds)
  };
}

async function telegramAuthSettings(env: Env): Promise<AnyRecord> {
  return normalizeTelegramAuthSettings(await setting(env, "telegram_auth", defaultTelegramAuthSettings()));
}

function telegramLoginMode(value: unknown): "" | "widget" | "oidc" {
  const config = normalizeTelegramAuthSettings(value);
  if (!config.enabled) return "";
  if (config.client_secret && config.oidc_redirect_uri && /^\d+:[^\s]+$/.test(config.bot_token)) return "oidc";
  return config.bot_token ? "widget" : "";
}

function redactTelegramAuthSettings(value: unknown): AnyRecord {
  const config = normalizeTelegramAuthSettings(value);
  return {
    ...config,
    bot_token: "",
    has_bot_token: Boolean(config.bot_token),
    client_secret: "",
    has_client_secret: Boolean(config.client_secret),
    mode: telegramLoginMode(config)
  };
}

function publicTelegramAuthSettings(value: unknown): AnyRecord {
  const config = normalizeTelegramAuthSettings(value);
  return {
    enabled: config.enabled,
    bot_username: config.bot_username,
    mini_app_url: config.mini_app_url,
    mode: telegramLoginMode(config)
  };
}

function sanitizeTelegramAuthSettings(value: unknown, current: unknown): AnyRecord {
  const patch = jsonObject(value);
  const next = normalizeTelegramAuthSettings(current);
  if (Object.prototype.hasOwnProperty.call(patch, "enabled")) next.enabled = patch.enabled === true;
  if (Object.prototype.hasOwnProperty.call(patch, "bot_username")) next.bot_username = clean(patch.bot_username, 120).replace(/^@/, "");
  if (Object.prototype.hasOwnProperty.call(patch, "bot_token")) {
    const token = clean(patch.bot_token, 500);
    if (token) next.bot_token = token;
  }
  if (Object.prototype.hasOwnProperty.call(patch, "client_secret")) {
    const secret = clean(patch.client_secret, 500);
    if (secret) next.client_secret = secret;
  }
  if (Object.prototype.hasOwnProperty.call(patch, "oidc_redirect_uri")) {
    next.oidc_redirect_uri = clean(patch.oidc_redirect_uri, 1000).replace(/\/+$/, "");
    if (!next.oidc_redirect_uri) next.client_secret = "";
  }
  if (Object.prototype.hasOwnProperty.call(patch, "mini_app_url")) next.mini_app_url = clean(patch.mini_app_url, 1000);
  if (Object.prototype.hasOwnProperty.call(patch, "login_expire_seconds")) {
    next.login_expire_seconds = clampInteger(patch.login_expire_seconds, 30, 86400, next.login_expire_seconds);
  }
  if (Object.prototype.hasOwnProperty.call(patch, "replay_ttl_seconds")) {
    next.replay_ttl_seconds = clampInteger(patch.replay_ttl_seconds, 60, 86400, next.replay_ttl_seconds);
  }

  const normalized = normalizeTelegramAuthSettings(next);
  if (normalized.enabled) {
    if (!normalized.bot_username || /\s/.test(normalized.bot_username)) {
      throw new ApiRequestError(400, "Bot 用户名不能为空且不能包含空白字符");
    }
    if (!normalized.bot_token) throw new ApiRequestError(400, "Bot Token 不能为空");
  }
  if (normalized.client_secret) {
    if (!normalized.oidc_redirect_uri || !isHttpUrl(normalized.oidc_redirect_uri)) {
      throw new ApiRequestError(400, "配置 client_secret 时必须填写合法的 OIDC HTTP(S) 回调地址");
    }
    if (!/^\d+:[^\s]+$/.test(normalized.bot_token)) {
      throw new ApiRequestError(400, "Bot Token 格式无效，无法解析 OIDC client_id");
    }
  }
  return normalized;
}

type CaptchaScene = "login" | "register_send_code" | "reset_send_code" | "guest_create_order" | "gift_card_redeem";

function defaultCaptchaSettings(): AnyRecord {
  return {
    provider: "none",
    scenes: {
      login: false,
      register_send_code: false,
      reset_send_code: false,
      guest_create_order: false,
      gift_card_redeem: false
    },
    image: {
      length: 5,
      width: 240,
      height: 80,
      noise_count: 2,
      show_line: 2,
      expire_seconds: 300,
      max_store: 10240
    },
    turnstile: {
      site_key: "",
      secret_key: "",
      verify_url: "https://challenges.cloudflare.com/turnstile/v0/siteverify",
      timeout_ms: 2000
    }
  };
}

async function captchaSettings(env: Env): Promise<AnyRecord> {
  return normalizeCaptchaSettings(await setting(env, "captcha", defaultCaptchaSettings()), defaultCaptchaSettings());
}

function normalizeCaptchaSettings(value: unknown, current: AnyRecord): AnyRecord {
  const defaults = defaultCaptchaSettings();
  const raw = jsonObject(value);
  const currentValue = jsonObject(current);
  const rawScenes = jsonObject(raw.scenes);
  const currentScenes = jsonObject(currentValue.scenes);
  const rawImage = jsonObject(raw.image);
  const currentImage = jsonObject(currentValue.image);
  const rawTurnstile = jsonObject(raw.turnstile);
  const currentTurnstile = jsonObject(currentValue.turnstile);
  const providerInput = clean(raw.provider, 20).toLowerCase();
  const currentProvider = clean(currentValue.provider, 20).toLowerCase();
  const provider = ["none", "image", "turnstile"].includes(providerInput)
    ? providerInput
    : (["none", "image", "turnstile"].includes(currentProvider) ? currentProvider : "none");
  const scenes: AnyRecord = {};
  for (const scene of ["login", "register_send_code", "reset_send_code", "guest_create_order", "gift_card_redeem"]) {
    scenes[scene] = Object.prototype.hasOwnProperty.call(rawScenes, scene)
      ? rawScenes[scene] === true
      : currentScenes[scene] === true;
  }
  const secretInput = clean(rawTurnstile.secret_key, 500);
  const secretKey = secretInput || clean(currentTurnstile.secret_key, 500);
  return {
    provider,
    scenes,
    image: {
      length: clampInteger(rawImage.length ?? currentImage.length, 4, 8, defaults.image.length),
      width: clampInteger(rawImage.width ?? currentImage.width, 120, 600, defaults.image.width),
      height: clampInteger(rawImage.height ?? currentImage.height, 40, 200, defaults.image.height),
      noise_count: clampInteger(rawImage.noise_count ?? currentImage.noise_count, 0, 20, defaults.image.noise_count),
      show_line: clampInteger(rawImage.show_line ?? currentImage.show_line, 0, 10, defaults.image.show_line),
      expire_seconds: clampInteger(rawImage.expire_seconds ?? currentImage.expire_seconds, 60, 900, defaults.image.expire_seconds),
      max_store: clampInteger(rawImage.max_store ?? currentImage.max_store, 100, 50000, defaults.image.max_store)
    },
    turnstile: {
      site_key: clean(rawTurnstile.site_key ?? currentTurnstile.site_key, 300),
      secret_key: secretKey,
      verify_url: "https://challenges.cloudflare.com/turnstile/v0/siteverify",
      timeout_ms: clampInteger(rawTurnstile.timeout_ms ?? currentTurnstile.timeout_ms, 500, 10000, defaults.turnstile.timeout_ms)
    }
  };
}

function redactCaptchaSettings(value: AnyRecord): AnyRecord {
  const config = cloneJsonRecord(value);
  const turnstile = jsonObject(config.turnstile);
  const hasSecret = Boolean(clean(turnstile.secret_key, 500));
  turnstile.secret_key = "";
  turnstile.has_secret = hasSecret;
  config.turnstile = turnstile;
  return config;
}

function publicCaptchaSettings(value: AnyRecord): AnyRecord {
  const config = redactCaptchaSettings(value);
  const turnstile = jsonObject(config.turnstile);
  return {
    enabled: config.provider !== "none",
    provider: config.provider,
    scenes: config.scenes,
    image: config.image,
    turnstile: {
      site_key: clean(turnstile.site_key, 300),
      has_secret: turnstile.has_secret === true
    }
  };
}

async function apiPublicCaptchaConfig(env: Env): Promise<Response> {
  return apiOk(publicCaptchaSettings(await captchaSettings(env)));
}

async function apiPublicCaptchaImage(env: Env): Promise<Response> {
  const config = await captchaSettings(env);
  if (config.provider !== "image") return apiError("图片验证码未启用", 400);
  const image = jsonObject(config.image);
  const length = clampInteger(image.length, 4, 8, 5);
  const width = clampInteger(image.width, 120, 600, 240);
  const height = clampInteger(image.height, 40, 200, 80);
  const expiresAt = new Date(Date.now() + clampInteger(image.expire_seconds, 60, 900, 300) * 1000).toISOString();
  const captchaId = randomToken();
  const code = randomCaptchaCode(length);
  const codeHash = await sha256Hex(`${captchaId}:${code}`);
  await env.DB.batch([
    env.DB.prepare("DELETE FROM captcha_challenges WHERE expires_at<=CURRENT_TIMESTAMP OR consumed_at IS NOT NULL"),
    env.DB.prepare(
      "INSERT INTO captcha_challenges (id, code_hash, expires_at) VALUES (?, ?, ?)"
    ).bind(captchaId, codeHash, expiresAt)
  ]);
  const maxStore = clampInteger(image.max_store, 100, 50000, 10240);
  await env.DB.prepare(
    `DELETE FROM captcha_challenges
     WHERE id NOT IN (SELECT id FROM captcha_challenges ORDER BY created_at DESC LIMIT ?)`
  ).bind(maxStore).run();
  const svg = captchaSvg(code, width, height, clampInteger(image.show_line, 0, 10, 2));
  return apiOk({
    captcha_id: captchaId,
    image_base64: `data:image/svg+xml;base64,${btoa(svg)}`,
    expires_at: expiresAt
  });
}

function randomCaptchaCode(length: number): string {
  const alphabet = "23456789ABCDEFGHJKLMNPQRSTUVWXYZ";
  const bytes = crypto.getRandomValues(new Uint8Array(length));
  return Array.from(bytes, (byte) => alphabet[byte % alphabet.length]).join("");
}

function captchaSvg(code: string, width: number, height: number, lineCount: number): string {
  const lines = Array.from({ length: lineCount }, (_, index) => {
    const y1 = Math.round((index + 1) * height / (lineCount + 1));
    const y2 = Math.round(height - y1 / 2);
    return `<line x1="0" y1="${y1}" x2="${width}" y2="${y2}" stroke="#64748b" stroke-width="1" opacity="0.55"/>`;
  }).join("");
  const fontSize = Math.max(24, Math.floor(height * 0.58));
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}"><rect width="100%" height="100%" fill="#f8fafc"/>${lines}<text x="50%" y="52%" dominant-baseline="middle" text-anchor="middle" font-family="Arial,sans-serif" font-size="${fontSize}" font-weight="700" letter-spacing="8" fill="#111827">${code}</text></svg>`;
}

async function validateCaptchaForScene(
  env: Env,
  request: Request,
  body: AnyRecord,
  scene: CaptchaScene
): Promise<{ ok: true } | { ok: false; error: string; status: number }> {
  const config = await captchaSettings(env);
  if (config.provider === "none" || jsonObject(config.scenes)[scene] !== true) return { ok: true };
  const nested = jsonObject(body.captcha_payload);
  const payload = Object.keys(nested).length ? nested : body;
  if (config.provider === "image") {
    const captchaId = clean(payload.captcha_id, 160);
    const captchaCode = clean(payload.captcha_code, 20).toUpperCase();
    if (!captchaId || !captchaCode) return { ok: false, error: "请输入验证码", status: 400 };
    const codeHash = await sha256Hex(`${captchaId}:${captchaCode}`);
    const result = await env.DB.prepare(
      `UPDATE captcha_challenges
       SET attempts=attempts+1,
           consumed_at=CASE
             WHEN code_hash=? OR attempts+1>=5 THEN CURRENT_TIMESTAMP
             ELSE consumed_at
           END
       WHERE id=? AND consumed_at IS NULL AND expires_at>CURRENT_TIMESTAMP
       RETURNING CASE WHEN code_hash=? THEN 1 ELSE 0 END AS matched`
    ).bind(codeHash, captchaId, codeHash).first<{ matched: number }>();
    return result?.matched
      ? { ok: true }
      : { ok: false, error: "验证码错误或已过期", status: 400 };
  }
  if (config.provider === "turnstile") {
    const token = clean(payload.turnstile_token || payload["cf-turnstile-response"], 4000);
    const secret = clean(jsonObject(config.turnstile).secret_key, 500);
    if (!token) return { ok: false, error: "请完成人机验证", status: 400 };
    if (!secret) return { ok: false, error: "人机验证服务未配置", status: 503 };
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), clampInteger(jsonObject(config.turnstile).timeout_ms, 500, 10000, 2000));
    try {
      const params = new URLSearchParams({ secret, response: token });
      const ip = clientIp(request);
      if (ip) params.set("remoteip", ip);
      const response = await fetch("https://challenges.cloudflare.com/turnstile/v0/siteverify", {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: params,
        signal: controller.signal
      });
      const result = await response.json<AnyRecord>();
      return response.ok && result.success === true
        ? { ok: true }
        : { ok: false, error: "人机验证失败，请重试", status: 400 };
    } catch {
      return { ok: false, error: "人机验证服务暂不可用", status: 503 };
    } finally {
      clearTimeout(timeout);
    }
  }
  return { ok: false, error: "验证码配置不合法", status: 503 };
}

