async function guestOrderFromPaymentPayload(
  request: Request,
  env: Env,
  body: AnyRecord
): Promise<{ ok: true; order: OrderRow } | { ok: false; error: string; status: number }> {
  const orderNo = clean(body.order_no, 80);
  const email = normalizeEmail(body.email);
  const orderPassword = String(body.order_password || "");
  if (!orderNo) return { ok: false, error: "订单号不能为空", status: 400 };
  if (!email || !orderPassword) return { ok: false, error: "请输入查询邮箱和订单密码", status: 400 };
  const scope = await storefrontOrderScope(request, env);
  const order = await env.DB.prepare(`SELECT * FROM orders WHERE order_no=? AND user_id=0 AND parent_id IS NULL AND ${scope.sql}`)
    .bind(orderNo, ...scope.params)
    .first<OrderRow>();
  if (!order) return { ok: false, error: "订单不存在", status: 404 };
  if (!await verifyGuestOrderAccess(order, email, orderPassword)) {
    return { ok: false, error: "订单不存在或查询信息错误", status: 403 };
  }
  return { ok: true, order };
}

async function guestOrderFromPaymentQuery(
  request: Request,
  env: Env,
  url: URL
): Promise<{ ok: true; order: OrderRow } | { ok: false; error: string; status: number }> {
  return guestOrderFromPaymentPayload(request, env, {
    order_no: url.searchParams.get("order_no"),
    email: url.searchParams.get("email"),
    order_password: url.searchParams.get("order_password")
  });
}

async function createOrReturnOrderPayment(
  env: Env,
  order: OrderRow,
  channelId: number,
  useBalance = false,
  authenticatedUser: UserRow | null = null
): Promise<AnyRecord> {
  if (order.parent_id != null) throw new ApiRequestError(400, "子订单不能单独发起支付");
  const expiresAt = order.expires_at ? new Date(order.expires_at).getTime() : 0;
  if (order.status === "pending_payment" && expiresAt > 0 && expiresAt <= Date.now()) {
    await cancelExpiredPendingOrder(env, order.id);
    order = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(order.id).first<OrderRow>() || order;
  }
  if (order.status !== "pending_payment") {
    return {
      order_paid: ["paid", "fulfilling", "partially_delivered", "delivered", "completed"].includes(order.status),
      order_no: order.order_no,
      order_status: order.status,
      status: order.status,
      wallet_paid_amount: money(Number(order.wallet_paid_amount || 0)),
      online_pay_amount: money(Number(order.online_paid_amount || 0)),
      online_paid_amount: money(Number(order.online_paid_amount || 0)),
      payment_id: null,
      provider_type: "manual",
      channel_type: "manual",
      interaction_mode: "none",
      pay_url: "",
      qr_code: ""
    };
  }

  let channel: PaymentChannelRow | null = null;
  let existing: PaymentRow | null = null;
  let orderProducts: ProductRow[] = [];
  if (channelId > 0) {
    [channel, existing, orderProducts] = await paymentChannelAndReusablePayment(env, order.id, channelId);
    if (!channel) throw new ApiRequestError(404, "支付渠道不存在");
    if (existing) {
      const existingProviderType = clean(existing.provider_type, 40).toLowerCase();
      const missingPaymentTarget = !clean(existing.pay_url, 1000) && !clean(existing.qr_code, 2000);
      if (isImplementedPaymentProvider(existingProviderType, existing.channel_type) && missingPaymentTarget) {
        const prepared = await prepareProviderOrderPayment(env, existing, order, channel);
        if (!prepared.ok) {
          await failOrderPaymentCreation(env, existing, order, prepared.error);
          throw new ApiRequestError(400, prepared.error);
        }
        return formatPaymentCreateResult(prepared.payment, order);
      }
      return formatPaymentCreateResult(existing, order);
    }
  }

  if (order.user_id) {
    if (useBalance) {
      order = await applyOrderWalletBalance(env, order);
    } else if (moneyToCents(Number(order.wallet_paid_amount || 0)) > 0) {
      await releaseOrderWalletBalance(env, order.id, "用户改为在线支付，退回余额");
      order = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(order.id).first<OrderRow>() || order;
    }
  }

  const amount = Number(order.online_paid_amount || order.total_amount || 0);
  if (moneyToCents(amount) <= 0) {
    await markOrderPaid(env, order.id);
    return {
      order_paid: true,
      order_no: order.order_no,
      order_status: "paid",
      status: "paid",
      wallet_paid_amount: money(Number(order.wallet_paid_amount || 0)),
      online_pay_amount: "0.00",
      online_paid_amount: "0.00",
      payment_id: null,
      provider_type: "manual",
      channel_type: "manual",
      interaction_mode: "none",
      pay_url: "",
      qr_code: ""
    };
  }

  if (channelId <= 0) throw new ApiRequestError(400, "请选择支付方式");
  if (!channel) throw new ApiRequestError(404, "支付渠道不存在");
  const validationError = await validatePaymentChannelForOrder(
    env,
    channel,
    order,
    amount,
    authenticatedUser,
    orderProducts
  );
  if (validationError) throw new ApiRequestError(400, validationError);

  let payment = await createManualPaymentForOrder(env, {
    orderId: order.id,
    orderNo: order.order_no,
    userId: order.user_id || 0,
    guestEmail: order.guest_email || "",
    channelId,
    channel,
    amount,
    status: "pending",
    paidAt: null
  });
  if (!payment) {
    payment = await reusablePaymentForOrderChannel(env, order.id, channelId);
    if (!payment) throw new ApiRequestError(409, "支付正在创建，请稍后重试");
  }
  const hydrated = payment ? { ...payment, order_no: order.order_no, channel_name: channel.name } : null;
  if (hydrated && clean(hydrated.provider_type, 40).toLowerCase() !== "manual") {
    const prepared = await prepareProviderOrderPayment(env, hydrated, order, channel);
    if (!prepared.ok) {
      await failOrderPaymentCreation(env, hydrated, order, prepared.error);
      throw new ApiRequestError(400, prepared.error);
    }
    return formatPaymentCreateResult(prepared.payment, order);
  }
  return hydrated ? formatPaymentCreateResult(hydrated, order) : {
    order_paid: false,
    order_no: order.order_no,
    order_status: order.status,
    status: order.status,
    payment_id: null
  };
}

async function failOrderPaymentCreation(
  env: Env,
  payment: PaymentRow,
  order: OrderRow,
  error: string
): Promise<void> {
  await env.DB.prepare(
    `UPDATE payments
     SET status='failed', provider_payload_json=?, updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND status IN ('initiated','pending','created')`
  ).bind(stringify({ error: clean(error, 500) || "payment_create_failed" }), payment.id).run();
  await releaseOrderWalletBalance(env, order.id, "在线支付创建失败，退回余额");
}

async function captureOrderPayment(env: Env, payment: PaymentRow, order: OrderRow): Promise<Response> {
  if (payment.status === "success") {
    if (!await markOrderPaid(env, order.id)) return apiError("订单已取消或当前状态不能支付", 409);
    const fresh = await paymentByIdWithContext(env, payment.id);
    return apiOk(formatPaymentCreateResult(fresh || payment, order));
  }

  const providerKey = paymentProviderKey(payment.provider_type, payment.channel_type);
  if (!["official:stripe", "official:paypal", "official:wechat"].includes(providerKey)) {
    return apiError("该支付渠道不支持主动确认，请等待支付平台回调", 409);
  }
  const queried = await queryOfficialPayment(env, payment);
  if (!queried.ok) return apiError(queried.error, queried.statusCode);
  const verified = verifyQueriedPaymentAgainstRecord(payment, queried);
  if (!verified.ok) return apiError(verified.error, 409);
  await applyVerifiedPaymentCallback(env, payment, verified.callback);
  const freshPayment = await paymentByIdWithContext(env, payment.id) || payment;
  const freshOrder = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(order.id).first<OrderRow>() || order;
  return apiOk(formatPaymentCreateResult(freshPayment, freshOrder));
}

async function markOrderPaid(env: Env, orderId: number, ctx?: ExecutionContext): Promise<boolean> {
  const result = await env.DB.prepare(
    "UPDATE orders SET status='paid', paid_at=COALESCE(paid_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP WHERE id=? AND status='pending_payment'"
  ).bind(orderId).run();
  const order = await env.DB.prepare("SELECT status, paid_at FROM orders WHERE id=?").bind(orderId).first<{ status: string; paid_at: string | null }>();
  if (!order?.paid_at || !["paid", "fulfilling", "partially_delivered", "delivered", "completed", "partially_refunded", "refunded"].includes(order.status)) {
    return false;
  }
  if (order.status !== "refunded") {
    await finalizePaidOrder(env, orderId, ctx);
  }
  return Number(result.meta.changes || 0) > 0 || Boolean(order.paid_at);
}

async function latestPaymentForOrder(env: Env, orderId: number): Promise<PaymentRow | null> {
  return env.DB.prepare(
    `SELECT p.*, o.order_no AS order_no, pc.name AS channel_name
     FROM payments p
     LEFT JOIN orders o ON o.id=p.order_id
     LEFT JOIN payment_channels pc ON pc.id=p.channel_id
     WHERE p.order_id=?
     ORDER BY p.id DESC
     LIMIT 1`
  ).bind(orderId).first<PaymentRow>();
}

async function paymentChannelAndReusablePayment(
  env: Env,
  orderId: number,
  channelId: number
): Promise<[PaymentChannelRow | null, PaymentRow | null, ProductRow[]]> {
  const [channelResult, paymentResult, productsResult] = await env.DB.batch([
    env.DB.prepare("SELECT * FROM payment_channels WHERE id=?").bind(channelId),
    env.DB.prepare(
      `SELECT p.*, o.order_no AS order_no, pc.name AS channel_name
       FROM payments p
       LEFT JOIN orders o ON o.id=p.order_id
       LEFT JOIN payment_channels pc ON pc.id=p.channel_id
       WHERE p.order_id=? AND p.channel_id=?
         AND p.status IN ('initiated','pending','created')
         AND (p.expired_at IS NULL OR p.expired_at > CURRENT_TIMESTAMP)
       ORDER BY p.id DESC
       LIMIT 1`
    ).bind(orderId, channelId),
    env.DB.prepare(
      `SELECT DISTINCT p.*
       FROM order_items oi
       JOIN orders item_order ON item_order.id=oi.order_id
       JOIN products p ON p.id=oi.product_id
       WHERE item_order.id=? OR item_order.parent_id=?`
    ).bind(orderId, orderId)
  ]);
  return [
    (channelResult.results?.[0] as PaymentChannelRow | undefined) || null,
    (paymentResult.results?.[0] as PaymentRow | undefined) || null,
    (productsResult.results || []) as ProductRow[]
  ];
}

async function reusablePaymentForOrderChannel(
  env: Env,
  orderId: number,
  channelId: number
): Promise<PaymentRow | null> {
  return env.DB.prepare(
    `SELECT p.*, o.order_no AS order_no, pc.name AS channel_name
     FROM payments p
     LEFT JOIN orders o ON o.id=p.order_id
     LEFT JOIN payment_channels pc ON pc.id=p.channel_id
     WHERE p.order_id=? AND p.channel_id=?
       AND p.status IN ('initiated','pending','created')
       AND (p.expired_at IS NULL OR p.expired_at > CURRENT_TIMESTAMP)
     ORDER BY p.id DESC
     LIMIT 1`
  ).bind(orderId, channelId).first<PaymentRow>();
}

async function paymentByIdWithContext(env: Env, paymentId: number): Promise<PaymentRow | null> {
  return env.DB.prepare(
    `SELECT p.*, o.order_no AS order_no, pc.name AS channel_name,
            wr.recharge_no AS recharge_no, wr.user_id AS recharge_user_id, wr.status AS recharge_status
     FROM payments p
     LEFT JOIN orders o ON o.id=p.order_id
     LEFT JOIN payment_channels pc ON pc.id=p.channel_id
     LEFT JOIN wallet_recharges wr ON wr.payment_id=p.id
     WHERE p.id=?`
  ).bind(paymentId).first<PaymentRow>();
}

function formatPaymentCreateResult(payment: PaymentRow, order: OrderRow): AnyRecord {
  return {
    ...formatPayment(payment),
    order_paid: payment.status === "success" || ["paid", "fulfilling", "partially_delivered", "delivered", "completed"].includes(order.status),
    order_no: order.order_no,
    order_status: order.status,
    payment_id: payment.id,
    online_pay_amount: money(Number(payment.amount || order.online_paid_amount || 0)),
    online_paid_amount: money(Number(order.online_paid_amount || payment.amount || 0)),
    wallet_paid_amount: money(Number(order.wallet_paid_amount || 0))
  };
}

type ProviderPaymentTarget = {
  bizType: "order" | "wallet_recharge";
  businessNo: string;
  subject: string;
  returnUrl: string;
  orderUserKey: string;
  clientIp?: string;
};

type PreparedProviderPayment = { ok: true; payment: PaymentRow } | { ok: false; error: string };

const IMPLEMENTED_PAYMENT_PROVIDERS = new Set([
  "epay",
  "bepusdt",
  "epusdt",
  "tokenpay",
  "okpay",
  "dujiaopay",
  "official:stripe",
  "official:paypal",
  "official:alipay",
  "official:wechat"
]);

function paymentProviderKey(providerType: unknown, channelType?: unknown): string {
  const provider = clean(providerType, 40).toLowerCase();
  return provider === "official" ? `${provider}:${clean(channelType, 40).toLowerCase()}` : provider;
}

function isImplementedPaymentProvider(providerType: unknown, channelType?: unknown): boolean {
  return IMPLEMENTED_PAYMENT_PROVIDERS.has(paymentProviderKey(providerType, channelType));
}

async function prepareProviderOrderPayment(
  env: Env,
  payment: PaymentRow,
  order: OrderRow,
  channel?: PaymentChannelRow
): Promise<PreparedProviderPayment> {
  const siteUrl = await sitePublicUrl(env);
  return prepareProviderPaymentTarget(env, payment, {
    bizType: "order",
    businessNo: order.order_no,
    subject: `订单 ${order.order_no}`,
    returnUrl: `${siteUrl}/pay?${order.user_id ? "" : "guest=1&"}order_no=${encodeURIComponent(order.order_no)}`,
    orderUserKey: order.user_id ? String(order.user_id) : (clean(order.guest_email, 255) || order.order_no),
    clientIp: clean(order.client_ip, 100)
  }, channel);
}

async function prepareProviderRechargePayment(env: Env, payment: PaymentRow, recharge: WalletRechargeRow): Promise<PreparedProviderPayment> {
  const siteUrl = await sitePublicUrl(env);
  const providerPayload = jsonObject(jsonParse(payment.provider_payload_json || "{}", {}));
  return prepareProviderPaymentTarget(env, payment, {
    bizType: "wallet_recharge",
    businessNo: recharge.recharge_no,
    subject: `余额充值 ${recharge.recharge_no}`,
    returnUrl: `${siteUrl}/recharge-orders/${encodeURIComponent(recharge.recharge_no)}`,
    orderUserKey: String(recharge.user_id),
    clientIp: clean(providerPayload.client_ip, 100)
  });
}

async function prepareProviderPaymentTarget(
  env: Env,
  payment: PaymentRow,
  target: ProviderPaymentTarget,
  channel?: PaymentChannelRow
): Promise<PreparedProviderPayment> {
  const providerType = clean(payment.provider_type, 40).toLowerCase();
  switch (paymentProviderKey(providerType, payment.channel_type)) {
    case "epay":
      return prepareEpayPaymentTarget(env, payment, target, channel);
    case "bepusdt":
      return prepareBepusdtPaymentTarget(env, payment, target);
    case "epusdt":
      return prepareEpusdtPaymentTarget(env, payment, target);
    case "tokenpay":
      return prepareTokenpayPaymentTarget(env, payment, target);
    case "okpay":
      return prepareOkpayPaymentTarget(env, payment, target);
    case "dujiaopay":
      return prepareDujiaoPayPaymentTarget(env, payment, target);
    case "official:stripe":
      return prepareStripePaymentTarget(env, payment, target);
    case "official:paypal":
      return preparePaypalPaymentTarget(env, payment, target);
    case "official:alipay":
      return prepareAlipayPaymentTarget(env, payment, target);
    case "official:wechat":
      return prepareWechatPaymentTarget(env, payment, target);
    default:
      return { ok: false, error: `支付服务 ${providerType || "unknown"} 尚未接入 Cloudflare 运行时` };
  }
}

async function prepareEpayPaymentTarget(
  env: Env,
  payment: PaymentRow,
  target: ProviderPaymentTarget,
  paymentChannel?: PaymentChannelRow
): Promise<{ ok: true; payment: PaymentRow } | { ok: false; error: string }> {
  const channel = paymentChannel || await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const gateway = clean(config.gateway_url, 1000).replace(/\/+$/, "");
  const version = (clean(config.epay_version, 20) || "v1").toLowerCase();
  const merchantId = clean(config.merchant_id || config.pid, 120);
  const merchantKey = clean(config.merchant_key || config.key, 2000);
  const privateKey = clean(config.private_key, 20000);
  if (!gateway || !merchantId || !["v1", "v2"].includes(version)
    || (version === "v1" && !merchantKey) || (version === "v2" && !privateKey)) {
    return { ok: false, error: "易支付渠道配置不完整" };
  }
  const notifyUrl = clean(config.notify_url, 1000) || await paymentCallbackUrl(env);
  const returnUrl = paymentReturnUrl(config.return_url, target, "epay_return");
  const mode = clean(payment.interaction_mode, 30).toLowerCase();
  if (!["qr", "redirect"].includes(mode)) return { ok: false, error: "易支付仅支持二维码或跳转模式" };
  const gatewayAmount = convertedPaymentAmount(payment, config);
  const payType = normalizeEpayPayType(payment.channel_type);
  if (!payType) return { ok: false, error: "易支付渠道类型仅支持支付宝、微信或 QQ 钱包" };
  const params: Record<string, string> = {
    pid: merchantId,
    type: payType,
    out_trade_no: payment.payment_no,
    notify_url: notifyUrl,
    return_url: returnUrl,
    name: target.subject || payment.payment_no,
    money: gatewayAmount.amount
  };
  if (version === "v2") params.timestamp = String(Math.floor(Date.now() / 1000));
  if (mode === "qr") {
    params.clientip = wechatClientIp(target.clientIp);
    if (version === "v1") params.device = clean(config.device, 30) || "pc";
    else params.method = clean(config.method, 30) || "web";
  }
  try {
    params.sign = version === "v2"
      ? await rsaPkcs1SignBase64(privateKey, providerSignContent(params), "SHA-256")
      : epaySignPayload(params, merchantKey);
  } catch (error) {
    return { ok: false, error: error instanceof Error ? error.message : "易支付请求签名失败" };
  }
  params.sign_type = version === "v2" ? "RSA" : (clean(config.sign_type, 20) || "MD5");

  let payUrl = "";
  let qrCode = "";
  let providerRef = "";
  let providerResponse: AnyRecord;
  if (mode === "redirect") {
    const submitPath = version === "v2" ? "/api/pay/submit" : "/submit.php";
    const endpoint = providerEndpoint(gateway, submitPath);
    if (!endpoint) return { ok: false, error: "易支付跳转地址无效或指向内网" };
    payUrl = `${endpoint}?${new URLSearchParams(params).toString()}`;
    providerResponse = { mode, endpoint, params: { ...params, sign: "" } };
  } else {
    const apiPath = clean(config.api_path, 200) || (version === "v2" ? "/api/pay/create" : "/mapi.php");
    const endpoint = providerEndpoint(gateway, apiPath);
    if (!endpoint) return { ok: false, error: "易支付 API 地址无效或指向内网" };
    const response = await requestPaymentProvider(endpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
        "Accept-Language": "zh-CN,zh;q=0.9,en;q=0.8"
      },
      body: new URLSearchParams(params).toString()
    });
    if (!response.ok) return { ok: false, error: `易支付创建支付失败：${response.error}` };
    providerResponse = response.data;
    const code = Number(response.data.code);
    const expectedCode = version === "v2" ? 0 : 1;
    if (code !== expectedCode) {
      return { ok: false, error: `易支付创建支付失败：${responseString(response.data.msg, 300) || `code ${String(response.data.code ?? "")}`}` };
    }
    providerRef = responseString(response.data.trade_no, 200);
    if (version === "v2") {
      const payInfo = responseString(response.data.pay_info, 4000);
      if (responseString(response.data.pay_type, 40).toLowerCase() === "qrcode") qrCode = payInfo;
      else payUrl = payInfo;
    } else {
      payUrl = responseString(response.data.payurl, 4000) || responseString(response.data.urlscheme, 4000);
      qrCode = responseString(response.data.qrcode, 4000);
    }
    if (!payUrl && !qrCode) return { ok: false, error: "易支付响应缺少支付地址或二维码" };
  }
  const providerPayload: AnyRecord = {
    provider_response: providerResponse,
    epay_version: version,
    gateway_amount: gatewayAmount.amount,
    gateway_currency: gatewayAmount.currency,
    notify_url: notifyUrl,
    return_url: returnUrl
  };
  if (gatewayAmount.converted) {
    providerPayload.exchange_rate = clean(config.exchange_rate, 80);
    providerPayload.original_amount = gatewayAmount.originalAmount;
    providerPayload.original_currency = gatewayAmount.originalCurrency;
  }
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode,
    providerRef,
    amount: gatewayAmount.amount,
    currency: gatewayAmount.currency,
    payload: providerPayload
  });
}

function normalizeEpayPayType(value: unknown): string {
  const type = clean(value, 40).toLowerCase();
  if (["alipay", "wxpay", "wechat", "qqpay"].includes(type)) {
    return type === "wechat" ? "wxpay" : type;
  }
  return "";
}

async function paymentCallbackUrl(env: Env): Promise<string> {
  const [routeSetting, publicUrl] = await Promise.all([
    setting(env, "callback_routes_config", {}),
    sitePublicUrl(env)
  ]);
  const routes = normalizeCallbackRoutesSetting(routeSetting);
  const path = clean(routes.payment_callback, 500) || CALLBACK_ROUTE_DEFAULTS.payment_callback;
  return `${publicUrl.replace(/\/+$/, "")}${path}`;
}

function paymentReturnUrl(configured: unknown, target: ProviderPaymentTarget, marker: string): string {
  const raw = clean(configured, 1000) || target.returnUrl;
  try {
    const url = new URL(raw);
    if (url.protocol !== "http:" && url.protocol !== "https:") return target.returnUrl;
    url.searchParams.set("biz_type", target.bizType);
    url.searchParams.set(target.bizType === "wallet_recharge" ? "recharge_no" : "order_no", target.businessNo);
    url.searchParams.set(marker, "1");
    return url.toString();
  } catch {
    return target.returnUrl;
  }
}

function providerEndpoint(base: unknown, path: string): string {
  const normalized = clean(base, 1000).replace(/\/+$/, "");
  if (!normalized) return "";
  const endpoint = `${normalized}${path.startsWith("/") ? path : `/${path}`}`;
  return isSafeCallbackUrl(endpoint) ? endpoint : "";
}

async function postPaymentProvider(
  endpoint: string,
  body: AnyRecord,
  contentType: "json" | "form" = "json"
): Promise<{ ok: true; data: AnyRecord } | { ok: false; error: string }> {
  if (!endpoint || !isSafeCallbackUrl(endpoint)) return { ok: false, error: "支付网关地址无效或指向内网" };
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 15000);
  try {
    const requestBody = contentType === "json"
      ? JSON.stringify(body)
      : new URLSearchParams(Object.entries(body).map(([key, value]) => [key, String(value ?? "")] as [string, string])).toString();
    const response = await fetch(endpoint, {
      method: "POST",
      headers: {
        "Accept": "application/json",
        "Content-Type": contentType === "json" ? "application/json" : "application/x-www-form-urlencoded"
      },
      body: requestBody,
      redirect: "manual",
      signal: controller.signal
    });
    if (response.status >= 300 && response.status < 400) {
      return { ok: false, error: "支付网关返回了不安全的重定向" };
    }
    const contentLength = Number(response.headers.get("Content-Length") || 0);
    if (contentLength > 1024 * 1024) return { ok: false, error: "支付网关响应过大" };
    const text = await response.text();
    if (new TextEncoder().encode(text).byteLength > 1024 * 1024) return { ok: false, error: "支付网关响应过大" };
    if (!response.ok) return { ok: false, error: `支付网关 HTTP ${response.status}` };
    let parsed: unknown;
    try {
      parsed = JSON.parse(text);
    } catch {
      return { ok: false, error: "支付网关返回的不是有效 JSON" };
    }
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return { ok: false, error: "支付网关响应格式不正确" };
    }
    return { ok: true, data: parsed as AnyRecord };
  } catch (error) {
    return { ok: false, error: error instanceof Error && error.name === "AbortError" ? "支付网关请求超时" : "连接支付网关失败" };
  } finally {
    clearTimeout(timer);
  }
}

async function postPaymentProviderRaw(
  endpoint: string,
  body: string,
  headers: Record<string, string>
): Promise<{ ok: true; data: AnyRecord } | { ok: false; error: string }> {
  if (!endpoint || !isSafeCallbackUrl(endpoint)) return { ok: false, error: "支付网关地址无效或指向内网" };
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 15000);
  try {
    const response = await fetch(endpoint, {
      method: "POST",
      headers: { "Accept": "application/json", "Content-Type": "application/json", ...headers },
      body,
      redirect: "manual",
      signal: controller.signal
    });
    if (response.status >= 300 && response.status < 400) return { ok: false, error: "支付网关返回了不安全的重定向" };
    const contentLength = Number(response.headers.get("Content-Length") || 0);
    if (contentLength > 1024 * 1024) return { ok: false, error: "支付网关响应过大" };
    const text = await response.text();
    if (new TextEncoder().encode(text).byteLength > 1024 * 1024) return { ok: false, error: "支付网关响应过大" };
    if (!response.ok) return { ok: false, error: `支付网关 HTTP ${response.status}` };
    try {
      const parsed = JSON.parse(text);
      return parsed && typeof parsed === "object" && !Array.isArray(parsed)
        ? { ok: true, data: parsed as AnyRecord }
        : { ok: false, error: "支付网关响应格式不正确" };
    } catch {
      return { ok: false, error: "支付网关返回的不是有效 JSON" };
    }
  } catch (error) {
    return { ok: false, error: error instanceof Error && error.name === "AbortError" ? "支付网关请求超时" : "连接支付网关失败" };
  } finally {
    clearTimeout(timer);
  }
}

function providerSignValue(value: unknown): string {
  if (value === null || value === undefined) return "";
  if (typeof value === "string") return value.trim();
  if (typeof value === "number") return Number.isFinite(value) ? String(value) : "";
  if (typeof value === "boolean") return value ? "true" : "false";
  return stableJsonStringify(value);
}

function stableJsonStringify(value: unknown): string {
  if (value === null || typeof value !== "object") return JSON.stringify(value);
  if (Array.isArray(value)) return `[${value.map(stableJsonStringify).join(",")}]`;
  const object = value as AnyRecord;
  return `{${Object.keys(object).sort().map((key) => `${JSON.stringify(key)}:${stableJsonStringify(object[key])}`).join(",")}}`;
}

function sortedProviderSignature(
  payload: AnyRecord,
  secret: string,
  options: { signatureKey?: string; suffix?: string; caseInsensitiveKey?: boolean } = {}
): string {
  const signatureKey = options.signatureKey || "signature";
  const parts = Object.keys(payload)
    .filter((key) => options.caseInsensitiveKey ? key.toLowerCase() !== signatureKey.toLowerCase() : key !== signatureKey)
    .map((key) => [key, providerSignValue(payload[key])] as const)
    .filter(([, value]) => value !== "")
    .sort(([left], [right]) => left.localeCompare(right))
    .map(([key, value]) => `${key}=${value}`);
  return md5Hex(`${parts.join("&")}${options.suffix || ""}${secret}`);
}

function responseString(value: unknown, max = 2000): string {
  return typeof value === "string" || typeof value === "number" ? clean(value, max) : "";
}

async function persistPreparedProviderPayment(
  env: Env,
  payment: PaymentRow,
  result: { payUrl: string; qrCode: string; providerRef: string; payload: AnyRecord; amount?: string; currency?: string }
): Promise<PreparedProviderPayment> {
  const previous = jsonObject(jsonParse(payment.provider_payload_json || "{}", {}));
  const providerPayload = { ...previous, ...result.payload };
  const amount = clean(result.amount, 80);
  const currency = clean(result.currency, 20).toUpperCase();
  const fresh = await env.DB.prepare(
    `UPDATE payments
     SET pay_url=?, qr_code=?, provider_ref=COALESCE(NULLIF(?, ''), provider_ref),
         provider_payload_json=?, amount=CASE WHEN ?<>'' THEN CAST(? AS REAL) ELSE amount END,
         currency=CASE WHEN ?<>'' THEN ? ELSE currency END, status='pending', updated_at=CURRENT_TIMESTAMP
     WHERE id=?
     RETURNING *`
  ).bind(
    clean(result.payUrl, 4000), clean(result.qrCode, 10000), clean(result.providerRef, 200),
    stringify(providerPayload), amount, amount, currency, currency, payment.id
  ).first<PaymentRow>();
  return {
    ok: true,
    payment: fresh
      ? { ...fresh, order_no: payment.order_no, channel_name: payment.channel_name }
      : { ...payment, pay_url: result.payUrl, qr_code: result.qrCode, provider_ref: result.providerRef }
  };
}

function bepusdtTradeType(channelType: unknown): string {
  switch (clean(channelType, 40).toLowerCase()) {
    case "usdt":
    case "usdt-trc20": return "usdt.trc20";
    case "usdc-trc20": return "usdc.trc20";
    case "trx": return "tron.trx";
    default: return "";
  }
}

function bepusdtTradeLabels(tradeType: string): { chain: string; tokenId: string } {
  const labels: Record<string, [string, string]> = {
    "usdt.trc20": ["tron", "tron-usdt"],
    "usdt.erc20": ["ethereum", "ethereum-usdt"],
    "usdt.bep20": ["bsc", "bsc-usdt"],
    "usdt.polygon": ["polygon", "polygon-usdt"],
    "usdc.trc20": ["tron", "tron-usdc"],
    "usdc.erc20": ["ethereum", "ethereum-usdc"],
    "usdc.polygon": ["polygon", "polygon-usdc"],
    "usdc.bep20": ["bsc", "bsc-usdc"],
    "tron.trx": ["tron", "tron-trx"],
    "eth.eth": ["ethereum", "ethereum-eth"],
    "bsc.bnb": ["bsc", "bsc-bnb"]
  };
  const [chain = "", tokenId = ""] = labels[tradeType.toLowerCase()] || [];
  return { chain, tokenId };
}

async function prepareBepusdtPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const authToken = clean(config.auth_token, 1000);
  const tradeType = clean(config.trade_type, 80) || bepusdtTradeType(payment.channel_type);
  const fiat = (clean(config.fiat, 20) || payment.currency || "CNY").toUpperCase();
  const endpoint = providerEndpoint(config.gateway_url, "/api/v1/order/create-transaction");
  if (!endpoint || !authToken || !tradeType) return { ok: false, error: "BEpusdt 渠道配置不完整" };
  const notifyUrl = clean(config.notify_url, 1000) || await paymentCallbackUrl(env);
  const returnUrl = paymentReturnUrl(config.return_url, target, "bepusdt_return");
  const amount = money(Number(payment.payable_amount || payment.amount || 0));
  const payload: AnyRecord = {
    order_id: payment.payment_no,
    amount: Number(amount),
    notify_url: notifyUrl,
    redirect_url: returnUrl,
    trade_type: tradeType,
    fiat,
    name: target.subject
  };
  payload.signature = sortedProviderSignature(payload, authToken);
  const response = await postPaymentProvider(endpoint, payload);
  if (!response.ok) return response;
  if (Number(response.data.status_code) !== 200) return { ok: false, error: clean(response.data.message, 300) || "BEpusdt 创建支付失败" };
  const data = jsonObject(response.data.data);
  const tradeId = responseString(data.trade_id, 200);
  const token = responseString(data.token, 1000);
  const paymentUrl = responseString(data.payment_url, 2000);
  if (!tradeId || (!token && !paymentUrl)) return { ok: false, error: "BEpusdt 响应缺少交易信息" };
  const isQr = clean(payment.interaction_mode, 30).toLowerCase() === "qr";
  const labels = bepusdtTradeLabels(tradeType);
  return persistPreparedProviderPayment(env, payment, {
    payUrl: isQr ? "" : paymentUrl,
    qrCode: isQr ? token : paymentUrl,
    providerRef: tradeId,
    payload: {
      provider_response: response.data,
      gateway_amount: amount,
      gateway_currency: fiat,
      notify_url: notifyUrl,
      return_url: returnUrl,
      wallet_address: token,
      chain_amount: responseString(data.actual_amount, 120),
      chain: labels.chain,
      token_id: labels.tokenId,
      trade_type: tradeType
    }
  });
}

async function prepareEpusdtPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const gateway = clean(config.gateway_url, 1000).replace(/\/+$/, "");
  const endpoint = providerEndpoint(gateway, "/payments/gmpay/v1/order/create-transaction");
  const pid = clean(config.pid, 200);
  const secretKey = clean(config.secret_key, 1000);
  const token = clean(config.token, 80).toLowerCase();
  const network = clean(config.network, 80).toLowerCase();
  const currency = (clean(config.currency, 20) || "cny").toLowerCase();
  if (!endpoint || !pid || !secretKey || !token || !network) return { ok: false, error: "epusdt 渠道配置不完整" };
  if (payment.payment_no.length > 32) return { ok: false, error: "epusdt 支付单号超过 32 个字符" };
  const amount = money(Number(payment.payable_amount || payment.amount || 0));
  if (Number(amount) <= 0.01) return { ok: false, error: "epusdt 支付金额必须大于 0.01" };
  const notifyUrl = clean(config.notify_url, 1000) || await paymentCallbackUrl(env);
  const returnUrl = paymentReturnUrl(config.return_url, target, "epusdt_return");
  const payload: AnyRecord = {
    pid,
    order_id: payment.payment_no,
    currency,
    token,
    network,
    amount: Number(amount),
    notify_url: notifyUrl,
    redirect_url: returnUrl,
    name: target.subject
  };
  if (clean(config.payment_type, 80)) payload.payment_type = clean(config.payment_type, 80);
  payload.signature = sortedProviderSignature(payload, secretKey);
  const response = await postPaymentProvider(endpoint, payload);
  if (!response.ok) return response;
  const data = jsonObject(response.data.data);
  const tradeId = responseString(response.data.trade_id || data.trade_id || data.id, 200);
  if (!tradeId) return { ok: false, error: "epusdt 响应缺少 trade_id" };
  const paymentUrl = `${gateway}/pay/checkout-counter/${encodeURIComponent(tradeId)}`;
  return persistPreparedProviderPayment(env, payment, {
    payUrl: paymentUrl,
    qrCode: paymentUrl,
    providerRef: tradeId,
    payload: {
      provider_response: response.data,
      gateway_amount: amount,
      gateway_currency: currency.toUpperCase(),
      notify_url: notifyUrl,
      return_url: returnUrl
    }
  });
}

async function prepareTokenpayPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const endpoint = providerEndpoint(config.gateway_url, "/CreateOrder");
  const secret = clean(config.notify_secret, 1000);
  const currency = clean(config.currency, 80) || "USDT";
  const baseCurrency = (clean(config.base_currency, 20) || payment.currency || "CNY").toUpperCase();
  if (!endpoint || !secret || !currency) return { ok: false, error: "TokenPay 渠道配置不完整" };
  const notifyUrl = clean(config.notify_url, 1000) || await paymentCallbackUrl(env);
  const returnUrl = paymentReturnUrl(config.redirect_url, target, "tokenpay_return");
  const amount = money(Number(payment.payable_amount || payment.amount || 0));
  const payload: AnyRecord = {
    OutOrderId: payment.payment_no,
    OrderUserKey: target.orderUserKey,
    ActualAmount: amount,
    Currency: currency,
    NotifyUrl: notifyUrl,
    RedirectUrl: returnUrl
  };
  payload.Signature = sortedProviderSignature(payload, secret, { signatureKey: "Signature", caseInsensitiveKey: true });
  const response = await postPaymentProvider(endpoint, payload);
  if (!response.ok) return response;
  if (response.data.success !== true) return { ok: false, error: clean(response.data.message, 300) || "TokenPay 创建支付失败" };
  const info = jsonObject(response.data.info);
  const payUrl = responseString(response.data.data || info.PaymentUrl, 2000);
  const qrCode = responseString(info.QrCodeLink || info.QrCodeBase64, 10000);
  if (!payUrl && !qrCode) return { ok: false, error: "TokenPay 响应缺少支付链接" };
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode,
    providerRef: responseString(info.Id, 200),
    payload: {
      provider_response: response.data,
      gateway_amount: amount,
      gateway_currency: baseCurrency,
      notify_url: notifyUrl,
      return_url: returnUrl,
      wallet_address: responseString(info.ToAddress, 1000),
      chain_amount: responseString(info.Amount, 120),
      token_id: currency
    }
  });
}

function okpayCoin(channelType: unknown): string {
  const type = clean(channelType, 40).toLowerCase();
  return type === "usdt" ? "USDT" : type === "trx" ? "TRX" : "";
}

function okpaySignature(pairs: Array<[string, string]>, merchantToken: string): string {
  const content = pairs
    .filter(([key, value]) => key.trim() && value.trim() && key.toLowerCase() !== "sign")
    .map(([key, value]) => `${key.trim()}=${value.trim()}`)
    .join("&");
  return md5Hex(`${content}&token=${merchantToken.trim()}`).toUpperCase();
}

async function prepareOkpayPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const endpoint = providerEndpoint(clean(config.gateway_url, 1000) || "https://api.okaypay.me/shop", "/payLink");
  const merchantId = clean(config.merchant_id, 200);
  const merchantToken = clean(config.merchant_token, 1000);
  const coin = (clean(config.coin, 20) || okpayCoin(payment.channel_type)).toUpperCase();
  const exchangeRate = Number(config.exchange_rate || 1);
  if (!endpoint || !merchantId || !merchantToken || !["USDT", "TRX"].includes(coin) || !Number.isFinite(exchangeRate) || exchangeRate <= 0) {
    return { ok: false, error: "OKPAY 渠道配置不完整" };
  }
  const notifyUrl = clean(config.callback_url, 1000) || await paymentCallbackUrl(env);
  const returnUrl = paymentReturnUrl(config.return_url, target, "okpay_return");
  const originalAmount = Number(payment.payable_amount || payment.amount || 0);
  const gatewayAmount = (Math.round(originalAmount * exchangeRate * 100000000) / 100000000).toFixed(8);
  const unsigned: Record<string, string> = {
    unique_id: payment.payment_no,
    amount: gatewayAmount,
    return_url: returnUrl,
    callback_url: notifyUrl,
    coin,
    name: clean(config.display_name, 255) || target.subject
  };
  if (clean(config.status, 40)) unsigned.status = clean(config.status, 40);
  const pairs = [...Object.entries(unsigned), ["id", merchantId] as [string, string]].sort(([left], [right]) => left.localeCompare(right));
  const payload: AnyRecord = Object.fromEntries(pairs);
  payload.sign = okpaySignature(pairs, merchantToken);
  const response = await postPaymentProvider(endpoint, payload, "form");
  if (!response.ok) return response;
  const rawData = Array.isArray(response.data.data) ? response.data.data[0] : response.data.data;
  const data = jsonObject(rawData);
  const orderId = responseString(data.order_id, 200);
  const payUrl = responseString(data.pay_url, 2000);
  if (!orderId || !payUrl) return { ok: false, error: "OKPAY 响应缺少 order_id 或 pay_url" };
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode: payUrl,
    providerRef: orderId,
    amount: gatewayAmount,
    currency: coin,
    payload: {
      provider_response: response.data,
      gateway_amount: gatewayAmount,
      gateway_currency: coin,
      original_amount: money(originalAmount),
      original_currency: payment.currency,
      exchange_rate: String(exchangeRate),
      notify_url: notifyUrl,
      return_url: returnUrl
    }
  });
}

const DUJIAOPAY_TOKEN_CHAINS: Record<string, string> = {
  "tron-trx": "tron",
  "tron-usdt": "tron",
  "ethereum-eth": "ethereum",
  "ethereum-usdt": "ethereum",
  "ethereum-usdc": "ethereum",
  "bsc-bnb": "bsc",
  "bsc-usdt": "bsc",
  "polygon-usdc": "polygon",
  "polygon-usdt0": "polygon",
  "base-usdc": "base",
  "arbitrum-usdc": "arbitrum",
  "arbitrum-usdt0": "arbitrum",
  "plasma-usdt0": "plasma",
  "x-layer-usdt0": "x-layer",
  "solana-usdc": "solana",
  "solana-usdt": "solana",
  "aptos-usdc": "aptos",
  "aptos-usdt": "aptos"
};

function dujiaoPayChain(tokenId: unknown): string {
  return DUJIAOPAY_TOKEN_CHAINS[clean(tokenId, 80).toLowerCase()] || "";
}

function randomHex(byteCount: number): string {
  const bytes = new Uint8Array(byteCount);
  crypto.getRandomValues(bytes);
  return [...bytes].map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

async function prepareDujiaoPayPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const endpoint = providerEndpoint(config.api_base_url, "/v1/orders");
  const keyId = clean(config.api_key_id, 500);
  const secret = clean(config.api_secret, 1000);
  const webhookSecret = clean(config.webhook_secret, 1000);
  const tokenId = (clean(config.token_id, 80) || clean(payment.channel_type, 80)).toLowerCase();
  const chain = clean(config.chain, 80).toLowerCase() || dujiaoPayChain(tokenId);
  const fiatCurrency = (clean(config.fiat_currency, 20) || payment.currency || "CNY").toUpperCase();
  if (!endpoint || !keyId || !secret || !webhookSecret || !chain || !dujiaoPayChain(tokenId)) {
    return { ok: false, error: "DujiaoPay 渠道配置不完整" };
  }
  const amount = money(Number(payment.payable_amount || payment.amount || 0));
  const successUrl = paymentReturnUrl(config.success_url, target, "dujiaopay_return");
  const cancelUrl = clean(config.cancel_url, 1000);
  const payload: AnyRecord = {
    chain,
    token_id: tokenId,
    fiat_currency: fiatCurrency,
    fiat_amount: amount,
    merchant_order_id: payment.payment_no,
    success_url: successUrl,
    metadata: {
      payment_id: payment.id,
      order_id: payment.order_id,
      subject: target.subject
    }
  };
  if (cancelUrl) payload.cancel_url = cancelUrl;
  const body = JSON.stringify(payload);
  const timestamp = Math.floor(Date.now() / 1000);
  const nonce = randomHex(16);
  const canonical = ["POST", "/v1/orders", "", await sha256Hex(body), String(timestamp), nonce].join("\n");
  const signature = await hmacSha256Hex(secret, canonical);
  const response = await postPaymentProviderRaw(endpoint, body, {
    "Idempotency-Key": payment.payment_no,
    "DJP-Key-ID": keyId,
    "DJP-Timestamp": String(timestamp),
    "DJP-Nonce": nonce,
    "DJP-Signature": signature
  });
  if (!response.ok) return response;
  const data = Object.keys(jsonObject(response.data.data)).length ? jsonObject(response.data.data) : response.data;
  const orderId = responseString(data.order_id, 200);
  const checkoutUrl = responseString(data.checkout_url, 2000);
  const payAddress = responseString(data.pay_address, 1000);
  if (!orderId || !checkoutUrl) return { ok: false, error: "DujiaoPay 响应缺少 order_id 或 checkout_url" };
  const qrCode = clean(payment.interaction_mode, 30).toLowerCase() === "qr" ? (payAddress || checkoutUrl) : checkoutUrl;
  return persistPreparedProviderPayment(env, payment, {
    payUrl: checkoutUrl,
    qrCode,
    providerRef: orderId,
    payload: {
      provider_response: response.data,
      gateway_amount: amount,
      gateway_currency: fiatCurrency,
      order_id: orderId,
      chain: responseString(data.chain, 80) || chain,
      token_id: responseString(data.token_id, 80) || tokenId,
      pay_address: payAddress,
      payable_amount: responseString(data.payable_amount, 120),
      checkout_url: checkoutUrl,
      expires_at: responseString(data.expires_at, 80),
      return_url: successUrl
    }
  });
}

type PaymentProviderHttpResult =
  | { ok: true; status: number; data: AnyRecord }
  | { ok: false; status: number; error: string; data: AnyRecord };

async function readResponseTextLimited(response: Response, maxBytes: number): Promise<{ ok: true; text: string } | { ok: false }> {
  if (!response.body) return { ok: true, text: "" };
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let total = 0;
  let text = "";
  try {
    while (true) {
      const chunk = await reader.read();
      if (chunk.done) break;
      total += chunk.value.byteLength;
      if (total > maxBytes) {
        await reader.cancel("response_too_large").catch(() => undefined);
        return { ok: false };
      }
      text += decoder.decode(chunk.value, { stream: true });
    }
    text += decoder.decode();
    return { ok: true, text };
  } finally {
    reader.releaseLock();
  }
}

async function requestPaymentProvider(
  endpoint: string,
  options: { method?: string; headers?: Record<string, string>; body?: string }
): Promise<PaymentProviderHttpResult> {
  if (!endpoint || !isSafeCallbackUrl(endpoint)) {
    return { ok: false, status: 400, error: "支付网关地址无效或指向内网", data: {} };
  }
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 15000);
  try {
    const response = await fetch(endpoint, {
      method: options.method || "GET",
      headers: { "Accept": "application/json", ...(options.headers || {}) },
      body: options.body,
      redirect: "manual",
      signal: controller.signal
    });
    if (response.status >= 300 && response.status < 400) {
      return { ok: false, status: response.status, error: "支付网关返回了不安全的重定向", data: {} };
    }
    const contentLength = Number(response.headers.get("Content-Length") || 0);
    if (contentLength > 1024 * 1024) {
      return { ok: false, status: 502, error: "支付网关响应过大", data: {} };
    }
    const responseBody = await readResponseTextLimited(response, 1024 * 1024);
    if (!responseBody.ok) {
      return { ok: false, status: 502, error: "支付网关响应过大", data: {} };
    }
    const text = responseBody.text;
    let data: AnyRecord = {};
    if (text) {
      try {
        let parsed = JSON.parse(text);
        if (typeof parsed === "string") parsed = JSON.parse(parsed);
        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) data = parsed as AnyRecord;
      } catch {
        return { ok: false, status: response.status, error: "支付网关返回的不是有效 JSON", data: {} };
      }
    }
    if (!response.ok) {
      const detail = clean(jsonObject(data.error).message || data.message, 300);
      return { ok: false, status: response.status, error: detail || `支付网关 HTTP ${response.status}`, data };
    }
    return { ok: true, status: response.status, data };
  } catch (error) {
    return {
      ok: false,
      status: 502,
      error: error instanceof Error && error.name === "AbortError" ? "支付网关请求超时" : "连接支付网关失败",
      data: {}
    };
  } finally {
    clearTimeout(timer);
  }
}

function roundedDecimalProduct(value: unknown, multiplier: unknown, places = 2): string {
  const parse = (input: unknown): { units: bigint; scale: number } | null => {
    const match = String(input ?? "").trim().match(/^\+?(\d+)(?:\.(\d+))?$/);
    if (!match) return null;
    const fraction = match[2] || "";
    return { units: BigInt(`${match[1]}${fraction}`), scale: fraction.length };
  };
  const left = parse(value);
  const right = parse(multiplier);
  if (!left || !right || left.units <= 0n || right.units <= 0n) throw new ApiRequestError(400, "支付汇率或金额格式不正确");
  let units = left.units * right.units;
  const sourceScale = left.scale + right.scale;
  if (sourceScale > places) {
    const divisor = 10n ** BigInt(sourceScale - places);
    const quotient = units / divisor;
    const remainder = units % divisor;
    units = quotient + (remainder * 2n >= divisor ? 1n : 0n);
  } else if (sourceScale < places) {
    units *= 10n ** BigInt(places - sourceScale);
  }
  const base = 10n ** BigInt(places);
  return places > 0
    ? `${units / base}.${(units % base).toString().padStart(places, "0")}`
    : units.toString();
}

function convertedPaymentAmount(payment: PaymentRow, config: AnyRecord): {
  amount: string;
  currency: string;
  originalAmount: string;
  originalCurrency: string;
  converted: boolean;
} {
  const originalAmount = money(Number(payment.payable_amount || payment.amount || 0));
  const originalCurrency = (payment.currency || "CNY").toUpperCase();
  const targetCurrency = clean(config.target_currency, 20).toUpperCase();
  const exchangeRate = clean(config.exchange_rate, 80);
  if (!targetCurrency || !exchangeRate) {
    return { amount: originalAmount, currency: originalCurrency, originalAmount, originalCurrency, converted: false };
  }
  return {
    amount: roundedDecimalProduct(originalAmount, exchangeRate, 2),
    currency: targetCurrency,
    originalAmount,
    originalCurrency,
    converted: true
  };
}

const STRIPE_ZERO_DECIMAL_CURRENCIES = new Set([
  "BIF", "CLP", "DJF", "GNF", "JPY", "KMF", "KRW", "MGA", "PYG", "RWF", "UGX", "VND", "VUV", "XAF", "XOF", "XPF"
]);

function stripeMinorAmount(amount: string, currency: string): string {
  const places = STRIPE_ZERO_DECIMAL_CURRENCIES.has(currency.toUpperCase()) ? 0 : 2;
  return roundedDecimalProduct(amount, "1", places).replace(".", "");
}

async function prepareStripePaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const secretKey = clean(config.secret_key, 2000);
  const endpoint = providerEndpoint(clean(config.api_base_url, 1000) || "https://api.stripe.com", "/v1/checkout/sessions");
  const webhookSecret = clean(config.webhook_secret, 1000);
  const successUrl = paymentReturnUrl(config.success_url, target, "stripe_return");
  const cancelUrl = clean(config.cancel_url, 1000);
  const methodTypes = Array.isArray(config.payment_method_types)
    ? normalizeStringArray(config.payment_method_types)
    : clean(config.payment_method_types, 500).split(",").map((item) => item.trim().toLowerCase()).filter(Boolean);
  if (!secretKey || !endpoint || !webhookSecret || !successUrl || !cancelUrl || !methodTypes.length) {
    return { ok: false, error: "Stripe 渠道配置不完整" };
  }
  const gateway = convertedPaymentAmount(payment, config);
  const form = new URLSearchParams();
  form.set("mode", "payment");
  form.set("success_url", successUrl);
  form.set("cancel_url", cancelUrl);
  form.set("client_reference_id", payment.payment_no);
  form.set("line_items[0][quantity]", "1");
  form.set("line_items[0][price_data][currency]", gateway.currency.toLowerCase());
  form.set("line_items[0][price_data][unit_amount]", stripeMinorAmount(gateway.amount, gateway.currency));
  form.set("line_items[0][price_data][product_data][name]", target.subject || payment.payment_no);
  form.set("metadata[order_no]", payment.payment_no);
  form.set("payment_intent_data[metadata][order_no]", payment.payment_no);
  for (const methodType of methodTypes) {
    form.append("payment_method_types[]", methodType);
    if (methodType === "wechat_pay") form.set("payment_method_options[wechat_pay][client]", "web");
  }
  const response = await requestPaymentProvider(endpoint, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${secretKey}`,
      "Content-Type": "application/x-www-form-urlencoded"
    },
    body: form.toString()
  });
  if (!response.ok) return { ok: false, error: `Stripe 创建支付失败：${response.error}` };
  const sessionId = responseString(response.data.id, 200);
  const payUrl = responseString(response.data.url, 4000);
  if (!sessionId || !payUrl) return { ok: false, error: "Stripe 响应缺少 Checkout Session 或支付地址" };
  const payload: AnyRecord = {
    provider_response: response.data,
    gateway_amount: gateway.amount,
    gateway_currency: gateway.currency,
    success_url: successUrl,
    cancel_url: cancelUrl
  };
  if (gateway.converted) {
    payload.exchange_rate = clean(config.exchange_rate, 80);
    payload.original_amount = gateway.originalAmount;
    payload.original_currency = gateway.originalCurrency;
  }
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode: "",
    providerRef: sessionId,
    amount: gateway.amount,
    currency: gateway.currency,
    payload
  });
}

async function paypalAccessToken(config: AnyRecord): Promise<{ ok: true; token: string } | { ok: false; error: string }> {
  const clientId = clean(config.client_id, 1000);
  const clientSecret = clean(config.client_secret, 2000);
  const endpoint = providerEndpoint(clean(config.base_url, 1000) || "https://api-m.sandbox.paypal.com", "/v1/oauth2/token");
  if (!clientId || !clientSecret || !endpoint) return { ok: false, error: "PayPal OAuth 配置不完整" };
  const response = await requestPaymentProvider(endpoint, {
    method: "POST",
    headers: {
      "Authorization": `Basic ${btoa(`${clientId}:${clientSecret}`)}`,
      "Content-Type": "application/x-www-form-urlencoded"
    },
    body: "grant_type=client_credentials"
  });
  if (!response.ok) return { ok: false, error: `PayPal 授权失败：${response.error}` };
  const token = responseString(response.data.access_token, 4000);
  return token ? { ok: true, token } : { ok: false, error: "PayPal 授权响应缺少 access_token" };
}

function paypalApprovalUrl(data: AnyRecord): string {
  const links = Array.isArray(data.links) ? data.links : [];
  for (const item of links) {
    const link = jsonObject(item);
    if (clean(link.rel, 30).toLowerCase() === "approve") return responseString(link.href, 4000);
  }
  return "";
}

async function preparePaypalPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const endpoint = providerEndpoint(clean(config.base_url, 1000) || "https://api-m.sandbox.paypal.com", "/v2/checkout/orders");
  const returnUrl = paymentReturnUrl(config.return_url, target, "paypal_return");
  const cancelUrl = clean(config.cancel_url, 1000);
  if (!endpoint || !returnUrl || !cancelUrl) return { ok: false, error: "PayPal 渠道配置不完整" };
  const access = await paypalAccessToken(config);
  if (!access.ok) return access;
  const gateway = convertedPaymentAmount(payment, config);
  const applicationContext: AnyRecord = {
    return_url: returnUrl,
    cancel_url: cancelUrl,
    user_action: clean(config.user_action, 40) || "PAY_NOW",
    shipping_preference: clean(config.shipping_preference, 40) || "NO_SHIPPING"
  };
  for (const [source, destination] of [["brand_name", "brand_name"], ["locale", "locale"], ["landing_page", "landing_page"]] as const) {
    const value = clean(config[source], 160);
    if (value) applicationContext[destination] = value;
  }
  const requestPayload = {
    intent: "CAPTURE",
    purchase_units: [{
      invoice_id: payment.payment_no,
      amount: { currency_code: gateway.currency, value: gateway.amount },
      description: target.subject
    }],
    application_context: applicationContext
  };
  const response = await requestPaymentProvider(endpoint, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${access.token}`,
      "Content-Type": "application/json",
      "PayPal-Request-Id": payment.payment_no
    },
    body: JSON.stringify(requestPayload)
  });
  if (!response.ok) return { ok: false, error: `PayPal 创建支付失败：${response.error}` };
  const orderId = responseString(response.data.id, 200);
  const payUrl = paypalApprovalUrl(response.data);
  if (!orderId || !payUrl) return { ok: false, error: "PayPal 响应缺少订单号或付款地址" };
  const payload: AnyRecord = {
    provider_response: response.data,
    gateway_amount: gateway.amount,
    gateway_currency: gateway.currency,
    return_url: returnUrl,
    cancel_url: cancelUrl
  };
  if (gateway.converted) {
    payload.exchange_rate = clean(config.exchange_rate, 80);
    payload.original_amount = gateway.originalAmount;
    payload.original_currency = gateway.originalCurrency;
  }
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode: "",
    providerRef: orderId,
    amount: gateway.amount,
    currency: gateway.currency,
    payload
  });
}

function concatBytes(...parts: Uint8Array[]): Uint8Array {
  const output = new Uint8Array(parts.reduce((total, part) => total + part.length, 0));
  let offset = 0;
  for (const part of parts) {
    output.set(part, offset);
    offset += part.length;
  }
  return output;
}

function derLength(length: number): Uint8Array {
  if (length < 128) return new Uint8Array([length]);
  const bytes: number[] = [];
  let remaining = length;
  while (remaining > 0) {
    bytes.unshift(remaining & 0xff);
    remaining >>>= 8;
  }
  return new Uint8Array([0x80 | bytes.length, ...bytes]);
}

function derElement(tag: number, content: Uint8Array): Uint8Array {
  return concatBytes(new Uint8Array([tag]), derLength(content.length), content);
}

function hexBytes(value: string): Uint8Array {
  const normalized = value.replace(/\s+/g, "");
  const output = new Uint8Array(normalized.length / 2);
  for (let index = 0; index < output.length; index++) output[index] = Number.parseInt(normalized.slice(index * 2, index * 2 + 2), 16);
  return output;
}

const RSA_ALGORITHM_IDENTIFIER = hexBytes("300d06092a864886f70d0101010500");

function wrapPkcs1PrivateKey(pkcs1: Uint8Array): Uint8Array {
  const version = new Uint8Array([0x02, 0x01, 0x00]);
  return derElement(0x30, concatBytes(version, RSA_ALGORITHM_IDENTIFIER, derElement(0x04, pkcs1)));
}

function wrapPkcs1PublicKey(pkcs1: Uint8Array): Uint8Array {
  return derElement(0x30, concatBytes(RSA_ALGORITHM_IDENTIFIER, derElement(0x03, concatBytes(new Uint8Array([0]), pkcs1))));
}

function base64ToBytes(value: string): Uint8Array {
  const binary = atob(value.replace(/\s+/g, ""));
  const output = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index++) output[index] = binary.charCodeAt(index);
  return output;
}

function bytesToBase64Value(value: ArrayBuffer | Uint8Array): string {
  const bytes = value instanceof Uint8Array ? value : new Uint8Array(value);
  let binary = "";
  for (let offset = 0; offset < bytes.length; offset += 0x8000) {
    binary += String.fromCharCode(...bytes.subarray(offset, offset + 0x8000));
  }
  return btoa(binary);
}

function pemKeyBytes(raw: unknown): { bytes: Uint8Array; label: string } {
  const normalized = String(raw ?? "").trim().replace(/\\n/g, "\n");
  if (!normalized) throw new ApiRequestError(400, "RSA 密钥为空");
  const match = normalized.match(/-----BEGIN ([A-Z0-9 ]+)-----([\s\S]*?)-----END \1-----/);
  const label = match?.[1] || "";
  const encoded = (match?.[2] || normalized).replace(/\s+/g, "");
  try {
    return { bytes: base64ToBytes(encoded), label };
  } catch {
    throw new ApiRequestError(400, "RSA 密钥不是有效的 PEM/Base64 格式");
  }
}

async function importRsaPrivateKey(raw: unknown, hash: "SHA-1" | "SHA-256"): Promise<CryptoKey> {
  const parsed = pemKeyBytes(raw);
  const algorithm = { name: "RSASSA-PKCS1-v1_5", hash };
  const attempts = parsed.label === "RSA PRIVATE KEY"
    ? [wrapPkcs1PrivateKey(parsed.bytes), parsed.bytes]
    : [parsed.bytes, wrapPkcs1PrivateKey(parsed.bytes)];
  for (const bytes of attempts) {
    try {
      return await crypto.subtle.importKey("pkcs8", bytes, algorithm, false, ["sign"]);
    } catch {
      // Try the alternate PKCS#1/PKCS#8 representation.
    }
  }
  throw new ApiRequestError(400, "RSA 私钥无法解析，请使用 PKCS#8 或 PKCS#1 格式");
}

async function importRsaPublicKey(raw: unknown, hash: "SHA-1" | "SHA-256"): Promise<CryptoKey> {
  const parsed = pemKeyBytes(raw);
  const algorithm = { name: "RSASSA-PKCS1-v1_5", hash };
  const attempts = parsed.label === "RSA PUBLIC KEY"
    ? [wrapPkcs1PublicKey(parsed.bytes), parsed.bytes]
    : [parsed.bytes, wrapPkcs1PublicKey(parsed.bytes)];
  for (const bytes of attempts) {
    try {
      return await crypto.subtle.importKey("spki", bytes, algorithm, false, ["verify"]);
    } catch {
      // Try the alternate PKCS#1/SPKI representation.
    }
  }
  throw new ApiRequestError(400, "RSA 公钥无法解析，请使用 SubjectPublicKeyInfo 或 PKCS#1 格式");
}

async function rsaPkcs1SignBase64(rawKey: unknown, content: string, hash: "SHA-1" | "SHA-256"): Promise<string> {
  const key = await importRsaPrivateKey(rawKey, hash);
  const signature = await crypto.subtle.sign("RSASSA-PKCS1-v1_5", key, new TextEncoder().encode(content));
  return bytesToBase64Value(signature);
}

async function rsaPkcs1VerifyBase64(rawKey: unknown, content: string, signature: string, hash: "SHA-1" | "SHA-256"): Promise<boolean> {
  try {
    const key = await importRsaPublicKey(rawKey, hash);
    return crypto.subtle.verify("RSASSA-PKCS1-v1_5", key, base64ToBytes(signature), new TextEncoder().encode(content));
  } catch {
    return false;
  }
}

function alipaySignContent(params: Record<string, string>): string {
  return Object.keys(params)
    .filter((key) => key !== "sign" && clean(params[key], 100000) !== "")
    .sort()
    .map((key) => `${key}=${params[key]}`)
    .join("&");
}

function shanghaiTimestamp(date = new Date()): string {
  const parts = dashboardDateParts(date, "Asia/Shanghai");
  return `${parts.year}-${String(parts.month).padStart(2, "0")}-${String(parts.day).padStart(2, "0")} ${String(parts.hour).padStart(2, "0")}:${String(parts.minute).padStart(2, "0")}:${String(parts.second).padStart(2, "0")}`;
}

async function prepareAlipayPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const appId = clean(config.app_id, 200);
  const privateKey = clean(config.private_key, 10000);
  const publicKey = clean(config.alipay_public_key, 10000);
  const gatewayUrl = clean(config.gateway_url, 1000) || "https://openapi.alipay.com/gateway.do";
  const notifyUrl = clean(config.notify_url, 1000) || await paymentCallbackUrl(env);
  const mode = clean(payment.interaction_mode, 30).toLowerCase();
  const returnUrl = mode === "qr" ? clean(config.return_url, 1000) : paymentReturnUrl(config.return_url, target, "alipay_return");
  const signType = (clean(config.sign_type, 20) || "RSA2").toUpperCase();
  if (!appId || !privateKey || !publicKey || !isSafeCallbackUrl(gatewayUrl) || !notifyUrl || !["qr", "wap", "page"].includes(mode)) {
    return { ok: false, error: "支付宝官方渠道配置不完整" };
  }
  const gateway = convertedPaymentAmount(payment, config);
  const method = mode === "qr" ? "alipay.trade.precreate" : mode === "wap" ? "alipay.trade.wap.pay" : "alipay.trade.page.pay";
  const productCode = mode === "qr" ? "FACE_TO_FACE_PAYMENT" : mode === "wap" ? "QUICK_WAP_WAY" : "FAST_INSTANT_TRADE_PAY";
  const bizContent: AnyRecord = {
    out_trade_no: payment.payment_no,
    total_amount: gateway.amount,
    subject: target.subject || payment.payment_no,
    product_code: productCode
  };
  if (mode === "wap" && clean(config.quit_url, 1000)) bizContent.quit_url = clean(config.quit_url, 1000);
  if (clean(config.timeout_express, 80)) bizContent.timeout_express = clean(config.timeout_express, 80);
  const params: Record<string, string> = {
    app_id: appId,
    method,
    format: "JSON",
    charset: "utf-8",
    sign_type: signType,
    timestamp: shanghaiTimestamp(),
    version: "1.0",
    notify_url: notifyUrl,
    biz_content: JSON.stringify(bizContent)
  };
  if (returnUrl) params.return_url = returnUrl;
  if (clean(config.app_cert_sn, 500)) params.app_cert_sn = clean(config.app_cert_sn, 500);
  if (clean(config.alipay_root_cert_sn, 500)) params.alipay_root_cert_sn = clean(config.alipay_root_cert_sn, 500);
  try {
    params.sign = await rsaPkcs1SignBase64(privateKey, alipaySignContent(params), signType === "RSA" ? "SHA-1" : "SHA-256");
  } catch (error) {
    return { ok: false, error: error instanceof Error ? error.message : "支付宝请求签名失败" };
  }

  let payUrl = "";
  let qrCode = "";
  let providerRef = payment.payment_no;
  let providerResponse: AnyRecord;
  if (mode === "qr") {
    const response = await requestPaymentProvider(gatewayUrl, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams(params).toString()
    });
    if (!response.ok) return { ok: false, error: `支付宝预下单失败：${response.error}` };
    providerResponse = response.data;
    const responseKey = method.replace(/\./g, "_") + "_response";
    const node = jsonObject(response.data[responseKey]);
    if (responseString(node.code, 30) !== "10000") {
      return { ok: false, error: `支付宝预下单失败：${responseString(node.sub_msg, 300) || responseString(node.msg, 300) || responseString(node.code, 30)}` };
    }
    qrCode = responseString(node.qr_code, 4000);
    providerRef = responseString(node.trade_no, 200) || payment.payment_no;
    if (!qrCode) return { ok: false, error: "支付宝预下单响应缺少二维码内容" };
  } else {
    const url = new URL(gatewayUrl);
    for (const [key, value] of Object.entries(params)) url.searchParams.set(key, value);
    payUrl = url.toString();
    providerResponse = { pay_url: payUrl, method, out_trade_no: payment.payment_no };
  }
  const payload: AnyRecord = {
    provider_response: providerResponse,
    gateway_amount: gateway.amount,
    gateway_currency: gateway.currency,
    notify_url: notifyUrl,
    return_url: returnUrl,
    method
  };
  if (gateway.converted) {
    payload.exchange_rate = clean(config.exchange_rate, 80);
    payload.original_amount = gateway.originalAmount;
    payload.original_currency = gateway.originalCurrency;
  }
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode,
    providerRef,
    amount: gateway.amount,
    currency: gateway.currency,
    payload
  });
}

type WechatApiResult =
  | { ok: true; data: AnyRecord }
  | { ok: false; error: string; statusCode: number };

function wechatApiBaseUrl(config: AnyRecord): string {
  return clean(config.base_url, 1000) || "https://api.mch.weixin.qq.com";
}

function wechatAuthorizationValue(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

async function requestWechatApi(
  config: AnyRecord,
  method: "GET" | "POST",
  path: string,
  body = ""
): Promise<WechatApiResult> {
  const mchid = clean(config.mchid, 200);
  const serial = clean(config.merchant_serial_no, 500);
  const privateKey = clean(config.merchant_private_key, 20000);
  const endpoint = providerEndpoint(wechatApiBaseUrl(config), path);
  if (!mchid || !serial || !privateKey || !endpoint) {
    return { ok: false, error: "微信支付请求配置不完整", statusCode: 400 };
  }
  const parsed = new URL(endpoint);
  const requestTarget = `${parsed.pathname}${parsed.search}`;
  const timestamp = String(Math.floor(Date.now() / 1000));
  const nonce = randomHex(16);
  const canonical = `${method}\n${requestTarget}\n${timestamp}\n${nonce}\n${body}\n`;
  let signature: string;
  try {
    signature = await rsaPkcs1SignBase64(privateKey, canonical, "SHA-256");
  } catch (error) {
    return { ok: false, error: error instanceof Error ? error.message : "微信支付请求签名失败", statusCode: 400 };
  }
  const authorization = `WECHATPAY2-SHA256-RSA2048 mchid="${wechatAuthorizationValue(mchid)}",nonce_str="${nonce}",timestamp="${timestamp}",serial_no="${wechatAuthorizationValue(serial)}",signature="${signature}"`;
  const response = await requestPaymentProvider(endpoint, {
    method,
    headers: {
      "Authorization": authorization,
      ...(method === "POST" ? { "Content-Type": "application/json" } : {})
    },
    body: method === "POST" ? body : undefined
  });
  if (!response.ok) return { ok: false, error: response.error, statusCode: response.status || 502 };
  return { ok: true, data: response.data };
}

function wechatAmountToFen(amount: string): number {
  const match = amount.trim().match(/^\+?(\d+)(?:\.(\d{1,2}))?$/);
  if (!match) throw new ApiRequestError(400, "微信支付金额必须精确到分");
  const fen = BigInt(match[1]) * 100n + BigInt((match[2] || "").padEnd(2, "0") || "0");
  if (fen <= 0n || fen > BigInt(Number.MAX_SAFE_INTEGER)) throw new ApiRequestError(400, "微信支付金额超出允许范围");
  return Number(fen);
}

function wechatFenToAmount(value: unknown): string {
  const text = String(value ?? "").trim();
  if (!/^\d+$/.test(text)) return "";
  const fen = BigInt(text);
  return `${fen / 100n}.${(fen % 100n).toString().padStart(2, "0")}`;
}

function wechatClientIp(value: unknown): string {
  const raw = clean(value, 100).replace(/^\[|\]$/g, "").split("%", 1)[0];
  return parseIpAddress(raw) ? raw : "127.0.0.1";
}

function wechatPaymentStatus(value: unknown): "success" | "pending" | "failed" | "expired" | "" {
  switch (clean(value, 50).toUpperCase()) {
    case "SUCCESS":
    case "REFUND": return "success";
    case "NOTPAY":
    case "USERPAYING": return "pending";
    case "CLOSED": return "expired";
    case "REVOKED":
    case "PAYERROR": return "failed";
    default: return "";
  }
}

function wechatGatewayAmount(payment: PaymentRow, config: AnyRecord): ReturnType<typeof convertedPaymentAmount> {
  const gateway = convertedPaymentAmount(payment, config);
  if (gateway.currency.toUpperCase() !== "CNY") {
    throw new ApiRequestError(400, "微信官方支付仅支持 CNY；跨币种时请将目标币种配置为 CNY");
  }
  return { ...gateway, currency: "CNY" };
}

async function prepareWechatPaymentTarget(env: Env, payment: PaymentRow, target: ProviderPaymentTarget): Promise<PreparedProviderPayment> {
  const channel = await paymentChannelById(env, payment.channel_id);
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const appid = clean(config.appid, 200);
  const mchid = clean(config.mchid, 200);
  const notifyUrl = clean(config.notify_url, 1000) || await paymentCallbackUrl(env);
  const mode = clean(payment.interaction_mode, 30).toLowerCase();
  if (!appid || !mchid || !notifyUrl || !["qr", "redirect"].includes(mode)) {
    return { ok: false, error: "微信官方支付渠道配置不完整" };
  }
  let gateway: ReturnType<typeof convertedPaymentAmount>;
  let amountFen: number;
  try {
    gateway = wechatGatewayAmount(payment, config);
    amountFen = wechatAmountToFen(gateway.amount);
  } catch (error) {
    return { ok: false, error: error instanceof Error ? error.message : "微信支付金额不正确" };
  }
  const requestPayload: AnyRecord = {
    appid,
    mchid,
    description: clean(target.subject, 127) || `订单 ${payment.payment_no}`,
    out_trade_no: payment.payment_no,
    notify_url: notifyUrl,
    amount: { total: amountFen, currency: "CNY" },
    scene_info: { payer_client_ip: wechatClientIp(target.clientIp) }
  };
  const endpointPath = mode === "redirect" ? "/v3/pay/transactions/h5" : "/v3/pay/transactions/native";
  if (mode === "redirect") {
    const h5Info: AnyRecord = { type: (clean(config.h5_type, 20) || "WAP").toUpperCase() };
    if (clean(config.h5_wap_name, 255)) h5Info.app_name = clean(config.h5_wap_name, 255);
    if (clean(config.h5_wap_url, 1000)) h5Info.app_url = clean(config.h5_wap_url, 1000);
    requestPayload.scene_info.h5_info = h5Info;
  }
  const response = await requestWechatApi(config, "POST", endpointPath, JSON.stringify(requestPayload));
  if (!response.ok) return { ok: false, error: `微信支付创建失败：${response.error}` };
  let payUrl = "";
  let qrCode = "";
  if (mode === "redirect") {
    payUrl = responseString(response.data.h5_url, 4000);
    if (!payUrl) return { ok: false, error: "微信支付响应缺少 h5_url" };
    const redirectUrl = clean(config.h5_redirect_url, 1000);
    if (redirectUrl) {
      try {
        const parsed = new URL(payUrl);
        parsed.searchParams.set("redirect_url", redirectUrl);
        payUrl = parsed.toString();
      } catch {
        return { ok: false, error: "微信支付返回的 H5 地址无效" };
      }
    }
  } else {
    qrCode = responseString(response.data.code_url, 4000);
    if (!qrCode) return { ok: false, error: "微信支付响应缺少 code_url" };
  }
  const payload: AnyRecord = {
    provider_response: response.data,
    prepay_id: responseString(response.data.prepay_id, 500),
    gateway_amount: gateway.amount,
    gateway_currency: "CNY",
    notify_url: notifyUrl,
    h5_redirect_url: clean(config.h5_redirect_url, 1000)
  };
  if (gateway.converted) {
    payload.exchange_rate = clean(config.exchange_rate, 80);
    payload.original_amount = gateway.originalAmount;
    payload.original_currency = gateway.originalCurrency;
  }
  return persistPreparedProviderPayment(env, payment, {
    payUrl,
    qrCode,
    providerRef: payment.payment_no,
    amount: gateway.amount,
    currency: "CNY",
    payload
  });
}

type OfficialPaymentQueryResult =
  | {
    ok: true;
    status: "success" | "pending" | "failed" | "expired";
    amount: string;
    currency: string;
    providerRef: string;
    providerTradeNo: string;
    paidAt: string;
    payload: AnyRecord;
  }
  | { ok: false; statusCode: number; error: string };

function paymentJsonPath(root: unknown, ...path: Array<string | number>): unknown {
  let current = root;
  for (const segment of path) {
    if (typeof segment === "number") {
      if (!Array.isArray(current) || segment < 0 || segment >= current.length) return undefined;
      current = current[segment];
    } else {
      if (!current || typeof current !== "object" || Array.isArray(current)) return undefined;
      current = (current as AnyRecord)[segment];
    }
  }
  return current;
}

function stripeMajorAmount(minorValue: unknown, currency: string): string {
  const text = String(minorValue ?? "").trim();
  if (!/^\d+$/.test(text)) return "";
  const places = STRIPE_ZERO_DECIMAL_CURRENCIES.has(currency.toUpperCase()) ? 0 : 2;
  const units = BigInt(text);
  if (places === 0) return units.toString();
  const base = 10n ** BigInt(places);
  return `${units / base}.${(units % base).toString().padStart(places, "0")}`;
}

function stripePaymentStatus(paymentStatus: unknown, sessionStatus: unknown): "success" | "pending" | "failed" | "expired" {
  const paid = clean(paymentStatus, 50).toLowerCase();
  const session = clean(sessionStatus, 50).toLowerCase();
  if (paid === "paid" || (session === "complete" && paid === "no_payment_required")) return "success";
  if (session === "expired") return "expired";
  return "pending";
}

function stripeIntentStatus(status: unknown): "success" | "pending" | "failed" | "expired" {
  switch (clean(status, 50).toLowerCase()) {
    case "succeeded": return "success";
    case "canceled":
    case "requires_payment_method": return "failed";
    default: return "pending";
  }
}

async function queryStripePayment(payment: PaymentRow, config: AnyRecord): Promise<OfficialPaymentQueryResult> {
  const providerRef = clean(payment.provider_ref, 200);
  const secretKey = clean(config.secret_key, 2000);
  const baseUrl = clean(config.api_base_url, 1000) || "https://api.stripe.com";
  if (!providerRef || !secretKey) return { ok: false, statusCode: 400, error: "Stripe 查询配置或支付引用不完整" };
  const sessionQuery = providerRef.startsWith("cs_");
  const path = sessionQuery
    ? `/v1/checkout/sessions/${encodeURIComponent(providerRef)}?expand[]=payment_intent`
    : `/v1/payment_intents/${encodeURIComponent(providerRef)}`;
  const endpoint = providerEndpoint(baseUrl, path);
  const response = await requestPaymentProvider(endpoint, {
    method: "GET",
    headers: { "Authorization": `Bearer ${secretKey}` }
  });
  if (!response.ok) return { ok: false, statusCode: 502, error: `Stripe 查询支付失败：${response.error}` };
  const currency = responseString(response.data.currency, 20).toUpperCase();
  if (sessionQuery) {
    const sessionId = responseString(response.data.id, 200);
    const intentRaw = response.data.payment_intent;
    const intentId = typeof intentRaw === "string" ? clean(intentRaw, 200) : responseString(jsonObject(intentRaw).id, 200);
    return {
      ok: true,
      status: stripePaymentStatus(response.data.payment_status, response.data.status),
      amount: stripeMajorAmount(response.data.amount_total, currency),
      currency,
      providerRef: sessionId || providerRef,
      providerTradeNo: intentId,
      paidAt: Number(response.data.created || 0) > 0 ? new Date(Number(response.data.created) * 1000).toISOString() : "",
      payload: response.data
    };
  }
  const intentId = responseString(response.data.id, 200);
  const amountMinor = Number(response.data.amount_received || 0) > 0 ? response.data.amount_received : response.data.amount;
  return {
    ok: true,
    status: stripeIntentStatus(response.data.status),
    amount: stripeMajorAmount(amountMinor, currency),
    currency,
    providerRef: intentId || providerRef,
    providerTradeNo: intentId || providerRef,
    paidAt: Number(response.data.created || 0) > 0 ? new Date(Number(response.data.created) * 1000).toISOString() : "",
    payload: response.data
  };
}

function paypalPaymentStatus(status: unknown): "success" | "pending" | "failed" | "expired" {
  switch (clean(status, 50).toUpperCase()) {
    case "COMPLETED": return "success";
    case "DENIED":
    case "DECLINED":
    case "FAILED":
    case "VOIDED": return "failed";
    default: return "pending";
  }
}

async function queryPaypalPayment(payment: PaymentRow, config: AnyRecord): Promise<OfficialPaymentQueryResult> {
  const providerRef = clean(payment.provider_ref, 200);
  if (!providerRef) return { ok: false, statusCode: 400, error: "PayPal 支付引用为空" };
  const access = await paypalAccessToken(config);
  if (!access.ok) return { ok: false, statusCode: 502, error: access.error };
  const endpoint = providerEndpoint(clean(config.base_url, 1000) || "https://api-m.sandbox.paypal.com", `/v2/checkout/orders/${encodeURIComponent(providerRef)}/capture`);
  const response = await requestPaymentProvider(endpoint, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${access.token}`,
      "Content-Type": "application/json",
      "PayPal-Request-Id": `${payment.payment_no}-capture`
    },
    body: "{}"
  });
  if (!response.ok) return { ok: false, statusCode: 502, error: `PayPal 捕获支付失败：${response.error}` };
  const capture = jsonObject(paymentJsonPath(response.data, "purchase_units", 0, "payments", "captures", 0));
  const orderId = responseString(response.data.id, 200) || providerRef;
  const captureId = responseString(capture.id, 200);
  const status = responseString(capture.status, 50) || responseString(response.data.status, 50);
  return {
    ok: true,
    status: paypalPaymentStatus(status),
    amount: responseString(paymentJsonPath(capture, "amount", "value"), 80),
    currency: responseString(paymentJsonPath(capture, "amount", "currency_code"), 20).toUpperCase(),
    providerRef: orderId,
    providerTradeNo: captureId,
    paidAt: responseString(capture.create_time, 80),
    payload: response.data
  };
}

async function queryWechatPayment(payment: PaymentRow, config: AnyRecord): Promise<OfficialPaymentQueryResult> {
  const orderNo = clean(payment.payment_no || payment.provider_ref, 120);
  const mchid = clean(config.mchid, 200);
  if (!orderNo || !mchid) return { ok: false, statusCode: 400, error: "微信支付查询配置或商户订单号不完整" };
  const path = `/v3/pay/transactions/out-trade-no/${encodeURIComponent(orderNo)}?mchid=${encodeURIComponent(mchid)}`;
  const response = await requestWechatApi(config, "GET", path);
  if (!response.ok) return { ok: false, statusCode: 502, error: `微信支付查询失败：${response.error}` };
  const returnedOrderNo = responseString(response.data.out_trade_no, 120);
  if (returnedOrderNo && returnedOrderNo !== orderNo) {
    return { ok: false, statusCode: 409, error: "微信支付返回的商户订单号不一致" };
  }
  const status = wechatPaymentStatus(response.data.trade_state);
  if (!status) return { ok: false, statusCode: 502, error: "微信支付返回了未知交易状态" };
  const transactionId = responseString(response.data.transaction_id, 200);
  return {
    ok: true,
    status,
    amount: wechatFenToAmount(paymentJsonPath(response.data, "amount", "total")),
    currency: responseString(paymentJsonPath(response.data, "amount", "currency"), 20).toUpperCase(),
    providerRef: transactionId || orderNo,
    providerTradeNo: transactionId,
    paidAt: responseString(response.data.success_time, 80),
    payload: response.data
  };
}

async function queryOfficialPayment(env: Env, payment: PaymentRow): Promise<OfficialPaymentQueryResult> {
  const channel = await paymentChannelById(env, payment.channel_id);
  if (!channel || !channel.is_active) return { ok: false, statusCode: 404, error: "支付渠道不存在或已停用" };
  const config = jsonObject(jsonParse(channel.config_json || "{}", {}));
  switch (paymentProviderKey(channel.provider_type, channel.channel_type)) {
    case "official:stripe": return queryStripePayment(payment, config);
    case "official:paypal": return queryPaypalPayment(payment, config);
    case "official:wechat": return queryWechatPayment(payment, config);
    default: return { ok: false, statusCode: 409, error: "该支付渠道不支持主动确认" };
  }
}

function verifyQueriedPaymentAgainstRecord(
  payment: PaymentRow,
  queried: Extract<OfficialPaymentQueryResult, { ok: true }>
): { ok: true; callback: Extract<VerifiedPaymentCallback, { ok: true }> } | { ok: false; error: string } {
  if (queried.status === "success") {
    const payload = jsonObject(jsonParse(payment.provider_payload_json || "{}", {}));
    const expectedAmount = clean(payload.gateway_amount, 80) || String(payment.amount || 0);
    const expectedCurrency = (clean(payload.gateway_currency, 20) || payment.currency || "CNY").toUpperCase();
    if (queried.amount && !decimalStringsEqual(queried.amount, "0", 8) && !decimalStringsEqual(queried.amount, expectedAmount, 8)) {
      return { ok: false, error: "支付平台返回金额与订单不一致" };
    }
    if (queried.currency && queried.currency.toUpperCase() !== expectedCurrency) {
      return { ok: false, error: "支付平台返回币种与订单不一致" };
    }
  }
  return {
    ok: true,
    callback: {
      ok: true,
      status: queried.status,
      amount: queried.amount,
      currency: queried.currency,
      providerRef: queried.providerRef,
      providerTradeNo: queried.providerTradeNo,
      paidAt: queried.paidAt,
      payload: queried.payload
    }
  };
}

async function apiPaymentCallback(request: Request, env: Env, url: URL, ctx?: ExecutionContext): Promise<Response> {
  if (isWechatPaymentCallbackRequest(request)) return apiWechatPaymentCallback(request, env, url);
  const callback = await readPaymentCallback(request, url);
  const paymentNo = clean(
    callback.flat.out_trade_no
      || callback.flat.outTradeNo
      || callback.flat.payment_no
      || callback.flat.order_id
      || callback.flat.OutOrderId
      || callback.flat.out_order_id
      || callback.flat["data[unique_id]"]
      || callback.flat.unique_id,
    120
  );
  if (!paymentNo) return new Response("fail", { status: 400 });
  const payment = await paymentByNoWithContext(env, paymentNo);
  if (!payment) return new Response("fail", { status: 404 });
  const channel = await paymentChannelById(env, payment.channel_id);
  if (!channel) return new Response("fail", { status: 404 });
  const providerType = clean(channel.provider_type || payment.provider_type, 40).toLowerCase();
  const config = jsonObject(jsonParse(channel?.config_json || "{}", {}));
  const verified = await verifyProviderPaymentCallback(providerType, payment.channel_type, payment, config, callback);
  if (!verified.ok) return new Response("fail", { status: verified.status });

  const providerPayload = jsonObject(jsonParse(payment.provider_payload_json || "{}", {}));
  const expectedAmount = clean(providerPayload.gateway_amount, 80)
    || String(providerType === "okpay" ? payment.amount : (payment.payable_amount || payment.amount || 0));
  const expectedCurrency = (clean(providerPayload.gateway_currency, 20) || payment.currency || "CNY").toUpperCase();
  if (!decimalStringsEqual(verified.amount, expectedAmount, 8)) return new Response("fail", { status: 400 });
  if (verified.currency && verified.currency.toUpperCase() !== expectedCurrency) return new Response("fail", { status: 400 });

  await applyVerifiedPaymentCallback(env, payment, verified, ctx);
  return paymentCallbackSuccessResponse();
}

type PaymentCallbackEnvelope = {
  rawText: string;
  json: AnyRecord;
  flat: Record<string, string>;
  orderedPairs: Array<[string, string]>;
};

type VerifiedPaymentCallback = {
  ok: true;
  status: "pending" | "success" | "failed" | "expired";
  amount: string;
  currency: string;
  providerRef: string;
  providerTradeNo: string;
  paidAt?: string;
  payload: AnyRecord;
} | { ok: false; status: number };

async function readPaymentCallback(request: Request, url: URL): Promise<PaymentCallbackEnvelope> {
  const flat: Record<string, string> = {};
  const orderedPairs: Array<[string, string]> = [];
  url.searchParams.forEach((value, key) => {
    flat[key] = value;
    orderedPairs.push([key, value]);
  });
  let rawText = "";
  let json: AnyRecord = {};
  if (request.method.toUpperCase() === "POST") {
    const contentLength = Number(request.headers.get("Content-Length") || 0);
    if (contentLength > 256 * 1024) throw new ApiRequestError(413, "支付回调内容过大");
    const contentType = request.headers.get("Content-Type") || "";
    rawText = await request.text();
    if (new TextEncoder().encode(rawText).byteLength > 256 * 1024) throw new ApiRequestError(413, "支付回调内容过大");
    if (contentType.includes("application/json") || rawText.trim().startsWith("{")) {
      try {
        const parsed = JSON.parse(rawText);
        if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error("invalid callback JSON");
        json = parsed as AnyRecord;
      } catch {
        throw new ApiRequestError(400, "支付回调 JSON 格式不正确");
      }
      for (const pair of flattenProviderPayload(json)) {
        flat[pair[0]] = pair[1];
        orderedPairs.push(pair);
      }
    } else {
      const params = new URLSearchParams(rawText);
      params.forEach((value, key) => {
        flat[key] = value;
        orderedPairs.push([key, value]);
      });
    }
  }
  return { rawText, json, flat, orderedPairs };
}

function flattenProviderPayload(value: unknown, prefix = ""): Array<[string, string]> {
  if (!value || typeof value !== "object") return prefix ? [[prefix, providerSignValue(value)]] : [];
  const pairs: Array<[string, string]> = [];
  for (const [key, item] of Object.entries(value as AnyRecord)) {
    const fullKey = prefix ? `${prefix}[${key}]` : key;
    if (item && typeof item === "object") pairs.push(...flattenProviderPayload(item, fullKey));
    else pairs.push([fullKey, providerSignValue(item)]);
  }
  return pairs;
}

async function verifyProviderPaymentCallback(
  providerType: string,
  channelType: string,
  payment: PaymentRow,
  config: AnyRecord,
  callback: PaymentCallbackEnvelope
): Promise<VerifiedPaymentCallback> {
  switch (paymentProviderKey(providerType, channelType)) {
    case "epay": return verifyEpayPaymentCallback(payment, config, callback);
    case "bepusdt": return verifyBepusdtPaymentCallback(config, callback);
    case "epusdt": return verifyEpusdtPaymentCallback(config, callback);
    case "tokenpay": return verifyTokenpayPaymentCallback(config, callback);
    case "okpay": return verifyOkpayPaymentCallback(config, callback);
    case "official:alipay": return verifyAlipayPaymentCallback(config, callback);
    default: return { ok: false, status: 400 };
  }
}

async function verifyAlipayPaymentCallback(config: AnyRecord, callback: PaymentCallbackEnvelope): Promise<VerifiedPaymentCallback> {
  const payload = callback.flat;
  const appId = clean(payload.app_id || payload.appid, 200);
  if (!appId || appId.toLowerCase() !== clean(config.app_id, 200).toLowerCase()) return { ok: false, status: 403 };
  const signature = clean(payload.sign, 4000);
  const signType = (clean(payload.sign_type || config.sign_type, 20) || "RSA2").toUpperCase();
  if (!signature || !["RSA", "RSA2"].includes(signType)) return { ok: false, status: 403 };
  const signedParams: Record<string, string> = {};
  for (const [key, value] of Object.entries(payload)) {
    if (key.toLowerCase() === "sign" || key.toLowerCase() === "sign_type" || value === "") continue;
    signedParams[key] = value;
  }
  const valid = await rsaPkcs1VerifyBase64(
    config.alipay_public_key,
    alipaySignContent(signedParams),
    signature,
    signType === "RSA" ? "SHA-1" : "SHA-256"
  );
  if (!valid) return { ok: false, status: 403 };
  const tradeStatus = clean(payload.trade_status, 50).toUpperCase();
  const paidAtRaw = clean(payload.gmt_payment, 80);
  const paidAt = /^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(paidAtRaw)
    ? new Date(`${paidAtRaw.replace(" ", "T")}+08:00`).toISOString()
    : "";
  return {
    ok: true,
    status: ["TRADE_SUCCESS", "TRADE_FINISHED"].includes(tradeStatus) ? "success" : "pending",
    amount: clean(payload.total_amount, 80),
    currency: "CNY",
    providerRef: clean(payload.trade_no, 200),
    providerTradeNo: clean(payload.trade_no, 200),
    paidAt,
    payload
  };
}

async function verifyEpayPaymentCallback(payment: PaymentRow, config: AnyRecord, callback: PaymentCallbackEnvelope): Promise<VerifiedPaymentCallback> {
  const payload = callback.flat;
  const merchantId = clean(config.merchant_id || config.pid, 120);
  const callbackMerchantId = clean(payload.pid || payload.merchant_id, 120);
  if (!merchantId || !callbackMerchantId || callbackMerchantId !== merchantId) return { ok: false, status: 403 };
  const version = (clean(config.epay_version, 20) || "v1").toLowerCase();
  if (version === "v2") {
    const publicKey = clean(config.platform_public_key, 20000);
    const signature = clean(payload.sign, 5000);
    if (!publicKey || !signature || !await rsaPkcs1VerifyBase64(publicKey, providerSignContent(payload), signature, "SHA-256")) {
      return { ok: false, status: 403 };
    }
  } else {
    const merchantKey = clean(config.merchant_key || config.key, 2000);
    if (!merchantKey || !verifyEpaySignature(payload, merchantKey)) return { ok: false, status: 403 };
  }
  return {
    ok: true,
    status: isEpaySuccessPayload(payload) ? "success" : "pending",
    amount: clean(payload.money || payload.amount, 80),
    currency: (clean(payload.currency, 20) || payment.currency || "CNY").toUpperCase(),
    providerRef: clean(payload.buyer || payload.buyer_id || payload.buyer_email, 200),
    providerTradeNo: clean(payload.trade_no || payload.tradeNo, 200),
    payload: { ...payload }
  };
}

function verifyBepusdtPaymentCallback(config: AnyRecord, callback: PaymentCallbackEnvelope): VerifiedPaymentCallback {
  const payload = callback.json;
  const secret = clean(config.auth_token, 1000);
  const status = toInt(payload.status, 0);
  if (!secret || status !== 2) return { ok: false, status: 400 };
  const signed: AnyRecord = {
    trade_id: payload.trade_id,
    order_id: payload.order_id,
    amount: payload.amount,
    actual_amount: payload.actual_amount,
    token: payload.token,
    block_transaction_id: payload.block_transaction_id,
    status
  };
  const signature = clean(payload.signature, 100).toLowerCase();
  if (!signature || !timingSafeEqualHex(signature, sortedProviderSignature(signed, secret))) return { ok: false, status: 403 };
  return {
    ok: true,
    status: "success",
    amount: providerSignValue(payload.amount),
    currency: (clean(config.fiat, 20) || "CNY").toUpperCase(),
    providerRef: clean(payload.trade_id, 200),
    providerTradeNo: clean(payload.block_transaction_id, 200),
    payload
  };
}

function verifyEpusdtPaymentCallback(config: AnyRecord, callback: PaymentCallbackEnvelope): VerifiedPaymentCallback {
  const payload = callback.json;
  const secret = clean(config.secret_key, 1000);
  const status = toInt(payload.status, 0);
  if (!secret || status !== 2) return { ok: false, status: 400 };
  const signed: AnyRecord = {
    pid: payload.pid,
    trade_id: payload.trade_id,
    order_id: payload.order_id,
    amount: payload.amount,
    actual_amount: payload.actual_amount,
    receive_address: payload.receive_address,
    token: payload.token,
    block_transaction_id: payload.block_transaction_id,
    status
  };
  const signature = clean(payload.signature, 100).toLowerCase();
  if (!signature || !timingSafeEqualHex(signature, sortedProviderSignature(signed, secret))) return { ok: false, status: 403 };
  return {
    ok: true,
    status: "success",
    amount: providerSignValue(payload.amount),
    currency: (clean(config.currency, 20) || "CNY").toUpperCase(),
    providerRef: clean(payload.trade_id, 200),
    providerTradeNo: clean(payload.block_transaction_id, 200),
    payload
  };
}

function verifyTokenpayPaymentCallback(config: AnyRecord, callback: PaymentCallbackEnvelope): VerifiedPaymentCallback {
  const payload = callback.json;
  const secret = clean(config.notify_secret, 1000);
  const provided = clean(payload.Signature || payload.signature, 100).toLowerCase();
  if (!secret || !provided) return { ok: false, status: 403 };
  const expected = sortedProviderSignature(payload, secret, { signatureKey: "Signature", caseInsensitiveKey: true });
  if (!timingSafeEqualHex(provided, expected)) return { ok: false, status: 403 };
  const statusCode = toInt(payload.Status ?? payload.status, 0);
  const status = statusCode === 1 ? "success" : statusCode === 2 ? "expired" : "pending";
  return {
    ok: true,
    status,
    amount: clean(payload.ActualAmount ?? payload.actual_amount, 80),
    currency: (clean(payload.BaseCurrency ?? payload.base_currency, 20) || clean(config.base_currency, 20) || "CNY").toUpperCase(),
    providerRef: clean(payload.Id ?? payload.id, 200),
    providerTradeNo: clean(payload.Id ?? payload.id, 200),
    payload
  };
}

function verifyOkpayPaymentCallback(config: AnyRecord, callback: PaymentCallbackEnvelope): VerifiedPaymentCallback {
  const merchantId = clean(config.merchant_id, 200);
  const token = clean(config.merchant_token, 1000);
  const callbackMerchantId = clean(callback.flat.id, 200);
  const provided = clean(callback.flat.sign, 100).toUpperCase();
  if (!merchantId || !token || !provided || (callbackMerchantId && callbackMerchantId !== merchantId)) return { ok: false, status: 403 };
  const pairs = callback.orderedPairs.filter(([key]) => key.toLowerCase() !== "sign");
  const expectedOrdered = okpaySignature(pairs, token);
  const expectedSorted = okpaySignature([...pairs].sort(([left], [right]) => left.localeCompare(right)), token);
  if (!timingSafeEqualHex(provided, expectedOrdered) && !timingSafeEqualHex(provided, expectedSorted)) return { ok: false, status: 403 };
  const requestStatus = clean(callback.flat.status, 40).toLowerCase();
  const paymentStatus = clean(callback.flat["data[status]"], 40);
  const status = requestStatus !== "success" ? "failed" : paymentStatus === "1" ? "success" : paymentStatus === "2" ? "failed" : "pending";
  return {
    ok: true,
    status,
    amount: clean(callback.flat["data[amount]"], 80),
    currency: (clean(callback.flat["data[coin]"], 20) || clean(config.coin, 20)).toUpperCase(),
    providerRef: clean(callback.flat["data[order_id]"], 200),
    providerTradeNo: clean(callback.flat["data[pay_user_id]"] || callback.flat["data[order_id]"], 200),
    payload: Object.keys(callback.json).length ? callback.json : { ...callback.flat }
  };
}

function decimalStringsEqual(left: unknown, right: unknown, scale: number): boolean {
  const normalize = (value: unknown): bigint | null => {
    const text = String(value ?? "").trim();
    const match = text.match(/^([+-]?)(\d+)(?:\.(\d+))?$/);
    if (!match) return null;
    const fraction = (match[3] || "").padEnd(scale, "0");
    if (fraction.length > scale && /[1-9]/.test(fraction.slice(scale))) return null;
    const units = BigInt(match[2]) * (10n ** BigInt(scale)) + BigInt((fraction.slice(0, scale) || "0").padEnd(scale, "0"));
    return match[1] === "-" ? -units : units;
  };
  const a = normalize(left);
  const b = normalize(right);
  return a !== null && b !== null && a === b;
}

async function applyVerifiedPaymentCallback(
  env: Env,
  payment: PaymentRow,
  callback: Extract<VerifiedPaymentCallback, { ok: true }>,
  ctx?: ExecutionContext
): Promise<void> {
  const previousPayload = jsonObject(jsonParse(payment.provider_payload_json || "{}", {}));
  const payload = {
    ...previousPayload,
    callback: callback.payload,
    trade_no: callback.providerTradeNo,
    provider_ref: callback.providerRef,
    paid_at: clean(callback.paidAt, 80)
  };
  if (callback.status === "success") {
    if (Number(payment.order_id || 0) === 0) {
      const recharge = await getWalletRechargeByPaymentId(env, payment.id);
      if (!recharge) throw new ApiRequestError(404, "钱包充值记录不存在");
      await applyWalletRechargeSuccess(env, payment, recharge, payload);
      return;
    }
    if (!await markOrderPaid(env, payment.order_id, ctx)) throw new ApiRequestError(409, "订单状态不能更新为已支付");
    await env.DB.prepare(
      `UPDATE payments
       SET status='success', provider_trade_no=COALESCE(NULLIF(?, ''), provider_trade_no),
           provider_ref=COALESCE(NULLIF(?, ''), provider_ref), provider_payload_json=?,
           paid_at=COALESCE(paid_at, NULLIF(?, ''), CURRENT_TIMESTAMP), callback_at=CURRENT_TIMESTAMP,
           updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    ).bind(callback.providerTradeNo, callback.providerRef, stringify(payload), clean(callback.paidAt, 80), payment.id).run();
    await env.DB.prepare(
      `UPDATE payments
       SET status='expired', expired_at=COALESCE(expired_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP
       WHERE order_id=? AND id<>? AND status IN ('initiated','pending','created')`
    ).bind(payment.order_id, payment.id).run();
    return;
  }

  if (payment.status === "success") {
    await env.DB.prepare(
      "UPDATE payments SET callback_at=CURRENT_TIMESTAMP, provider_payload_json=?, updated_at=CURRENT_TIMESTAMP WHERE id=?"
    ).bind(stringify(payload), payment.id).run();
    return;
  }
  await env.DB.prepare(
    `UPDATE payments
     SET status=?, provider_trade_no=COALESCE(NULLIF(?, ''), provider_trade_no),
         provider_ref=COALESCE(NULLIF(?, ''), provider_ref), provider_payload_json=?,
         expired_at=CASE WHEN ?='expired' THEN COALESCE(expired_at, CURRENT_TIMESTAMP) ELSE expired_at END,
         callback_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP
     WHERE id=?`
  ).bind(callback.status, callback.providerTradeNo, callback.providerRef, stringify(payload), callback.status, payment.id).run();
  if (Number(payment.order_id || 0) === 0) {
    await env.DB.prepare(
      `UPDATE wallet_recharges SET status=?, updated_at=CURRENT_TIMESTAMP
       WHERE payment_id=? AND status<>'success'`
    ).bind(callback.status === "expired" ? "expired" : callback.status === "failed" ? "failed" : "pending", payment.id).run();
  } else if (callback.status === "expired" || callback.status === "failed") {
    await releaseOrderWalletBalance(env, payment.order_id, "在线支付失败，退回余额");
  }
}

function paymentCallbackSuccessResponse(): Response {
  return new Response("success", { status: 200, headers: { "Content-Type": "text/plain; charset=utf-8" } });
}

async function apiDujiaoPayWebhook(request: Request, env: Env, url: URL): Promise<Response> {
  const contentLength = Number(request.headers.get("Content-Length") || 0);
  if (contentLength > 256 * 1024) throw new ApiRequestError(413, "支付回调内容过大");
  const body = await request.text();
  if (new TextEncoder().encode(body).byteLength > 256 * 1024) throw new ApiRequestError(413, "支付回调内容过大");
  let event: AnyRecord;
  try {
    const parsed = JSON.parse(body);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error("invalid webhook JSON");
    event = parsed as AnyRecord;
  } catch {
    throw new ApiRequestError(400, "DujiaoPay Webhook JSON 格式不正确");
  }

  const timestamp = clean(request.headers.get("DJP-Webhook-Timestamp"), 40);
  const providedSignature = clean(request.headers.get("DJP-Webhook-Signature"), 200).replace(/^sha256=/i, "").toLowerCase();
  const timestampNumber = Number(timestamp);
  if (!/^\d{1,16}$/.test(timestamp) || !/^[a-f0-9]{64}$/.test(providedSignature)
    || !Number.isFinite(timestampNumber) || Math.abs(Math.floor(Date.now() / 1000) - timestampNumber) > 300) {
    return apiError("DujiaoPay Webhook 签名无效或已过期", 403);
  }

  const channelId = toInt(url.searchParams.get("channel_id"), 0);
  const rows = channelId > 0
    ? await env.DB.prepare("SELECT * FROM payment_channels WHERE id=? AND provider_type='dujiaopay' AND is_active=1").bind(channelId).all<PaymentChannelRow>()
    : await env.DB.prepare("SELECT * FROM payment_channels WHERE provider_type='dujiaopay' AND is_active=1 ORDER BY id ASC").all<PaymentChannelRow>();
  let matchedChannel: PaymentChannelRow | null = null;
  for (const candidate of rows.results || []) {
    const config = jsonObject(jsonParse(candidate.config_json || "{}", {}));
    const webhookSecret = clean(config.webhook_secret, 1000);
    if (!webhookSecret) continue;
    const expected = await hmacSha256Hex(webhookSecret, `${timestamp}.${body}`);
    if (timingSafeEqualHex(providedSignature, expected)) {
      matchedChannel = candidate;
      break;
    }
  }
  if (!matchedChannel) return apiError("DujiaoPay Webhook 签名校验失败", 403);

  const eventType = clean(event.event_type, 80);
  const status = eventType === "order.paid" ? "success"
    : eventType === "order.expired" ? "expired"
      : eventType === "order.canceled" ? "failed" : "";
  if (!status) return apiOk({ accepted: true, event_type: eventType, updated: false });
  const data = jsonObject(event.data);
  const merchantOrderId = clean(data.merchant_order_id, 120);
  const providerRef = clean(data.order_id, 200);
  let payment = merchantOrderId ? await paymentByNoWithContext(env, merchantOrderId) : null;
  if ((!payment || payment.channel_id !== matchedChannel.id) && providerRef) {
    const row = await env.DB.prepare(
      "SELECT id FROM payments WHERE channel_id=? AND provider_ref=? ORDER BY id DESC LIMIT 1"
    ).bind(matchedChannel.id, providerRef).first<{ id: number }>();
    payment = row ? await paymentByIdWithContext(env, row.id) : null;
  }
  if (!payment || payment.channel_id !== matchedChannel.id) {
    return apiOk({ accepted: true, event_type: eventType, updated: false });
  }
  await applyVerifiedPaymentCallback(env, payment, {
    ok: true,
    status,
    amount: "",
    currency: "",
    providerRef,
    providerTradeNo: clean(data.tx_hash, 200),
    payload: event
  });
  return apiOk({ accepted: true, event_type: eventType, updated: true, payment_id: payment.id, status });
}

async function readPaymentWebhookJson(request: Request): Promise<{ body: string; event: AnyRecord }> {
  const contentLength = Number(request.headers.get("Content-Length") || 0);
  if (contentLength > 256 * 1024) throw new ApiRequestError(413, "支付 Webhook 内容过大");
  const body = await request.text();
  if (new TextEncoder().encode(body).byteLength > 256 * 1024) throw new ApiRequestError(413, "支付 Webhook 内容过大");
  try {
    const parsed = JSON.parse(body);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error("invalid JSON object");
    return { body, event: parsed as AnyRecord };
  } catch {
    throw new ApiRequestError(400, "支付 Webhook JSON 格式不正确");
  }
}

type DerNode = { tag: number; start: number; contentStart: number; end: number; next: number };
type WechatPlatformCertificate = { serial: string; key: CryptoKey; effectiveAt: number; expiresAt: number };

const wechatPlatformCertificateCache = new Map<string, { loadedAt: number; certificates: WechatPlatformCertificate[] }>();

function readDerNode(bytes: Uint8Array, offset: number): DerNode | null {
  if (offset < 0 || offset + 2 > bytes.length) return null;
  const start = offset;
  const tag = bytes[offset++];
  const firstLength = bytes[offset++];
  let length = 0;
  if ((firstLength & 0x80) === 0) {
    length = firstLength;
  } else {
    const count = firstLength & 0x7f;
    if (count < 1 || count > 4 || offset + count > bytes.length) return null;
    for (let index = 0; index < count; index += 1) length = length * 256 + bytes[offset++];
  }
  const end = offset + length;
  if (end < offset || end > bytes.length) return null;
  return { tag, start, contentStart: offset, end, next: end };
}

function extractCertificateSpki(certificatePem: string): Uint8Array {
  const certificate = pemKeyBytes(certificatePem).bytes;
  const root = readDerNode(certificate, 0);
  if (!root || root.tag !== 0x30 || root.next !== certificate.length) throw new ApiRequestError(502, "微信支付平台证书格式不正确");
  const tbs = readDerNode(certificate, root.contentStart);
  if (!tbs || tbs.tag !== 0x30) throw new ApiRequestError(502, "微信支付平台证书缺少 TBSCertificate");
  let offset = tbs.contentStart;
  let node = readDerNode(certificate, offset);
  if (!node) throw new ApiRequestError(502, "微信支付平台证书无法解析");
  if (node.tag === 0xa0) {
    offset = node.next;
    node = readDerNode(certificate, offset);
  }
  // serialNumber, signature, issuer, validity and subject precede SubjectPublicKeyInfo.
  for (let index = 0; index < 5; index += 1) {
    if (!node) throw new ApiRequestError(502, "微信支付平台证书字段不完整");
    offset = node.next;
    node = readDerNode(certificate, offset);
  }
  if (!node || node.tag !== 0x30) throw new ApiRequestError(502, "微信支付平台证书缺少公钥");
  return certificate.slice(node.start, node.next);
}

async function decryptWechatAesGcm(apiV3Key: string, resource: AnyRecord): Promise<string> {
  const nonce = clean(resource.nonce, 200);
  const associatedData = typeof resource.associated_data === "string" ? resource.associated_data : "";
  const ciphertext = clean(resource.ciphertext, 200000);
  if (!nonce || !ciphertext || new TextEncoder().encode(apiV3Key).byteLength !== 32) {
    throw new ApiRequestError(400, "微信支付加密资源或 APIv3 Key 不正确");
  }
  try {
    const key = await crypto.subtle.importKey("raw", new TextEncoder().encode(apiV3Key), "AES-GCM", false, ["decrypt"]);
    const plaintext = await crypto.subtle.decrypt({
      name: "AES-GCM",
      iv: new TextEncoder().encode(nonce),
      additionalData: new TextEncoder().encode(associatedData),
      tagLength: 128
    }, key, base64ToBytes(ciphertext));
    return new TextDecoder("utf-8", { fatal: true, ignoreBOM: false }).decode(plaintext);
  } catch {
    throw new ApiRequestError(403, "微信支付回调解密失败");
  }
}

function wechatCertificateCacheKey(config: AnyRecord): string {
  return `${clean(config.mchid, 200)}|${wechatApiBaseUrl(config).replace(/\/+$/, "")}`;
}

async function downloadWechatPlatformCertificates(config: AnyRecord): Promise<WechatPlatformCertificate[]> {
  const response = await requestWechatApi(config, "GET", "/v3/certificates");
  if (!response.ok) throw new ApiRequestError(502, `下载微信支付平台证书失败：${response.error}`);
  const apiV3Key = clean(config.api_v3_key, 200);
  const records = Array.isArray(response.data.data) ? response.data.data : [];
  const certificates: WechatPlatformCertificate[] = [];
  for (const raw of records) {
    const record = jsonObject(raw);
    const serial = responseString(record.serial_no, 500);
    const encrypted = jsonObject(record.encrypt_certificate);
    if (!serial || !Object.keys(encrypted).length) continue;
    const certificatePem = await decryptWechatAesGcm(apiV3Key, encrypted);
    const spki = extractCertificateSpki(certificatePem);
    let key: CryptoKey;
    try {
      key = await crypto.subtle.importKey(
        "spki",
        spki,
        { name: "RSASSA-PKCS1-v1_5", hash: "SHA-256" },
        false,
        ["verify"]
      );
    } catch {
      throw new ApiRequestError(502, "微信支付平台证书公钥无法解析");
    }
    const effectiveAt = Date.parse(responseString(record.effective_time, 100));
    const expiresAt = Date.parse(responseString(record.expire_time, 100));
    certificates.push({
      serial,
      key,
      effectiveAt: Number.isFinite(effectiveAt) ? effectiveAt : 0,
      expiresAt: Number.isFinite(expiresAt) ? expiresAt : Date.now() + 60 * 60 * 1000
    });
  }
  if (!certificates.length) throw new ApiRequestError(502, "微信支付未返回可用的平台证书");
  wechatPlatformCertificateCache.set(wechatCertificateCacheKey(config), { loadedAt: Date.now(), certificates });
  return certificates;
}

async function wechatPlatformCertificate(config: AnyRecord, serial: string): Promise<WechatPlatformCertificate | null> {
  const key = wechatCertificateCacheKey(config);
  const now = Date.now();
  const cached = wechatPlatformCertificateCache.get(key);
  const find = (items: WechatPlatformCertificate[]) => items.find((item) => item.serial === serial && item.expiresAt > now);
  if (cached && now - cached.loadedAt < 60 * 60 * 1000) {
    const match = find(cached.certificates);
    if (match) return match;
  }
  const downloaded = await downloadWechatPlatformCertificates(config);
  return find(downloaded) || null;
}

function isWechatPaymentCallbackRequest(request: Request): boolean {
  return ["Wechatpay-Signature", "Wechatpay-Timestamp", "Wechatpay-Nonce", "Wechatpay-Serial"]
    .every((header) => clean(request.headers.get(header), 5000) !== "");
}

function wechatCallbackResponse(success: boolean, status = success ? 200 : 400): Response {
  return new Response(JSON.stringify({ code: success ? "SUCCESS" : "FAIL", message: success ? "成功" : "失败" }), {
    status,
    headers: JSON_HEADERS
  });
}

async function verifyWechatCallbackSignature(
  config: AnyRecord,
  serial: string,
  timestamp: string,
  nonce: string,
  signature: string,
  body: string
): Promise<boolean> {
  const certificate = await wechatPlatformCertificate(config, serial);
  if (!certificate) return false;
  try {
    return await crypto.subtle.verify(
      "RSASSA-PKCS1-v1_5",
      certificate.key,
      base64ToBytes(signature),
      new TextEncoder().encode(`${timestamp}\n${nonce}\n${body}\n`)
    );
  } catch {
    return false;
  }
}

async function apiWechatPaymentCallback(request: Request, env: Env, url: URL): Promise<Response> {
  let webhook: { body: string; event: AnyRecord };
  try {
    webhook = await readPaymentWebhookJson(request);
  } catch {
    return wechatCallbackResponse(false);
  }
  const timestamp = clean(request.headers.get("Wechatpay-Timestamp"), 40);
  const nonce = clean(request.headers.get("Wechatpay-Nonce"), 500);
  const signature = clean(request.headers.get("Wechatpay-Signature"), 5000);
  const serial = clean(request.headers.get("Wechatpay-Serial"), 500);
  const timestampNumber = Number(timestamp);
  if (!/^\d{1,16}$/.test(timestamp) || !Number.isFinite(timestampNumber)
    || Math.abs(Math.floor(Date.now() / 1000) - timestampNumber) > 300 || !nonce || !signature || !serial) {
    return wechatCallbackResponse(false, 403);
  }
  const resource = jsonObject(webhook.event.resource);
  if (!Object.keys(resource).length) return wechatCallbackResponse(false);
  const channelId = toInt(url.searchParams.get("channel_id"), 0);
  const candidates = await officialWebhookChannels(env, "wechat", channelId, true);
  let matched: PaymentChannelRow | null = null;
  let plaintext = "";
  for (const channel of candidates) {
    const config = jsonObject(jsonParse(channel.config_json || "{}", {}));
    try {
      if (!await verifyWechatCallbackSignature(config, serial, timestamp, nonce, signature, webhook.body)) continue;
      plaintext = await decryptWechatAesGcm(clean(config.api_v3_key, 200), resource);
      matched = channel;
      break;
    } catch {
      // Try the next active WeChat channel when channel_id is intentionally absent.
    }
  }
  if (!matched || !plaintext) return wechatCallbackResponse(false, 403);
  let transaction: AnyRecord;
  try {
    const parsed = JSON.parse(plaintext);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error("invalid transaction");
    transaction = parsed as AnyRecord;
  } catch {
    return wechatCallbackResponse(false);
  }
  const status = wechatPaymentStatus(transaction.trade_state);
  const orderNo = responseString(transaction.out_trade_no, 120);
  if (!status || !orderNo) return wechatCallbackResponse(false);
  const transactionId = responseString(transaction.transaction_id, 200);
  const result: Extract<OfficialPaymentQueryResult, { ok: true }> = {
    ok: true,
    status,
    amount: wechatFenToAmount(paymentJsonPath(transaction, "amount", "total")),
    currency: responseString(paymentJsonPath(transaction, "amount", "currency"), 20).toUpperCase(),
    providerRef: transactionId || orderNo,
    providerTradeNo: transactionId,
    paidAt: responseString(transaction.success_time, 80),
    payload: { event: webhook.event, resource_plaintext: transaction }
  };
  const settled = await settleOfficialWebhook(env, matched, responseString(webhook.event.event_type, 100), result, orderNo);
  return settled.ok ? wechatCallbackResponse(true) : wechatCallbackResponse(false, settled.status);
}

async function officialWebhookChannels(
  env: Env,
  channelType: "stripe" | "paypal" | "wechat",
  channelId: number,
  allowBlindMatch: boolean
): Promise<PaymentChannelRow[]> {
  if (channelId > 0) {
    const channel = await paymentChannelById(env, channelId);
    return channel && paymentProviderKey(channel.provider_type, channel.channel_type) === `official:${channelType}` ? [channel] : [];
  }
  if (!allowBlindMatch) return [];
  const rows = await env.DB.prepare(
    "SELECT * FROM payment_channels WHERE provider_type='official' AND channel_type=? AND is_active=1 ORDER BY id ASC"
  ).bind(channelType).all<PaymentChannelRow>();
  return rows.results || [];
}

async function findOfficialWebhookPayment(
  env: Env,
  channelId: number,
  orderNo: string,
  providerRef: string
): Promise<PaymentRow | null> {
  if (orderNo) {
    const row = await env.DB.prepare(
      "SELECT id FROM payments WHERE channel_id=? AND payment_no=? ORDER BY id DESC LIMIT 1"
    ).bind(channelId, orderNo).first<{ id: number }>();
    if (row) return paymentByIdWithContext(env, row.id);
  }
  if (providerRef) {
    const row = await env.DB.prepare(
      "SELECT id FROM payments WHERE channel_id=? AND provider_ref=? ORDER BY id DESC LIMIT 1"
    ).bind(channelId, providerRef).first<{ id: number }>();
    if (row) return paymentByIdWithContext(env, row.id);
  }
  return null;
}

async function settleOfficialWebhook(
  env: Env,
  channel: PaymentChannelRow,
  eventType: string,
  result: Extract<OfficialPaymentQueryResult, { ok: true }>,
  orderNo: string
): Promise<Response> {
  if (!result.status) return apiOk({ accepted: true, event_type: eventType, updated: false });
  const payment = await findOfficialWebhookPayment(env, channel.id, orderNo, result.providerRef);
  if (!payment) return apiOk({ accepted: true, event_type: eventType, updated: false });
  const verified = verifyQueriedPaymentAgainstRecord(payment, result);
  if (!verified.ok) return apiError(verified.error, 409);
  await applyVerifiedPaymentCallback(env, payment, verified.callback);
  const fresh = await paymentByIdWithContext(env, payment.id) || payment;
  return apiOk({
    accepted: true,
    event_type: eventType,
    updated: true,
    payment_id: payment.id,
    status: fresh.status
  });
}

function parseStripeSignatureHeader(value: string): { timestamp: number; signatures: string[] } | null {
  let timestamp = 0;
  const signatures: string[] = [];
  for (const item of value.split(",")) {
    const [rawKey, ...rest] = item.trim().split("=");
    const key = rawKey?.trim();
    const part = rest.join("=").trim();
    if (key === "t" && /^\d{1,16}$/.test(part)) timestamp = Number(part);
    if (key === "v1" && /^[a-f0-9]{64}$/i.test(part)) signatures.push(part.toLowerCase());
  }
  return timestamp > 0 && signatures.length > 0 ? { timestamp, signatures } : null;
}

function stripeWebhookQueryResult(event: AnyRecord): {
  eventType: string;
  orderNo: string;
  result: Extract<OfficialPaymentQueryResult, { ok: true }> | null;
} {
  const eventType = clean(event.type, 100);
  const object = jsonObject(paymentJsonPath(event, "data", "object"));
  const objectType = clean(object.object, 60).toLowerCase();
  const metadata = jsonObject(object.metadata);
  const orderNo = clean(metadata.order_no, 120);
  let status: "success" | "pending" | "failed" | "expired" | "" = "";
  switch (eventType.toLowerCase()) {
    case "checkout.session.completed":
    case "checkout.session.async_payment_succeeded":
    case "payment_intent.succeeded": status = "success"; break;
    case "checkout.session.expired": status = "expired"; break;
    case "checkout.session.async_payment_failed":
    case "payment_intent.payment_failed":
    case "payment_intent.canceled": status = "failed"; break;
    case "payment_intent.processing": status = "pending"; break;
  }
  if (objectType === "checkout.session") {
    if (!status) status = stripePaymentStatus(object.payment_status, object.status);
    const sessionId = responseString(object.id, 200);
    const intentRaw = object.payment_intent;
    const intentId = typeof intentRaw === "string" ? clean(intentRaw, 200) : responseString(jsonObject(intentRaw).id, 200);
    const currency = responseString(object.currency, 20).toUpperCase();
    return {
      eventType,
      orderNo,
      result: {
        ok: true,
        status,
        amount: stripeMajorAmount(object.amount_total, currency),
        currency,
        providerRef: sessionId,
        providerTradeNo: intentId,
        paidAt: Number(object.created || 0) > 0 ? new Date(Number(object.created) * 1000).toISOString() : "",
        payload: event
      }
    };
  }
  if (objectType === "payment_intent") {
    if (!status) status = stripeIntentStatus(object.status);
    const intentId = responseString(object.id, 200);
    const currency = responseString(object.currency, 20).toUpperCase();
    const amountMinor = Number(object.amount_received || 0) > 0 ? object.amount_received : object.amount;
    return {
      eventType,
      orderNo,
      result: {
        ok: true,
        status,
        amount: stripeMajorAmount(amountMinor, currency),
        currency,
        providerRef: intentId,
        providerTradeNo: intentId,
        paidAt: Number(object.created || 0) > 0 ? new Date(Number(object.created) * 1000).toISOString() : "",
        payload: event
      }
    };
  }
  return { eventType, orderNo, result: null };
}

async function apiStripeWebhook(request: Request, env: Env, url: URL): Promise<Response> {
  const { body, event } = await readPaymentWebhookJson(request);
  const signature = parseStripeSignatureHeader(request.headers.get("Stripe-Signature") || "");
  if (!signature) return apiError("Stripe Webhook 签名格式不正确", 403);
  const channelId = toInt(url.searchParams.get("channel_id"), 0);
  const candidates = await officialWebhookChannels(env, "stripe", channelId, true);
  let matched: PaymentChannelRow | null = null;
  for (const channel of candidates) {
    const config = jsonObject(jsonParse(channel.config_json || "{}", {}));
    const secret = clean(config.webhook_secret, 1000);
    const tolerance = Math.max(1, toInt(config.webhook_tolerance_seconds, 300));
    if (!secret || Math.abs(Math.floor(Date.now() / 1000) - signature.timestamp) > tolerance) continue;
    const expected = await hmacSha256Hex(secret, `${signature.timestamp}.${body}`);
    if (signature.signatures.some((item) => timingSafeEqualHex(item, expected))) {
      matched = channel;
      break;
    }
  }
  if (!matched) return apiError("Stripe Webhook 签名校验失败", 403);
  const parsed = stripeWebhookQueryResult(event);
  if (!parsed.result) return apiOk({ accepted: true, event_type: parsed.eventType, updated: false });
  return settleOfficialWebhook(env, matched, parsed.eventType, parsed.result, parsed.orderNo);
}

function paypalWebhookStatus(eventType: string, resourceStatus: string): "success" | "pending" | "failed" | "expired" | "" {
  switch (eventType.toUpperCase()) {
    case "PAYMENT.CAPTURE.COMPLETED":
    case "CHECKOUT.ORDER.COMPLETED": return "success";
    case "PAYMENT.CAPTURE.DENIED":
    case "PAYMENT.CAPTURE.DECLINED":
    case "PAYMENT.CAPTURE.FAILED":
    case "CHECKOUT.ORDER.DENIED": return "failed";
    case "PAYMENT.CAPTURE.PENDING":
    case "CHECKOUT.ORDER.APPROVED": return "pending";
  }
  const mapped = paypalPaymentStatus(resourceStatus);
  return resourceStatus ? mapped : "";
}

function paypalWebhookValues(event: AnyRecord): {
  eventType: string;
  orderNo: string;
  result: Extract<OfficialPaymentQueryResult, { ok: true }> | null;
} {
  const eventType = clean(event.event_type, 100);
  const resource = jsonObject(event.resource);
  const resourceStatus = clean(resource.status, 60);
  const status = paypalWebhookStatus(eventType, resourceStatus);
  if (!status) return { eventType, orderNo: "", result: null };
  let providerRef = responseString(paymentJsonPath(resource, "supplementary_data", "related_ids", "order_id"), 200);
  if (!providerRef && eventType.toUpperCase().startsWith("CHECKOUT.ORDER")) providerRef = responseString(resource.id, 200);
  if (!providerRef) providerRef = responseString(resource.order_id, 200);
  const orderNo = responseString(paymentJsonPath(resource, "purchase_units", 0, "invoice_id"), 120);
  let amount = responseString(paymentJsonPath(resource, "amount", "value"), 80);
  let currency = responseString(paymentJsonPath(resource, "amount", "currency_code"), 20).toUpperCase();
  if (!amount || !currency) {
    amount = responseString(paymentJsonPath(resource, "purchase_units", 0, "amount", "value"), 80);
    currency = responseString(paymentJsonPath(resource, "purchase_units", 0, "amount", "currency_code"), 20).toUpperCase();
  }
  if (!amount || !currency) {
    amount = responseString(paymentJsonPath(resource, "purchase_units", 0, "payments", "captures", 0, "amount", "value"), 80);
    currency = responseString(paymentJsonPath(resource, "purchase_units", 0, "payments", "captures", 0, "amount", "currency_code"), 20).toUpperCase();
  }
  const paidAt = responseString(resource.create_time, 80) || responseString(resource.update_time, 80) || responseString(event.create_time, 80);
  return {
    eventType,
    orderNo,
    result: {
      ok: true,
      status,
      amount,
      currency,
      providerRef,
      providerTradeNo: responseString(resource.id, 200),
      paidAt,
      payload: { event }
    }
  };
}

async function apiPaypalWebhook(request: Request, env: Env, url: URL): Promise<Response> {
  const channelId = toInt(url.searchParams.get("channel_id"), 0);
  if (channelId <= 0) return apiError("PayPal Webhook 必须提供 channel_id", 400);
  const candidates = await officialWebhookChannels(env, "paypal", channelId, false);
  const channel = candidates[0];
  if (!channel) return apiError("PayPal 支付渠道不存在", 404);
  const { event } = await readPaymentWebhookJson(request);
  const config = jsonObject(jsonParse(channel.config_json || "{}", {}));
  const webhookId = clean(config.webhook_id, 500);
  if (!webhookId) return apiError("PayPal 渠道未配置 Webhook ID", 400);
  const headerMap: Record<string, string> = {
    transmission_id: clean(request.headers.get("Paypal-Transmission-Id"), 500),
    transmission_time: clean(request.headers.get("Paypal-Transmission-Time"), 500),
    cert_url: clean(request.headers.get("Paypal-Cert-Url"), 2000),
    auth_algo: clean(request.headers.get("Paypal-Auth-Algo"), 200),
    transmission_sig: clean(request.headers.get("Paypal-Transmission-Sig"), 4000)
  };
  if (Object.values(headerMap).some((value) => !value)) return apiError("PayPal Webhook 签名头不完整", 403);
  const access = await paypalAccessToken(config);
  if (!access.ok) return apiError(access.error, 502);
  const endpoint = providerEndpoint(clean(config.base_url, 1000) || "https://api-m.sandbox.paypal.com", "/v1/notifications/verify-webhook-signature");
  const verify = await requestPaymentProvider(endpoint, {
    method: "POST",
    headers: { "Authorization": `Bearer ${access.token}`, "Content-Type": "application/json" },
    body: JSON.stringify({ ...headerMap, webhook_id: webhookId, webhook_event: event })
  });
  if (!verify.ok || responseString(verify.data.verification_status, 30).toUpperCase() !== "SUCCESS") {
    return apiError("PayPal Webhook 签名校验失败", 403);
  }
  const parsed = paypalWebhookValues(event);
  if (!parsed.result) return apiOk({ accepted: true, event_type: parsed.eventType, updated: false });
  return settleOfficialWebhook(env, channel, parsed.eventType, parsed.result, parsed.orderNo);
}

function verifyEpaySignature(payload: Record<string, string>, merchantKey: string): boolean {
  const expected = clean(payload.sign, 100).toLowerCase();
  if (!expected) return false;
  return timingSafeEqualHex(expected, epaySignPayload(payload, merchantKey));
}

function providerSignContent(payload: Record<string, unknown>): string {
  return Object.keys(payload)
    .filter((key) => key !== "sign" && key !== "sign_type")
    .filter((key) => payload[key] !== undefined && payload[key] !== null && String(payload[key]) !== "")
    .sort()
    .map((key) => `${key}=${String(payload[key])}`)
    .join("&");
}

function epaySignPayload(payload: Record<string, unknown>, merchantKey: string): string {
  return md5Hex(`${providerSignContent(payload)}${merchantKey}`);
}

function isEpaySuccessPayload(payload: Record<string, string>): boolean {
  const status = clean(payload.trade_status || payload.status || payload.state, 80).toUpperCase();
  return ["TRADE_SUCCESS", "TRADE_FINISHED", "SUCCESS", "PAID", "1"].includes(status);
}

async function paymentByNoWithContext(env: Env, paymentNo: string): Promise<PaymentRow | null> {
  return env.DB.prepare(
    `SELECT p.*, o.order_no AS order_no, pc.name AS channel_name,
            wr.recharge_no AS recharge_no, wr.user_id AS recharge_user_id, wr.status AS recharge_status
     FROM payments p
     LEFT JOIN orders o ON o.id=p.order_id
     LEFT JOIN payment_channels pc ON pc.id=p.channel_id
     LEFT JOIN wallet_recharges wr ON wr.payment_id=p.id
     WHERE p.payment_no=?`
  ).bind(paymentNo).first<PaymentRow>();
}

function calculateParentOrderStatus(childStatuses: string[], currentStatus: string): string {
  if (!childStatuses.length) return currentStatus;
  const counts = new Map<string, number>();
  for (const rawStatus of childStatuses) {
    const status = clean(rawStatus, 40).toLowerCase();
    counts.set(status, Number(counts.get(status) || 0) + 1);
  }
  const total = childStatuses.length;
  const count = (status: string) => Number(counts.get(status) || 0);
  if (count("canceled") === total) return "canceled";
  if (count("refunded") === total) return "refunded";
  if (count("refunded") > 0 || count("partially_refunded") > 0) return "partially_refunded";
  if (count("completed") === total) return "completed";
  if (count("delivered") + count("completed") === total) return "delivered";
  if (count("delivered") + count("completed") + count("partially_delivered") > 0) return "partially_delivered";
  if (count("fulfilling") > 0) return "fulfilling";
  if (count("paid") > 0) return "paid";
  if (count("pending_payment") > 0) return "pending_payment";
  return currentStatus;
}

async function syncParentOrderStatus(env: Env, parentId: number): Promise<string> {
  if (!parentId) return "";
  const parent = await env.DB.prepare("SELECT id, parent_id, status FROM orders WHERE id=?")
    .bind(parentId)
    .first<{ id: number; parent_id: number | null; status: string }>();
  if (!parent || parent.parent_id != null || parent.status === "canceled") return parent?.status || "";
  const children = await env.DB.prepare("SELECT status FROM orders WHERE parent_id=? ORDER BY id ASC")
    .bind(parentId)
    .all<{ status: string }>();
  const childStatuses = (children.results || []).map((child) => child.status);
  const target = calculateParentOrderStatus(childStatuses, parent.status);
  if (!target || target === parent.status) return parent.status;
  const updated = await env.DB.prepare(
    "UPDATE orders SET status=?, updated_at=CURRENT_TIMESTAMP WHERE id=? AND status=?"
  ).bind(target, parentId, parent.status).run();
  if (Number(updated.meta.changes || 0) !== 1) {
    const fresh = await env.DB.prepare("SELECT status FROM orders WHERE id=?").bind(parentId).first<{ status: string }>();
    return fresh?.status || parent.status;
  }
  if (["delivered", "completed"].includes(target)) {
    await sendOrderLifecycleEmail(env, parentId, target);
  }
  await sendDownstreamCallbackForOrder(env, parentId);
  return target;
}

async function finalizeSinglePaidOrder(env: Env, order: OrderRow): Promise<{
  storedItems: Array<OrderItemRow & AnyRecord>;
  hasManualItems: boolean;
}> {
  const items = await env.DB.prepare("SELECT * FROM order_items WHERE order_id=? ORDER BY id ASC")
    .bind(order.id)
    .all<OrderItemRow & AnyRecord>();
  const storedItems = items.results || [];
  let hasManualItems = false;
  const autoSecrets: Array<{ product: ProductRow; sku: SkuRow; secret: CardSecretRow }> = [];
  const autoItems = storedItems.filter((item) => (clean(item.fulfillment_type, 40) || "manual") === "auto");
  const productIds = Array.from(new Set(autoItems.map((item) => Number(item.product_id || 0)).filter((id) => id > 0)));
  const skuIds = Array.from(new Set(autoItems.map((item) => Number(item.sku_id || 0)).filter((id) => id > 0)));
  let productsById = new Map<number, ProductRow>();
  let skusById = new Map<number, SkuRow>();
  if (productIds.length && skuIds.length) {
    const productPlaceholders = productIds.map(() => "?").join(",");
    const skuPlaceholders = skuIds.map(() => "?").join(",");
    const [productsResult, skusResult] = await env.DB.batch([
      env.DB.prepare(`SELECT * FROM products WHERE id IN (${productPlaceholders})`).bind(...productIds),
      env.DB.prepare(`SELECT * FROM product_skus WHERE id IN (${skuPlaceholders})`).bind(...skuIds)
    ]);
    productsById = new Map(
      ((productsResult.results || []) as ProductRow[]).map((row) => [Number(row.id), row])
    );
    skusById = new Map(
      ((skusResult.results || []) as SkuRow[]).map((row) => [Number(row.id), row])
    );
  }
  for (const item of storedItems) {
    const fulfillmentType = clean(item.fulfillment_type, 40) || "manual";
    if (fulfillmentType === "upstream") continue;
    if (fulfillmentType !== "auto") {
      hasManualItems = true;
      continue;
    }
    const product = productsById.get(Number(item.product_id || 0));
    const sku = skusById.get(Number(item.sku_id || 0));
    if (!product || !sku) continue;
    const consumed = await consumeCardSecretsForOrder(env, order.id, product, sku, Number(item.quantity || 0));
    if (consumed.length !== Number(item.quantity || 0)) continue;
    for (const secret of consumed) autoSecrets.push({ product, sku, secret });
  }

  if (autoSecrets.length) await createAutoFulfillment(env, order.id, autoSecrets);
  if (hasManualItems) await consumeLockedStockForOrder(env, order.id);
  await refreshOrderFulfillmentStatus(env, order.id);
  return { storedItems, hasManualItems };
}

async function finalizePaidOrderPostProcessing(
  env: Env,
  order: OrderRow,
  storedItems: Array<OrderItemRow & AnyRecord>,
  hasManualItems: boolean,
  syncParent: boolean
): Promise<void> {
  const processing = await ensureOrderProcessingState(env, order.id);
  if (!processing.business_effects_completed_at) {
    await finalizePaidOrderBusinessSideEffects(env, order, storedItems);
    await markOrderProcessingStep(env, order.id, "business_effects_completed_at");
  }

  if (!processing.notifications_sent_at) {
    await sendNotificationCenterEmail(env, "order_paid_success", { orderId: order.id });
    if (hasManualItems) {
      await sendNotificationCenterEmail(env, "manual_fulfillment_pending", { orderId: order.id });
    }
    await markOrderProcessingStep(env, order.id, "notifications_sent_at");
  }

  if (syncParent) await syncParentOrderStatus(env, order.id);
}

async function finalizePaidOrder(env: Env, orderId: number, ctx?: ExecutionContext): Promise<void> {
  const order = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(orderId).first<OrderRow>();
  if (!order) return;

  if (order.user_id && moneyToCents(Number(order.wallet_paid_amount || 0)) > 0) {
    const existingWalletTxn = await env.DB.prepare(
      "SELECT id FROM wallet_transactions WHERE order_id=? AND user_id=? AND type='order_payment' LIMIT 1"
    ).bind(order.id, order.user_id).first<{ id: number }>();
    if (!existingWalletTxn) {
      await adjustWalletBalance(env, order.user_id, Number(order.wallet_paid_amount || 0), "out", {
        type: "order_payment",
        orderId: order.id,
        reference: order.order_no,
        remark: `订单支付 ${order.order_no}`
      });
    }
  }

  if (order.user_id) {
    await env.DB.prepare(
      `UPDATE users
       SET total_spent=(SELECT COALESCE(SUM(total_amount), 0) FROM orders WHERE user_id=? AND parent_id IS NULL AND paid_at IS NOT NULL),
           updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    )
      .bind(order.user_id, order.user_id)
      .run();
    await updateUserMemberLevelForThresholds(env, order.user_id);
  }

  let children: OrderRow[] = [];
  if (order.parent_id == null) {
    const childResults = await env.DB.batch([
      env.DB.prepare(
        `UPDATE orders
         SET status='paid', paid_at=COALESCE(paid_at, ?), updated_at=CURRENT_TIMESTAMP
         WHERE parent_id=? AND status='pending_payment'`
      ).bind(order.paid_at || new Date().toISOString(), order.id),
      env.DB.prepare("SELECT * FROM orders WHERE parent_id=? ORDER BY id ASC").bind(order.id)
    ]);
    children = (childResults[1].results || []) as OrderRow[];
  }

  const targets = children.length ? children : [order];
  const storedItems: Array<OrderItemRow & AnyRecord> = [];
  let hasManualItems = false;
  for (const target of targets) {
    if (!["paid", "fulfilling", "partially_delivered", "delivered", "completed"].includes(target.status)) continue;
    const finalized = await finalizeSinglePaidOrder(env, target);
    storedItems.push(...finalized.storedItems);
    hasManualItems ||= finalized.hasManualItems;
  }
  if (children.length) await syncParentOrderStatus(env, order.id);

  const postProcessing = finalizePaidOrderPostProcessing(
    env,
    order,
    storedItems,
    hasManualItems,
    children.length > 0
  );
  if (ctx) {
    ctx.waitUntil(postProcessing.catch((error) => {
      console.error(`paid order post-processing failed: ${order.id}`, error);
    }));
  } else {
    await postProcessing;
  }
}

async function apiSendUserVerifyCode(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const email = normalizeEmail(body.email);
  if (!email) return apiError("邮箱格式不正确", 400);
  const purpose = normalizeEmailVerifyPurpose(body.purpose || body.scene || body.type);
  if (purpose !== "register" && purpose !== "reset") return apiError("验证码场景不合法", 400);
  const captcha = await validateCaptchaForScene(
    env,
    request,
    body,
    purpose === "register" ? "register_send_code" : "reset_send_code"
  );
  if (!captcha.ok) return apiError(captcha.error, captcha.status);

  if (purpose === "register") {
    const registration = await registrationSettings(env);
    if (registration.registration_enabled === false) return apiError("注册已关闭", 403);
    if (!emailDomainAllowed(email, registration)) return apiError("该邮箱域名不允许注册", 400);
    const exists = await env.DB.prepare("SELECT id FROM users WHERE email=?").bind(email).first<{ id: number }>();
    if (exists) return apiError("邮箱已注册", 409);
  }

  if (purpose === "reset") {
    const exists = await env.DB.prepare("SELECT id FROM users WHERE email=?").bind(email).first<{ id: number }>();
    if (!exists) return apiOk({ sent: true, email, message: "如果邮箱存在，验证码会发送到该邮箱" });
  }

  const result = await sendEmailVerificationCode(env, request, email, purpose);
  if (!result.ok) return apiError(result.error, result.status);
  return apiOk({ sent: true, email, expires_at: result.expiresAt });
}

async function apiUserRegister(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const email = normalizeEmail(body.email);
  const password = String(body.password || "");
  const passwordConfirmation = String(body.password_confirmation || body.password_confirm || "");
  const registration = await registrationSettings(env);
  if (registration.registration_enabled === false) return apiError("注册已关闭", 403);
  if (!email) return apiError("邮箱格式不正确", 400);
  if (!emailDomainAllowed(email, registration)) return apiError("该邮箱域名不允许注册", 400);
  if (password.length < 6) return apiError("密码至少 6 位", 400);
  if (passwordConfirmation && passwordConfirmation !== password) return apiError("两次输入的密码不一致", 400);
  const exists = await env.DB.prepare("SELECT id FROM users WHERE email=?").bind(email).first<{ id: number }>();
  if (exists) return apiError("邮箱已注册", 409);
  if (registration.email_verification_enabled !== false) {
    const verification = await consumeEmailVerificationCode(env, email, "register", body.code);
    if (!verification.ok) return apiError(verification.error, verification.status);
  }

  const nickname = clean(body.nickname || email.split("@")[0], 80);
  const locale = clean(body.locale || request.headers.get("X-Lang") || "zh-CN", 20);
  const salt = randomToken().slice(0, 16);
  const passwordHash = await hashPassword(password, salt);
  const now = new Date().toISOString();
  const result = await env.DB.prepare(
    `INSERT INTO users (email, password_salt, password_hash, nickname, display_name, locale, status, email_verified_at)
     VALUES (?, ?, ?, ?, ?, ?, 'active', ?)`
  ).bind(email, salt, passwordHash, nickname, nickname, locale, now).run();
  const userId = Number(result.meta.last_row_id);
  await ensureWallet(env, userId);
  await assignDefaultMemberLevel(env, userId);
  const user = await getUserById(env, userId);
  if (!user) return apiError("注册失败", 500);
  const session = await createUserSession(env, user.id);
  await recordUserLogin(env, request, user.id, email, "success", "");
  return apiOk({ token: session.token, user: formatUser(user), expires_at: session.expiresAt });
}

async function apiUserForgotPassword(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const email = normalizeEmail(body.email);
  const code = clean(body.code, 20);
  const newPassword = String(body.new_password || body.password || "");
  if (!email) return apiError("邮箱格式不正确", 400);
  if (!code) return apiError("请输入邮箱验证码", 400);
  if (newPassword.length < 6) return apiError("新密码至少 6 位", 400);

  const verification = await consumeEmailVerificationCode(env, email, "reset", code);
  if (!verification.ok) return apiError(verification.error, verification.status);
  const user = await env.DB.prepare("SELECT * FROM users WHERE email=?").bind(email).first<UserRow>();
  if (!user) return apiError("验证码错误或已过期", 400);

  const salt = randomToken().slice(0, 16);
  const passwordHash = await hashPassword(newPassword, salt);
  await env.DB.batch([
    env.DB.prepare("UPDATE users SET password_salt=?, password_hash=?, updated_at=CURRENT_TIMESTAMP WHERE id=?").bind(salt, passwordHash, user.id),
    env.DB.prepare("DELETE FROM user_sessions WHERE user_id=?").bind(user.id)
  ]);
  return apiOk({ reset: true, message: "密码已重置，请重新登录" });
}

async function apiUserLogin(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const email = normalizeEmail(body.email);
  const password = String(body.password || "");
  if (!email || !password) return apiError("请输入邮箱和密码", 400);
  const captcha = await validateCaptchaForScene(env, request, body, "login");
  if (!captcha.ok) return apiError(captcha.error, captcha.status);
  if (await tooManyUserLoginFailures(env, request, email)) {
    await recordUserLogin(env, request, 0, email, "failed", "rate_limited");
    return apiError("登录失败次数过多，请稍后再试", 429);
  }
  const user = await env.DB.prepare("SELECT * FROM users WHERE email=?").bind(email).first<UserRow>();
  if (!user) {
    await hashPassword(password, "missing-user-salt");
    await recordUserLogin(env, request, 0, email, "failed", "user_not_found");
    return apiError("账号或密码错误", 401);
  }
  if (user.status !== "active") {
    await recordUserLogin(env, request, user.id, email, "failed", "disabled");
    return apiError("账号已被禁用", 403);
  }
  const passwordVerification = await verifyPassword(password, user.password_salt, user.password_hash);
  if (!passwordVerification.valid) {
    await recordUserLogin(env, request, user.id, email, "failed", "bad_password");
    return apiError("账号或密码错误", 401);
  }
  if (passwordVerification.needsUpgrade) {
    const upgradedSalt = randomToken().slice(0, 32);
    const upgradedHash = await hashPassword(password, upgradedSalt);
    await env.DB.prepare("UPDATE users SET password_salt=?, password_hash=?, updated_at=CURRENT_TIMESTAMP WHERE id=?")
      .bind(upgradedSalt, upgradedHash, user.id)
      .run();
  }
  if (user.totp_secret && user.totp_enabled_at) {
    const challenge = await createUserLoginChallenge(env, user.id);
    await recordUserLogin(env, request, user.id, email, "challenge", "totp_required");
    return apiOk({
      requires_totp: true,
      challenge_token: challenge.token,
      challenge_expires_at: challenge.expiresAt
    });
  }
  await env.DB.prepare("UPDATE users SET last_login_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=?")
    .bind(user.id)
    .run();
  await recordUserLogin(env, request, user.id, email, "success", "");
  const fresh = await getUserById(env, user.id);
  const session = await createUserSession(env, user.id);
  return apiOk({ token: session.token, user: formatUser(fresh || user), expires_at: session.expiresAt });
}

async function apiUserLoginVerify2FA(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const challengeToken = clean(body.challenge_token, 200);
  const code = clean(body.code, 20);
  const recoveryCode = clean(body.recovery_code, 80);
  if (!challengeToken) return apiError("二次验证挑战不存在，请重新登录", 400);
  if (!code && !recoveryCode) return apiError("请输入二次验证码或恢复码", 400);

  const tokenHash = await sha256Hex(challengeToken);
  const challenge = await env.DB.prepare(
    `SELECT c.id, c.user_id, c.token_hash, c.expires_at, c.created_at,
            u.email, u.totp_secret, u.totp_enabled_at
     FROM user_login_challenges c
     JOIN users u ON u.id=c.user_id
     WHERE c.token_hash=?`
  ).bind(tokenHash).first<UserLoginChallengeRow>();
  if (!challenge || new Date(challenge.expires_at).getTime() <= Date.now()) {
    if (challenge) await env.DB.prepare("DELETE FROM user_login_challenges WHERE id=?").bind(challenge.id).run();
    return apiError("二次验证已过期，请重新登录", 401);
  }
  if (!challenge.totp_secret || !challenge.totp_enabled_at) {
    await env.DB.prepare("DELETE FROM user_login_challenges WHERE id=?").bind(challenge.id).run();
    return apiError("该账号未启用 2FA", 400);
  }
  if (await tooManyUserLoginFailures(env, request, challenge.email || "")) {
    await recordUserLogin(env, request, challenge.user_id, challenge.email || "", "failed", "rate_limited");
    return apiError("验证失败次数过多，请稍后再试", 429);
  }
  const verified = recoveryCode
    ? await consumeUserRecoveryCode(env, challenge.user_id, recoveryCode)
    : await verifyTotpCode(challenge.totp_secret, code);
  if (!verified) {
    await recordUserLogin(env, request, challenge.user_id, challenge.email || "", "failed", recoveryCode ? "bad_recovery_code" : "bad_totp");
    return apiError("二次验证码或恢复码错误", 401);
  }

  await env.DB.prepare("DELETE FROM user_login_challenges WHERE id=?").bind(challenge.id).run();
  await env.DB.prepare("UPDATE users SET last_login_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=?")
    .bind(challenge.user_id)
    .run();
  await recordUserLogin(env, request, challenge.user_id, challenge.email || "", "success", recoveryCode ? "recovery_code" : "totp");
  const user = await getUserById(env, challenge.user_id);
  if (!user) return apiError("账号不存在", 404);
  const session = await createUserSession(env, challenge.user_id);
  return apiOk({ token: session.token, user: formatUser(user), expires_at: session.expiresAt });
}

async function apiUser2FAStatus(env: Env, userId: number): Promise<Response> {
  const user = await env.DB.prepare("SELECT id, email, totp_secret, totp_enabled_at FROM users WHERE id=?")
    .bind(userId)
    .first<UserRow>();
  if (!user) return apiError("账号不存在", 404);
  const total = await count(env, "SELECT COUNT(*) AS count FROM user_recovery_codes WHERE user_id=?", [userId]);
  const remaining = await count(env, "SELECT COUNT(*) AS count FROM user_recovery_codes WHERE user_id=? AND used_at IS NULL", [userId]);
  return apiOk({
    enabled: Boolean(user.totp_secret && user.totp_enabled_at),
    enabled_at: user.totp_enabled_at || null,
    recovery_codes_remaining: remaining,
    recovery_codes_total: total
  });
}

async function apiUser2FASetup(env: Env, user: UserRow): Promise<Response> {
  const current = await env.DB.prepare("SELECT id, email, totp_secret, totp_enabled_at FROM users WHERE id=?")
    .bind(user.id)
    .first<UserRow>();
  if (!current) return apiError("账号不存在", 404);
  if (current.totp_secret && current.totp_enabled_at) return apiError("2FA 已启用", 400);
  const secret = randomBase32Secret();
  const now = new Date().toISOString();
  const expiresAt = new Date(Date.now() + ADMIN_2FA_SETUP_TTL_MS).toISOString();
  await env.DB.prepare("DELETE FROM user_totp_setups WHERE user_id=? OR expires_at <= ?")
    .bind(user.id, now)
    .run();
  await env.DB.prepare("INSERT INTO user_totp_setups (user_id, secret, expires_at) VALUES (?, ?, ?)")
    .bind(user.id, secret, expiresAt)
    .run();
  const issuerName = await siteIssuerName(env);
  const issuer = encodeURIComponent(issuerName);
  const label = encodeURIComponent(`${issuerName}:${current.email}`);
  return apiOk({
    secret,
    otpauth_url: `otpauth://totp/${label}?secret=${secret}&issuer=${issuer}&digits=${TOTP_DIGITS}&period=${TOTP_STEP_SECONDS}`,
    expires_at: expiresAt
  });
}

async function apiUser2FAEnable(request: Request, env: Env, user: UserRow): Promise<Response> {
  const body = await readJson(request);
  const code = clean(body.code, 20);
  if (!/^\d{6}$/.test(code)) return apiError("请输入 6 位验证码", 400);
  const setup = await env.DB.prepare(
    "SELECT id, user_id, secret, expires_at FROM user_totp_setups WHERE user_id=? ORDER BY id DESC LIMIT 1"
  ).bind(user.id).first<{ id: number; user_id: number; secret: string; expires_at: string }>();
  if (!setup || new Date(setup.expires_at).getTime() <= Date.now()) {
    if (setup) await env.DB.prepare("DELETE FROM user_totp_setups WHERE id=?").bind(setup.id).run();
    return apiError("2FA 设置已过期，请重新生成二维码", 400);
  }
  if (!await verifyTotpCode(setup.secret, code)) return apiError("验证码错误", 400);
  const enabledAt = new Date().toISOString();
  const codes = await replaceUserRecoveryCodes(env, user.id);
  await env.DB.prepare("UPDATE users SET totp_secret=?, totp_enabled_at=?, updated_at=CURRENT_TIMESTAMP WHERE id=?")
    .bind(setup.secret, enabledAt, user.id)
    .run();
  await env.DB.prepare("DELETE FROM user_totp_setups WHERE user_id=?").bind(user.id).run();
  return apiOk({ enabled_at: enabledAt, recovery_codes: codes });
}

async function apiUser2FADisable(request: Request, env: Env, user: UserRow): Promise<Response> {
  const body = await readJson(request);
  const code = clean(body.code, 20);
  const recoveryCode = clean(body.recovery_code, 80);
  const current = await env.DB.prepare("SELECT id, email, totp_secret, totp_enabled_at FROM users WHERE id=?")
    .bind(user.id)
    .first<UserRow>();
  if (!current) return apiError("账号不存在", 404);
  if (!current.totp_secret || !current.totp_enabled_at) return apiOk({});
  const verified = recoveryCode
    ? await consumeUserRecoveryCode(env, user.id, recoveryCode)
    : await verifyTotpCode(current.totp_secret, code);
  if (!verified) return apiError("验证码或恢复码错误", 400);
  await env.DB.batch([
    env.DB.prepare("UPDATE users SET totp_secret='', totp_enabled_at=NULL, updated_at=CURRENT_TIMESTAMP WHERE id=?").bind(user.id),
    env.DB.prepare("DELETE FROM user_recovery_codes WHERE user_id=?").bind(user.id),
    env.DB.prepare("DELETE FROM user_totp_setups WHERE user_id=?").bind(user.id),
    env.DB.prepare("DELETE FROM user_login_challenges WHERE user_id=?").bind(user.id)
  ]);
  return apiOk({});
}

async function apiUser2FARegenerateRecoveryCodes(request: Request, env: Env, user: UserRow): Promise<Response> {
  const body = await readJson(request);
  const code = clean(body.code, 20);
  const current = await env.DB.prepare("SELECT id, email, totp_secret, totp_enabled_at FROM users WHERE id=?")
    .bind(user.id)
    .first<UserRow>();
  if (!current) return apiError("账号不存在", 404);
  if (!current.totp_secret || !current.totp_enabled_at) return apiError("2FA 未启用", 400);
  if (!await verifyTotpCode(current.totp_secret, code)) return apiError("验证码错误", 400);
  const codes = await replaceUserRecoveryCodes(env, user.id);
  return apiOk({ recovery_codes: codes });
}

