async function apiChangeUserEmail(request: Request, env: Env, user: UserRow): Promise<Response> {
  const body = await readJson(request);
  const email = normalizeEmail(body.new_email || body.email);
  if (!email) return apiError("邮箱格式不正确", 400);
  if (email !== user.email) {
    const exists = await env.DB.prepare("SELECT id FROM users WHERE email=? AND id<>?").bind(email, user.id).first<{ id: number }>();
    if (exists) return apiError("邮箱已被使用", 409);
    const oldVerification = await consumeEmailVerificationCode(env, user.email, "change_email_old", body.old_code);
    if (!oldVerification.ok) return apiError(oldVerification.error, oldVerification.status);
  }
  const newVerification = await consumeEmailVerificationCode(env, email, "change_email_new", body.new_code || body.code);
  if (!newVerification.ok) return apiError(newVerification.error, newVerification.status);
  await env.DB.prepare("UPDATE users SET email=?, email_verified_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP WHERE id=?")
    .bind(email, user.id)
    .run();
  const fresh = await getUserById(env, user.id);
  return apiOk(formatUser(fresh || user));
}

async function apiChangeUserPassword(request: Request, env: Env, user: UserRow): Promise<Response> {
  const body = await readJson(request);
  const newPassword = String(body.new_password || body.password || "");
  const oldPassword = String(body.old_password || body.current_password || "");
  if (newPassword.length < 6) return apiError("新密码至少 6 位", 400);
  if (user.password_hash) {
    if (!oldPassword) return apiError("请输入旧密码", 400);
    if (!(await verifyPassword(oldPassword, user.password_salt, user.password_hash)).valid) return apiError("旧密码错误", 400);
  }
  const salt = randomToken().slice(0, 16);
  const passwordHash = await hashPassword(newPassword, salt);
  await env.DB.prepare("UPDATE users SET password_salt=?, password_hash=?, updated_at=CURRENT_TIMESTAMP WHERE id=?")
    .bind(salt, passwordHash, user.id)
    .run();
  return apiOk({});
}

