async function apiUserWalletRechargeDetail(env: Env, userId: number, rechargeNo: string): Promise<Response> {
  let recharge = await getWalletRechargeByNo(env, rechargeNo, userId);
  if (!recharge) return apiError("充值订单不存在", 404);
  recharge = await expireWalletRechargeIfDue(env, recharge);
  const payment = recharge.payment_id ? await paymentByIdWithContext(env, recharge.payment_id) : null;
  return apiOk(formatWalletRechargePaymentPayload(recharge, payment, await ensureWallet(env, userId)));
}

async function apiUserCaptureWalletRechargePayment(env: Env, user: UserRow, paymentId: number): Promise<Response> {
  if (!Number.isFinite(paymentId) || paymentId <= 0) return apiError("支付记录不存在", 404);
  let recharge = await getWalletRechargeByPaymentId(env, paymentId, user.id);
  if (!recharge) return apiError("充值订单不存在", 404);
  recharge = await expireWalletRechargeIfDue(env, recharge);
  let payment = await paymentByIdWithContext(env, paymentId);
  if (!payment) return apiError("支付记录不存在", 404);
  if (payment.status !== "success" && ["official:stripe", "official:paypal", "official:wechat"].includes(paymentProviderKey(payment.provider_type, payment.channel_type))) {
    const queried = await queryOfficialPayment(env, payment);
    if (!queried.ok) return apiError(queried.error, queried.statusCode);
    const verified = verifyQueriedPaymentAgainstRecord(payment, queried);
    if (!verified.ok) return apiError(verified.error, 409);
    await applyVerifiedPaymentCallback(env, payment, verified.callback);
    payment = await paymentByIdWithContext(env, paymentId) || payment;
  }
  if (payment.status === "success" && recharge.status !== "success") {
    await applyWalletRechargeSuccess(env, payment, recharge, {});
    payment = await paymentByIdWithContext(env, paymentId) || payment;
  }
  const fresh = await getWalletRechargeByNo(env, recharge.recharge_no, user.id) || recharge;
  return apiOk(formatWalletRechargePaymentPayload(fresh, payment, await ensureWallet(env, user.id)));
}

async function apiRedeemGiftCard(request: Request, env: Env, user: UserRow): Promise<Response> {
  const body = await readJson(request);
  const captcha = await validateCaptchaForScene(env, request, body, "gift_card_redeem");
  if (!captcha.ok) return apiError(captcha.error, captcha.status);
  const code = clean(body.code, 120).toUpperCase();
  if (!code) return apiError("请输入礼品卡卡密", 400);
  const card = await env.DB.prepare("SELECT * FROM gift_cards WHERE code=?").bind(code).first<GiftCardRow>();
  if (!card) return apiError("礼品卡不存在", 404);
  if (card.status === "redeemed" || card.redeemed_at) {
    const existingTransaction = await giftCardWalletTransaction(env, card.id);
    if (Number(card.redeemed_user_id || 0) === user.id && existingTransaction) {
      if (!card.wallet_txn_id) {
        await env.DB.prepare("UPDATE gift_cards SET wallet_txn_id=?, updated_at=CURRENT_TIMESTAMP WHERE id=? AND wallet_txn_id IS NULL")
          .bind(existingTransaction.id, card.id)
          .run();
      }
      return giftCardRedeemResponse(env, card.id, Number(card.amount || 0));
    }
    return apiError("礼品卡已使用", 409);
  }
  if (card.status !== "active") return apiError("礼品卡已禁用", 409);
  if (card.expires_at && new Date(card.expires_at).getTime() < Date.now()) return apiError("礼品卡已过期", 400);
  if (moneyToCents(Number(card.amount || 0)) <= 0) return apiError("礼品卡金额不合法", 400);

  const atomicTriggerEnabled = await runtimeFlag(env, "atomic_gift_card_redeem_enabled");

  const claimed = await env.DB.prepare(
    "UPDATE gift_cards SET status='redeemed', redeemed_at=CURRENT_TIMESTAMP, redeemed_user_id=?, updated_at=CURRENT_TIMESTAMP WHERE id=? AND status='active' AND redeemed_at IS NULL"
  ).bind(user.id, card.id).run();
  if (!claimed.meta.changes) return apiError("礼品卡已被兑换", 409);

  if (!atomicTriggerEnabled) {
    try {
      const transaction = await adjustWalletBalance(env, user.id, Number(card.amount || 0), "in", {
        type: "gift_card",
        reference: `GIFT:${card.id}`,
        remark: `礼品卡兑换 ${card.code}`,
        relatedType: "gift_card",
        relatedId: card.id
      });
      if (!transaction) throw new Error("gift_card_wallet_credit_failed");
      await env.DB.prepare(
        "UPDATE gift_cards SET wallet_txn_id=COALESCE(wallet_txn_id, ?), updated_at=CURRENT_TIMESTAMP WHERE id=?"
      ).bind(transaction.id, card.id).run();
    } catch (error) {
      const credited = await giftCardWalletTransaction(env, card.id);
      if (!credited) {
        await env.DB.prepare(
          `UPDATE gift_cards
           SET status='active', redeemed_at=NULL, redeemed_user_id=NULL, updated_at=CURRENT_TIMESTAMP
           WHERE id=? AND status='redeemed' AND redeemed_user_id=? AND wallet_txn_id IS NULL`
        ).bind(card.id, user.id).run();
      }
      throw error;
    }
  }
  return giftCardRedeemResponse(env, card.id, Number(card.amount || 0));
}

async function giftCardWalletTransaction(env: Env, cardId: number): Promise<WalletTransactionRow | null> {
  return env.DB.prepare(
    `SELECT * FROM wallet_transactions
     WHERE type='gift_card' AND related_type='gift_card' AND related_id=?
     ORDER BY id ASC LIMIT 1`
  ).bind(cardId).first<WalletTransactionRow>();
}

async function giftCardRedeemResponse(env: Env, cardId: number, amount: number): Promise<Response> {
  const freshCard = await env.DB.prepare("SELECT * FROM gift_cards WHERE id=?").bind(cardId).first<GiftCardRow>();
  if (!freshCard?.redeemed_user_id) return apiError("礼品卡兑换失败", 500);
  const wallet = await ensureWallet(env, freshCard.redeemed_user_id);
  const transaction = freshCard.wallet_txn_id
    ? await env.DB.prepare("SELECT * FROM wallet_transactions WHERE id=?")
      .bind(freshCard.wallet_txn_id)
      .first<WalletTransactionRow>()
    : await giftCardWalletTransaction(env, cardId);
  return apiOk({
    gift_card: formatGiftCard(freshCard),
    wallet: formatWalletAccount(wallet),
    transaction: transaction ? formatWalletTransaction(transaction) : null,
    wallet_delta: money(amount)
  });
}

