async function apiUserAffiliateEndpoint(request: Request, env: Env, method: string, path: string, url: URL, user: UserRow): Promise<Response> {
  if (method === "POST" && path === "/affiliate/open") return apiUserOpenAffiliate(env, user);
  if (method === "GET" && path === "/affiliate/dashboard") return apiUserAffiliateDashboard(env, user.id);
  if (method === "GET" && path === "/affiliate/commissions") return apiUserAffiliateCommissions(env, url, user.id);
  if (method === "GET" && path === "/affiliate/withdraws") return apiUserAffiliateWithdraws(env, url, user.id);
  if (method === "POST" && path === "/affiliate/withdraws") return apiUserCreateAffiliateWithdraw(request, env, user.id);
  return apiError("not_found", 404);
}

async function apiUserOpenAffiliate(env: Env, user: UserRow): Promise<Response> {
  const settings = await affiliateSettings(env);
  if (settings.enabled !== true) return apiError("返利功能未启用", 400);
  const profile = await ensureAffiliateProfile(env, user.id);
  await recalculateAffiliateProfile(env, profile.id);
  return apiOk({ opened: true, ...await affiliateDashboardPayload(env, profile.id) });
}

async function apiUserAffiliateDashboard(env: Env, userId: number): Promise<Response> {
  await confirmDueAffiliateCommissions(env);
  const profile = await getAffiliateProfileByUser(env, userId);
  if (!profile) {
    return apiOk({
      opened: false,
      affiliate_code: "",
      promotion_path: "",
      click_count: 0,
      valid_order_count: 0,
      conversion_rate: 0,
      pending_commission: "0.00",
      available_commission: "0.00",
      withdrawn_commission: "0.00"
    });
  }
  await reconcileAffiliateWithdrawAllocations(env, Number(profile.id || 0));
  return apiOk({ opened: true, ...await affiliateDashboardPayload(env, profile.id) });
}

async function apiUserAffiliateCommissions(env: Env, url: URL, userId: number): Promise<Response> {
  await confirmDueAffiliateCommissions(env);
  const profile = await getAffiliateProfileByUser(env, userId);
  if (!profile) return apiOk([], paginationFromTotal(url, 0));
  await reconcileAffiliateWithdrawAllocations(env, Number(profile.id || 0));
  const { page, size, offset } = paging(url);
  const total = await count(env, "SELECT COUNT(*) AS count FROM affiliate_commissions WHERE affiliate_profile_id=?", [profile.id]);
  const rows = await env.DB.prepare(
    `SELECT * FROM affiliate_commissions
     WHERE affiliate_profile_id=?
     ORDER BY id DESC LIMIT ? OFFSET ?`
  ).bind(profile.id, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map(formatAffiliateCommission), pagination(page, size, total));
}

async function apiUserAffiliateWithdraws(env: Env, url: URL, userId: number): Promise<Response> {
  const profile = await getAffiliateProfileByUser(env, userId);
  if (!profile) return apiOk([], paginationFromTotal(url, 0));
  await reconcileAffiliateWithdrawAllocations(env, Number(profile.id || 0));
  const { page, size, offset } = paging(url);
  const total = await count(env, "SELECT COUNT(*) AS count FROM affiliate_withdraws WHERE affiliate_profile_id=?", [profile.id]);
  const rows = await env.DB.prepare(
    `SELECT * FROM affiliate_withdraws
     WHERE affiliate_profile_id=?
     ORDER BY id DESC LIMIT ? OFFSET ?`
  ).bind(profile.id, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map(formatAffiliateWithdraw), pagination(page, size, total));
}

async function apiUserCreateAffiliateWithdraw(request: Request, env: Env, userId: number): Promise<Response> {
  const profile = await getAffiliateProfileByUser(env, userId);
  if (!profile || profile.status !== "active") return apiError("返利账户未开通或已禁用", 400);
  const body = await readJson(request);
  const amount = Number(money(Math.max(0, numberValue(body.amount, 0))));
  const channel = clean(body.channel, 80);
  const account = clean(body.account, 500);
  if (amount <= 0) return apiError("提现金额不正确", 400);
  if (!channel) return apiError("提现渠道不能为空", 400);
  if (!account) return apiError("提现账号不能为空", 400);
  const settings = await affiliateSettings(env);
  if (settings.enabled !== true) return apiError("返利功能未启用", 400);
  const minAmount = Math.max(0, numberValue(settings.min_withdraw_amount, 0));
  if (minAmount > 0 && amount < minAmount) return apiError(`最低提现金额为 ${money(minAmount)}`, 400);
  const allowedChannels = normalizeStringArray(settings.withdraw_channels).map((item) => item.toLowerCase());
  if (allowedChannels.length && !allowedChannels.includes(channel.toLowerCase())) return apiError("提现渠道未启用", 400);
  await confirmDueAffiliateCommissions(env);
  await reconcileAffiliateWithdrawAllocations(env, Number(profile.id || 0));
  const available = await affiliateAvailableAmount(env, profile.id);
  if (moneyToCents(amount) > moneyToCents(available)) return apiError("可提现佣金不足", 400);
  let result: D1Result;
  try {
    result = await env.DB.prepare(
      "INSERT INTO affiliate_withdraws (affiliate_profile_id, amount, channel, account_info) VALUES (?, ?, ?, ?)"
    ).bind(profile.id, money(amount), channel, account).run();
  } catch (error) {
    if (databaseErrorIncludes(error, "affiliate_withdraw_insufficient")) return apiError("可提现佣金不足", 409);
    if (databaseErrorIncludes(error, "affiliate_withdraw_amount_invalid")) return apiError("提现金额不正确", 400);
    throw error;
  }
  try {
    await bindAffiliateCommissionsToWithdraw(env, profile.id, Number(result.meta.last_row_id), amount);
  } catch (error) {
    await env.DB.batch([
      env.DB.prepare(
        "UPDATE affiliate_commissions SET withdraw_request_id=NULL, updated_at=CURRENT_TIMESTAMP WHERE withdraw_request_id=?"
      ).bind(Number(result.meta.last_row_id)),
      env.DB.prepare(
        "UPDATE affiliate_withdraws SET status='rejected', reject_reason='commission_allocation_failed', updated_at=CURRENT_TIMESTAMP WHERE id=? AND status='pending_review'"
      ).bind(Number(result.meta.last_row_id))
    ]);
    throw error;
  }
  await recalculateAffiliateProfile(env, profile.id);
  const row = await env.DB.prepare("SELECT * FROM affiliate_withdraws WHERE id=?").bind(result.meta.last_row_id).first<AnyRecord>();
  return apiOk(row ? formatAffiliateWithdraw(row) : {});
}

async function createAffiliateCommissionForOrder(
  env: Env,
  orderId: number,
  orderNo: string,
  items: CalculatedOrderItem[],
  body: AnyRecord,
  buyerUserId: number
): Promise<void> {
  const code = clean(body.affiliate_code || body.aff || body.ref, 80);
  if (!code) return;
  const settings = await affiliateSettings(env);
  if (settings.enabled !== true) return;
  const profile = await env.DB.prepare("SELECT * FROM affiliate_profiles WHERE code=? AND status='active'")
    .bind(code)
    .first<AnyRecord>();
  if (!profile || Number(profile.user_id || 0) === buyerUserId) return;
  const eligibleAmount = items
    .filter((item) => Number(item.product.is_affiliate_enabled || 0) === 1)
    .reduce((sum, item) => sum + Math.max(0, item.lineTotal - item.couponDiscountAmount), 0);
  if (eligibleAmount <= 0) return;
  const rate = Math.max(0, numberValue(settings.commission_rate, 0));
  const commission = Number(money(eligibleAmount * rate / 100));
  if (commission <= 0) return;
  const confirmDays = Math.max(0, toInt(settings.confirm_days, 0));
  const now = new Date();
  const status = confirmDays > 0 ? "pending_confirm" : "available";
  const confirmAt = confirmDays > 0 ? addDays(now, confirmDays).toISOString() : null;
  const availableAt = confirmDays > 0 ? null : now.toISOString();
  await env.DB.batch([
    env.DB.prepare(
      `UPDATE orders
       SET affiliate_profile_id=?, affiliate_code=?, affiliate_visitor_key=?, updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    ).bind(Number(profile.id), code, clean(body.affiliate_visitor_key, 160), orderId),
    env.DB.prepare(
      `INSERT OR IGNORE INTO affiliate_commissions (
        affiliate_profile_id, order_id, order_no, base_amount, rate_percent, commission_amount,
        status, confirm_at, available_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
    ).bind(Number(profile.id), orderId, orderNo, money(eligibleAmount), money(rate), money(commission), status, confirmAt, availableAt)
  ]);
  await recalculateAffiliateProfile(env, Number(profile.id));
}

async function confirmDueAffiliateCommissions(env: Env): Promise<number> {
  const due = await env.DB.prepare(
    `SELECT DISTINCT affiliate_profile_id
     FROM affiliate_commissions
     WHERE status='pending_confirm' AND confirm_at IS NOT NULL AND confirm_at<=CURRENT_TIMESTAMP`
  ).all<{ affiliate_profile_id: number }>();
  if (!(due.results || []).length) return 0;
  const updated = await env.DB.prepare(
    `UPDATE affiliate_commissions
     SET status='available', available_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP
     WHERE status='pending_confirm' AND confirm_at IS NOT NULL AND confirm_at<=CURRENT_TIMESTAMP`
  ).run();
  for (const row of due.results || []) {
    await recalculateAffiliateProfile(env, Number(row.affiliate_profile_id || 0));
  }
  return Number(updated.meta.changes || 0);
}

async function bindAffiliateCommissionsToWithdraw(
  env: Env,
  profileId: number,
  withdrawId: number,
  amount: number
): Promise<void> {
  let remainingCents = moneyToCents(amount);
  const rows = await env.DB.prepare(
    `SELECT * FROM affiliate_commissions
     WHERE affiliate_profile_id=? AND status='available' AND withdraw_request_id IS NULL
     ORDER BY id ASC`
  ).bind(profileId).all<AnyRecord>();
  for (const row of rows.results || []) {
    if (remainingCents <= 0) break;
    const rowCents = moneyToCents(Number(row.commission_amount || 0));
    if (rowCents <= 0) continue;
    if (rowCents <= remainingCents) {
      const updated = await env.DB.prepare(
        `UPDATE affiliate_commissions
         SET withdraw_request_id=?, updated_at=CURRENT_TIMESTAMP
         WHERE id=? AND status='available' AND withdraw_request_id IS NULL`
      ).bind(withdrawId, Number(row.id)).run();
      if (!updated.meta.changes) throw new ApiRequestError(409, "可提现佣金已变化，请重试");
      remainingCents -= rowCents;
      continue;
    }

    const boundAmount = centsToMoney(remainingCents);
    const remainderAmount = centsToMoney(rowCents - remainingCents);
    const splitType = (`sp${Number(row.id).toString(36)}${randomToken().replace(/[^a-z0-9]/gi, "").slice(0, 10)}`).slice(0, 20);
    const updated = await env.DB.prepare(
      `UPDATE affiliate_commissions
       SET commission_amount=?, withdraw_request_id=?, updated_at=CURRENT_TIMESTAMP
       WHERE id=? AND status='available' AND withdraw_request_id IS NULL`
    ).bind(money(boundAmount), withdrawId, Number(row.id)).run();
    if (!updated.meta.changes) throw new ApiRequestError(409, "可提现佣金已变化，请重试");
    await env.DB.prepare(
      `INSERT INTO affiliate_commissions (
        affiliate_profile_id, order_id, order_item_id, order_no, commission_type,
        base_amount, rate_percent, commission_amount, status, confirm_at,
        available_at, withdrawn_at, invalid_reason, created_at, updated_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'available', ?, ?, ?, '', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`
    ).bind(
      profileId,
      Number(row.order_id || 0),
      row.order_item_id ? Number(row.order_item_id) : null,
      clean(row.order_no, 80),
      splitType,
      money(Number(row.base_amount || 0)),
      money(Number(row.rate_percent || 0)),
      money(remainderAmount),
      row.confirm_at || null,
      row.available_at || new Date().toISOString(),
      row.withdrawn_at || null
    ).run();
    remainingCents = 0;
  }
  if (remainingCents > 0) throw new ApiRequestError(409, "可提现佣金不足");
}

async function reconcileAffiliateWithdrawAllocations(env: Env, profileId = 0): Promise<number> {
  const params: unknown[] = [];
  let where = "WHERE withdraw.status IN ('pending_review','paid')";
  if (profileId > 0) {
    where += " AND withdraw.affiliate_profile_id=?";
    params.push(profileId);
  }
  where += ` AND NOT EXISTS (
    SELECT 1 FROM affiliate_commissions commission WHERE commission.withdraw_request_id=withdraw.id
  )`;
  const rows = await env.DB.prepare(
    `SELECT withdraw.* FROM affiliate_withdraws withdraw ${where} ORDER BY withdraw.id ASC`
  ).bind(...params).all<AnyRecord>();
  let reconciled = 0;
  const touchedProfiles = new Set<number>();
  for (const row of rows.results || []) {
    try {
      await bindAffiliateCommissionsToWithdraw(
        env,
        Number(row.affiliate_profile_id || 0),
        Number(row.id || 0),
        Number(row.amount || 0)
      );
      if (row.status === "paid") {
        await env.DB.prepare(
          `UPDATE affiliate_commissions
           SET status='withdrawn', withdrawn_at=COALESCE(withdrawn_at, ?), updated_at=CURRENT_TIMESTAMP
           WHERE withdraw_request_id=? AND status='available'`
        ).bind(row.processed_at || row.updated_at || new Date().toISOString(), Number(row.id || 0)).run();
      }
      touchedProfiles.add(Number(row.affiliate_profile_id || 0));
      reconciled++;
    } catch (error) {
      console.error("affiliate withdraw reconciliation failed", Number(row.id || 0), error);
    }
  }
  for (const id of touchedProfiles) await recalculateAffiliateProfile(env, id);
  return reconciled;
}

async function apiAdminAffiliateUsers(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const keyword = clean(url.searchParams.get("keyword") || url.searchParams.get("search"), 120);
  const status = clean(url.searchParams.get("status"), 40);
  if (keyword) {
    where += " AND (ap.code LIKE ? OR u.email LIKE ? OR u.display_name LIKE ?)";
    params.push(`%${keyword}%`, `%${keyword}%`, `%${keyword}%`);
  }
  if (status && status !== "__all__") {
    where += " AND ap.status=?";
    params.push(status);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM affiliate_profiles ap LEFT JOIN users u ON u.id=ap.user_id ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT ap.*, u.email AS user_email, u.display_name AS user_display_name,
            COALESCE((SELECT COUNT(*) FROM affiliate_clicks c WHERE c.affiliate_profile_id=ap.id), 0) AS click_count,
            COALESCE((SELECT COUNT(*) FROM affiliate_commissions ac WHERE ac.affiliate_profile_id=ap.id), 0) AS valid_order_count
     FROM affiliate_profiles ap LEFT JOIN users u ON u.id=ap.user_id
     ${where}
     ORDER BY ap.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map(formatAdminAffiliateProfile), pagination(page, size, total));
}

async function apiAdminUpdateAffiliateProfileStatus(request: Request, env: Env, id: number): Promise<Response> {
  const body = await readJson(request);
  const status = clean(body.status, 40) === "disabled" ? "disabled" : "active";
  await env.DB.prepare("UPDATE affiliate_profiles SET status=?, updated_at=CURRENT_TIMESTAMP WHERE id=?").bind(status, id).run();
  await recalculateAffiliateProfile(env, id);
  const row = await env.DB.prepare(
    `SELECT ap.*, u.email AS user_email, u.display_name AS user_display_name
     FROM affiliate_profiles ap LEFT JOIN users u ON u.id=ap.user_id WHERE ap.id=?`
  ).bind(id).first<AnyRecord>();
  return row ? apiOk(formatAdminAffiliateProfile(row)) : apiError("返利用户不存在", 404);
}

async function apiAdminBatchUpdateAffiliateProfileStatus(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const ids = arrayNumbers(body.profile_ids || body.ids);
  const status = clean(body.status, 40) === "disabled" ? "disabled" : "active";
  let success = 0;
  for (const chunk of chunkNumbers(ids, 100)) {
    if (!chunk.length) continue;
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(`UPDATE affiliate_profiles SET status=?, updated_at=CURRENT_TIMESTAMP WHERE id IN (${placeholders})`)
      .bind(status, ...chunk)
      .run();
    success += Number(result.meta.changes || 0);
  }
  return apiOk({ success_count: success });
}

async function apiAdminAffiliateCommissions(env: Env, url: URL): Promise<Response> {
  await confirmDueAffiliateCommissions(env);
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const status = clean(url.searchParams.get("status"), 40);
  const orderNo = clean(url.searchParams.get("order_no"), 80);
  const profileId = toInt(url.searchParams.get("affiliate_profile_id"), 0);
  if (status && status !== "__all__") {
    where += " AND ac.status=?";
    params.push(status);
  }
  if (orderNo) {
    where += " AND ac.order_no LIKE ?";
    params.push(`%${orderNo}%`);
  }
  if (profileId > 0) {
    where += " AND ac.affiliate_profile_id=?";
    params.push(profileId);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM affiliate_commissions ac ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT ac.*, ap.user_id, ap.code AS affiliate_code, u.email AS user_email, u.display_name AS user_display_name,
            o.order_no AS joined_order_no, o.total_amount AS order_total_amount
     FROM affiliate_commissions ac
     LEFT JOIN affiliate_profiles ap ON ap.id=ac.affiliate_profile_id
     LEFT JOIN users u ON u.id=ap.user_id
     LEFT JOIN orders o ON o.id=ac.order_id
     ${where}
     ORDER BY ac.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map(formatAffiliateCommission), pagination(page, size, total));
}

async function apiAdminAffiliateWithdraws(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const status = clean(url.searchParams.get("status"), 40);
  const keyword = clean(url.searchParams.get("keyword"), 120);
  const profileId = toInt(url.searchParams.get("affiliate_profile_id"), 0);
  if (status && status !== "__all__") {
    where += " AND aw.status=?";
    params.push(status);
  }
  if (keyword) {
    where += " AND (aw.channel LIKE ? OR aw.account_info LIKE ? OR ap.code LIKE ? OR u.email LIKE ?)";
    params.push(`%${keyword}%`, `%${keyword}%`, `%${keyword}%`, `%${keyword}%`);
  }
  if (profileId > 0) {
    where += " AND aw.affiliate_profile_id=?";
    params.push(profileId);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM affiliate_withdraws aw LEFT JOIN affiliate_profiles ap ON ap.id=aw.affiliate_profile_id LEFT JOIN users u ON u.id=ap.user_id ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT aw.*, ap.user_id, ap.code AS affiliate_code, u.email AS user_email, u.display_name AS user_display_name,
            a.username AS processor_username
     FROM affiliate_withdraws aw
     LEFT JOIN affiliate_profiles ap ON ap.id=aw.affiliate_profile_id
     LEFT JOIN users u ON u.id=ap.user_id
     LEFT JOIN admins a ON a.id=aw.processed_by
     ${where}
     ORDER BY aw.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map(formatAffiliateWithdraw), pagination(page, size, total));
}

async function apiAdminRejectAffiliateWithdraw(request: Request, env: Env, id: number, adminId: number): Promise<Response> {
  const body = await readJson(request);
  const row = await env.DB.prepare("SELECT * FROM affiliate_withdraws WHERE id=?").bind(id).first<AnyRecord>();
  if (!row) return apiError("提现申请不存在", 404);
  if (row.status !== "pending_review") return apiError("当前状态不可驳回", 400);
  const updated = await env.DB.prepare(
    `UPDATE affiliate_withdraws
     SET status='rejected', reject_reason=?, processed_by=?, processed_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND status='pending_review'`
  ).bind(clean(body.reason, 500), adminId, id).run();
  if (!updated.meta.changes) return apiError("当前状态已变更，请刷新后重试", 409);
  await env.DB.prepare(
    "UPDATE affiliate_commissions SET withdraw_request_id=NULL, updated_at=CURRENT_TIMESTAMP WHERE withdraw_request_id=?"
  ).bind(id).run();
  await recalculateAffiliateProfile(env, Number(row.affiliate_profile_id));
  const fresh = await env.DB.prepare("SELECT * FROM affiliate_withdraws WHERE id=?").bind(id).first<AnyRecord>();
  return apiOk(formatAffiliateWithdraw(fresh || row));
}

async function apiAdminPayAffiliateWithdraw(env: Env, id: number, adminId: number): Promise<Response> {
  const row = await env.DB.prepare("SELECT * FROM affiliate_withdraws WHERE id=?").bind(id).first<AnyRecord>();
  if (!row) return apiError("提现申请不存在", 404);
  if (row.status !== "pending_review") return apiError("当前状态不可打款", 400);
  const updated = await env.DB.prepare(
    `UPDATE affiliate_withdraws
     SET status='paid', processed_by=?, processed_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND status='pending_review'`
  ).bind(adminId, id).run();
  if (!updated.meta.changes) return apiError("当前状态已变更，请刷新后重试", 409);
  await env.DB.prepare(
    `UPDATE affiliate_commissions
     SET status='withdrawn', withdrawn_at=CURRENT_TIMESTAMP, updated_at=CURRENT_TIMESTAMP
     WHERE withdraw_request_id=? AND status='available'`
  ).bind(id).run();
  await recalculateAffiliateProfile(env, Number(row.affiliate_profile_id));
  const fresh = await env.DB.prepare("SELECT * FROM affiliate_withdraws WHERE id=?").bind(id).first<AnyRecord>();
  return apiOk(formatAffiliateWithdraw(fresh || row));
}

async function ensureAffiliateProfile(env: Env, userId: number): Promise<AnyRecord> {
  const existing = await getAffiliateProfileByUser(env, userId);
  if (existing) return existing;
  let code = "";
  for (let index = 0; index < 5; index += 1) {
    code = `U${userId}${randomToken().slice(0, 6).toUpperCase()}`.replace(/[^A-Z0-9]/g, "");
    const exists = await env.DB.prepare("SELECT id FROM affiliate_profiles WHERE code=?").bind(code).first<{ id: number }>();
    if (!exists) break;
  }
  await env.DB.prepare("INSERT INTO affiliate_profiles (user_id, code, status) VALUES (?, ?, 'active')")
    .bind(userId, code)
    .run();
  return await getAffiliateProfileByUser(env, userId) || { id: 0, user_id: userId, code, status: "active" };
}

async function getAffiliateProfileByUser(env: Env, userId: number): Promise<AnyRecord | null> {
  return env.DB.prepare("SELECT * FROM affiliate_profiles WHERE user_id=?").bind(userId).first<AnyRecord>();
}

async function affiliateDashboardPayload(env: Env, profileId: number): Promise<AnyRecord> {
  const profile = await env.DB.prepare("SELECT * FROM affiliate_profiles WHERE id=?").bind(profileId).first<AnyRecord>();
  if (!profile) return { opened: false };
  const clickCount = await count(env, "SELECT COUNT(*) AS count FROM affiliate_clicks WHERE affiliate_profile_id=? OR affiliate_code=?", [profileId, profile.code]);
  const validOrderCount = await count(env, "SELECT COUNT(DISTINCT order_id) AS count FROM affiliate_commissions WHERE affiliate_profile_id=? AND status<>'rejected'", [profileId]);
  const pending = await sumNumber(env, "SELECT COALESCE(SUM(commission_amount),0) AS value FROM affiliate_commissions WHERE affiliate_profile_id=? AND status='pending_confirm'", [profileId]);
  const available = await affiliateAvailableAmount(env, profileId);
  const withdrawn = await sumNumber(env, "SELECT COALESCE(SUM(amount),0) AS value FROM affiliate_withdraws WHERE affiliate_profile_id=? AND status='paid'", [profileId]);
  return {
    affiliate_code: profile.code || "",
    promotion_path: `/?aff=${encodeURIComponent(profile.code || "")}`,
    click_count: clickCount,
    valid_order_count: validOrderCount,
    conversion_rate: clickCount > 0 ? Number((validOrderCount / clickCount * 100).toFixed(2)) : 0,
    pending_commission: money(pending),
    available_commission: money(available),
    withdrawn_commission: money(withdrawn)
  };
}

async function affiliateAvailableAmount(env: Env, profileId: number): Promise<number> {
  const available = await sumNumber(
    env,
    "SELECT COALESCE(SUM(commission_amount),0) AS value FROM affiliate_commissions WHERE affiliate_profile_id=? AND status='available' AND withdraw_request_id IS NULL",
    [profileId]
  );
  return Math.max(0, centsToMoney(moneyToCents(available)));
}

async function recalculateAffiliateProfile(env: Env, profileId: number): Promise<void> {
  if (!profileId) return;
  const total = await sumNumber(env, "SELECT COALESCE(SUM(commission_amount),0) AS value FROM affiliate_commissions WHERE affiliate_profile_id=? AND status<>'rejected'", [profileId]);
  const pending = await sumNumber(env, "SELECT COALESCE(SUM(commission_amount),0) AS value FROM affiliate_commissions WHERE affiliate_profile_id=? AND status='pending_confirm'", [profileId]);
  const available = await affiliateAvailableAmount(env, profileId);
  const withdrawn = await sumNumber(env, "SELECT COALESCE(SUM(amount),0) AS value FROM affiliate_withdraws WHERE affiliate_profile_id=? AND status='paid'", [profileId]);
  const referrals = await count(env, "SELECT COUNT(DISTINCT order_id) AS count FROM affiliate_commissions WHERE affiliate_profile_id=? AND status<>'rejected'", [profileId]);
  await env.DB.prepare(
    `UPDATE affiliate_profiles
     SET total_earnings=?, pending_earnings=?, confirmed_earnings=?, withdrawn_earnings=?, total_referrals=?,
         updated_at=CURRENT_TIMESTAMP
     WHERE id=?`
  ).bind(money(total), money(pending), money(available), money(withdrawn), referrals, profileId).run();
}

async function sumNumber(env: Env, sql: string, params: unknown[]): Promise<number> {
  const row = await env.DB.prepare(sql).bind(...params).first<{ value: number }>();
  return Number(row?.value || 0);
}

