async function upsertResellerSiteConfig(env: Env, resellerId: number, body: AnyRecord): Promise<void> {
  const siteName = clean(body.site_name, 160);
  const logo = clean(body.logo, 500);
  const favicon = clean(body.favicon, 500);
  const announcement = jsonObject(body.announcement);
  const support = jsonObject(body.support);
  const seo = jsonObject(body.seo);
  const navConfig = jsonObject(body.nav_config);
  await env.DB.prepare(
    `INSERT INTO reseller_site_configs (
      reseller_id, site_name, logo, favicon, announcement_json, support_json, seo_json, footer_links_json, nav_config_json
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(reseller_id) DO UPDATE SET
      site_name=excluded.site_name, logo=excluded.logo, favicon=excluded.favicon,
      announcement_json=excluded.announcement_json, support_json=excluded.support_json,
      seo_json=excluded.seo_json, footer_links_json=excluded.footer_links_json,
      nav_config_json=excluded.nav_config_json, updated_at=CURRENT_TIMESTAMP`
  ).bind(
    resellerId,
    siteName,
    logo,
    favicon,
    JSON.stringify({
      enabled: announcement.enabled === true,
      type: clean(announcement.type, 40) || "notice",
      title: normalizeLocalizedText(announcement.title, ""),
      content: normalizeLocalizedHtml(announcement.content, "")
    }),
    JSON.stringify({
      telegram: clean(support.telegram, 255),
      whatsapp: clean(support.whatsapp, 255),
      email: clean(support.email, 255),
      support_url: clean(support.support_url, 500)
    }),
    JSON.stringify({
      title: normalizeLocalizedText(seo.title, ""),
      keywords: normalizeLocalizedText(seo.keywords, ""),
      description: normalizeLocalizedText(seo.description, ""),
      default_og_image: clean(seo.default_og_image, 500)
    }),
    JSON.stringify(Array.isArray(body.footer_links) ? body.footer_links.slice(0, 20) : []),
    JSON.stringify({
      builtin: jsonObject(navConfig.builtin),
      custom_items: Array.isArray(navConfig.custom_items) ? navConfig.custom_items.slice(0, 20) : []
    })
  ).run();
}

async function resellerProductSettingDetail(env: Env, profile: AnyRecord, productId: number): Promise<AnyRecord | null> {
  const product = await env.DB.prepare("SELECT * FROM products WHERE id=?").bind(productId).first<ProductRow>();
  if (!product) return null;
  const skus = await env.DB.prepare("SELECT * FROM product_skus WHERE product_id=? ORDER BY sort_order ASC, id ASC")
    .bind(productId).all<SkuRow>();
  const settings = await env.DB.prepare("SELECT * FROM reseller_product_settings WHERE reseller_id=? AND product_id=?")
    .bind(profile.id, productId).all<AnyRecord>();
  const bySku = new Map<number, AnyRecord>();
  for (const setting of settings.results || []) bySku.set(Number(setting.sku_id || 0), setting);
  const productRule = bySku.get(0);
  const productPayload = {
    id: product.id,
    slug: product.slug,
    title: jsonParse(product.title_json, {}),
    price_amount: money(Number(product.price_amount || 0)),
    is_active: Boolean(product.is_active)
  };
  const productSetting = formatResellerProductSetting(
    productRule || {
      reseller_id: profile.id,
      product_id: product.id,
      sku_id: 0,
      is_listed: true,
      pricing_mode: "inherit",
      markup_percent: 0,
      fixed_markup_amount: 0,
      fixed_price_amount: 0,
      sort_order: product.sort_order
    },
    Number(product.price_amount || 0),
    profile
  );
  return {
    product: productPayload,
    product_setting: productSetting,
    skus: (skus.results || []).map((sku) => {
      const skuRule = bySku.get(sku.id);
      const rule = skuRule || productRule || {
        reseller_id: profile.id,
        product_id: product.id,
        sku_id: sku.id,
        is_listed: true,
        pricing_mode: "inherit",
        markup_percent: 0,
        fixed_markup_amount: 0,
        fixed_price_amount: 0,
        sort_order: sku.sort_order
      };
      return {
        id: sku.id,
        sku_code: sku.sku_code,
        spec_values: jsonParse(sku.spec_values_json, {}),
        base_price_amount: money(Number(sku.price_amount || product.price_amount || 0)),
        is_active: Boolean(sku.is_active),
        setting: formatResellerProductSetting({ ...rule, sku_id: skuRule ? sku.id : Number(rule.sku_id || 0) }, Number(sku.price_amount || product.price_amount || 0), profile),
        effective_price_amount: money(resellerEffectivePrice(Number(sku.price_amount || product.price_amount || 0), rule, profile))
      };
    })
  };
}

async function previewResellerProductSettings(env: Env, profile: AnyRecord, productId: number, settings: AnyRecord[]): Promise<AnyRecord[]> {
  const product = await env.DB.prepare("SELECT * FROM products WHERE id=?").bind(productId).first<ProductRow>();
  if (!product) return [];
  const skus = await env.DB.prepare("SELECT * FROM product_skus WHERE product_id=? ORDER BY sort_order ASC, id ASC")
    .bind(productId).all<SkuRow>();
  return settings.map((item) => {
    const skuId = toInt(item.sku_id, 0);
    const sku = (skus.results || []).find((candidate) => candidate.id === skuId);
    const basePrice = Number((sku?.price_amount ?? product.price_amount) || 0);
    const validation = validateResellerRule(profile, item);
    return {
      sku_id: skuId,
      is_listed: item.is_listed !== false,
      base_price_amount: money(basePrice),
      effective_price_amount: money(resellerEffectivePrice(basePrice, item, profile)),
      valid: validation.valid,
      error_code: validation.error || ""
    };
  });
}

async function saveResellerProductSettings(env: Env, profile: AnyRecord, productId: number, settings: AnyRecord[]): Promise<void> {
  const product = await env.DB.prepare("SELECT id FROM products WHERE id=?").bind(productId).first<{ id: number }>();
  if (!product) throw new Error("商品不存在");
  for (const item of settings) {
    const skuId = Math.max(0, toInt(item.sku_id, 0));
    const validation = validateResellerRule(profile, item);
    if (!validation.valid) throw new Error(validation.error || "分销商品规则不合法");
    await env.DB.prepare(
      `INSERT INTO reseller_product_settings (
        reseller_id, product_id, sku_id, is_listed, pricing_mode, markup_percent,
        fixed_markup_amount, fixed_price_amount, sort_order
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(reseller_id, product_id, sku_id) DO UPDATE SET
        is_listed=excluded.is_listed, pricing_mode=excluded.pricing_mode,
        markup_percent=excluded.markup_percent, fixed_markup_amount=excluded.fixed_markup_amount,
        fixed_price_amount=excluded.fixed_price_amount, sort_order=excluded.sort_order,
        updated_at=CURRENT_TIMESTAMP`
    ).bind(
      profile.id,
      productId,
      skuId,
      boolInt(item.is_listed, true),
      resellerPricingMode(item.pricing_mode),
      money(Math.max(0, numberValue(item.markup_percent, 0))),
      money(Math.max(0, numberValue(item.fixed_markup_amount, 0))),
      money(Math.max(0, numberValue(item.fixed_price_amount, 0))),
      toInt(item.sort_order, 0)
    ).run();
  }
}

function resellerPricingMode(value: unknown): string {
  const mode = clean(value, 40);
  return ["inherit", "markup_percent", "fixed_markup", "fixed_price"].includes(mode) ? mode : "inherit";
}

function resellerEffectivePrice(basePrice: number, rule: AnyRecord, profile?: AnyRecord): number {
  const mode = resellerPricingMode(rule.pricing_mode);
  if (mode === "fixed_price") return Math.max(0, Number(rule.fixed_price_amount || 0));
  if (mode === "fixed_markup") return Math.max(0, basePrice + Number(rule.fixed_markup_amount || 0));
  const markup = mode === "markup_percent"
    ? Number(rule.markup_percent || 0)
    : Number(profile?.default_markup_percent || 0);
  return Math.max(0, basePrice * (1 + Math.max(0, markup) / 100));
}

async function resellerPricingForSku(
  env: Env,
  context: ResellerContext,
  product: ProductRow,
  sku: SkuRow
): Promise<{ listed: boolean; unitPrice: number; baseUnitPrice: number; rule: AnyRecord }> {
  const rows = await env.DB.prepare(
    "SELECT * FROM reseller_product_settings WHERE reseller_id=? AND product_id=? AND sku_id IN (0, ?)"
  ).bind(context.profile.id, product.id, sku.id).all<AnyRecord>();
  const productRule = (rows.results || []).find((row) => Number(row.sku_id || 0) === 0);
  const skuRule = (rows.results || []).find((row) => Number(row.sku_id || 0) === sku.id);
  if (productRule && Number(productRule.is_listed) === 0) {
    return { listed: false, unitPrice: 0, baseUnitPrice: Number(sku.price_amount || 0), rule: productRule };
  }
  if (skuRule && Number(skuRule.is_listed) === 0) {
    return { listed: false, unitPrice: 0, baseUnitPrice: Number(sku.price_amount || 0), rule: skuRule };
  }
  const rule = skuRule || productRule || {
    reseller_id: context.profile.id,
    product_id: product.id,
    sku_id: sku.id,
    is_listed: 1,
    pricing_mode: "inherit",
    markup_percent: 0,
    fixed_markup_amount: 0,
    fixed_price_amount: 0
  };
  const baseUnitPrice = Number(sku.price_amount || 0);
  return {
    listed: true,
    unitPrice: resellerEffectivePrice(baseUnitPrice, rule, context.profile),
    baseUnitPrice,
    rule
  };
}

function validateResellerRule(profile: AnyRecord, rule: AnyRecord): { valid: boolean; error?: string } {
  const mode = resellerPricingMode(rule.pricing_mode);
  const maxMarkup = Number(profile.max_markup_percent || 0);
  const markup = Number(rule.markup_percent || 0);
  if (mode === "markup_percent" && maxMarkup > 0 && markup > maxMarkup) return { valid: false, error: "markup_exceeds_limit" };
  if (mode === "fixed_price" && Number(rule.fixed_price_amount || 0) < 0) return { valid: false, error: "invalid_fixed_price" };
  if (mode === "fixed_markup" && Number(rule.fixed_markup_amount || 0) < 0) return { valid: false, error: "invalid_fixed_markup" };
  return { valid: true };
}

async function ensureResellerBalance(env: Env, resellerId: number, currency: string): Promise<AnyRecord> {
  await env.DB.prepare(
    "INSERT OR IGNORE INTO reseller_balance_accounts (reseller_id, currency, status) VALUES (?, ?, 'normal')"
  ).bind(resellerId, currency || "CNY").run();
  return env.DB.prepare("SELECT * FROM reseller_balance_accounts WHERE reseller_id=? AND currency=?")
    .bind(resellerId, currency || "CNY").first<AnyRecord>() as Promise<AnyRecord>;
}

async function resellerBalances(env: Env, resellerId: number): Promise<AnyRecord[]> {
  const rows = await env.DB.prepare("SELECT * FROM reseller_balance_accounts WHERE reseller_id=? ORDER BY currency ASC")
    .bind(resellerId).all<AnyRecord>();
  return (rows.results || []).map(formatResellerBalance);
}

async function resellerAvailableAmount(env: Env, resellerId: number, currency: string): Promise<number> {
  const balance = await ensureResellerBalance(env, resellerId, currency);
  return Math.max(0, centsToMoney(moneyToCents(Number(balance.available_amount_cache || 0))));
}

function resellerSettlementConfirmDays(env: Env): number {
  return clampInteger(env.RESELLER_SETTLEMENT_CONFIRM_DAYS, 0, 3650, 7);
}

async function confirmDueResellerLedgerEntries(env: Env): Promise<number> {
  const result = await env.DB.prepare(
    `UPDATE reseller_ledger_entries
     SET status='available', updated_at=CURRENT_TIMESTAMP
     WHERE status='pending_confirm'
       AND available_at IS NOT NULL
       AND datetime(available_at) <= CURRENT_TIMESTAMP`
  ).run();
  const affected = Number(result.meta.changes || 0);
  if (affected > 0) {
    await env.DB.prepare(
      `UPDATE orders
       SET reseller_profit_status='credited', updated_at=CURRENT_TIMESTAMP
       WHERE status NOT IN ('canceled', 'refunded', 'partially_refunded')
         AND EXISTS (
           SELECT 1 FROM reseller_ledger_entries entry
           WHERE entry.order_id=orders.id
             AND entry.type='order_profit'
             AND entry.status IN ('available', 'locked', 'withdrawn')
         )`
    ).run();
  }
  return affected;
}

async function resellerOrderProfitRisk(
  env: Env,
  context: ResellerContext,
  buyerUserId: number
): Promise<{ eligible: boolean; reason: string }> {
  if (buyerUserId <= 0) return { eligible: true, reason: "" };
  if (buyerUserId === Number(context.profile.user_id || 0)) {
    return { eligible: false, reason: "self_dealing_owner" };
  }
  const related = await env.DB.prepare(
    "SELECT id FROM reseller_related_accounts WHERE reseller_id=? AND user_id=? AND status='active' LIMIT 1"
  ).bind(Number(context.profile.id || 0), buyerUserId).first<{ id: number }>();
  return related
    ? { eligible: false, reason: "self_dealing_related_account" }
    : { eligible: true, reason: "" };
}

async function createResellerOrderSnapshot(
  env: Env,
  input: {
    orderId: number;
    context: ResellerContext;
    buyerUserId: number;
    baseAmount: number;
    resellerAmount: number;
    potentialProfit: number;
    profitEligible: boolean;
    profitBlockReason: string;
    children: Array<{ id: number; item: CalculatedOrderItem; orderItemId: number }>;
  }
): Promise<void> {
  const items = input.children.map((child) => ({
    product_id: child.item.product.id,
    sku_id: child.item.sku.id,
    quantity: child.item.quantity,
    child_order_id: child.id,
    order_id: child.id,
    order_item_id: child.orderItemId,
    base_unit_amount: money(child.item.baseUnitPrice),
    reseller_unit_amount: money(child.item.unitPrice),
    base_total_amount: money(child.item.baseLineTotal),
    reseller_total_amount: money(child.item.lineTotal),
    profit_amount: money(centsToMoney(moneyToCents(child.item.lineTotal) - moneyToCents(child.item.baseLineTotal))),
    pricing_mode: child.item.resellerPricingMode || "inherit",
    rule_source: child.item.resellerRuleSource || "profile",
    setting_id: child.item.resellerSettingId || null
  }));
  const riskSnapshot = {
    buyer_user_id: input.buyerUserId,
    reseller_user_id: Number(input.context.profile.user_id || 0),
    profit_eligible: input.profitEligible,
    profit_block_reason: input.profitBlockReason,
    guest_buyer: input.buyerUserId <= 0,
    self_dealing_deferred: "same_contact_and_risk_detected_account_linking",
    self_dealing: {
      owner_match: input.profitBlockReason === "self_dealing_owner",
      related_account_match: input.profitBlockReason === "self_dealing_related_account"
    }
  };
  await env.DB.prepare(
    `INSERT INTO reseller_order_snapshots (
      order_id, reseller_id, domain, currency, reseller_user_id, buyer_user_id,
      base_amount, reseller_amount, profit_amount, profit_eligible, profit_block_reason,
      pricing_snapshot_json, risk_snapshot_json
    ) VALUES (?, ?, ?, 'CNY', ?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).bind(
    input.orderId,
    Number(input.context.profile.id || 0),
    clean(input.context.domain.domain, 255),
    Number(input.context.profile.user_id || 0),
    input.buyerUserId,
    money(input.baseAmount),
    money(input.resellerAmount),
    money(input.potentialProfit),
    input.profitEligible ? 1 : 0,
    input.profitBlockReason,
    JSON.stringify({
      currency: "CNY",
      base_amount: money(input.baseAmount),
      reseller_amount: money(input.resellerAmount),
      profit_amount: money(input.potentialProfit),
      items
    }),
    JSON.stringify(riskSnapshot)
  ).run();
}

async function createResellerLedgerForOrder(
  env: Env,
  context: ResellerContext,
  orderId: number,
  orderNo: string,
  baseAmount: number,
  profitAmount: number
): Promise<void> {
  const resellerId = Number(context.profile.id || 0);
  if (!resellerId) return;
  const snapshot = await env.DB.prepare(
    "SELECT profit_eligible, profit_amount, currency, domain FROM reseller_order_snapshots WHERE order_id=? AND reseller_id=?"
  ).bind(orderId, resellerId).first<{ profit_eligible: number; profit_amount: number; currency: string; domain: string }>();
  const snapshotProfit = Number(snapshot?.profit_amount ?? profitAmount);
  if (!snapshot || Number(snapshot.profit_eligible) !== 1 || moneyToCents(snapshotProfit) <= 0) {
    await env.DB.prepare("UPDATE orders SET reseller_profit_status='unavailable', updated_at=CURRENT_TIMESTAMP WHERE id=?")
      .bind(orderId).run();
    return;
  }
  const idempotencyKey = `order_profit:${orderId}`;
  const exists = await env.DB.prepare(
    `SELECT id, status FROM reseller_ledger_entries
     WHERE (idempotency_key=? OR idempotency_key=? OR (reseller_id=? AND order_id=? AND type='order_profit'))
     ORDER BY id ASC LIMIT 1`
  ).bind(idempotencyKey, `reseller-order:${orderId}`, resellerId, orderId).first<{ id: number; status: string }>();
  if (exists) {
    const profitStatus = exists.status === "pending_confirm" ? "pending"
      : (["available", "locked", "withdrawn"].includes(exists.status) ? "credited" : "unavailable");
    await env.DB.prepare("UPDATE orders SET reseller_profit_status=?, updated_at=CURRENT_TIMESTAMP WHERE id=?")
      .bind(profitStatus, orderId).run();
    return;
  }
  const currency = clean(snapshot.currency, 12) || "CNY";
  await ensureResellerBalance(env, resellerId, currency);
  const profit = money(snapshotProfit);
  const availableAt = new Date(Date.now() + resellerSettlementConfirmDays(env) * 24 * 60 * 60 * 1000).toISOString();
  const inserted = await env.DB.prepare(
    `INSERT OR IGNORE INTO reseller_ledger_entries (
      reseller_id, order_id, type, amount, currency, idempotency_key, metadata_json, status, available_at, remark
    ) VALUES (?, ?, 'order_profit', ?, ?, ?, ?, 'pending_confirm', ?, ?)`
  ).bind(
    resellerId,
    orderId,
    profit,
    currency,
    idempotencyKey,
    JSON.stringify({
      order_no: orderNo,
      domain: snapshot.domain || context.domain.domain || "",
      base_amount: money(baseAmount),
      sell_amount: money(Number(baseAmount || 0) + snapshotProfit),
      settlement_confirm_days: resellerSettlementConfirmDays(env)
    }),
    availableAt,
    `分站订单利润 ${orderNo}`
  ).run();
  if (Number(inserted.meta.changes || 0) !== 1) return;
  await env.DB.prepare("UPDATE orders SET reseller_profit_status='pending', updated_at=CURRENT_TIMESTAMP WHERE id=?")
    .bind(orderId).run();
}

async function apiUserResellerEndpoint(request: Request, env: Env, method: string, path: string, url: URL, user: UserRow): Promise<Response> {
  if (method === "POST" && path === "/reseller/upload") return apiUserResellerUpload(request, env, user.id);
  if (method === "GET" && path === "/reseller/profile") return apiUserResellerProfile(env, user.id);
  if (method === "POST" && path === "/reseller/apply") return apiUserApplyReseller(request, env, user.id);
  if (method === "GET" && path === "/reseller/domains") return apiUserResellerDomains(env, url, user.id);
  if (method === "POST" && path === "/reseller/domains") return apiUserCreateResellerDomain(request, env, user.id);
  if (method === "GET" && path === "/reseller/site-config") return apiUserResellerSiteConfig(env, user.id);
  if (method === "PUT" && path === "/reseller/site-config") return apiUserUpdateResellerSiteConfig(request, env, user.id);
  if (method === "GET" && path === "/reseller/product-settings") return apiUserResellerProductSettings(env, url, user.id);
  if (method === "GET" && /^\/reseller\/product-settings\/\d+$/.test(path)) return apiUserResellerProductSetting(env, user.id, Number(path.split("/").pop()));
  if (method === "PUT" && /^\/reseller\/product-settings\/\d+$/.test(path)) return apiUserUpdateResellerProductSettings(request, env, user.id, Number(path.split("/").pop()));
  if (method === "POST" && /^\/reseller\/product-settings\/\d+\/preview$/.test(path)) return apiUserPreviewResellerProductSettings(request, env, user.id, Number(path.split("/").at(-2)));
  if (method === "DELETE" && /^\/reseller\/product-settings\/\d+$/.test(path)) return apiUserResetResellerProductSetting(env, url, user.id, Number(path.split("/").pop()));
  if (method === "GET" && path === "/reseller/dashboard") return apiUserResellerDashboard(env, user.id);
  if (method === "GET" && path === "/reseller/orders/stats") return apiUserResellerOrderStats(env, url, user.id);
  if (method === "GET" && path === "/reseller/orders") return apiUserResellerOrders(env, url, user.id);
  if (method === "GET" && /^\/reseller\/orders\/[^/]+$/.test(path)) {
    const encodedOrderNo = path.split("/").pop() || "";
    let orderNo = encodedOrderNo;
    try { orderNo = decodeURIComponent(encodedOrderNo); } catch { /* keep the raw value */ }
    return apiUserResellerOrderDetail(env, user.id, clean(orderNo, 120));
  }
  if (method === "GET" && path === "/reseller/balance-accounts") return apiUserResellerBalanceAccounts(env, url, user.id);
  if (method === "GET" && path === "/reseller/ledger-entries") return apiUserResellerLedgerEntries(env, url, user.id);
  if (method === "GET" && path === "/reseller/withdraws") return apiUserResellerWithdraws(env, url, user.id);
  if (method === "POST" && path === "/reseller/withdraws") return apiUserCreateResellerWithdraw(request, env, user.id);
  return apiError("not_found", 404);
}

