async function apiUserCreateResellerDomain(request: Request, env: Env, userId: number): Promise<Response> {
  const profile = await resellerProfileByUser(env, userId);
  if (!profile) return apiError("请先申请分销商", 400);
  if (profile.status !== "active") return apiError("分销商审核通过后才能提交自定义域名", 403);
  const body = await readJson(request);
  const domain = normalizeDomain(body.domain);
  if (!domain) return apiError("域名格式不正确", 400);
  const exists = await env.DB.prepare("SELECT id FROM reseller_domains WHERE domain=?").bind(domain).first<{ id: number }>();
  if (exists) return apiError("域名已存在", 409);
  const result = await env.DB.prepare(
    `INSERT INTO reseller_domains (
      reseller_id, domain, type, verification_token, verification_status, status, is_primary
    ) VALUES (?, ?, 'custom', ?, 'pending', 'pending_review', ?)`
  ).bind(profile.id, domain, "", 0).run();
  const row = await env.DB.prepare("SELECT * FROM reseller_domains WHERE id=?").bind(result.meta.last_row_id).first<AnyRecord>();
  return apiOk(row ? formatResellerDomain(row) : {});
}

