async function apiUserResellerOrders(env: Env, url: URL, userId: number): Promise<Response> {
  const profile = await resellerProfileByUser(env, userId);
  if (!profile) return apiOk([], paginationFromTotal(url, 0));
  if (profile.status !== "active") return apiError("分销商审核通过后才能查看分站订单", 403);
  const { page, size, offset } = paging(url);
  const filter = buildResellerOrdersWhere(url, profile.id);
  const total = await count(env, `SELECT COUNT(*) AS count FROM orders o ${filter.where}`, filter.params);
  const rows = await env.DB.prepare(
    `SELECT o.*,
            ${resellerProfitStatusSql("o")} AS ledger_profit_status,
            COALESCE((
              SELECT SUM(oi.quantity) FROM order_items oi
              JOIN orders item_order ON item_order.id=oi.order_id
              WHERE item_order.id=o.id OR item_order.parent_id=o.id
            ), 0) AS items_count
     FROM orders o ${filter.where}
     ORDER BY o.id DESC LIMIT ? OFFSET ?`
  ).bind(...filter.params, size, offset).all<OrderRow & { items_count: number }>();
  return apiOk((rows.results || []).map(formatResellerOrderSummary), pagination(page, size, total));
}

async function apiUserResellerOrderStats(env: Env, url: URL, userId: number): Promise<Response> {
  const profile = await resellerProfileByUser(env, userId);
  if (!profile) return apiOk({ total: 0, by_status: {}, by_currency: {} });
  if (profile.status !== "active") return apiError("分销商审核通过后才能查看分站订单", 403);
  const filter = buildResellerOrdersWhere(url, profile.id);
  const rows = await env.DB.prepare(
    `SELECT o.status, o.currency, COUNT(*) AS count
     FROM orders o ${filter.where}
     GROUP BY o.status, o.currency`
  ).bind(...filter.params).all<{ status: string; currency: string; count: number }>();
  const byStatus: AnyRecord = {};
  const byCurrency: AnyRecord = {};
  let total = 0;
  for (const row of rows.results || []) {
    total += Number(row.count || 0);
    byStatus[row.status || "unknown"] = Number(byStatus[row.status || "unknown"] || 0) + Number(row.count || 0);
    byCurrency[row.currency || "CNY"] = Number(byCurrency[row.currency || "CNY"] || 0) + Number(row.count || 0);
  }
  return apiOk({ total, by_status: byStatus, by_currency: byCurrency });
}

function buildResellerOrdersWhere(url: URL, resellerId: number): { where: string; params: unknown[] } {
  const where = ["o.reseller_id=?", "o.parent_id IS NULL"];
  const params: unknown[] = [resellerId];
  const status = clean(url.searchParams.get("status"), 40);
  const orderNo = clean(url.searchParams.get("order_no"), 120);
  if (status && status !== "__all__") {
    where.push("o.status=?");
    params.push(status);
  }
  if (orderNo) {
    where.push("o.order_no LIKE ?");
    params.push(`%${orderNo}%`);
  }
  for (const [key, column, op] of [
    ["created_from", "o.created_at", ">="],
    ["created_to", "o.created_at", "<="],
    ["paid_from", "o.paid_at", ">="],
    ["paid_to", "o.paid_at", "<="]
  ] as const) {
    const value = clean(url.searchParams.get(key), 80);
    if (!value) continue;
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) continue;
    where.push(`${dashboardSqlDate(column)} ${op} datetime(?)`);
    params.push(dashboardDbDate(date));
  }
  return { where: `WHERE ${where.join(" AND ")}`, params };
}

function resellerProfitStatusSql(orderAlias: string): string {
  return `CASE
    WHEN ${orderAlias}.status IN ('canceled', 'refunded', 'partially_refunded') THEN 'unavailable'
    WHEN EXISTS (
      SELECT 1 FROM reseller_order_snapshots snapshot
      WHERE snapshot.order_id=${orderAlias}.id
        AND (snapshot.profit_eligible<>1 OR ROUND(snapshot.profit_amount, 2)<=0)
    ) THEN 'unavailable'
    WHEN ${orderAlias}.paid_at IS NULL OR ${orderAlias}.status='pending_payment' THEN 'pending'
    WHEN EXISTS (
      SELECT 1 FROM reseller_ledger_entries entry
      WHERE entry.order_id=${orderAlias}.id
        AND entry.type='order_profit'
        AND entry.status IN ('available', 'locked', 'withdrawn')
    ) THEN 'credited'
    WHEN EXISTS (
      SELECT 1 FROM reseller_ledger_entries entry
      WHERE entry.order_id=${orderAlias}.id
        AND entry.type='order_profit'
        AND entry.status='canceled'
    ) THEN 'unavailable'
    ELSE 'pending'
  END`;
}

async function apiUserResellerOrderDetail(env: Env, userId: number, orderNo: string): Promise<Response> {
  if (!orderNo) return apiError("订单不存在", 404);
  const profile = await resellerProfileByUser(env, userId);
  if (!profile) return apiError("订单不存在", 404);
  if (profile.status !== "active") return apiError("分销商审核通过后才能查看分站订单", 403);
  const order = await env.DB.prepare(
    `SELECT o.*,
            ${resellerProfitStatusSql("o")} AS ledger_profit_status,
            COALESCE((
              SELECT SUM(oi.quantity) FROM order_items oi
              JOIN orders item_order ON item_order.id=oi.order_id
              WHERE item_order.id=o.id OR item_order.parent_id=o.id
            ), 0) AS items_count
     FROM orders o
     WHERE o.reseller_id=? AND o.parent_id IS NULL AND o.order_no=?`
  ).bind(profile.id, orderNo).first<OrderRow & { items_count: number }>();
  if (!order) return apiError("订单不存在", 404);
  const rows = await env.DB.prepare(
    `SELECT oi.* FROM order_items oi
     JOIN orders item_order ON item_order.id=oi.order_id
     WHERE item_order.id=? OR item_order.parent_id=?
     ORDER BY item_order.id ASC, oi.id ASC`
  ).bind(order.id, order.id).all<OrderItemRow>();
  const storedItems = rows.results || [];
  const baseTotalCents = moneyToCents(Number(order.reseller_base_amount || 0));
  const saleTotalCents = Math.max(1, moneyToCents(Number(order.total_amount || 0)));
  let allocatedBaseCents = 0;
  const items = storedItems.map((item, index) => {
    const lineSaleCents = moneyToCents(Number(item.total_price || 0));
    const lineBaseCents = index === storedItems.length - 1
      ? Math.max(0, baseTotalCents - allocatedBaseCents)
      : Math.max(0, Math.round(baseTotalCents * lineSaleCents / saleTotalCents));
    allocatedBaseCents += lineBaseCents;
    const quantity = Math.max(1, Number(item.quantity || 1));
    return {
      title: jsonParse(item.title_json || "{}", {}),
      sku_snapshot: jsonParse(item.sku_snapshot_json || "{}", {}),
      quantity,
      unit_price: money(Number(item.unit_price || 0)),
      total_price: money(Number(item.total_price || 0)),
      base_unit_amount: money(centsToMoney(Math.round(lineBaseCents / quantity))),
      reseller_unit_amount: money(Number(item.unit_price || 0)),
      base_total_amount: money(centsToMoney(lineBaseCents)),
      reseller_total_amount: money(Number(item.total_price || 0)),
      profit_amount: money(centsToMoney(lineSaleCents - lineBaseCents))
    };
  });
  return apiOk({ ...formatResellerOrderSummary(order), items });
}

