async function apiUserCreateResellerWithdraw(request: Request, env: Env, userId: number): Promise<Response> {
  await confirmDueResellerLedgerEntries(env);
  const profile = await resellerProfileByUser(env, userId);
  if (!profile || profile.status !== "active") return apiError("分销未开通", 400);
  if (profile.settlement_status === "frozen") return apiError("分销结算已冻结", 400);
  const body = await readJson(request);
  const amount = Number(money(Math.max(0, numberValue(body.amount, 0))));
  const currency = clean(body.currency, 12) || "CNY";
  const channel = clean(body.channel, 80);
  const account = clean(body.account, 500);
  if (amount <= 0) return apiError("提现金额不正确", 400);
  if (!channel || !account) return apiError("提现渠道和账号不能为空", 400);
  const available = await resellerAvailableAmount(env, profile.id, currency);
  if (moneyToCents(amount) > moneyToCents(available)) return apiError("可提现余额不足", 400);
  let result: D1Result;
  try {
    result = await env.DB.prepare(
      "INSERT INTO reseller_withdraws (reseller_id, amount, currency, channel, account, status) VALUES (?, ?, ?, ?, ?, 'pending')"
    ).bind(profile.id, money(amount), currency, channel, account).run();
  } catch (error) {
    if (databaseErrorIncludes(error, "reseller_withdraw_insufficient")) return apiError("可提现余额不足", 409);
    if (databaseErrorIncludes(error, "reseller_withdraw_amount_invalid")) return apiError("提现金额不正确", 400);
    if (databaseErrorIncludes(error, "reseller_balance_frozen")) return apiError("分销结算已冻结", 409);
    throw error;
  }
  const row = await env.DB.prepare("SELECT * FROM reseller_withdraws WHERE id=?").bind(result.meta.last_row_id).first<AnyRecord>();
  return apiOk(row ? formatResellerWithdraw(row) : {});
}

async function apiAdminResellerProfiles(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const keyword = clean(url.searchParams.get("keyword"), 120);
  const userId = toInt(url.searchParams.get("user_id"), 0);
  const status = clean(url.searchParams.get("status"), 40);
  const settlement = clean(url.searchParams.get("settlement_status"), 40);
  if (keyword) {
    where += " AND (u.email LIKE ? OR u.display_name LIKE ? OR rp.apply_reason LIKE ?)";
    params.push(`%${keyword}%`, `%${keyword}%`, `%${keyword}%`);
  }
  if (userId > 0) {
    where += " AND rp.user_id=?";
    params.push(userId);
  }
  if (status && status !== "__all__") {
    where += " AND rp.status=?";
    params.push(status);
  }
  if (settlement && settlement !== "__all__") {
    where += " AND rp.settlement_status=?";
    params.push(settlement);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM reseller_profiles rp LEFT JOIN users u ON u.id=rp.user_id ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT rp.*, u.email AS user_email, u.display_name AS user_display_name
     FROM reseller_profiles rp LEFT JOIN users u ON u.id=rp.user_id
     ${where}
     ORDER BY rp.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map(formatResellerProfile), pagination(page, size, total));
}

async function apiAdminResellerProfile(env: Env, id: number): Promise<Response> {
  const profile = await resellerProfileById(env, id);
  if (!profile) return apiError("分销商不存在", 404);
  const domains = await env.DB.prepare("SELECT * FROM reseller_domains WHERE reseller_id=? ORDER BY is_primary DESC, id DESC").bind(id).all<AnyRecord>();
  const siteConfig = await resellerSiteConfigByProfile(env, id);
  const productSummary = await env.DB.prepare(
    `SELECT
       COUNT(DISTINCT product_id) AS configured_products,
       SUM(CASE WHEN is_listed=0 THEN 1 ELSE 0 END) AS hidden_products,
       SUM(CASE WHEN sku_id>0 THEN 1 ELSE 0 END) AS sku_overrides,
       SUM(CASE WHEN pricing_mode<>'inherit' THEN 1 ELSE 0 END) AS pricing_overrides
     FROM reseller_product_settings WHERE reseller_id=?`
  ).bind(id).first<AnyRecord>();
  const balances = await env.DB.prepare("SELECT * FROM reseller_balance_accounts WHERE reseller_id=? ORDER BY currency ASC").bind(id).all<AnyRecord>();
  const recentOrders = await env.DB.prepare("SELECT * FROM orders WHERE reseller_id=? ORDER BY id DESC LIMIT 10").bind(id).all<OrderRow>();
  const recentLedger = await env.DB.prepare("SELECT * FROM reseller_ledger_entries WHERE reseller_id=? ORDER BY id DESC LIMIT 10").bind(id).all<AnyRecord>();
  const recentWithdraws = await env.DB.prepare("SELECT * FROM reseller_withdraws WHERE reseller_id=? ORDER BY id DESC LIMIT 10").bind(id).all<AnyRecord>();
  return apiOk({
    profile: formatResellerProfile(profile),
    domains: (domains.results || []).map(formatResellerDomain),
    site_config: siteConfig ? formatResellerSiteConfig(siteConfig, profile) : undefined,
    product_summary: {
      configured_products: Number(productSummary?.configured_products || 0),
      hidden_products: Number(productSummary?.hidden_products || 0),
      sku_overrides: Number(productSummary?.sku_overrides || 0),
      pricing_overrides: Number(productSummary?.pricing_overrides || 0)
    },
    finance_summary: {
      balances: (balances.results || []).map(formatResellerBalance),
      recent_ledger_count: Number(recentLedger.results?.length || 0),
      recent_withdraw_count: Number(recentWithdraws.results?.length || 0)
    },
    recent_orders: (recentOrders.results || []).map(formatResellerOrderSummary),
    recent_ledger_entries: (recentLedger.results || []).map(formatResellerLedger),
    recent_withdraws: (recentWithdraws.results || []).map(formatResellerWithdraw)
  });
}

