  const resellerId = toInt(url.searchParams.get("reseller_id"), 0);
  const userId = toInt(url.searchParams.get("user_id"), 0);
  const domain = clean(url.searchParams.get("domain"), 120);
  const type = clean(url.searchParams.get("type"), 40);
  const status = clean(url.searchParams.get("status"), 40);
  const verification = clean(url.searchParams.get("verification_status"), 40);
  if (keyword) {
    where += " AND (rd.domain LIKE ? OR u.email LIKE ?)";
    params.push(`%${keyword}%`, `%${keyword}%`);
  }
  if (resellerId > 0) { where += " AND rd.reseller_id=?"; params.push(resellerId); }
  if (userId > 0) { where += " AND rp.user_id=?"; params.push(userId); }
  if (domain) { where += " AND rd.domain LIKE ?"; params.push(`%${domain}%`); }
  if (type && type !== "__all__") { where += " AND rd.type=?"; params.push(type); }
  if (status && status !== "__all__") { where += " AND rd.status=?"; params.push(status); }
  if (verification && verification !== "__all__") { where += " AND rd.verification_status=?"; params.push(verification); }
  const join = "FROM reseller_domains rd LEFT JOIN reseller_profiles rp ON rp.id=rd.reseller_id LEFT JOIN users u ON u.id=rp.user_id";
  const total = await count(env, `SELECT COUNT(*) AS count ${join} ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT rd.*, rp.user_id, rp.status AS profile_status, rp.settlement_status, u.email AS user_email, u.display_name AS user_display_name
     ${join} ${where}
     ORDER BY rd.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<AnyRecord>();
