async function apiAdminResellerProductSettings(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const resellerId = toInt(url.searchParams.get("reseller_id"), 0);
  const productId = toInt(url.searchParams.get("product_id"), 0);
  if (resellerId > 0) { where += " AND rps.reseller_id=?"; params.push(resellerId); }
  if (productId > 0) { where += " AND rps.product_id=?"; params.push(productId); }
  const total = await count(env, `SELECT COUNT(*) AS count FROM reseller_product_settings rps ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT rps.*, p.slug, p.title_json, p.price_amount, p.is_active AS product_is_active,
            rp.user_id, rp.status AS profile_status, rp.settlement_status,
            u.email AS user_email, u.display_name AS user_display_name
     FROM reseller_product_settings rps
     LEFT JOIN products p ON p.id=rps.product_id
     LEFT JOIN reseller_profiles rp ON rp.id=rps.reseller_id
     LEFT JOIN users u ON u.id=rp.user_id
     ${where}
     ORDER BY rps.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<AnyRecord>();
  return apiOk((rows.results || []).map((row) => ({
    ...formatResellerProductSetting(row, Number(row.price_amount || 0), row),
    profile: formatResellerProfileRef(row),
    product: {
      id: Number(row.product_id || 0),
      slug: row.slug || "",
      title: jsonParse(row.title_json || "{}", {}),
      price_amount: money(Number(row.price_amount || 0)),
      is_active: Boolean(row.product_is_active)
    }
  })), pagination(page, size, total));
}

