async function apiAdminAuthzGrantPolicy(request: Request, env: Env, operator: AdminSessionUser): Promise<Response> {
  const body = await readJson(request);
  const role = normalizeAuthzRole(body.role);
  const object = normalizeAuthzObject(body.object);
  const action = normalizeAuthzAction(body.action);
  if (!role) return apiError("请选择角色", 400);
  if (!object) return apiError("权限对象不能为空", 400);
  if (!action) return apiError("权限动作不合法", 400);
  const exists = await env.DB.prepare("SELECT role FROM authz_roles WHERE role=?").bind(role).first<{ role: string }>();
  if (!exists) return apiError("角色不存在", 404);
  await env.DB.prepare("INSERT OR IGNORE INTO authz_policies (role, object, action) VALUES (?, ?, ?)")
    .bind(role, object, action)
    .run();
  await recordAuthzAudit(env, operator, "policy_grant", { role, object, method: action }, { role, object, method: action });
  return apiOk(formatAuthzPolicy({ role, object, action }));
}

async function apiAdminAuthzRevokePolicy(request: Request, env: Env, operator: AdminSessionUser): Promise<Response> {
  const body = await readJson(request);
  const role = normalizeAuthzRole(body.role);
  const object = normalizeAuthzObject(body.object);
  const action = normalizeAuthzAction(body.action);
  if (!role || !object || !action) return apiError("权限参数不完整", 400);
  await env.DB.prepare("DELETE FROM authz_policies WHERE role=? AND object=? AND action=?")
    .bind(role, object, action)
    .run();
  await recordAuthzAudit(env, operator, "policy_revoke", { role, object, method: action }, { role, object, method: action });
  return apiOk({});
}

async function apiAdminAuthzAdmins(env: Env): Promise<Response> {
  const rows = await env.DB.prepare(
    `SELECT a.id, a.username, a.is_super, a.created_at, a.totp_secret, a.totp_enabled_at,
            MAX(CASE WHEN l.status='success' THEN l.created_at ELSE NULL END) AS last_login_at
     FROM admins a
     LEFT JOIN admin_login_logs l ON l.admin_id=a.id
     GROUP BY a.id
     ORDER BY a.id ASC`
  ).all<AdminSecurityRow & { created_at: string; last_login_at?: string | null }>();
  const admins: AnyRecord[] = [];
  for (const row of rows.results || []) {
    admins.push({
      id: row.id,
      username: row.username,
      is_super: Boolean(row.is_super),
      roles: await authzRolesForAdmin(env, row.id),
      totp_enabled: Boolean(row.totp_secret && row.totp_enabled_at),
      totp_enabled_at: row.totp_enabled_at || "",
      created_at: row.created_at,
      last_login_at: row.last_login_at || ""
    });
  }
  return apiOk(admins);
}

async function apiAdminAuthzCreateAdmin(request: Request, env: Env, operator: AdminSessionUser): Promise<Response> {
  const body = await readJson(request);
  const username = normalizeAdminUsername(body.username);
  const password = String(body.password || "");
  const isSuper = Boolean(body.is_super);
  if (!username) return apiError("管理员账号须为 3-64 个字符且不能包含空白", 400);
  if (password.length < 8) return apiError("密码至少 8 位", 400);
  const exists = await env.DB.prepare("SELECT id FROM admins WHERE username=?").bind(username).first<{ id: number }>();
  if (exists) return apiError("管理员账号已存在", 409);
  const salt = randomToken().slice(0, 16);
  const passwordHash = await hashPassword(password, salt);
  const result = await env.DB.prepare(
    "INSERT INTO admins (username, password_salt, password_hash, is_super) VALUES (?, ?, ?, ?)"
  ).bind(username, salt, passwordHash, isSuper ? 1 : 0).run();
  const id = Number(result.meta.last_row_id || 0);
  if (isSuper) {
    await ensureDefaultAuthz(env);
    await env.DB.prepare("INSERT OR IGNORE INTO authz_admin_roles (admin_id, role) VALUES (?, 'role:super_admin')")
      .bind(id)
      .run();
  }
  await recordAuthzAudit(env, operator, "admin_create", { targetAdminId: id, targetUsername: username }, {
    target_admin_id: id,
    target_username: username,
    detail: { is_super: isSuper }
  });
  return apiOk({ id, username, is_super: isSuper });
}

async function apiAdminAuthzUpdateAdmin(request: Request, env: Env, adminId: number, operator: AdminSessionUser): Promise<Response> {
  const body = await readJson(request);
  const current = await env.DB.prepare("SELECT id, username, is_super FROM admins WHERE id=?").bind(adminId).first<{ id: number; username: string; is_super: number }>();
  if (!current) return apiError("管理员不存在", 404);
  const username = normalizeAdminUsername(body.username ?? current.username);
  if (!username) return apiError("管理员账号须为 3-64 个字符且不能包含空白", 400);
  const duplicate = await env.DB.prepare("SELECT id FROM admins WHERE username=? AND id<>?").bind(username, adminId).first<{ id: number }>();
  if (duplicate) return apiError("管理员账号已存在", 409);
  const isSuper = body.is_super === undefined ? Boolean(current.is_super) : Boolean(body.is_super);
  if (current.is_super && !isSuper) {
    const superAdminCount = await count(env, "SELECT COUNT(*) AS count FROM admins WHERE is_super=1", []);
    if (superAdminCount <= 1) return apiError("至少保留一个超级管理员", 400);
  }
  const password = String(body.password || "");
  if (password) {
    if (password.length < 8) return apiError("密码至少 8 位", 400);
    const salt = randomToken().slice(0, 16);
    const passwordHash = await hashPassword(password, salt);
    await env.DB.prepare(
      "UPDATE admins SET username=?, password_salt=?, password_hash=?, is_super=?, updated_at=CURRENT_TIMESTAMP WHERE id=?"
    ).bind(username, salt, passwordHash, isSuper ? 1 : 0, adminId).run();
    await env.DB.prepare("DELETE FROM admin_sessions WHERE admin_id=?").bind(adminId).run();
  } else {
    await env.DB.prepare(
      "UPDATE admins SET username=?, is_super=?, updated_at=CURRENT_TIMESTAMP WHERE id=?"
    ).bind(username, isSuper ? 1 : 0, adminId).run();
  }
  if (isSuper) {
    await ensureDefaultAuthz(env);
    await env.DB.prepare("INSERT OR IGNORE INTO authz_admin_roles (admin_id, role) VALUES (?, 'role:super_admin')")
      .bind(adminId)
      .run();
  } else {
    await env.DB.prepare("DELETE FROM authz_admin_roles WHERE admin_id=? AND role='role:super_admin'")
      .bind(adminId)
      .run();
  }
  await recordAuthzAudit(env, operator, "admin_update", { targetAdminId: adminId, targetUsername: username }, {
    target_admin_id: adminId,
    target_username: username,
    detail: { is_super: isSuper, password_changed: Boolean(password) }
  });
  return apiOk({ id: adminId, username, is_super: isSuper });
}

async function apiAdminAuthzDeleteAdmin(env: Env, adminId: number, operator: AdminSessionUser): Promise<Response> {
  if (!adminId) return apiError("管理员不存在", 404);
  if (adminId === operator.id) return apiError("不能删除当前登录管理员", 400);
  const current = await env.DB.prepare("SELECT id, username, is_super FROM admins WHERE id=?").bind(adminId).first<{ id: number; username: string; is_super: number }>();
  if (!current) return apiError("管理员不存在", 404);
  const total = await count(env, "SELECT COUNT(*) AS count FROM admins", []);
  if (total <= 1) return apiError("至少保留一个管理员", 400);
  if (current.is_super) {
    const superAdminCount = await count(env, "SELECT COUNT(*) AS count FROM admins WHERE is_super=1", []);
    if (superAdminCount <= 1) return apiError("至少保留一个超级管理员", 400);
  }
  await env.DB.prepare("DELETE FROM admins WHERE id=?").bind(adminId).run();
  await recordAuthzAudit(env, operator, "admin_delete", { targetAdminId: adminId, targetUsername: current.username }, {
    target_admin_id: adminId,
    target_username: current.username
  });
  return apiOk({});
}

