async function apiAdminUpdateUser(request: Request, env: Env, id: number): Promise<Response> {
  const body = await readJson(request);
  const current = await getUserById(env, id);
  if (!current) return apiError("用户不存在", 404);
  const email = normalizeEmail(body.email || current.email);
  if (!email) return apiError("邮箱格式不正确", 400);
  const exists = await env.DB.prepare("SELECT id FROM users WHERE email=? AND id<>?").bind(email, id).first<{ id: number }>();
  if (exists) return apiError("邮箱已被使用", 409);
  const nickname = clean(body.nickname ?? current.nickname, 80) || email.split("@")[0];
  const locale = clean(body.locale ?? current.locale, 20) || "zh-CN";
  const status = clean(body.status ?? current.status, 30) === "disabled" ? "disabled" : "active";
  const adminNote = clean(body.admin_note ?? current.admin_note, 1000);
  const emailVerified = body.email_verified === undefined
    ? current.email_verified_at
    : body.email_verified
      ? (current.email_verified_at || new Date().toISOString())
      : null;
  const password = String(body.password || "");
  if (password) {
    if (password.length < 6) return apiError("密码至少 6 位", 400);
    const salt = randomToken().slice(0, 16);
    const passwordHash = await hashPassword(password, salt);
    await env.DB.prepare(
      `UPDATE users SET email=?, password_salt=?, password_hash=?, nickname=?, display_name=?, locale=?,
       status=?, email_verified_at=?, admin_note=?, updated_at=CURRENT_TIMESTAMP WHERE id=?`
    ).bind(email, salt, passwordHash, nickname, nickname, locale, status, emailVerified, adminNote, id).run();
  } else {
    await env.DB.prepare(
      `UPDATE users SET email=?, nickname=?, display_name=?, locale=?, status=?, email_verified_at=?,
       admin_note=?, updated_at=CURRENT_TIMESTAMP WHERE id=?`
    ).bind(email, nickname, nickname, locale, status, emailVerified, adminNote, id).run();
  }
  const fresh = await getUserById(env, id);
  return apiOk(formatUser(fresh || current));
}

async function apiAdminBatchUserStatus(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const ids = arrayNumbers(body.user_ids || body.ids);
  const status = clean(body.status, 30) === "disabled" ? "disabled" : "active";
  let success = 0;
  for (const chunk of chunkNumbers(ids, 100)) {
    if (!chunk.length) continue;
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(
      `UPDATE users SET status=?, updated_at=CURRENT_TIMESTAMP WHERE id IN (${placeholders})`
    ).bind(status, ...chunk).run();
    success += Number(result.meta.changes || 0);
  }
  return apiOk({ success_count: success });
}

