async function apiAdminNotificationCenterLogs(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const where = ["scene LIKE 'notification_%'"];
  const params: unknown[] = [];
  const channel = clean(url.searchParams.get("channel"), 40);
  const status = clean(url.searchParams.get("status"), 40);
  const eventType = clean(url.searchParams.get("event_type"), 80);
  const isTest = clean(url.searchParams.get("is_test"), 20);
  const createdFrom = clean(url.searchParams.get("created_from"), 80);
  const createdTo = clean(url.searchParams.get("created_to"), 80);

  if (channel && channel !== "email") where.push("1=0");
  if (status) {
    where.push("status=?");
    params.push(status === "success" ? "sent" : status);
  }
  if (eventType) {
    where.push("scene=?");
    params.push(`notification_${eventType}`);
  }
  if (isTest === "true") where.push("dedupe_key LIKE 'notification-test:%'");
  if (isTest === "false") where.push("dedupe_key NOT LIKE 'notification-test:%'");
  if (createdFrom) {
    where.push("created_at>=?");
    params.push(createdFrom);
  }
  if (createdTo) {
    where.push("created_at<=?");
    params.push(createdTo);
  }

  const whereSql = `WHERE ${where.join(" AND ")}`;
  const total = await count(env, `SELECT COUNT(*) AS count FROM email_delivery_logs ${whereSql}`, params);
  const rows = await env.DB.prepare(
    `SELECT * FROM email_delivery_logs ${whereSql} ORDER BY id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<{
    id: number;
    scene: string;
    recipient: string;
    subject: string;
    body: string;
    provider: string;
    status: string;
    provider_message_id: string;
    order_id: number;
    user_id: number;
    dedupe_key: string;
    error_message: string;
    created_at: string;
  }>();
  const data = (rows.results || []).map((row) => ({
    id: row.id,
    event_type: clean(row.scene, 100).replace(/^notification_/, ""),
    biz_type: "email_delivery",
    biz_id: Number(row.order_id || row.user_id || 0),
    channel: "email",
    recipient: normalizeEmail(row.recipient) || row.recipient || "",
    locale: "",
    title: row.subject || "",
    body: row.body || "",
    status: row.status === "sent" ? "success" : "failed",
    error_message: row.error_message || "",
    is_test: clean(row.dedupe_key, 200).startsWith("notification-test:"),
    variables: {
      provider: row.provider || "",
      provider_message_id: row.provider_message_id || ""
    },
    created_at: row.created_at || ""
  }));
  return apiOk(data, pagination(page, size, total));
}

async function apiAdminTestNotificationCenterSettings(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const channel = clean(body.channel || "email", 40);
  if (channel !== "email") return apiError("Telegram 通知暂未接入，请先使用邮件通道测试", 400);
  const recipient = normalizeEmail(body.target || body.email || body.to);
  if (!recipient) return apiError("请输入有效的通知测试邮箱", 400);
  const scene = normalizeNotificationScene(body.scene);
  const locale = normalizeEmailLocale(body.locale);
  const siteName = await siteIssuerName(env);
  const siteUrl = await sitePublicUrl(env);
  const template = await selectNotificationEmailTemplate(env, scene, locale);
  const variables: AnyRecord = {
    site_name: siteName,
    site_url: siteUrl,
    scene: notificationSceneLabelForEmail(scene),
    recipient,
    order_no: "测试订单",
    order_status: "测试通知",
    amount: "0.00",
    currency: "CNY",
    guest_email: recipient,
    now: new Date().toISOString()
  };
  const subject = renderEmailTemplate(template.title, variables);
  const text = renderEmailTemplate(template.body, variables);
  const result = await sendTransactionalEmail(env, {
    to: recipient,
    subject,
    text,
    html: textToHtml(text),
    scene: `notification_${scene}`,
    dedupeKey: `notification-test:${scene}:${Date.now()}:${Math.random().toString(16).slice(2)}`
  });
  if (!result.sent) return apiError(result.error || "通知测试发送失败", 502);
  return apiOk({ sent: true, provider: result.provider, message_id: result.messageId || "" });
}

async function selectNotificationEmailTemplate(env: Env, scene: string, locale: string): Promise<{ title: string; body: string }> {
  const settings = await setting(env, "notification_center", defaultNotificationCenterSettings());
  const templates = jsonObject(settings.templates);
  const sceneTemplate = jsonObject(templates[scene]);
  const lang = normalizeEmailLocale(locale || settings.default_locale);
  const localized = jsonObject(sceneTemplate[lang] || sceneTemplate["zh-CN"] || sceneTemplate["en-US"]);
  const label = notificationSceneLabelForEmail(scene);
  const fallback = defaultNotificationEmailTemplate(scene);
  return {
    title: templateText(localized.title, fallback.title || `【{{site_name}}】${label}`, 500),
    body: templateText(localized.body, fallback.body, 200000)
  };
}

function defaultNotificationEmailTemplate(scene: string): { title: string; body: string } {
  if (scene === "order_paid_success") {
    return {
      title: "【{{site_name}}】订单 {{order_no}} 已支付",
      body: "订单 {{order_no}} 已支付。\n状态：{{order_status}}\n金额：{{amount}} {{currency}}\n客户邮箱：{{guest_email}}\n站点：{{site_url}}\n时间：{{now}}"
    };
  }
  if (scene === "manual_fulfillment_pending") {
    return {
      title: "【{{site_name}}】订单 {{order_no}} 待人工发货",
      body: "订单 {{order_no}} 需要人工发货。\n状态：{{order_status}}\n金额：{{amount}} {{currency}}\n客户邮箱：{{guest_email}}\n站点：{{site_url}}\n时间：{{now}}"
    };
  }
  if (scene === "wallet_recharge_success") {
    return {
      title: "【{{site_name}}】余额充值成功",
      body: "余额充值成功。\n站点：{{site_url}}\n时间：{{now}}"
    };
  }
  return {
    title: "【{{site_name}}】{{scene}}",
    body: "这是一封来自 {{site_name}} 的通知中心邮件。\n通知场景：{{scene}}\n站点地址：{{site_url}}\n发送时间：{{now}}"
  };
}

async function sendNotificationCenterEmail(env: Env, sceneInput: string, context: AnyRecord = {}): Promise<void> {
  try {
    const scene = normalizeNotificationScene(sceneInput);
    const settings = await setting(env, "notification_center", defaultNotificationCenterSettings());
    const scenes = jsonObject(settings.scenes);
    if (scenes[scene] !== true) return;
    const emailChannel = jsonObject(jsonObject(settings.channels).email);
    if (emailChannel.enabled !== true) return;
    const recipients = normalizeEmailRecipients(emailChannel.recipients);
    if (!recipients.length) return;
    const mail = await smtpSettings(env);
    if (mail.enabled !== true) return;

    const locale = normalizeEmailLocale(settings.default_locale);
    const template = await selectNotificationEmailTemplate(env, scene, locale);
    const variables = await notificationEmailVariables(env, scene, context);
    const subject = renderEmailTemplate(template.title, variables);
    const text = renderEmailTemplate(template.body, variables);
    if (!subject || !text) return;
    const orderId = toInt(context.orderId, 0);
    const userId = toInt(context.userId, 0);
    for (const recipient of recipients) {
      await sendTransactionalEmail(env, {
        to: recipient,
        subject,
        text,
        html: textToHtml(text),
        scene: `notification_${scene}`,
        orderId,
        userId,
        dedupeKey: `notification:${scene}:${orderId || userId || clean(context.reference, 120) || Date.now()}:${recipient}`
      });
    }
  } catch (error) {
    console.warn("notification_email_failed", error);
  }
}

async function notificationEmailVariables(env: Env, scene: string, context: AnyRecord): Promise<AnyRecord> {
  const siteName = await siteIssuerName(env);
  const siteUrl = await sitePublicUrl(env);
  const variables: AnyRecord = {
    site_name: siteName,
    site_url: siteUrl,
    scene: notificationSceneLabelForEmail(scene),
    now: new Date().toISOString(),
    order_id: "",
    order_no: "",
    order_status: "",
    amount: "0.00",
    currency: "CNY",
    guest_email: ""
  };
  const orderId = toInt(context.orderId, 0);
  if (orderId) {
    const order = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(orderId).first<OrderRow>();
    if (order) {
      variables.order_id = String(order.id);
      variables.order_no = order.order_no || "";
      variables.order_status = orderStatusLabelForEmail(order.status);
      variables.amount = money(Number(order.total_amount || 0));
      variables.currency = order.currency || "CNY";
      variables.guest_email = order.guest_email || "";
    }
  } else {
    variables.order_no = "测试订单";
    variables.order_status = "测试通知";
    variables.guest_email = normalizeEmail(context.recipient) || "";
  }
  return { ...variables, ...context };
}

function normalizeEmailRecipients(value: unknown): string[] {
  const input = Array.isArray(value) ? value : String(value ?? "").split(/[\n,;]/);
  const seen = new Set<string>();
  const recipients: string[] = [];
  for (const item of input) {
    const email = normalizeEmail(item);
    if (!email || seen.has(email)) continue;
    seen.add(email);
    recipients.push(email);
  }
  return recipients;
}

function normalizeNotificationScene(value: unknown): string {
  const scene = clean(value, 80);
  return ["wallet_recharge_success", "order_paid_success", "manual_fulfillment_pending", "exception_alert"].includes(scene)
    ? scene
    : "exception_alert";
}

function notificationSceneLabelForEmail(scene: string): string {
  const labels: Record<string, string> = {
    wallet_recharge_success: "余额充值成功",
    order_paid_success: "订单支付成功",
    manual_fulfillment_pending: "人工发货待处理",
    exception_alert: "异常告警"
  };
  return labels[scene] || scene || "系统通知";
}

