async function apiAdminDeletePostCategory(env: Env, id: number): Promise<Response> {
  const existing = await env.DB.prepare("SELECT id FROM post_categories WHERE id=?").bind(id).first<{ id: number }>();
  if (!existing) return apiError("文章分类不存在", 404);
  const childCount = await count(env, "SELECT COUNT(*) AS count FROM post_categories WHERE parent_id=?", [id]);
  const postCount = await count(env, "SELECT COUNT(*) AS count FROM posts WHERE category_id=?", [id]);
  if (childCount > 0 || postCount > 0) return apiError("文章分类正在使用中", 400);
  await env.DB.prepare("DELETE FROM post_categories WHERE id=?").bind(id).run();
  return apiOk({});
}

function normalizePostCategoryInput(body: AnyRecord): { name: AnyRecord; slug: string; parentId: number | null; sortOrder: number; icon: string } {
  const name = normalizeLocalized(body.name, "未命名分类");
  return {
    name,
    slug: clean(body.slug, 160) || slugify(localizedFirst(name)),
    parentId: toInt(body.parent_id, 0) || null,
    sortOrder: toInt(body.sort_order, 0),
    icon: clean(body.icon, 500)
  };
}

async function validatePostCategoryInput(
  env: Env,
  input: { slug: string; parentId: number | null },
  id?: number
): Promise<{ ok: true } | { ok: false; error: string; status: number }> {
  if (!input.slug) return { ok: false, error: "分类标识不能为空", status: 400 };
  const duplicate = await env.DB.prepare("SELECT id FROM post_categories WHERE slug=? AND (? IS NULL OR id<>?)")
    .bind(input.slug, id ?? null, id ?? null)
    .first<{ id: number }>();
  if (duplicate) return { ok: false, error: "分类标识已存在", status: 409 };
  if (!input.parentId) return { ok: true };
  if (id && input.parentId === id) return { ok: false, error: "父级分类不合法", status: 400 };
  const parent = await env.DB.prepare("SELECT * FROM post_categories WHERE id=?").bind(input.parentId).first<PostCategoryRow>();
  if (!parent || Number(parent.parent_id || 0) > 0) return { ok: false, error: "父级分类不合法", status: 400 };
  if (id) {
    const childCount = await count(env, "SELECT COUNT(*) AS count FROM post_categories WHERE parent_id=?", [id]);
    if (childCount > 0) return { ok: false, error: "父级分类不合法", status: 400 };
  }
  return { ok: true };
}

async function validatePostCategoryAssignment(
  env: Env,
  postType: string,
  categoryId: number | null,
  postId?: number
): Promise<{ ok: true } | { ok: false; error: string }> {
  if (postType === "notice" && categoryId) return { ok: false, error: "post_notice_category_unsupported" };
  if (!categoryId) return { ok: true };
  const category = await env.DB.prepare("SELECT * FROM post_categories WHERE id=?").bind(categoryId).first<PostCategoryRow>();
  if (!category) return { ok: false, error: "post_category_invalid" };
  const current = postId
    ? await env.DB.prepare("SELECT category_id FROM posts WHERE id=?").bind(postId).first<{ category_id: number | null }>()
    : null;
  const sameAsCurrent = Number(current?.category_id || 0) === categoryId;
  if (!category.is_active && !sameAsCurrent) return { ok: false, error: "post_category_invalid" };
  const childCount = await count(env, "SELECT COUNT(*) AS count FROM post_categories WHERE parent_id=?", [categoryId]);
  if (childCount > 0 && !sameAsCurrent) return { ok: false, error: "post_category_invalid" };
  return { ok: true };
}

async function apiPublicPosts(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const type = clean(url.searchParams.get("type"), 30);
  const search = clean(url.searchParams.get("search"), 120);
  const categoryId = toInt(url.searchParams.get("category_id"), 0);
  const params: unknown[] = [new Date().toISOString()];
  let where = "WHERE is_published=1 AND (published_at IS NULL OR published_at <= ?)";
  if (type && type !== "__all__") {
    where += " AND type=?";
    params.push(type);
  }
  if (search) {
    where += " AND (title_json LIKE ? OR summary_json LIKE ?)";
    params.push(`%${search}%`, `%${search}%`);
  }
  if (categoryId > 0) {
    where += " AND category_id=?";
    params.push(categoryId);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM posts ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT * FROM posts ${where} ORDER BY COALESCE(published_at, created_at) DESC, id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<PostRow>();
  return apiOk((rows.results || []).map(formatPost), pagination(page, size, total));
}

async function apiPublicPost(env: Env, slug: string): Promise<Response> {
  const row = await env.DB.prepare(
    "SELECT * FROM posts WHERE slug=? AND is_published=1 AND (published_at IS NULL OR published_at <= ?)"
  ).bind(slug, new Date().toISOString()).first<PostRow>();
  if (!row) return apiError("文章不存在", 404);
  const relatedProducts = await relatedProductsForPost(env, row.id);
  return apiOk({ ...formatPost(row), related_products: relatedProducts });
}

