async function apiAdminPromotions(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const id = toInt(url.searchParams.get("id"), 0);
  const name = clean(url.searchParams.get("name"), 120);
  const scopeRefId = toInt(url.searchParams.get("scope_ref_id"), 0);
  const isActive = clean(url.searchParams.get("is_active"), 20);
  if (id > 0) {
    where += " AND id=?";
    params.push(id);
  }
  if (name) {
    where += " AND name LIKE ?";
    params.push(`%${name}%`);
  }
  if (scopeRefId > 0) {
    where += " AND scope_ref_id=?";
    params.push(scopeRefId);
  }
  if (isActive === "true" || isActive === "false") {
    where += " AND is_active=?";
    params.push(isActive === "true" ? 1 : 0);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM promotions ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT * FROM promotions ${where} ORDER BY id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<PromotionRow>();
  return apiOk((rows.results || []).map(formatPromotion), pagination(page, size, total));
}

