async function savePromotion(env: Env, body: AnyRecord, id?: number): Promise<number> {
  const name = clean(body.name, 160);
  const type = ["percent", "fixed", "special_price"].includes(clean(body.type, 30)) ? clean(body.type, 30) : "percent";
  const scopeRefId = toInt(body.scope_ref_id, 0);
  const value = Math.max(0, numberValue(body.value, 0));
  const minAmount = Math.max(0, numberValue(body.min_amount, 0));
  const startsAt = normalizeDateString(body.starts_at);
  const endsAt = normalizeDateString(body.ends_at);
  const isActive = boolInt(body.is_active, true);
  if (id) {
    await env.DB.prepare(
      `UPDATE promotions
       SET name=?, scope_type='product', scope_ref_id=?, type=?, value=?, min_amount=?,
           starts_at=?, ends_at=?, is_active=?, updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    ).bind(name, scopeRefId, type, money(value), money(minAmount), startsAt, endsAt, isActive, id).run();
    return id;
  }
  const result = await env.DB.prepare(
    `INSERT INTO promotions (name, scope_type, scope_ref_id, type, value, min_amount, starts_at, ends_at, is_active)
     VALUES (?, 'product', ?, ?, ?, ?, ?, ?, ?)`
  ).bind(name, scopeRefId, type, money(value), money(minAmount), startsAt, endsAt, isActive).run();
  return Number(result.meta.last_row_id);
}

function validatePromotionPayload(body: AnyRecord): { ok: true } | { ok: false; error: string } {
  const name = clean(body.name, 160);
  const scopeRefId = toInt(body.scope_ref_id, 0);
  const value = numberValue(body.value, NaN);
  if (!name) return { ok: false, error: "促销名称不能为空" };
  if (scopeRefId <= 0) return { ok: false, error: "请选择促销商品" };
  if (!Number.isFinite(value) || value <= 0) return { ok: false, error: "促销数值必须大于 0" };
  const type = clean(body.type, 30);
  if (!["percent", "fixed", "special_price"].includes(type)) return { ok: false, error: "促销类型不正确" };
  if (type === "percent" && value > 100) return { ok: false, error: "百分比优惠不能超过 100" };
  const startsRaw = clean(body.starts_at, 80);
  const endsRaw = clean(body.ends_at, 80);
  const startsAt = normalizeDateString(startsRaw);
  const endsAt = normalizeDateString(endsRaw);
  if (startsRaw && !startsAt) return { ok: false, error: "促销开始时间不正确" };
  if (endsRaw && !endsAt) return { ok: false, error: "促销结束时间不正确" };
  if (startsAt && endsAt && new Date(endsAt).getTime() < new Date(startsAt).getTime()) {
    return { ok: false, error: "促销结束时间不能早于开始时间" };
  }
  return { ok: true };
}

