async function apiAdminDeleteMemberLevel(env: Env, id: number): Promise<Response> {
  const level = await env.DB.prepare("SELECT id, is_default FROM member_levels WHERE id=?")
    .bind(id)
    .first<{ id: number; is_default: number }>();
  if (!level) return apiError("会员等级不存在", 404);
  if (level.is_default) return apiError("默认会员等级不能删除", 400);
  await env.DB.prepare("UPDATE users SET member_level_id=0, updated_at=CURRENT_TIMESTAMP WHERE member_level_id=?").bind(id).run();
  await env.DB.prepare("DELETE FROM member_level_prices WHERE member_level_id=?").bind(id).run();
  await env.DB.prepare("DELETE FROM member_levels WHERE id=?").bind(id).run();
  return apiOk({});
}

