async function apiAdminBatchUpsertMemberLevelPrices(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const prices = Array.isArray(body.prices) ? body.prices : [];
  let upserted = 0;
  let deleted = 0;
  for (const item of prices) {
    const memberLevelId = toInt(item?.member_level_id, 0);
    const productId = toInt(item?.product_id, 0);
    const skuId = toInt(item?.sku_id, 0);
    const priceAmount = Number(item?.price_amount);
    if (memberLevelId <= 0 || productId <= 0 || !Number.isFinite(priceAmount)) continue;
    if (priceAmount <= 0) {
      const result = await env.DB.prepare(
        "DELETE FROM member_level_prices WHERE member_level_id=? AND product_id=? AND sku_id=?"
      ).bind(memberLevelId, productId, skuId).run();
      deleted += Number(result.meta.changes || 0);
      continue;
    }
    await env.DB.prepare(
      `INSERT INTO member_level_prices (member_level_id, product_id, sku_id, price_amount)
       VALUES (?, ?, ?, ?)
       ON CONFLICT(member_level_id, product_id, sku_id)
       DO UPDATE SET price_amount=excluded.price_amount, updated_at=CURRENT_TIMESTAMP`
    ).bind(memberLevelId, productId, skuId, money(priceAmount)).run();
    upserted++;
  }
  return apiOk({ upserted, deleted });
}

async function apiAdminDeleteMemberLevelPrice(env: Env, id: number): Promise<Response> {
  await env.DB.prepare("DELETE FROM member_level_prices WHERE id=?").bind(id).run();
  return apiOk({});
}

async function saveMemberLevel(env: Env, body: AnyRecord, id?: number): Promise<number> {
  const slug = slugify(clean(body.slug, 120));
  const name = normalizeLocalized(body.name, slug);
  const icon = clean(body.icon, 255);
  const discountRate = Math.max(0, Math.min(100, numberValue(body.discount_rate, 100)));
  const rechargeThreshold = Math.max(0, numberValue(body.recharge_threshold, 0));
  const spendThreshold = Math.max(0, numberValue(body.spend_threshold, 0));
  const isDefault = boolInt(body.is_default, false);
  const sortOrder = toInt(body.sort_order, 0);
  const isActive = boolInt(body.is_active, true);

  if (isDefault) {
    await env.DB.prepare("UPDATE member_levels SET is_default=0, updated_at=CURRENT_TIMESTAMP WHERE (? IS NULL OR id<>?)")
      .bind(id ?? null, id ?? null)
      .run();
  }

  if (id) {
    await env.DB.prepare(
      `UPDATE member_levels
       SET name_json=?, slug=?, icon=?, discount_rate=?, recharge_threshold=?, spend_threshold=?,
           is_default=?, sort_order=?, is_active=?, updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    ).bind(
      stringify(name),
      slug,
      icon,
      money(discountRate),
      money(rechargeThreshold),
      money(spendThreshold),
      isDefault,
      sortOrder,
      isActive,
      id
    ).run();
    return id;
  }

  const result = await env.DB.prepare(
    `INSERT INTO member_levels (
      name_json, slug, icon, discount_rate, recharge_threshold, spend_threshold,
      is_default, sort_order, is_active
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).bind(
    stringify(name),
    slug,
    icon,
    money(discountRate),
    money(rechargeThreshold),
    money(spendThreshold),
    isDefault,
    sortOrder,
    isActive
  ).run();
  return Number(result.meta.last_row_id);
}

async function validateMemberLevelPayload(
  env: Env,
  body: AnyRecord,
  id?: number
): Promise<{ ok: true } | { ok: false; error: string; status: number }> {
  const slug = slugify(clean(body.slug, 120));
  if (!slug) return { ok: false, error: "等级标识不能为空", status: 400 };
  const duplicate = await env.DB.prepare("SELECT id FROM member_levels WHERE slug=? AND (? IS NULL OR id<>?)")
    .bind(slug, id ?? null, id ?? null)
    .first<{ id: number }>();
  if (duplicate) return { ok: false, error: "等级标识已存在", status: 409 };
  if (boolInt(body.is_active, true)) {
    const sortOrder = toInt(body.sort_order, 0);
    const duplicateSort = await env.DB.prepare(
      "SELECT id FROM member_levels WHERE is_active=1 AND sort_order=? AND (? IS NULL OR id<>?) LIMIT 1"
    ).bind(sortOrder, id ?? null, id ?? null).first<{ id: number }>();
    if (duplicateSort) return { ok: false, error: "启用中的会员等级排序值不能重复", status: 400 };
  }
  return { ok: true };
}

