async function savePost(env: Env, body: AnyRecord, id?: number): Promise<number> {
  const title = normalizeLocalized(body.title, "未命名文章");
  const slug = clean(body.slug, 160) || slugify(localizedFirst(title));
  const type = clean(body.type, 30) === "notice" ? "notice" : "blog";
  const content = sanitizeLocalizedHtml(body.content);
  const categoryId = type === "notice" ? null : (toInt(body.category_id, 0) || null);
  const categoryValid = await validatePostCategoryAssignment(env, type, categoryId, id);
  if (!categoryValid.ok) throw new Error(categoryValid.error);
  const publishedAt = boolInt(body.is_published, true) ? new Date().toISOString() : "";
  if (id) {
    await env.DB.prepare(
      `UPDATE posts SET slug=?, type=?, title_json=?, summary_json=?, content_json=?,
       thumbnail=?, category_id=?, is_published=?, published_at=CASE WHEN ?=1 AND published_at IS NULL THEN ? WHEN ?=0 THEN NULL ELSE published_at END,
       updated_at=CURRENT_TIMESTAMP WHERE id=?`
    ).bind(
      slug,
      type,
      JSON.stringify(title),
      stringify(normalizeLocalized(body.summary, "")),
      JSON.stringify(content),
      clean(body.thumbnail, 500),
      categoryId,
      boolInt(body.is_published, true),
      boolInt(body.is_published, true),
      publishedAt,
      boolInt(body.is_published, true),
      id
    ).run();
  } else {
    const insert = await env.DB.prepare(
      `INSERT INTO posts (slug, type, title_json, summary_json, content_json, thumbnail, category_id, is_published, published_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
    ).bind(
      slug,
      type,
      JSON.stringify(title),
      stringify(normalizeLocalized(body.summary, "")),
      JSON.stringify(content),
      clean(body.thumbnail, 500),
      categoryId,
      boolInt(body.is_published, true),
      boolInt(body.is_published, true) ? publishedAt : null
    ).run();
    id = Number(insert.meta.last_row_id);
  }
  await syncPostProducts(env, id, arrayNumbers(body.product_ids));
  return id;
}

async function syncPostProducts(env: Env, postId: number, productIds: number[]): Promise<void> {
  await env.DB.prepare("DELETE FROM post_products WHERE post_id=?").bind(postId).run();
  for (const productId of productIds) {
    await env.DB.prepare("INSERT OR IGNORE INTO post_products (post_id, product_id) VALUES (?, ?)")
      .bind(postId, productId)
      .run();
  }
}

async function relatedProductsForPost(env: Env, postId: number): Promise<AnyRecord[]> {
  const rows = await env.DB.prepare(
    `SELECT p.* FROM products p
     INNER JOIN post_products pp ON pp.product_id=p.id
     WHERE pp.post_id=?
     ORDER BY p.sort_order ASC, p.id DESC`
  ).bind(postId).all<ProductRow>();
  const products = await Promise.all((rows.results || []).map((row) => hydrateProduct(env, row, { publicOnly: true })));
  return products;
}

async function relatedPostsForProduct(env: Env, productId: number): Promise<AnyRecord[]> {
  const rows = await env.DB.prepare(
    `SELECT p.* FROM posts p
     INNER JOIN post_products pp ON pp.post_id=p.id
     WHERE pp.product_id=? AND p.is_published=1
     ORDER BY COALESCE(p.published_at, p.created_at) DESC, p.id DESC
     LIMIT 10`
  ).bind(productId).all<PostRow>();
  return (rows.results || []).map(formatPost);
}

