async function saveBanner(env: Env, body: AnyRecord, id?: number): Promise<number> {
  const title = normalizeLocalized(body.title, "");
  const subtitle = normalizeLocalized(body.subtitle, "");
  const startAt = normalizeDateString(body.start_at);
  const endAt = normalizeDateString(body.end_at);
  const linkType = ["none", "internal", "external"].includes(clean(body.link_type, 20)) ? clean(body.link_type, 20) : "none";
  const params = [
    clean(body.name, 160),
    clean(body.position, 60) || "home_hero",
    JSON.stringify(title),
    JSON.stringify(subtitle),
    clean(body.image, 500),
    clean(body.mobile_image, 500),
    linkType,
    linkType === "none" ? "" : clean(body.link_value, 500),
    boolInt(body.open_in_new_tab, false),
    boolInt(body.is_active, true),
    startAt || null,
    endAt || null,
    toInt(body.sort_order, 0)
  ];
  if (id) {
    await env.DB.prepare(
      `UPDATE banners SET name=?, position=?, title_json=?, subtitle_json=?, image=?,
       mobile_image=?, link_type=?, link_value=?, open_in_new_tab=?, is_active=?,
       start_at=?, end_at=?, sort_order=?, updated_at=CURRENT_TIMESTAMP WHERE id=?`
    ).bind(...params, id).run();
    return id;
  }
  const insert = await env.DB.prepare(
    `INSERT INTO banners (name, position, title_json, subtitle_json, image, mobile_image,
      link_type, link_value, open_in_new_tab, is_active, start_at, end_at, sort_order)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).bind(...params).run();
  return Number(insert.meta.last_row_id);
}

