async function apiAdminDeleteProduct(env: Env, id: number): Promise<Response> {
  const result = await deleteProductSafely(env, id);
  if (result === "not_found") return apiError("商品不存在", 404);
  if (result === "has_stock") return apiError("商品仍有可用或锁定卡密，不能删除", 400);
  if (result === "has_order") return apiError("商品已有订单记录，不能删除", 400);
  return apiOk({});
}

async function deleteProductSafely(
  env: Env,
  id: number
): Promise<"deleted" | "not_found" | "has_stock" | "has_order"> {
  const product = await env.DB.prepare("SELECT id FROM products WHERE id=?").bind(id).first<{ id: number }>();
  if (!product) return "not_found";
  const stock = await count(
    env,
    "SELECT COUNT(*) AS count FROM card_secrets WHERE product_id=? AND status IN ('available','reserved')",
    [id]
  );
  if (stock > 0) return "has_stock";
  const orderItems = await count(env, "SELECT COUNT(*) AS count FROM order_items WHERE product_id=?", [id]);
  if (orderItems > 0) return "has_order";
  try {
    await env.DB.prepare("DELETE FROM products WHERE id=?").bind(id).run();
    return "deleted";
  } catch {
    const racedOrderItems = await count(env, "SELECT COUNT(*) AS count FROM order_items WHERE product_id=?", [id]);
    if (racedOrderItems > 0) return "has_order";
    throw new Error("product_delete_failed");
  }
}

