async function apiAdminBatchProductDelete(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const ids = arrayNumbers(body.ids);
  let successCount = 0;
  const failedIds: number[] = [];
  for (const id of ids) {
    const result = await deleteProductSafely(env, id);
    if (result === "deleted") successCount++;
    else failedIds.push(id);
  }
  return apiOk({ total: ids.length, success_count: successCount, failed_ids: failedIds });
}

