async function apiAdminCardSecretStats(env: Env, url: URL): Promise<Response> {
  const filter = cardSecretFilterFromUrl(url);
  const { where, params } = buildCardSecretWhere(filter);
  const row = await env.DB.prepare(
    `SELECT
       COUNT(*) AS total,
       COALESCE(SUM(CASE WHEN cs.status='available' THEN 1 ELSE 0 END), 0) AS available,
       COALESCE(SUM(CASE WHEN cs.status='reserved' THEN 1 ELSE 0 END), 0) AS reserved,
       COALESCE(SUM(CASE WHEN cs.status='used' THEN 1 ELSE 0 END), 0) AS used
     FROM card_secrets cs
     LEFT JOIN card_secret_batches b ON b.id = cs.batch_id
     ${where}`
  ).bind(...params).first<{ total: number; available: number; reserved: number; used: number }>();
  return apiOk({
    total: Number(row?.total || 0),
    available: Number(row?.available || 0),
    reserved: Number(row?.reserved || 0),
    used: Number(row?.used || 0)
  });
}

async function apiAdminCardSecretBatches(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const productId = toInt(url.searchParams.get("product_id"), 0);
  const skuId = toInt(url.searchParams.get("sku_id"), 0);
  const params: unknown[] = [];
  let where = "WHERE 1 = 1";
  if (productId > 0) {
    where += " AND b.product_id = ?";
    params.push(productId);
  }
  if (skuId > 0) {
    where += " AND b.sku_id = ?";
    params.push(skuId);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM card_secret_batches b ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT
       b.*,
       COUNT(cs.id) AS total_count,
       COALESCE(SUM(CASE WHEN cs.status='available' THEN 1 ELSE 0 END), 0) AS available_count,
       COALESCE(SUM(CASE WHEN cs.status='reserved' THEN 1 ELSE 0 END), 0) AS reserved_count,
       COALESCE(SUM(CASE WHEN cs.status='used' THEN 1 ELSE 0 END), 0) AS used_count
     FROM card_secret_batches b
     LEFT JOIN card_secrets cs ON cs.batch_id = b.id
     ${where}
     GROUP BY b.id
     ORDER BY b.id DESC
     LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<CardSecretBatchRow>();
  return apiOk((rows.results || []).map(formatCardSecretBatch), pagination(page, size, total));
}

