async function apiAdminCreateCardSecretBatch(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const productId = toInt(body.product_id, 0);
  const skuIdInput = toInt(body.sku_id, 0);
  const target = await resolveCardSecretTarget(env, productId, skuIdInput);
  if (!target.ok) return apiError(target.error, 400);
  const secrets = normalizeCardSecretLines(Array.isArray(body.secrets) ? body.secrets : []);
  if (!secrets.length) return apiError("卡密不能为空", 400);
  const result = await createCardSecretBatch(env, {
    productId: target.product.id,
    skuId: target.sku.id,
    secrets,
    batchNo: clean(body.batch_no, 80),
    source: "manual",
    note: clean(body.note, 1000),
    deduplicate: body.deduplicate !== false
  });
  return apiOk(result);
}

async function apiAdminImportCardSecrets(request: Request, env: Env): Promise<Response> {
  const form = await request.formData();
  const productId = toInt(form.get("product_id"), 0);
  const skuIdInput = toInt(form.get("sku_id"), 0);
  const target = await resolveCardSecretTarget(env, productId, skuIdInput);
  if (!target.ok) return apiError(target.error, 400);

  const file = form.get("file");
  if (!isUploadFile(file)) return apiError("请选择 CSV 文件", 400);
  if (file.size > 2 * 1024 * 1024) return apiError("CSV 文件不能超过 2MB", 400);
  const text = await file.text();
  const secrets = parseCardSecretImportText(text);
  if (!secrets.length) return apiError("CSV 中没有可导入的卡密", 400);
  const result = await createCardSecretBatch(env, {
    productId: target.product.id,
    skuId: target.sku.id,
    secrets,
    batchNo: clean(form.get("batch_no"), 80),
    source: "csv",
    note: clean(form.get("note"), 1000),
    deduplicate: clean(form.get("deduplicate"), 20).toLowerCase() !== "false"
  });
  return apiOk(result);
}

async function apiAdminUpdateCardSecret(request: Request, env: Env, id: number): Promise<Response> {
  const body = await readJson(request);
  const row = await env.DB.prepare("SELECT * FROM card_secrets WHERE id=?").bind(id).first<CardSecretRow>();
  if (!row) return apiError("卡密不存在", 404);

  const nextSecret = "secret" in body ? clean(body.secret, 4000) : row.secret;
  if (!nextSecret) return apiError("卡密不能为空", 400);
  const nextStatus = "status" in body ? clean(body.status, 30) : row.status;
  if (!isCardSecretStatus(nextStatus)) return apiError("卡密状态不合法", 400);
  const secretHash = await cardSecretHash(row.product_id, row.sku_id, nextSecret);
  await env.DB.prepare(
    `UPDATE card_secrets
     SET secret=?,
         secret_hash=?,
         status=?,
         order_id=CASE WHEN ?='available' THEN NULL ELSE order_id END,
         reserved_at=CASE
           WHEN ?='reserved' AND reserved_at IS NULL THEN CURRENT_TIMESTAMP
           WHEN ?='available' THEN NULL
           ELSE reserved_at
         END,
         used_at=CASE
           WHEN ?='used' AND used_at IS NULL THEN CURRENT_TIMESTAMP
           WHEN ?!='used' THEN NULL
           ELSE used_at
         END,
         updated_at=CURRENT_TIMESTAMP
     WHERE id=?`
  ).bind(
    nextSecret,
    secretHash,
    nextStatus,
    nextStatus,
    nextStatus,
    nextStatus,
    nextStatus,
    nextStatus,
    id
  ).run();
  const updated = await env.DB.prepare(
    `SELECT cs.*, b.batch_no AS batch_no, b.name AS batch_name, b.source AS batch_source, b.note AS batch_note, b.created_at AS batch_created_at
     FROM card_secrets cs LEFT JOIN card_secret_batches b ON b.id=cs.batch_id
     WHERE cs.id=?`
  ).bind(id).first<CardSecretRow>();
  return apiOk(updated ? formatCardSecret(updated) : {});
}

async function apiAdminBatchUpdateCardSecretStatus(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const status = clean(body.status, 30);
  if (!isCardSecretStatus(status)) return apiError("卡密状态不合法", 400);
  const ids = await cardSecretIdsForScope(env, body, 20000);
  if (!ids.length) return apiOk({ affected: 0 });
  const affected = await updateCardSecretStatusByIds(env, ids, status);
  return apiOk({ affected });
}

async function apiAdminBatchDeleteCardSecrets(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const ids = await cardSecretIdsForScope(env, body, 20000);
  if (!ids.length) return apiOk({ affected: 0 });
  let affected = 0;
  for (const chunk of chunkNumbers(ids, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(`DELETE FROM card_secrets WHERE id IN (${placeholders})`).bind(...chunk).run();
    affected += Number(result.meta.changes || 0);
  }
  await deleteEmptyCardSecretBatches(env);
  return apiOk({ affected });
}

async function apiAdminExportCardSecrets(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const format = normalizeExportFormat(body.format);
  const ids = await cardSecretIdsForScope(env, body, 20000);
  if (!ids.length) return apiError("没有可导出的卡密", 404);
  const rows = await cardSecretsByIds(env, ids);
  return cardSecretExportResponse(rows, format, "card-secrets");
}

async function apiAdminExportAvailableCardSecrets(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const productId = toInt(body.product_id, 0);
  const skuId = toInt(body.sku_id, 0);
  const batchId = toInt(body.batch_id, 0);
  const limit = strictPositiveInteger(body.limit);
  const format = normalizeExportFormat(body.format);
  if (!productId) return apiError("请选择商品", 400);
  if (!limit || limit > 10000) return apiError("出库数量不合法", 400);
  const product = await env.DB.prepare("SELECT fulfillment_type FROM products WHERE id=?")
    .bind(productId)
    .first<{ fulfillment_type: string }>();
  if (!product) return apiError("商品不存在", 404);
  if (clean(product.fulfillment_type, 40) !== "auto") return apiError("只有自动交付商品可以执行卡密出库", 400);
  if (skuId > 0) {
    const sku = await env.DB.prepare("SELECT id FROM product_skus WHERE id=? AND product_id=? AND is_active=1")
      .bind(skuId, productId)
      .first<{ id: number }>();
    if (!sku) return apiError("商品规格不存在或已停用", 400);
  }
  const selected = await claimAvailableCardSecretsForExport(env, {
    productId,
    skuId,
    batchId,
    limit,
    deleteAfterExport: body.delete_after_export === true
  });
  if (!selected.length) {
    const available = await availableCardSecretExportCount(env, productId, skuId, batchId);
    if (available <= 0) return apiError("没有可导出的可用卡密", 404);
    return apiError(`可用卡密不足，当前仅剩 ${available} 张`, 409);
  }
  if (body.delete_after_export === true) await deleteEmptyCardSecretBatches(env);
  return cardSecretExportResponse(selected, format, "card-secrets-available");
}

async function apiAdminCoupons(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1 = 1";
  const id = toInt(url.searchParams.get("id"), 0);
  const code = clean(url.searchParams.get("code"), 80);
  const scopeRefId = toInt(url.searchParams.get("scope_ref_id"), 0);
  const isActive = clean(url.searchParams.get("is_active"), 20);
  if (id > 0) {
    where += " AND id = ?";
    params.push(id);
  }
  if (code) {
    where += " AND code LIKE ?";
    params.push(`%${code.toUpperCase()}%`);
  }
  if (scopeRefId > 0) {
    where += " AND EXISTS (SELECT 1 FROM json_each(coupons.scope_ref_ids_json) WHERE CAST(value AS INTEGER)=?)";
    params.push(scopeRefId);
  }
  if (isActive === "true" || isActive === "false") {
    where += " AND is_active = ?";
    params.push(isActive === "true" ? 1 : 0);
  }
  const total = await count(env, `SELECT COUNT(*) AS count FROM coupons ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT * FROM coupons ${where} ORDER BY id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<CouponRow>();
  return apiOk((rows.results || []).map(formatCoupon), pagination(page, size, total));
}

async function apiAdminCreateCoupon(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  let id = 0;
  try {
    id = await saveCoupon(env, body);
  } catch (error) {
    return apiError(error instanceof Error ? error.message : "优惠券保存失败", 400);
  }
  const row = await env.DB.prepare("SELECT * FROM coupons WHERE id=?").bind(id).first<CouponRow>();
  return apiOk(row ? formatCoupon(row) : {});
}

async function apiAdminUpdateCoupon(request: Request, env: Env, id: number): Promise<Response> {
  const existing = await env.DB.prepare("SELECT id FROM coupons WHERE id=?").bind(id).first<{ id: number }>();
  if (!existing) return apiError("优惠券不存在", 404);
  const body = await readJson(request);
  try {
    await saveCoupon(env, body, id);
  } catch (error) {
    return apiError(error instanceof Error ? error.message : "优惠券保存失败", 400);
  }
  const row = await env.DB.prepare("SELECT * FROM coupons WHERE id=?").bind(id).first<CouponRow>();
  return apiOk(row ? formatCoupon(row) : {});
}

async function apiAdminDeleteCoupon(env: Env, id: number): Promise<Response> {
  const existing = await env.DB.prepare("SELECT id FROM coupons WHERE id=?").bind(id).first<{ id: number }>();
  if (!existing) return apiError("优惠券不存在", 404);
  await env.DB.prepare("DELETE FROM coupons WHERE id=?").bind(id).run();
  return apiOk({});
}

async function saveCoupon(env: Env, body: AnyRecord, id?: number): Promise<number> {
  const existing = id
    ? await env.DB.prepare("SELECT * FROM coupons WHERE id=?").bind(id).first<CouponRow>()
    : null;
  const code = clean(body.code, 80).toUpperCase();
  if (!code) throw new Error("优惠券代码不能为空");
  const duplicate = await env.DB.prepare("SELECT id FROM coupons WHERE code=? AND (? IS NULL OR id<>?) LIMIT 1")
    .bind(code, id ?? null, id ?? null)
    .first<{ id: number }>();
  if (duplicate) throw new Error("优惠券代码已存在");
  const type = clean(body.type, 20).toLowerCase();
  if (!["fixed", "percent"].includes(type)) throw new Error("优惠券类型不正确");
  const value = numberValue(body.value, 0);
  if (value <= 0) throw new Error("优惠值必须大于 0");
  if (type === "percent" && value > 100) throw new Error("百分比优惠不能超过 100");
  const scopeIds = arrayNumbers(body.scope_ref_ids);
  if (!scopeIds.length) throw new Error("请选择适用商品");
  const rawPaymentRoles = Array.isArray(body.payment_roles) ? body.payment_roles : [];
  const paymentRoles = normalizeStringArray(rawPaymentRoles, ["guest", "member"]);
  const invalidPaymentRole = rawPaymentRoles.some((role) => {
    const normalized = clean(role, 80).toLowerCase();
    return normalized && !["guest", "member"].includes(normalized);
  });
  if (invalidPaymentRole) throw new Error("优惠券付款角色不正确");
  const memberLevels = arrayNumbers(body.member_levels);
  const startsRaw = clean(body.starts_at, 80);
  const endsRaw = clean(body.ends_at, 80);
  const startsAt = normalizeDateString(startsRaw);
  const endsAt = normalizeDateString(endsRaw);
  if (startsRaw && !startsAt) throw new Error("优惠券开始时间不正确");
  if (endsRaw && !endsAt) throw new Error("优惠券结束时间不正确");
  if (startsAt && endsAt && new Date(endsAt).getTime() < new Date(startsAt).getTime()) {
    throw new Error("优惠券结束时间不能早于开始时间");
  }
  const disabledWholesalePrice = Object.prototype.hasOwnProperty.call(body, "disabled_wholesale_price")
    ? boolInt(body.disabled_wholesale_price, false)
    : Number(existing?.disabled_wholesale_price || 0);
  const perItemDiscount = type === "fixed"
    ? (Object.prototype.hasOwnProperty.call(body, "per_item_discount")
        ? boolInt(body.per_item_discount, false)
        : Number(existing?.per_item_discount || 0))
    : 0;
  const isActive = Object.prototype.hasOwnProperty.call(body, "is_active")
    ? boolInt(body.is_active, true)
    : Number(existing?.is_active ?? 1);
  if (id) {
    await env.DB.prepare(
      `UPDATE coupons SET
         code=?, type=?, value=?, min_amount=?, max_discount=?, usage_limit=?,
         per_user_limit=?, disabled_wholesale_price=?, per_item_discount=?,
         payment_roles_json=?, member_levels_json=?, scope_type='product',
         scope_ref_ids_json=?, starts_at=?, ends_at=?, is_active=?, updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    ).bind(
      code,
      type,
      value,
      Math.max(0, numberValue(body.min_amount, 0)),
      Math.max(0, numberValue(body.max_discount, 0)),
      Math.max(0, toInt(body.usage_limit, 0)),
      Math.max(0, toInt(body.per_user_limit, 0)),
      disabledWholesalePrice,
      perItemDiscount,
      JSON.stringify(paymentRoles),
      JSON.stringify(memberLevels),
      JSON.stringify(scopeIds),
      startsAt,
      endsAt,
      isActive,
      id
    ).run();
    return id;
  }
  const insert = await env.DB.prepare(
    `INSERT INTO coupons (
      code, type, value, min_amount, max_discount, usage_limit, per_user_limit,
      disabled_wholesale_price, per_item_discount,
      payment_roles_json, member_levels_json, scope_type, scope_ref_ids_json,
      starts_at, ends_at, is_active
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'product', ?, ?, ?, ?)`
  ).bind(
    code,
    type,
    value,
    Math.max(0, numberValue(body.min_amount, 0)),
    Math.max(0, numberValue(body.max_discount, 0)),
    Math.max(0, toInt(body.usage_limit, 0)),
    Math.max(0, toInt(body.per_user_limit, 0)),
    disabledWholesalePrice,
    perItemDiscount,
    JSON.stringify(paymentRoles),
    JSON.stringify(memberLevels),
    JSON.stringify(scopeIds),
    startsAt,
    endsAt,
    isActive
  ).run();
  return Number(insert.meta.last_row_id);
}

async function apiAdminGenerateGiftCards(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const name = clean(body.name, 160);
  const quantity = strictPositiveInteger(body.quantity);
  const amount = numberValue(body.amount, 0);
  const expiresRaw = clean(body.expires_at, 80);
  const expiresAt = normalizeDateString(expiresRaw);
  if (!name) return apiError("礼品卡名称不能为空", 400);
  if (!quantity || quantity > 10000) return apiError("礼品卡数量不合法", 400);
  if (amount <= 0) return apiError("礼品卡金额不合法", 400);
  if (expiresRaw && !expiresAt) return apiError("礼品卡过期时间不合法", 400);
  const batchNo = makeGiftCardBatchNo();
  const generatedCodes = new Set<string>();
  while (generatedCodes.size < quantity) generatedCodes.add(makeGiftCardCode());
  const cardRowsJson = JSON.stringify(Array.from(generatedCodes, (code) => ({ code })));
  await env.DB.batch([
    env.DB.prepare(
      "INSERT INTO gift_card_batches (name, batch_no, total_count, amount, currency) VALUES (?, ?, ?, ?, 'CNY')"
    ).bind(name, batchNo, quantity, money(amount)),
    env.DB.prepare(
      `INSERT INTO gift_cards (batch_id, name, code, amount, currency, status, expires_at)
       SELECT (SELECT id FROM gift_card_batches WHERE batch_no=?), ?, json_extract(value, '$.code'), ?, 'CNY', 'active', ?
       FROM json_each(?)`
    ).bind(batchNo, name, money(amount), expiresAt, cardRowsJson)
  ]);
  const batch = await env.DB.prepare("SELECT * FROM gift_card_batches WHERE batch_no=?").bind(batchNo).first<GiftCardBatchRow>();
  return apiOk({
    created: quantity,
    batch: batch ? formatGiftCardBatch(batch) : null
  });
}

async function apiAdminGiftCards(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE 1 = 1";
  const code = clean(url.searchParams.get("code"), 80);
  const status = clean(url.searchParams.get("status"), 30);
  const batchNo = clean(url.searchParams.get("batch_no"), 80);
  const redeemedUserId = toInt(url.searchParams.get("redeemed_user_id"), 0);
  const createdFrom = strictOptionalDateQuery(url, "created_from");
  const createdTo = strictOptionalDateQuery(url, "created_to");
  const redeemedFrom = strictOptionalDateQuery(url, "redeemed_from");
  const redeemedTo = strictOptionalDateQuery(url, "redeemed_to");
  const expiresFrom = strictOptionalDateQuery(url, "expires_from");
  const expiresTo = strictOptionalDateQuery(url, "expires_to");
  if (code) {
    where += " AND gc.code LIKE ?";
    params.push(`%${code.toUpperCase()}%`);
  }
  if (status === "expired") {
    where += " AND gc.status='active' AND gc.expires_at IS NOT NULL AND gc.expires_at < ?";
    params.push(new Date().toISOString());
  } else if (status && status !== "__all__") {
    where += " AND gc.status=?";
    params.push(status);
  }
  if (redeemedUserId > 0) {
    where += " AND gc.redeemed_user_id=?";
    params.push(redeemedUserId);
  }
  if (batchNo) {
    where += " AND b.batch_no LIKE ?";
    params.push(`%${batchNo.toUpperCase()}%`);
  }
  if (createdFrom) {
    where += " AND gc.created_at >= ?";
    params.push(createdFrom);
  }
  if (createdTo) {
    where += " AND gc.created_at <= ?";
    params.push(createdTo);
  }
  if (redeemedFrom) {
    where += " AND gc.redeemed_at >= ?";
    params.push(redeemedFrom);
  }
  if (redeemedTo) {
    where += " AND gc.redeemed_at <= ?";
    params.push(redeemedTo);
  }
  if (expiresFrom) {
    where += " AND gc.expires_at >= ?";
    params.push(expiresFrom);
  }
  if (expiresTo) {
    where += " AND gc.expires_at <= ?";
    params.push(expiresTo);
  }
  const total = await count(
    env,
    `SELECT COUNT(*) AS count FROM gift_cards gc LEFT JOIN gift_card_batches b ON b.id=gc.batch_id ${where}`,
    params
  );
  const rows = await env.DB.prepare(
    `SELECT gc.*, b.name AS batch_name, b.batch_no AS batch_no, b.total_count AS batch_total_count,
            b.amount AS batch_amount, b.currency AS batch_currency, b.created_at AS batch_created_at,
            u.email AS redeemed_user_email, u.display_name AS redeemed_user_display_name
     FROM gift_cards gc
     LEFT JOIN gift_card_batches b ON b.id=gc.batch_id
     LEFT JOIN users u ON u.id=gc.redeemed_user_id
     ${where}
     ORDER BY gc.id DESC
     LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<GiftCardRow>();
  return apiOk((rows.results || []).map(formatGiftCard), pagination(page, size, total));
}

async function apiAdminUpdateGiftCard(request: Request, env: Env, id: number): Promise<Response> {
  const body = await readJson(request);
  const row = await env.DB.prepare("SELECT * FROM gift_cards WHERE id=?").bind(id).first<GiftCardRow>();
  if (!row) return apiError("礼品卡不存在", 404);
  if (row.status === "redeemed") return apiError("已兑换的礼品卡不能修改", 400);
  const name = clean(body.name, 160) || row.name;
  const status = clean(body.status, 30) || row.status;
  if (status !== "active" && status !== "disabled") return apiError("礼品卡状态不合法", 400);
  const expiresRaw = "expires_at" in body ? clean(body.expires_at, 80) : "";
  const expiresAt = "expires_at" in body ? normalizeDateString(expiresRaw) : row.expires_at;
  if (expiresRaw && !expiresAt) return apiError("礼品卡过期时间不合法", 400);
  if (expiresAt && new Date(expiresAt).getTime() < Date.now()) return apiError("礼品卡过期时间不能早于当前时间", 400);
  await env.DB.prepare(
    "UPDATE gift_cards SET name=?, status=?, expires_at=?, updated_at=CURRENT_TIMESTAMP WHERE id=?"
  ).bind(name, status, expiresAt, id).run();
  const updated = await env.DB.prepare(
    `SELECT gc.*, b.name AS batch_name, b.batch_no AS batch_no, b.total_count AS batch_total_count,
            b.amount AS batch_amount, b.currency AS batch_currency, b.created_at AS batch_created_at,
            u.email AS redeemed_user_email, u.display_name AS redeemed_user_display_name
     FROM gift_cards gc
     LEFT JOIN gift_card_batches b ON b.id=gc.batch_id
     LEFT JOIN users u ON u.id=gc.redeemed_user_id
     WHERE gc.id=?`
  ).bind(id).first<GiftCardRow>();
  return apiOk(updated ? formatGiftCard(updated) : {});
}

async function apiAdminDeleteGiftCard(env: Env, id: number): Promise<Response> {
  const row = await env.DB.prepare("SELECT status FROM gift_cards WHERE id=?").bind(id).first<{ status: string }>();
  if (!row) return apiError("礼品卡不存在", 404);
  if (row.status === "redeemed") return apiError("已兑换的礼品卡不能删除", 400);
  await env.DB.prepare("DELETE FROM gift_cards WHERE id=?").bind(id).run();
  await deleteEmptyGiftCardBatches(env);
  return apiOk({});
}

async function apiAdminBatchGiftCardStatus(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const ids = arrayNumbers(body.ids);
  const status = clean(body.status, 30);
  if (!ids.length) return apiError("请选择礼品卡", 400);
  if (status !== "active" && status !== "disabled") return apiError("礼品卡状态不合法", 400);
  let affected = 0;
  for (const chunk of chunkNumbers(ids, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(
      `UPDATE gift_cards SET status=?, updated_at=CURRENT_TIMESTAMP
       WHERE status!='redeemed' AND id IN (${placeholders})`
    ).bind(status, ...chunk).run();
    affected += Number(result.meta.changes || 0);
  }
  return apiOk({ affected });
}

async function apiAdminExportGiftCards(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const ids = arrayNumbers(body.ids);
  if (!ids.length) return apiError("请选择礼品卡", 400);
  const format = normalizeExportFormat(body.format);
  const rows: GiftCardRow[] = [];
  for (const chunk of chunkNumbers(ids, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(
      `SELECT gc.*, b.name AS batch_name, b.batch_no AS batch_no, b.total_count AS batch_total_count,
              b.amount AS batch_amount, b.currency AS batch_currency, b.created_at AS batch_created_at
       FROM gift_cards gc LEFT JOIN gift_card_batches b ON b.id=gc.batch_id
       WHERE gc.id IN (${placeholders})`
    ).bind(...chunk).all<GiftCardRow>();
    rows.push(...(result.results || []));
  }
  const order = new Map(ids.map((id, index) => [id, index]));
  rows.sort((a, b) => (order.get(a.id) ?? 0) - (order.get(b.id) ?? 0));
  return giftCardExportResponse(rows, format);
}

async function apiAdminOrders(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const params: unknown[] = [];
  let where = "WHERE o.parent_id IS NULL";
  const orderId = toInt(url.searchParams.get("order_id"), 0);
  const userId = toInt(url.searchParams.get("user_id"), 0);
  const status = clean(url.searchParams.get("status"), 30);
  const orderNo = clean(url.searchParams.get("order_no"), 80);
  const guestEmail = clean(url.searchParams.get("guest_email"), 160);
  const userKeyword = clean(url.searchParams.get("user_keyword"), 160);
  const productKeyword = clean(url.searchParams.get("product_keyword"), 120);
  const createdFrom = clean(url.searchParams.get("created_from"), 80);
  const createdTo = clean(url.searchParams.get("created_to"), 80);
  if (orderId > 0) {
    where += " AND o.id = ?";
    params.push(orderId);
  }
  if (userId > 0) {
    where += " AND o.user_id = ?";
    params.push(userId);
  }
  if (status && status !== "__all__") {
    where += " AND o.status = ?";
    params.push(status);
  }
  if (orderNo) {
    where += " AND (o.order_no LIKE ? OR EXISTS (SELECT 1 FROM orders oc WHERE oc.parent_id=o.id AND oc.order_no LIKE ?))";
    params.push(`%${orderNo}%`, `%${orderNo}%`);
  }
  if (guestEmail) {
    where += " AND o.guest_email LIKE ?";
    params.push(`%${guestEmail}%`);
  }
  if (userKeyword) {
    where += " AND (u.email LIKE ? OR u.display_name LIKE ? OR u.nickname LIKE ? OR o.guest_email LIKE ?)";
    params.push(`%${userKeyword}%`, `%${userKeyword}%`, `%${userKeyword}%`, `%${userKeyword}%`);
  }
  if (productKeyword) {
    where += ` AND EXISTS (
      SELECT 1 FROM order_items oi
      JOIN orders item_order ON item_order.id=oi.order_id
      WHERE (item_order.id=o.id OR item_order.parent_id=o.id) AND oi.title_json LIKE ?
    )`;
    params.push(`%${productKeyword}%`);
  }
  if (createdFrom) {
    const date = new Date(createdFrom);
    if (!Number.isNaN(date.getTime())) {
      where += ` AND ${dashboardSqlDate("o.created_at")} >= datetime(?)`;
      params.push(dashboardDbDate(date));
    }
  }
  if (createdTo) {
    const date = new Date(createdTo);
    if (!Number.isNaN(date.getTime())) {
      where += ` AND ${dashboardSqlDate("o.created_at")} <= datetime(?)`;
      params.push(dashboardDbDate(date));
    }
  }
  const sortMap: Record<string, string> = {
    id: "o.id",
    created_at: dashboardSqlDate("o.created_at"),
    updated_at: dashboardSqlDate("o.updated_at"),
    total_amount: "o.total_amount"
  };
  const sortBy = sortMap[clean(url.searchParams.get("sort_by"), 40)] || "o.id";
  const sortOrder = clean(url.searchParams.get("sort_order"), 10).toLowerCase() === "asc" ? "ASC" : "DESC";
  const fromSql = "FROM orders o LEFT JOIN users u ON u.id=o.user_id";
  const total = await count(env, `SELECT COUNT(*) AS count ${fromSql} ${where}`, params);
  const rows = await env.DB.prepare(
    `SELECT o.*, u.email AS user_email, u.display_name AS user_display_name
     ${fromSql}
     ${where}
     ORDER BY ${sortBy} ${sortOrder}, o.id DESC LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<OrderRow>();
  const orders = await hydrateRootOrders(env, rows.results || [], { includeCost: true });
  return apiOk(orders, pagination(page, size, total));
}

async function apiAdminOrder(env: Env, id: number): Promise<Response> {
  const row = await env.DB.prepare(
    `SELECT o.*, u.email AS user_email, u.display_name AS user_display_name
     FROM orders o
     LEFT JOIN users u ON u.id=o.user_id
     WHERE o.id=?`
  ).bind(id).first<OrderRow>();
  if (!row) return apiError("订单不存在", 404);
  return apiOk(await hydrateOrder(env, row, { includeCost: true }));
}

const ORDER_STATUS_TRANSITIONS: Record<string, ReadonlySet<string>> = {
  pending_payment: new Set(["paid", "canceled"]),
  paid: new Set(["fulfilling", "partially_delivered", "delivered", "partially_refunded", "refunded"]),
  fulfilling: new Set(["partially_delivered", "delivered", "partially_refunded", "refunded"]),
  partially_delivered: new Set(["delivered", "completed", "partially_refunded", "refunded"]),
  delivered: new Set(["completed", "partially_refunded", "refunded"]),
  completed: new Set(["partially_refunded", "refunded"]),
  partially_refunded: new Set(["refunded"])
};

function isOrderStatusTransitionAllowed(current: string, target: string): boolean {
  return current === target || Boolean(ORDER_STATUS_TRANSITIONS[current]?.has(target));
}

async function apiAdminUpdateOrderStatus(request: Request, env: Env, id: number): Promise<Response> {
  const body = await readJson(request);
  const status = clean(body.status, 40);
  const allowed = new Set(["pending_payment", "paid", "fulfilling", "partially_delivered", "partially_refunded", "delivered", "completed", "canceled", "refunded"]);
  if (!allowed.has(status)) return apiError("订单状态不合法", 400);
  const order = await env.DB.prepare(
    `SELECT o.*, (SELECT COUNT(*) FROM orders child WHERE child.parent_id=o.id) AS child_count
     FROM orders o WHERE o.id=?`
  ).bind(id).first<OrderRow & { child_count: number }>();
  if (!order) return apiError("订单不存在", 404);
  if (!isOrderStatusTransitionAllowed(order.status, status)) {
    return apiError(`订单状态不能从 ${order.status} 变更为 ${status}`, 409);
  }
  if (status === order.status) return apiOk({});
  if (status === "paid" && order.status === "pending_payment") {
    await markOrderPaid(env, id);
    return apiOk({});
  }
  if (order.parent_id == null && Number(order.child_count || 0) > 0 && status === "completed") {
    const invalidChild = await env.DB.prepare(
      "SELECT id FROM orders WHERE parent_id=? AND status NOT IN ('delivered','completed') LIMIT 1"
    ).bind(id).first<{ id: number }>();
    if (invalidChild) return apiError("只有全部子订单已交付后才能完成父订单", 409);
    await env.DB.prepare(
      "UPDATE orders SET status='completed', updated_at=CURRENT_TIMESTAMP WHERE parent_id=? AND status='delivered'"
    ).bind(id).run();
  }
  if (order.parent_id == null && Number(order.child_count || 0) > 0 && ["partially_refunded", "refunded"].includes(status)) {
    const childRows = await env.DB.prepare("SELECT id, status FROM orders WHERE parent_id=? ORDER BY id ASC")
      .bind(id)
      .all<{ id: number; status: string }>();
    if ((childRows.results || []).some((child) => !isOrderStatusTransitionAllowed(child.status, status))) {
      return apiError("子订单当前状态不能同步为退款状态", 409);
    }
    await env.DB.prepare("UPDATE orders SET status=?, updated_at=CURRENT_TIMESTAMP WHERE parent_id=? AND status<>?")
      .bind(status, id, status)
      .run();
  }
  const updated = await env.DB.prepare(
    "UPDATE orders SET status=?, updated_at=CURRENT_TIMESTAMP, canceled_at=CASE WHEN ?='canceled' THEN CURRENT_TIMESTAMP ELSE canceled_at END WHERE id=? AND status=?"
  ).bind(status, status, id, order.status).run();
  if (Number(updated.meta.changes || 0) !== 1) {
    const fresh = await env.DB.prepare("SELECT status FROM orders WHERE id=?").bind(id).first<{ status: string }>();
    if (fresh?.status === status) return apiOk({});
    return apiError("订单状态已变化，请刷新后重试", 409);
  }
  if (status === "canceled") {
    await cancelOrderTreeAndRelease(env, id);
  }
  if (order.parent_id) {
    await syncParentOrderStatus(env, order.parent_id);
  } else if (["paid", "fulfilling", "partially_delivered", "delivered", "completed", "canceled", "refunded", "partially_refunded"].includes(status)) {
    await sendOrderLifecycleEmail(env, id, status);
  }
  return apiOk({});
}

async function apiAdminRefundOrder(request: Request, env: Env, orderId: number, type: "wallet" | "manual"): Promise<Response> {
  const body = await readJson(request);
  const amount = Number(body.amount || 0);
  const amountCents = moneyToCents(amount);
  if (!orderId) return apiError("订单不存在", 404);
  if (amountCents <= 0) return apiError("退款金额不合法", 400);
  const order = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(orderId).first<OrderRow>();
  if (!order) return apiError("订单不存在", 404);
  const refundableCents = refundableOrderCents(order);
  if (refundableCents <= 0) return apiError("该订单已无可退款金额", 400);
  if (amountCents > refundableCents) return apiError("退款金额不能超过可退款金额", 400);
  if (type === "wallet" && !order.user_id) return apiError("游客订单不能退款到用户钱包", 400);

  const items = await orderRefundItemsSnapshot(env, order.id);
  const remark = clean(body.remark, 1000);
  let result: D1Result;
  try {
    result = await env.DB.prepare(
      `INSERT INTO order_refunds (
        order_id, user_id, guest_email, guest_locale, type, amount, currency, remark, items_json, wallet_txn_id
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, NULL)`
    ).bind(
      order.id,
      order.user_id || 0,
      order.guest_email || "",
      order.guest_locale || "zh-CN",
      type,
      money(centsToMoney(amountCents)),
      order.currency || "CNY",
      remark,
      stringify(items)
    ).run();
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (message.includes("refund_amount_exceeded")) return apiError("退款金额不能超过可退款金额", 409);
    if (message.includes("refund_order_unpaid")) return apiError("未支付订单不能退款", 409);
    if (message.includes("refund_wallet_user_invalid")) return apiError("钱包退款用户不匹配", 409);
    if (message.includes("refund_amount_invalid")) return apiError("退款金额不合法", 400);
    throw error;
  }

  const freshOrder = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(order.id).first<OrderRow>();
  const nextStatus = freshOrder?.status || "partially_refunded";
  if (order.parent_id == null && ["partially_refunded", "refunded"].includes(nextStatus)) {
    await env.DB.prepare("UPDATE orders SET status=?, updated_at=CURRENT_TIMESTAMP WHERE parent_id=?")
      .bind(nextStatus, order.id)
      .run();
  }
  if (order.parent_id) {
    await syncParentOrderStatus(env, order.parent_id);
  } else {
    await sendOrderLifecycleEmail(env, order.id, nextStatus);
  }
  const row = await orderRefundById(env, Number(result.meta.last_row_id));
  return apiOk(row ? formatOrderRefund(row) : {});
}

async function apiAdminOrderRefunds(env: Env, url: URL): Promise<Response> {
  const { page, size, offset } = paging(url);
  const { where, params } = buildOrderRefundWhere(url);
  const total = await count(
    env,
    `SELECT COUNT(*) AS count
     FROM order_refunds r
     LEFT JOIN orders o ON o.id=r.order_id
     LEFT JOIN users u ON u.id=r.user_id
     ${where}`,
    params
  );
  const rows = await env.DB.prepare(
    `SELECT r.*, o.order_no AS order_no, u.email AS user_email, u.display_name AS user_display_name
     FROM order_refunds r
     LEFT JOIN orders o ON o.id=r.order_id
     LEFT JOIN users u ON u.id=r.user_id
     ${where}
     ORDER BY r.id DESC
     LIMIT ? OFFSET ?`
  ).bind(...params, size, offset).all<OrderRefundRow>();
  return apiOk((rows.results || []).map(formatOrderRefund), pagination(page, size, total));
}

async function apiAdminOrderRefund(env: Env, id: number): Promise<Response> {
  const row = await orderRefundById(env, id);
  if (!row) return apiError("退款记录不存在", 404);
  return apiOk(formatOrderRefund(row));
}

function buildOrderRefundWhere(url: URL): { where: string; params: unknown[] } {
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const userId = toInt(url.searchParams.get("user_id"), 0);
  const userKeyword = clean(url.searchParams.get("user_keyword"), 160);
  const orderNo = clean(url.searchParams.get("order_no"), 80);
  const guestEmail = clean(url.searchParams.get("guest_email"), 160);
  const productKeyword = clean(url.searchParams.get("product_keyword"), 120);
  const createdFrom = normalizeDateString(url.searchParams.get("created_from"));
  const createdTo = normalizeDateString(url.searchParams.get("created_to"));
  if (userId > 0) {
    where += " AND r.user_id=?";
    params.push(userId);
  }
  if (userKeyword) {
    where += " AND (u.email LIKE ? OR u.display_name LIKE ? OR u.nickname LIKE ?)";
    params.push(`%${userKeyword}%`, `%${userKeyword}%`, `%${userKeyword}%`);
  }
  if (orderNo) {
    where += " AND o.order_no LIKE ?";
    params.push(`%${orderNo}%`);
  }
  if (guestEmail) {
    where += " AND r.guest_email LIKE ?";
    params.push(`%${guestEmail}%`);
  }
  if (productKeyword) {
    where += ` AND EXISTS (
      SELECT 1 FROM order_items oi
      JOIN orders item_order ON item_order.id=oi.order_id
      WHERE (item_order.id=r.order_id OR item_order.parent_id=r.order_id) AND oi.title_json LIKE ?
    )`;
    params.push(`%${productKeyword}%`);
  }
  if (createdFrom) {
    where += " AND r.created_at >= ?";
    params.push(createdFrom);
  }
  if (createdTo) {
    where += " AND r.created_at <= ?";
    params.push(createdTo);
  }
  return { where, params };
}

async function orderRefundById(env: Env, id: number): Promise<OrderRefundRow | null> {
  if (!id) return null;
  return env.DB.prepare(
    `SELECT r.*, o.order_no AS order_no, u.email AS user_email, u.display_name AS user_display_name
     FROM order_refunds r
     LEFT JOIN orders o ON o.id=r.order_id
     LEFT JOIN users u ON u.id=r.user_id
     WHERE r.id=?`
  ).bind(id).first<OrderRefundRow>();
}

async function orderRefundItemsSnapshot(env: Env, orderId: number): Promise<AnyRecord[]> {
  const rows = await env.DB.prepare(
    `SELECT oi.* FROM order_items oi
     JOIN orders item_order ON item_order.id=oi.order_id
     WHERE item_order.id=? OR item_order.parent_id=?
     ORDER BY item_order.id ASC, oi.id ASC`
  )
    .bind(orderId, orderId)
    .all<OrderItemRow>();
  return (rows.results || []).map((item) => formatOrderItem(item, true));
}

function refundableOrderCents(order: OrderRow): number {
  const totalCents = moneyToCents(Number(order.total_amount || 0));
  const refundedCents = moneyToCents(Number(order.refunded_amount || 0));
  if (!order.paid_at && !["paid", "fulfilling", "partially_delivered", "delivered", "completed", "partially_refunded"].includes(order.status)) {
    return 0;
  }
  return Math.max(0, totalCents - refundedCents);
}

async function apiAdminCreateFulfillment(request: Request, env: Env): Promise<Response> {
  const body = await readJson(request);
  const orderId = toInt(body.order_id, 0);
  if (!orderId) return apiError("order_id required", 400);
  const order = await env.DB.prepare(
    `SELECT o.id, o.status, o.parent_id,
            (SELECT COUNT(*) FROM orders child WHERE child.parent_id=o.id) AS child_count
     FROM orders o WHERE o.id=?`
  )
    .bind(orderId)
    .first<{ id: number; status: string; parent_id: number | null; child_count: number }>();
  if (!order) return apiError("订单不存在", 404);
  if (order.parent_id == null && Number(order.child_count || 0) > 0) {
    return apiError("父订单不能直接交付，请选择需要处理的子订单", 409);
  }
  if (!["paid", "fulfilling", "partially_delivered"].includes(order.status)) {
    return apiError("订单当前状态不能交付", 409);
  }
  const deliveryData = normalizeFulfillmentDeliveryData(body.delivery_data);
  const payload = formatDeliveryPayload(deliveryData);
  if (!payload) return apiError("发货内容不能为空", 400);
  await upsertFulfillmentComponent(env, orderId, "manual", 0, "manual", deliveryData, payload);
  await rebuildOrderFulfillment(env, orderId);
  await refreshOrderFulfillmentStatus(env, orderId);
  await sendDownstreamCallbackForOrder(env, order.parent_id || orderId);
  return apiOk({});
}

async function fulfillmentDownloadByOrderNo(env: Env, orderNo: string): Promise<Response> {
  const order = await env.DB.prepare("SELECT id FROM orders WHERE order_no=?").bind(orderNo).first<{ id: number }>();
  if (!order) return apiError("订单不存在", 404);
  return fulfillmentDownloadResponse(env, order.id, orderNo);
}

async function fulfillmentDownloadByGuestOrderNo(request: Request, env: Env, orderNo: string, url: URL): Promise<Response> {
  const email = normalizeEmail(url.searchParams.get("email"));
  const orderPassword = String(url.searchParams.get("order_password") || "");
  if (!email || !orderPassword) return apiError("请输入查询邮箱和订单密码", 400);
  const scope = await storefrontOrderScope(request, env);
  const order = await env.DB.prepare(`SELECT * FROM orders WHERE order_no=? AND user_id=0 AND ${scope.sql}`)
    .bind(orderNo, ...scope.params)
    .first<OrderRow>();
  if (!order) return apiError("订单不存在", 404);
  if (!await verifyGuestOrderAccess(order, email, orderPassword)) return apiError("订单不存在或查询信息错误", 403);
  return fulfillmentDownloadResponse(env, order.id, order.order_no);
}

async function fulfillmentDownloadByOrderId(env: Env, orderId: number): Promise<Response> {
  if (!orderId) return apiError("订单不存在", 404);
  const order = await env.DB.prepare("SELECT order_no FROM orders WHERE id=?").bind(orderId).first<{ order_no: string }>();
  if (!order) return apiError("订单不存在", 404);
  return fulfillmentDownloadResponse(env, orderId, order.order_no);
}

async function fulfillmentDownloadResponse(env: Env, orderId: number, filename: string): Promise<Response> {
  const fulfillment = await env.DB.prepare("SELECT * FROM fulfillments WHERE order_id=?").bind(orderId).first<FulfillmentRow>();
  let payload = fulfillment ? formatFulfillmentPresentation(fulfillment).payload : "";
  if (!payload) {
    const childFulfillments = await env.DB.prepare(
      `SELECT f.* FROM fulfillments f
       JOIN orders child ON child.id=f.order_id
       WHERE child.parent_id=?
       ORDER BY child.id ASC, f.id ASC`
    ).bind(orderId).all<FulfillmentRow>();
    payload = (childFulfillments.results || [])
      .map((row) => formatFulfillmentPresentation(row).payload)
      .filter(Boolean)
      .join("\n");
  }
  return new Response(payload, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Content-Disposition": `attachment; filename="${safeDownloadFilename(filename)}.txt"`,
      "Cache-Control": "no-store",
      ...SECURITY_HEADERS
    }
  });
}

async function calculateOrder(env: Env, body: AnyRecord, resellerContext?: ResellerContext | null, user?: UserRow): Promise<
  {
    ok: true;
    items: CalculatedOrderItem[];
    originalAmount: number;
    promotionDiscountAmount: number;
    wholesaleDiscountAmount: number;
    memberDiscountAmount: number;
    discountAmount: number;
    totalAmount: number;
    coupon: CalculatedCoupon | null;
    promotion: CalculatedPromotion;
  } |
  { ok: false; error: string }
> {
  if (resellerContext && clean(body.coupon_code, 80)) return { ok: false, error: "分站订单暂不支持主站优惠券" };
  const rawItems = Array.isArray(body.items) ? body.items : [];
  for (const raw of rawItems) {
    if (!raw || typeof raw !== "object" || strictPositiveInteger(raw.product_id) === null || strictPositiveInteger(raw.quantity) === null) {
      return { ok: false, error: "订单商品或购买数量不合法" };
    }
    if (raw.sku_id !== undefined && raw.sku_id !== null && raw.sku_id !== "" && strictNonNegativeInteger(raw.sku_id) === null) {
      return { ok: false, error: "商品规格不合法" };
    }
  }
  const items = mergeOrderInputItems(rawItems);
  if (!items.length) return { ok: false, error: "订单商品不能为空" };
  const manualFormData = jsonObject(body.manual_form_data);
  const result: CalculatedOrderItem[] = [];
  let originalAmount = 0;
  let promotionDiscountAmount = 0;
  let wholesaleDiscountAmount = 0;
  let memberDiscountAmount = 0;
  const productQuantityTotals = new Map<number, number>();
  for (const raw of items) {
    const productId = toInt(raw.product_id, 0);
    const quantity = toInt(raw.quantity, 0);
    if (productId > 0) productQuantityTotals.set(productId, (productQuantityTotals.get(productId) || 0) + quantity);
  }
  const userMemberLevelId = resellerContext ? 0 : Number(user?.member_level_id || 0);
  const productIds = Array.from(productQuantityTotals.keys());
  const placeholders = productIds.map(() => "?").join(",");
  const now = new Date().toISOString();
  const [productsResult, skusResult, mappingsResult, cardStockResult, promotionsResult, memberLevelResult, memberPricesResult] = await env.DB.batch([
    env.DB.prepare(`SELECT * FROM products WHERE id IN (${placeholders}) AND is_active=1`).bind(...productIds),
    env.DB.prepare(
      `SELECT * FROM product_skus WHERE product_id IN (${placeholders}) AND is_active=1
       ORDER BY product_id ASC, sort_order ASC, id ASC`
    ).bind(...productIds),
    env.DB.prepare(
      `SELECT DISTINCT pm.local_product_id AS product_id, COALESCE(pms.local_sku_id, 0) AS sku_id
       FROM product_mappings pm
       LEFT JOIN product_mapping_skus pms ON pms.mapping_id=pm.id
       WHERE pm.local_product_id IN (${placeholders}) AND pm.is_active=1`
    ).bind(...productIds),
    env.DB.prepare(
      `SELECT product_id, sku_id, COUNT(*) AS count
       FROM card_secrets
       WHERE product_id IN (${placeholders}) AND status='available'
       GROUP BY product_id, sku_id`
    ).bind(...productIds),
    env.DB.prepare(
      `SELECT * FROM promotions
       WHERE is_active=1 AND scope_type='product' AND scope_ref_id IN (${placeholders})
         AND (starts_at IS NULL OR starts_at='' OR starts_at<=?)
         AND (ends_at IS NULL OR ends_at='' OR ends_at>=?)
       ORDER BY scope_ref_id ASC, min_amount ASC, id ASC`
    ).bind(...productIds, now, now),
    env.DB.prepare("SELECT * FROM member_levels WHERE id=? AND is_active=1").bind(userMemberLevelId),
    env.DB.prepare(
      `SELECT * FROM member_level_prices
       WHERE member_level_id=? AND product_id IN (${placeholders})
       ORDER BY product_id ASC, sku_id DESC, id ASC`
    ).bind(userMemberLevelId, ...productIds)
  ]);
  const productsById = new Map(((productsResult.results || []) as ProductRow[]).map((row) => [Number(row.id), row]));
  const skusByProduct = groupRowsByNumber((skusResult.results || []) as SkuRow[], (row) => row.product_id);
  const upstreamMappings = groupRowsByNumber(
    (mappingsResult.results || []) as Array<{ product_id: number; sku_id: number }>,
    (row) => row.product_id
  );
  const cardStock = new Map(
    ((cardStockResult.results || []) as Array<{ product_id: number; sku_id: number; count: number }>)
      .map((row) => [`${Number(row.product_id)}:${Number(row.sku_id)}`, Number(row.count || 0)] as const)
  );
  const promotionsByProduct = groupRowsByNumber((promotionsResult.results || []) as PromotionRow[], (row) => row.scope_ref_id);
  const memberLevel = ((memberLevelResult.results || []) as MemberLevelRow[])[0] || null;
  const memberPricesByProduct = groupRowsByNumber(
    (memberPricesResult.results || []) as MemberLevelPriceRow[],
    (row) => row.product_id
  );

  for (const raw of items) {
    const productId = toInt(raw.product_id, 0);
    const skuId = toInt(raw.sku_id, 0);
    const quantity = toInt(raw.quantity, 0);
    const product = productsById.get(productId) || null;
    const productSkus = skusByProduct.get(productId) || [];
    const sku = skuId ? (productSkus.find((row) => row.id === skuId) || null) : (productSkus[0] || null);
    if (!product) return { ok: false, error: "商品不存在或已下架" };
    if (!user && !resellerContext && (clean(product.purchase_type, 20) || "member") === "member") {
      return { ok: false, error: "该商品仅限登录会员购买" };
    }
    if (!sku) return { ok: false, error: "商品规格不存在或已下架" };
    if (quantity < Math.max(1, product.min_purchase_quantity || 1)) return { ok: false, error: "购买数量低于最低限制" };
    if (product.max_purchase_quantity > 0 && quantity > product.max_purchase_quantity) return { ok: false, error: "购买数量超过限制" };
    const fulfillmentType = clean(product.fulfillment_type, 40) || "manual";
    const usesUpstreamStock = fulfillmentType === "upstream"
      ? (upstreamMappings.get(product.id) || []).some((row) => Number(row.sku_id || 0) === 0 || Number(row.sku_id) === sku.id)
      : false;
    if (fulfillmentType === "upstream" && !usesUpstreamStock) {
      return { ok: false, error: "上游商品映射不存在或已停用" };
    }
    if (fulfillmentType === "auto") {
      const availableSecrets = cardStock.get(`${product.id}:${sku.id}`) || 0;
      if (availableSecrets < quantity) return { ok: false, error: "自动发货卡密库存不足" };
    } else if (fulfillmentType === "manual" && !hasStock(sku, quantity)) {
      return { ok: false, error: "人工库存不足" };
    }
    let manualFormSchemaSnapshot: AnyRecord = {};
    let manualFormSubmission: AnyRecord = {};
    if (fulfillmentType === "manual" || (fulfillmentType === "upstream" && hasManualFormFields(product.manual_form_schema_json))) {
      try {
        const normalized = validateAndNormalizeManualForm(
          product.manual_form_schema_json,
          resolveManualFormSubmission(manualFormData, product.id, sku.id)
        );
        manualFormSchemaSnapshot = normalized.schema;
        manualFormSubmission = normalized.submission;
      } catch (error) {
        return { ok: false, error: error instanceof ApiRequestError ? error.message : "人工交付表单不合法" };
      }
    }
    const resellerPricing = resellerContext ? await resellerPricingForSku(env, resellerContext, product, sku) : null;
    if (resellerContext && (!resellerPricing || !resellerPricing.listed)) return { ok: false, error: "商品未在当前分站上架" };
    const baseUnitPrice = centsToMoney(moneyToCents(Number(resellerPricing?.baseUnitPrice ?? sku.price_amount)));
    let unitPrice = resellerContext
      ? centsToMoney(moneyToCents(Number(resellerPricing?.unitPrice ?? baseUnitPrice)))
      : baseUnitPrice;
    let promotionDiscount = 0;
    let wholesaleDiscount = 0;
    let memberDiscount = 0;

    if (!resellerContext) {
      const promotion = resolvePromotionUnitPriceFromRows(promotionsByProduct.get(product.id) || [], baseUnitPrice, quantity);
      let promotionUnitPrice = promotion.unitPrice;
      if (promotionUnitPrice < baseUnitPrice) {
        promotionDiscount = centsToMoney((moneyToCents(baseUnitPrice) - moneyToCents(promotionUnitPrice)) * quantity);
      } else {
        promotionUnitPrice = baseUnitPrice;
      }

      const wholesale = resolveWholesaleUnitPrice(
        parseWholesalePrices(product.wholesale_prices_json),
        baseUnitPrice,
        productQuantityTotals.get(product.id) || quantity,
        quantity
      );
      if (wholesale.matched && wholesale.unitPrice < promotionUnitPrice) {
        unitPrice = wholesale.unitPrice;
        wholesaleDiscount = wholesale.discountAmount;
        promotionDiscount = 0;
      } else {
        unitPrice = promotionUnitPrice;
        wholesaleDiscount = 0;
      }

      const member = resolveMemberUnitPriceFromRows(memberLevel, memberPricesByProduct.get(product.id) || [], sku.id, unitPrice);
      if (member.unitPrice < unitPrice) {
        memberDiscount = centsToMoney((moneyToCents(unitPrice) - moneyToCents(member.unitPrice)) * quantity);
        unitPrice = member.unitPrice;
      }
    }

    const lineTotal = unitPrice * quantity;
    const baseLineTotal = baseUnitPrice * quantity;
    promotionDiscountAmount = centsToMoney(moneyToCents(promotionDiscountAmount) + moneyToCents(promotionDiscount));
    wholesaleDiscountAmount = centsToMoney(moneyToCents(wholesaleDiscountAmount) + moneyToCents(wholesaleDiscount));
    memberDiscountAmount = centsToMoney(moneyToCents(memberDiscountAmount) + moneyToCents(memberDiscount));
    result.push({
      product,
      sku,
      quantity,
      usesUpstreamStock,
      manualFormSchemaSnapshot,
      manualFormSubmission,
      unitPrice,
      baseUnitPrice,
      resellerPricingMode: resellerContext ? resellerPricingMode(resellerPricing?.rule?.pricing_mode) : "",
      resellerRuleSource: resellerContext
        ? (Number(resellerPricing?.rule?.id || 0) > 0
          ? (Number(resellerPricing?.rule?.sku_id || 0) > 0 ? "sku" : "product")
          : "profile")
        : "",
      resellerSettingId: Number(resellerPricing?.rule?.id || 0),
      lineTotal,
      baseLineTotal,
      promotionDiscountAmount: promotionDiscount,
      wholesaleDiscountAmount: wholesaleDiscount,
      memberDiscountAmount: memberDiscount,
      couponDiscountAmount: 0
    });
    originalAmount = centsToMoney(moneyToCents(originalAmount) + moneyToCents(baseLineTotal));
  }
  const couponBaseAmount = result.reduce((sum, item) => sum + item.lineTotal, 0);
  const couponResult = await calculateCouponDiscount(env, clean(body.coupon_code, 80), result, couponBaseAmount, user, userMemberLevelId);
  if (!couponResult.ok) return { ok: false, error: couponResult.error };
  const discountAmount = couponResult.discountAmount;
  const totalAmount = Math.max(0, centsToMoney(moneyToCents(couponBaseAmount) - moneyToCents(discountAmount)));
  if (moneyToCents(totalAmount) <= 0) return { ok: false, error: "订单金额不正确" };
  const promotion: CalculatedPromotion = { discountAmount: promotionDiscountAmount, promotions: [] };
  return {
    ok: true,
    items: result,
    originalAmount,
    promotionDiscountAmount,
    wholesaleDiscountAmount,
    memberDiscountAmount,
    discountAmount,
    totalAmount,
    coupon: couponResult.coupon,
    promotion
  };
}

function mergeOrderInputItems(items: AnyRecord[]): AnyRecord[] {
  const merged = new Map<string, AnyRecord>();
  for (const item of items) {
    const productId = toInt(item.product_id, 0);
    const skuId = toInt(item.sku_id, 0);
    const quantity = toInt(item.quantity, 0);
    if (productId <= 0 || quantity <= 0) continue;
    const key = `${productId}:${skuId}`;
    const current = merged.get(key);
    if (current) {
      current.quantity = toInt(current.quantity, 0) + quantity;
    } else {
      merged.set(key, { ...item, product_id: productId, sku_id: skuId, quantity });
    }
  }
  return Array.from(merged.values());
}

type ManualFormField = {
  key: string;
  type: string;
  required: boolean;
  label: AnyRecord;
  placeholder: AnyRecord;
  regex: string;
  min?: number;
  max?: number;
  max_len?: number;
  options: string[];
};

const MANUAL_FORM_FIELD_TYPES = new Set([
  "text", "textarea", "phone", "email", "number", "select", "radio", "checkbox", "china_region"
]);
const MANUAL_FORM_FIELD_KEY_PATTERN = /^[a-z0-9_]{1,64}$/;
const MANUAL_FORM_PHONE_PATTERN = /^\+?[0-9\-()\s]{6,20}$/;

function normalizeManualFormSchema(rawSchema: unknown): AnyRecord {
  let source: unknown = rawSchema;
  if (typeof source === "string") {
    try {
      source = JSON.parse(source);
    } catch {
      throw new ApiRequestError(400, "人工交付表单配置不合法");
    }
  }
  if (!source || typeof source !== "object" || Array.isArray(source)) {
    throw new ApiRequestError(400, "人工交付表单配置不合法");
  }
  const schema = source as AnyRecord;
  if (!Object.keys(schema).length) return { fields: [] };
  if (!Array.isArray(schema.fields)) throw new ApiRequestError(400, "人工交付表单配置不合法");

  const keys = new Set<string>();
  const fields: AnyRecord[] = [];
  for (const rawField of schema.fields) {
    if (!rawField || typeof rawField !== "object" || Array.isArray(rawField)) {
      throw new ApiRequestError(400, "人工交付表单配置不合法");
    }
    const raw = rawField as AnyRecord;
    if (typeof raw.key !== "string" || typeof raw.type !== "string") {
      throw new ApiRequestError(400, "人工交付表单配置不合法");
    }
    const key = raw.key.trim();
    const type = raw.type.trim();
    if (!MANUAL_FORM_FIELD_KEY_PATTERN.test(key) || keys.has(key) || !MANUAL_FORM_FIELD_TYPES.has(type)) {
      throw new ApiRequestError(400, "人工交付表单配置不合法");
    }
    keys.add(key);
    const required = strictOptionalBoolean(raw, "required", false);
    const label = strictLocaleText(raw, "label");
    const placeholder = strictLocaleText(raw, "placeholder");
    const regex = strictOptionalString(raw, "regex");
    if (regex) compileManualFormRegex(regex);
    const min = strictOptionalFiniteNumber(raw, "min");
    const max = strictOptionalFiniteNumber(raw, "max");
    if (min !== undefined && max !== undefined && min > max) {
      throw new ApiRequestError(400, "人工交付表单配置不合法");
    }
    const maxLen = strictOptionalInteger(raw, "max_len");
    if (maxLen !== undefined && maxLen <= 0) throw new ApiRequestError(400, "人工交付表单配置不合法");
    const options = strictManualFormOptions(raw, "options");
    if (["select", "radio", "checkbox"].includes(type) && !options.length) {
      throw new ApiRequestError(400, "人工交付表单配置不合法");
    }

    const normalized: AnyRecord = { key, type, required };
    if (Object.keys(label).length) normalized.label = label;
    if (Object.keys(placeholder).length) normalized.placeholder = placeholder;
    if (regex) normalized.regex = regex;
    if (min !== undefined) normalized.min = min;
    if (max !== undefined) normalized.max = max;
    if (maxLen !== undefined) normalized.max_len = maxLen;
    if (options.length) normalized.options = options;
    fields.push(normalized);
  }
  return { fields };
}

function validateAndNormalizeManualForm(rawSchema: unknown, rawSubmission: unknown): { schema: AnyRecord; submission: AnyRecord } {
  const schema = normalizeManualFormSchema(rawSchema);
  const fields = schema.fields as ManualFormField[];
  const submission = rawSubmission && typeof rawSubmission === "object" && !Array.isArray(rawSubmission)
    ? rawSubmission as AnyRecord
    : null;
  if (rawSubmission != null && !submission) throw new ApiRequestError(400, "人工交付表单字段类型不正确");
  const values = submission || {};
  if (!fields.length) {
    if (Object.keys(values).length) throw new ApiRequestError(400, "人工交付表单字段值不合法");
    return { schema, submission: {} };
  }
  const allowed = new Map(fields.map((field) => [field.key, field]));
  if (Object.keys(values).some((key) => !allowed.has(key))) {
    throw new ApiRequestError(400, "人工交付表单字段值不合法");
  }

  const normalized: AnyRecord = {};
  for (const field of fields) {
    if (!Object.prototype.hasOwnProperty.call(values, field.key)) {
      if (field.required) throw new ApiRequestError(400, "请填写完整的人工交付信息");
      continue;
    }
    const result = normalizeManualFormFieldValue(field, values[field.key]);
    if (!result.hasValue) {
      if (field.required) throw new ApiRequestError(400, "请填写完整的人工交付信息");
      continue;
    }
    normalized[field.key] = result.value;
  }
  return { schema, submission: normalized };
}

function normalizeManualFormFieldValue(field: ManualFormField, rawValue: unknown): { hasValue: boolean; value?: unknown } {
  if (["text", "textarea", "phone", "email"].includes(field.type)) {
    if (typeof rawValue !== "string") throw new ApiRequestError(400, "人工交付表单字段类型不正确");
    const text = rawValue.trim();
    if (!text) return { hasValue: false };
    if (field.max_len !== undefined && Array.from(text).length > field.max_len) {
      throw new ApiRequestError(400, "人工交付表单字段值不合法");
    }
    if (field.type === "phone" && !MANUAL_FORM_PHONE_PATTERN.test(text)) {
      throw new ApiRequestError(400, "人工交付表单字段值不合法");
    }
    if (field.type === "email" && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(text)) {
      throw new ApiRequestError(400, "人工交付表单字段值不合法");
    }
    if (field.regex && !manualFormRegexMatches(field.regex, text)) {
      throw new ApiRequestError(400, "人工交付表单字段值不合法");
    }
    return { hasValue: true, value: text };
  }
  if (field.type === "number") {
    if ((typeof rawValue !== "number" && typeof rawValue !== "string") || String(rawValue).trim() === "") {
      throw new ApiRequestError(400, "人工交付表单字段类型不正确");
    }
    const value = Number(rawValue);
    if (!Number.isFinite(value)) throw new ApiRequestError(400, "人工交付表单字段类型不正确");
    if ((field.min !== undefined && value < field.min) || (field.max !== undefined && value > field.max)) {
      throw new ApiRequestError(400, "人工交付表单字段值不合法");
    }
    return { hasValue: true, value };
  }
  if (field.type === "select" || field.type === "radio") {
    if (typeof rawValue !== "string") throw new ApiRequestError(400, "人工交付表单字段类型不正确");
    const value = rawValue.trim();
    if (!value) return { hasValue: false };
    if (!field.options.includes(value)) throw new ApiRequestError(400, "人工交付表单选项不合法");
    return { hasValue: true, value };
  }
  if (field.type === "checkbox") {
    if (!Array.isArray(rawValue) || rawValue.some((item) => typeof item !== "string")) {
      throw new ApiRequestError(400, "人工交付表单字段类型不正确");
    }
    const values = Array.from(new Set(rawValue.map((item) => item.trim()).filter(Boolean))).sort();
    if (!values.length) return { hasValue: false };
    if (values.some((value) => !field.options.includes(value))) {
      throw new ApiRequestError(400, "人工交付表单选项不合法");
    }
    return { hasValue: true, value: values };
  }
  if (field.type === "china_region") {
    if (typeof rawValue !== "string") throw new ApiRequestError(400, "人工交付表单字段类型不正确");
    const value = rawValue.trim();
    if (!value) return { hasValue: false };
    const [provinceCode = "", cityCode = "", districtCode = "", ...textParts] = value.split("|");
    const regionText = textParts.join("|").trim();
    if (![provinceCode, cityCode, districtCode].every((code) => /^\d{2,12}$/.test(code)) || !regionText || regionText.length > 160) {
      throw new ApiRequestError(400, "人工交付表单字段值不合法");
    }
    return { hasValue: true, value: regionText };
  }
  throw new ApiRequestError(400, "人工交付表单配置不合法");
}

function resolveManualFormSubmission(data: AnyRecord, productId: number, skuId: number): unknown {
  const itemKey = `${productId}:${skuId}`;
  if (Object.prototype.hasOwnProperty.call(data, itemKey)) return data[itemKey] ?? {};
  const legacyKey = String(productId);
  if (Object.prototype.hasOwnProperty.call(data, legacyKey)) return data[legacyKey] ?? {};
  return {};
}

function hasManualFormFields(rawSchema: unknown): boolean {
  try {
    const fields = normalizeManualFormSchema(rawSchema).fields;
    return Array.isArray(fields) && fields.length > 0;
  } catch {
    return true;
  }
}

function strictLocaleText(source: AnyRecord, key: string): AnyRecord {
  if (!Object.prototype.hasOwnProperty.call(source, key)) return {};
  const raw = source[key];
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) throw new ApiRequestError(400, "人工交付表单配置不合法");
  const result: AnyRecord = {};
  for (const [locale, value] of Object.entries(raw)) {
    if (typeof value !== "string") throw new ApiRequestError(400, "人工交付表单配置不合法");
    const text = value.trim();
    if (text) result[locale] = text;
  }
  return result;
}

function strictOptionalBoolean(source: AnyRecord, key: string, fallback: boolean): boolean {
  if (!Object.prototype.hasOwnProperty.call(source, key)) return fallback;
  if (typeof source[key] !== "boolean") throw new ApiRequestError(400, "人工交付表单配置不合法");
  return source[key];
}

function strictOptionalString(source: AnyRecord, key: string): string {
  if (!Object.prototype.hasOwnProperty.call(source, key)) return "";
  if (typeof source[key] !== "string") throw new ApiRequestError(400, "人工交付表单配置不合法");
  return source[key].trim();
}

function strictOptionalFiniteNumber(source: AnyRecord, key: string): number | undefined {
  if (!Object.prototype.hasOwnProperty.call(source, key)) return undefined;
  const value = source[key];
  if ((typeof value !== "number" && typeof value !== "string") || String(value).trim() === "" || !Number.isFinite(Number(value))) {
    throw new ApiRequestError(400, "人工交付表单配置不合法");
  }
  return Number(value);
}

function strictOptionalInteger(source: AnyRecord, key: string): number | undefined {
  const value = strictOptionalFiniteNumber(source, key);
  if (value === undefined) return undefined;
  if (!Number.isInteger(value)) throw new ApiRequestError(400, "人工交付表单配置不合法");
  return value;
}

function strictManualFormOptions(source: AnyRecord, key: string): string[] {
  if (!Object.prototype.hasOwnProperty.call(source, key)) return [];
  if (!Array.isArray(source[key]) || source[key].some((item: unknown) => typeof item !== "string" || !item.trim())) {
    throw new ApiRequestError(400, "人工交付表单配置不合法");
  }
  return Array.from(new Set((source[key] as string[]).map((item) => item.trim()))).sort();
}

function compileManualFormRegex(raw: string): RegExp {
  let pattern = raw.trim();
  let flags = "";
  if (pattern.startsWith("/")) {
    const end = findLastUnescapedSlash(pattern);
    if (end > 0) {
      flags = pattern.slice(end + 1);
      pattern = pattern.slice(1, end);
      if (!/^[gimsuy]*$/.test(flags)) throw new ApiRequestError(400, "人工交付表单配置不合法");
      flags = Array.from(new Set(flags.replace(/[gy]/g, "").split(""))).join("");
    }
  }
  try {
    return new RegExp(pattern, flags);
  } catch {
    throw new ApiRequestError(400, "人工交付表单配置不合法");
  }
}

function manualFormRegexMatches(raw: string, value: string): boolean {
  return compileManualFormRegex(raw).test(value);
}

function findLastUnescapedSlash(raw: string): number {
  for (let index = raw.length - 1; index > 0; index -= 1) {
    if (raw[index] !== "/") continue;
    let backslashes = 0;
    for (let cursor = index - 1; cursor >= 0 && raw[cursor] === "\\"; cursor -= 1) backslashes += 1;
    if (backslashes % 2 === 0) return index;
  }
  return -1;
}

function strictPositiveInteger(value: unknown): number | null {
  const parsed = strictNonNegativeInteger(value);
  return parsed !== null && parsed > 0 ? parsed : null;
}

function strictNonNegativeInteger(value: unknown): number | null {
  if (typeof value === "number") return Number.isSafeInteger(value) && value >= 0 ? value : null;
  if (typeof value !== "string" || !/^\d+$/.test(value.trim())) return null;
  const parsed = Number(value.trim());
  return Number.isSafeInteger(parsed) && parsed >= 0 ? parsed : null;
}

function parseWholesalePrices(raw: unknown): Array<{ min_quantity: number; unit_price: number }> {
  const rows = Array.isArray(raw) ? raw : jsonParse(String(raw || "[]"), []);
  if (!Array.isArray(rows)) return [];
  return rows
    .map((item) => ({
      min_quantity: Math.max(0, toInt(item?.min_quantity, 0)),
      unit_price: centsToMoney(moneyToCents(numberValue(item?.unit_price, 0)))
    }))
    .filter((item) => item.min_quantity > 0 && moneyToCents(item.unit_price) > 0)
    .sort((a, b) => a.min_quantity - b.min_quantity);
}

function normalizeWholesalePrices(raw: unknown): Array<{ min_quantity: number; unit_price: string }> {
  const tiers = parseWholesalePrices(raw);
  const seen = new Set<number>();
  let previousPriceCents = Number.POSITIVE_INFINITY;
  const normalized: Array<{ min_quantity: number; unit_price: string }> = [];
  for (const tier of tiers) {
    const priceCents = moneyToCents(tier.unit_price);
    if (seen.has(tier.min_quantity) || priceCents >= previousPriceCents) {
      throw new Error("wholesale_price_invalid");
    }
    seen.add(tier.min_quantity);
    previousPriceCents = priceCents;
    normalized.push({ min_quantity: tier.min_quantity, unit_price: money(tier.unit_price) });
  }
  return normalized;
}

function resolveWholesaleUnitPrice(
  tiers: Array<{ min_quantity: number; unit_price: number }>,
  baseUnitPrice: number,
  matchQuantity: number,
  quantity: number
): { unitPrice: number; discountAmount: number; matched: boolean } {
  const baseCents = moneyToCents(baseUnitPrice);
  if (baseCents <= 0 || matchQuantity <= 0 || quantity <= 0 || !tiers.length) {
    return { unitPrice: centsToMoney(baseCents), discountAmount: 0, matched: false };
  }
  let bestCents = 0;
  for (const tier of tiers) {
    const tierCents = moneyToCents(tier.unit_price);
    if (tier.min_quantity <= 0 || tierCents <= 0 || matchQuantity < tier.min_quantity) continue;
    if (bestCents === 0 || tierCents < bestCents) bestCents = tierCents;
  }
  if (bestCents <= 0 || bestCents >= baseCents) {
    return { unitPrice: centsToMoney(baseCents), discountAmount: 0, matched: false };
  }
  return {
    unitPrice: centsToMoney(bestCents),
    discountAmount: centsToMoney((baseCents - bestCents) * quantity),
    matched: true
  };
}

async function resolvePromotionUnitPrice(
  env: Env,
  productId: number,
  baseUnitPrice: number,
  quantity: number
): Promise<{ unitPrice: number; promotion: PromotionRow | null }> {
  const baseCents = moneyToCents(baseUnitPrice);
  if (productId <= 0 || baseCents <= 0 || quantity <= 0) return { unitPrice: centsToMoney(baseCents), promotion: null };
  const now = new Date().toISOString();
  const rows = await env.DB.prepare(
    `SELECT * FROM promotions
     WHERE is_active=1
       AND scope_type='product'
       AND scope_ref_id=?
       AND (starts_at IS NULL OR starts_at='' OR starts_at<=?)
       AND (ends_at IS NULL OR ends_at='' OR ends_at>=?)
     ORDER BY min_amount ASC, id ASC`
  ).bind(productId, now, now).all<PromotionRow>();
  return resolvePromotionUnitPriceFromRows(rows.results || [], baseUnitPrice, quantity);
}

function resolvePromotionUnitPriceFromRows(
  rows: PromotionRow[],
  baseUnitPrice: number,
  quantity: number
): { unitPrice: number; promotion: PromotionRow | null } {
  const baseCents = moneyToCents(baseUnitPrice);
  if (baseCents <= 0 || quantity <= 0) return { unitPrice: centsToMoney(baseCents), promotion: null };
  const subtotal = centsToMoney(baseCents * quantity);
  let matched: PromotionRow | null = null;
  for (const row of rows) {
    if (Number(row.min_amount || 0) <= 0 || subtotal >= Number(row.min_amount || 0)) {
      matched = row;
    }
  }
  if (!matched) return { unitPrice: centsToMoney(baseCents), promotion: null };
  const value = Number(matched.value || 0);
  if (value <= 0) return { unitPrice: centsToMoney(baseCents), promotion: null };
  let unitCents = baseCents;
  if (matched.type === "fixed") {
    unitCents = Math.max(0, baseCents - moneyToCents(value));
  } else if (matched.type === "percent") {
    const percent = Math.max(0, 100 - Math.min(100, value));
    unitCents = moneyToCents(centsToMoney(baseCents * percent / 100));
  } else if (matched.type === "special_price") {
    unitCents = moneyToCents(value);
  }
  if (unitCents >= baseCents) return { unitPrice: centsToMoney(baseCents), promotion: null };
  return { unitPrice: centsToMoney(unitCents), promotion: matched };
}

async function resolveMemberUnitPrice(
  env: Env,
  memberLevelId: number,
  productId: number,
  skuId: number,
  baseUnitPrice: number
): Promise<{ unitPrice: number; discountAmount: number }> {
  const baseCents = moneyToCents(baseUnitPrice);
  if (memberLevelId <= 0 || productId <= 0 || baseCents <= 0) {
    return { unitPrice: centsToMoney(baseCents), discountAmount: 0 };
  }
  const level = await env.DB.prepare("SELECT * FROM member_levels WHERE id=? AND is_active=1")
    .bind(memberLevelId)
    .first<MemberLevelRow>();
  if (!level) return { unitPrice: centsToMoney(baseCents), discountAmount: 0 };

  const rows = await env.DB.prepare(
    `SELECT * FROM member_level_prices
     WHERE member_level_id=? AND product_id=? AND sku_id IN (?, 0)
     ORDER BY CASE WHEN sku_id=? THEN 0 ELSE 1 END, id ASC`
  ).bind(memberLevelId, productId, skuId, skuId).all<MemberLevelPriceRow>();
  return resolveMemberUnitPriceFromRows(level, rows.results || [], skuId, baseUnitPrice);
}

function resolveMemberUnitPriceFromRows(
  level: MemberLevelRow | null,
  rows: MemberLevelPriceRow[],
  skuId: number,
  baseUnitPrice: number
): { unitPrice: number; discountAmount: number } {
  const baseCents = moneyToCents(baseUnitPrice);
  if (!level || baseCents <= 0) return { unitPrice: centsToMoney(baseCents), discountAmount: 0 };
  const orderedRows = [...rows].sort((left, right) => {
    const leftPriority = Number(left.sku_id) === skuId ? 0 : 1;
    const rightPriority = Number(right.sku_id) === skuId ? 0 : 1;
    return leftPriority - rightPriority || Number(left.id) - Number(right.id);
  });
  for (const row of orderedRows) {
    if (Number(row.sku_id) !== skuId && Number(row.sku_id) !== 0) continue;
    const priceCents = moneyToCents(Number(row.price_amount || 0));
    if (priceCents > 0 && priceCents < baseCents) {
      return { unitPrice: centsToMoney(priceCents), discountAmount: centsToMoney(baseCents - priceCents) };
    }
    if (priceCents > 0) return { unitPrice: centsToMoney(baseCents), discountAmount: 0 };
  }

  const rate = Number(level.discount_rate || 100);
  if (rate <= 0 || rate >= 100) return { unitPrice: centsToMoney(baseCents), discountAmount: 0 };
  const unitCents = moneyToCents(centsToMoney(baseCents * rate / 100));
  if (unitCents >= baseCents) return { unitPrice: centsToMoney(baseCents), discountAmount: 0 };
  return { unitPrice: centsToMoney(unitCents), discountAmount: centsToMoney(baseCents - unitCents) };
}

async function saveProduct(env: Env, body: AnyRecord, id?: number): Promise<number> {
  const currentProduct = id
    ? await env.DB.prepare("SELECT * FROM products WHERE id=?").bind(id).first<ProductRow>()
    : null;
  if (id && !currentProduct) throw new ApiRequestError(404, "商品不存在");

  const title = normalizeLocalized(body.title, "未命名商品");
  const description = normalizeLocalized(body.description, "");
  const content = sanitizeLocalizedHtml(body.content);
  const instructions = sanitizeLocalizedHtml(body.instructions);
  const slug = clean(body.slug, 160) || slugify(localizedFirst(title));
  if (!slug) throw new ApiRequestError(400, "商品别名不能为空");
  const duplicateSlug = await env.DB.prepare("SELECT id FROM products WHERE slug=? AND (? IS NULL OR id<>?) LIMIT 1")
    .bind(slug, id ?? null, id ?? null)
    .first<{ id: number }>();
  if (duplicateSlug) throw new ApiRequestError(409, "商品别名已存在");

  const categoryId = Object.prototype.hasOwnProperty.call(body, "category_id")
    ? (toInt(body.category_id, 0) || null)
    : (currentProduct?.category_id || null);
  if (categoryId) {
    const category = await env.DB.prepare("SELECT id FROM categories WHERE id=?").bind(categoryId).first<{ id: number }>();
    if (!category) throw new ApiRequestError(400, "商品分类不存在");
    const childCount = await count(env, "SELECT COUNT(*) AS count FROM categories WHERE parent_id=?", [categoryId]);
    if (childCount > 0 && Number(currentProduct?.category_id || 0) !== categoryId) {
      throw new ApiRequestError(400, "商品只能放在末级分类中");
    }
  }

  const hasActiveMapping = id ? await productHasActiveUpstreamMapping(env, id) : false;
  const requestedFulfillment = clean(body.fulfillment_type, 20) || currentProduct?.fulfillment_type || "manual";
  const fulfillmentType = hasActiveMapping ? "upstream" : requestedFulfillment;
  if (!["manual", "auto", "upstream"].includes(fulfillmentType)) throw new ApiRequestError(400, "交付方式不合法");
  const purchaseType = clean(body.purchase_type, 20) || currentProduct?.purchase_type || "member";
  if (!["member", "guest"].includes(purchaseType)) throw new ApiRequestError(400, "购买身份限制不合法");
  const stockDisplayMode = clean(body.stock_display_mode, 20) || currentProduct?.stock_display_mode || "exact";
  if (!["exact", "status", "range", "hidden"].includes(stockDisplayMode)) throw new ApiRequestError(400, "库存展示方式不合法");
  const manualFormSchema = normalizeManualFormSchema(body.manual_form_schema ?? jsonParse(currentProduct?.manual_form_schema_json || "{}", {}));

  const rawPrice = numberValue(body.price_amount, Number(currentProduct?.price_amount || 0));
  const rawCost = numberValue(body.cost_price_amount, Number(currentProduct?.cost_price_amount || 0));
  if (rawPrice <= 0 || rawCost < 0) throw new ApiRequestError(400, "商品价格或成本价不合法");
  const rawSkus = Array.isArray(body.skus) ? body.skus : [];
  const existingSkus = id
    ? (await env.DB.prepare("SELECT * FROM product_skus WHERE product_id=? ORDER BY sort_order ASC, id ASC").bind(id).all<SkuRow>()).results || []
    : [];
  const skus = await normalizeProductSkusForSave(env, {
    productId: id || 0,
    fulfillmentType,
    rawSkus,
    existingSkus,
    productPrice: rawPrice,
    productCost: rawCost,
    productStock: body.manual_stock_total
  });
  const activeSkus = skus.filter((sku) => sku.is_active !== false);
  const price = Math.min(...activeSkus.map((sku) => Number(sku.price_amount)));
  const cost = Math.min(...activeSkus.map((sku) => Number(sku.cost_price_amount)));
  const effectiveStock = fulfillmentType === "manual" ? aggregateSkuStock(skus) : 0;
  const minPurchaseQuantity = Math.max(0, toInt(body.min_purchase_quantity, Number(currentProduct?.min_purchase_quantity || 0)));
  const maxPurchaseQuantity = Math.max(0, toInt(body.max_purchase_quantity, Number(currentProduct?.max_purchase_quantity || 0)));
  if (minPurchaseQuantity > 0 && maxPurchaseQuantity > 0 && minPurchaseQuantity > maxPurchaseQuantity) {
    throw new ApiRequestError(400, "单次最小购买数量不能大于最大购买数量");
  }
  const hasWholesalePricesInput = Object.prototype.hasOwnProperty.call(body, "wholesale_prices");
  let wholesalePricesJson = "[]";
  if (hasWholesalePricesInput) {
    wholesalePricesJson = stringify(normalizeWholesalePrices(body.wholesale_prices || []));
  } else if (id) {
    const current = await env.DB.prepare("SELECT wholesale_prices_json FROM products WHERE id=?").bind(id).first<{ wholesale_prices_json?: string }>();
    wholesalePricesJson = current?.wholesale_prices_json || "[]";
  }

  if (id) {
    await env.DB.prepare(
      `UPDATE products SET
        category_id=?, slug=?, seo_meta_json=?, title_json=?, description_json=?,
        content_json=?, instructions_json=?, price_amount=?, cost_price_amount=?,
        wholesale_prices_json=?, images_json=?, tags_json=?, purchase_type=?, min_purchase_quantity=?,
        max_purchase_quantity=?, stock_display_mode=?, fulfillment_type=?,
        manual_form_schema_json=?, manual_stock_total=?, payment_channel_ids_json=?,
        is_affiliate_enabled=?, is_active=?, sort_order=?, updated_at=CURRENT_TIMESTAMP
       WHERE id=?`
    ).bind(
      categoryId, slug, stringify(body.seo_meta || {}), stringify(title),
      stringify(description), stringify(content),
      stringify(instructions), price, cost, wholesalePricesJson, stringifyArray(body.images),
      stringifyArray(body.tags), purchaseType,
      minPurchaseQuantity, maxPurchaseQuantity,
      stockDisplayMode,
      fulfillmentType,
      stringify(manualFormSchema), effectiveStock,
      stringifyArray(body.payment_channel_ids), boolInt(body.is_affiliate_enabled, false),
      boolInt(body.is_active, true), toInt(body.sort_order, 0), id
    ).run();
  } else {
    const insert = await env.DB.prepare(
      `INSERT INTO products (
        category_id, slug, seo_meta_json, title_json, description_json, content_json,
        instructions_json, price_amount, cost_price_amount, wholesale_prices_json, images_json, tags_json,
        purchase_type, min_purchase_quantity, max_purchase_quantity, stock_display_mode,
        fulfillment_type, manual_form_schema_json, manual_stock_total,
        payment_channel_ids_json, is_affiliate_enabled, is_active, sort_order
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    ).bind(
      categoryId, slug, stringify(body.seo_meta || {}), stringify(title),
      stringify(description), stringify(content),
      stringify(instructions), price, cost, wholesalePricesJson, stringifyArray(body.images),
      stringifyArray(body.tags), purchaseType,
      minPurchaseQuantity, maxPurchaseQuantity,
      stockDisplayMode,
      fulfillmentType,
      stringify(manualFormSchema), effectiveStock,
      stringifyArray(body.payment_channel_ids), boolInt(body.is_affiliate_enabled, false),
      boolInt(body.is_active, true), toInt(body.sort_order, 0)
    ).run();
    id = Number(insert.meta.last_row_id);
  }

  await syncSkus(env, id, skus, price, cost, effectiveStock);
  return id;
}

async function normalizeProductSkusForSave(
  env: Env,
  input: {
    productId: number;
    fulfillmentType: string;
    rawSkus: AnyRecord[];
    existingSkus: SkuRow[];
    productPrice: number;
    productCost: number;
    productStock: unknown;
  }
): Promise<AnyRecord[]> {
  const existingById = new Map(input.existingSkus.map((sku) => [sku.id, sku]));
  const existingByCode = new Map(input.existingSkus.map((sku) => [clean(sku.sku_code, 80).toLowerCase(), sku]));
  const source = input.rawSkus.length ? input.rawSkus : [{
    id: input.existingSkus[0]?.id || 0,
    sku_code: "DEFAULT",
    spec_values: {},
    price_amount: input.productPrice,
    cost_price_amount: input.productCost,
    manual_stock_total: input.productStock,
    is_active: true,
    sort_order: 0
  }];
  const seenIds = new Set<number>();
  const seenCodes = new Set<string>();
  const normalized: AnyRecord[] = [];

  for (const [index, raw] of source.entries()) {
    let skuId = toInt(raw?.id, 0);
    let existing = skuId > 0 ? existingById.get(skuId) : undefined;
    if (skuId > 0 && !existing) throw new ApiRequestError(400, "SKU 不属于当前商品");
    const skuCode = clean(raw?.sku_code, 80) || `SKU-${index + 1}`;
    const codeKey = skuCode.toLowerCase();
    if (seenCodes.has(codeKey)) throw new ApiRequestError(400, "同一商品的 SKU 编码不能重复");
    seenCodes.add(codeKey);
    if (!existing && existingByCode.has(codeKey)) {
      existing = existingByCode.get(codeKey);
      skuId = Number(existing?.id || 0);
    }
    if (skuId > 0 && seenIds.has(skuId)) throw new ApiRequestError(400, "SKU 不能重复提交");
    if (skuId > 0) seenIds.add(skuId);

    const price = centsToMoney(moneyToCents(numberValue(raw?.price_amount, input.productPrice)));
    const cost = centsToMoney(moneyToCents(numberValue(raw?.cost_price_amount, input.productCost)));
    if (price <= 0 || cost < 0) throw new ApiRequestError(400, "SKU 价格或成本价不合法");
    const stockText = String(raw?.manual_stock_total ?? "").trim().toLowerCase();
    if (input.fulfillmentType === "manual" && stockText && stockText !== "unlimited") {
      const parsedStock = Number(stockText);
      if (!Number.isInteger(parsedStock) || parsedStock < -1) throw new ApiRequestError(400, "SKU 库存不合法");
    }
    const stock = input.fulfillmentType === "manual" ? stockValue(raw?.manual_stock_total) : 0;
    const isActive = raw?.is_active !== false && ![0, "0", "false"].includes(raw?.is_active);
    normalized.push({
      ...raw,
      id: skuId,
      sku_code: skuCode,
      spec_values: jsonObject(raw?.spec_values),
      price_amount: price,
      cost_price_amount: cost,
      manual_stock_total: stock,
      is_active: isActive,
      sort_order: toInt(raw?.sort_order, index)
    });
  }

  if (!normalized.some((sku) => sku.is_active)) throw new ApiRequestError(400, "至少需要保留一个启用的 SKU");
  if (input.fulfillmentType === "auto" && input.productId > 0) {
    const activeIds = new Set(normalized.filter((sku) => sku.is_active && sku.id > 0).map((sku) => Number(sku.id)));
    for (const existing of input.existingSkus) {
      if (!existing.is_active || activeIds.has(existing.id)) continue;
      const outstanding = await count(
        env,
        "SELECT COUNT(*) AS count FROM card_secrets WHERE product_id=? AND sku_id=? AND status IN ('available','reserved')",
        [input.productId, existing.id]
      );
      if (outstanding > 0) throw new ApiRequestError(409, "仍有可用或已锁定卡密的 SKU 不能停用");
    }
  }
  return normalized;
}

async function syncSkus(env: Env, productId: number, skus: AnyRecord[], productPrice: number, productCost: number, productStock: number): Promise<void> {
  if (!skus.length) {
    const existing = await env.DB.prepare("SELECT id FROM product_skus WHERE product_id=? LIMIT 1").bind(productId).first<{ id: number }>();
    if (existing) {
      await env.DB.prepare(
        "UPDATE product_skus SET sku_code=?, spec_values_json=?, price_amount=?, cost_price_amount=?, manual_stock_total=?, is_active=1, sort_order=0, updated_at=CURRENT_TIMESTAMP WHERE id=?"
      ).bind("DEFAULT", "{}", productPrice, productCost, productStock, existing.id).run();
    } else {
      await env.DB.prepare(
        "INSERT INTO product_skus (product_id, sku_code, spec_values_json, price_amount, cost_price_amount, manual_stock_total, is_active, sort_order) VALUES (?, 'DEFAULT', '{}', ?, ?, ?, 1, 0)"
      ).bind(productId, productPrice, productCost, productStock).run();
    }
    return;
  }

  const seen = new Set<number>();
  for (const [index, sku] of skus.entries()) {
    const skuId = toInt(sku.id, 0);
    const values = stringify(sku.spec_values || {});
    const stock = stockValue(sku.manual_stock_total);
    if (skuId > 0) {
      seen.add(skuId);
      await env.DB.prepare(
        `UPDATE product_skus SET sku_code=?, spec_values_json=?, price_amount=?, cost_price_amount=?,
         manual_stock_total=?, is_active=?, sort_order=?, updated_at=CURRENT_TIMESTAMP WHERE id=? AND product_id=?`
      ).bind(
        clean(sku.sku_code, 80) || `SKU-${index + 1}`,
        values,
        numberValue(sku.price_amount, productPrice),
        numberValue(sku.cost_price_amount, productCost),
        stock,
        boolInt(sku.is_active, true),
        toInt(sku.sort_order, index),
        skuId,
        productId
      ).run();
    } else {
      const inserted = await env.DB.prepare(
        `INSERT INTO product_skus (product_id, sku_code, spec_values_json, price_amount, cost_price_amount, manual_stock_total, is_active, sort_order)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)`
      ).bind(
        productId,
        clean(sku.sku_code, 80) || `SKU-${index + 1}`,
        values,
        numberValue(sku.price_amount, productPrice),
        numberValue(sku.cost_price_amount, productCost),
        stock,
        boolInt(sku.is_active, true),
        toInt(sku.sort_order, index)
      ).run();
      seen.add(Number(inserted.meta.last_row_id));
    }
  }
  const existing = await env.DB.prepare("SELECT id FROM product_skus WHERE product_id=?").bind(productId).all<{ id: number }>();
  for (const row of existing.results || []) {
    if (!seen.has(row.id)) {
      await env.DB.prepare("UPDATE product_skus SET is_active=0, updated_at=CURRENT_TIMESTAMP WHERE id=? AND product_id=?")
        .bind(row.id, productId)
        .run();
    }
  }
}

type ProductHydrationPreload = {
  categories: Map<number, CategoryRow>;
  skus: Map<number, SkuRow[]>;
  upstreamProductIds: Set<number>;
  autoStock: Map<number, Map<number, CardSecretStockCounts>>;
};

async function preloadProductHydration(env: Env, products: ProductRow[]): Promise<ProductHydrationPreload> {
  const productIds = Array.from(new Set(products.map((product) => Number(product.id || 0)).filter((id) => id > 0)));
  if (!productIds.length) {
    return {
      categories: new Map(),
      skus: new Map(),
      upstreamProductIds: new Set(),
      autoStock: new Map()
    };
  }
  const categoryIds = Array.from(new Set(products.map((product) => Number(product.category_id || 0)).filter((id) => id > 0)));
  const autoProductIds = products
    .filter((product) => (clean(product.fulfillment_type, 40) || "manual") === "auto")
    .map((product) => Number(product.id || 0));
  const productPlaceholders = productIds.map(() => "?").join(",");
  const categoryPlaceholders = categoryIds.map(() => "?").join(",");
  const autoPlaceholders = autoProductIds.map(() => "?").join(",");
  const [categoryResult, skuResult, mappingResult, stockResult] = await env.DB.batch([
    categoryIds.length
      ? env.DB.prepare(`SELECT * FROM categories WHERE id IN (${categoryPlaceholders})`).bind(...categoryIds)
      : env.DB.prepare("SELECT * FROM categories WHERE 1=0"),
    env.DB.prepare(
      `SELECT * FROM product_skus WHERE product_id IN (${productPlaceholders}) ORDER BY product_id ASC, sort_order ASC, id ASC`
    ).bind(...productIds),
    env.DB.prepare(
      `SELECT DISTINCT local_product_id AS product_id FROM product_mappings
       WHERE local_product_id IN (${productPlaceholders}) AND is_active=1`
    ).bind(...productIds),
    autoProductIds.length
      ? env.DB.prepare(
        `SELECT product_id, sku_id, COUNT(*) AS total,
                COALESCE(SUM(CASE WHEN status='available' THEN 1 ELSE 0 END), 0) AS available,
                COALESCE(SUM(CASE WHEN status='reserved' THEN 1 ELSE 0 END), 0) AS reserved,
                COALESCE(SUM(CASE WHEN status='used' THEN 1 ELSE 0 END), 0) AS used
         FROM card_secrets WHERE product_id IN (${autoPlaceholders}) GROUP BY product_id, sku_id`
      ).bind(...autoProductIds)
      : env.DB.prepare("SELECT product_id, sku_id, 0 AS total, 0 AS available, 0 AS reserved, 0 AS used FROM card_secrets WHERE 1=0")
  ]);

  const categories = new Map<number, CategoryRow>();
  for (const row of (categoryResult.results || []) as CategoryRow[]) categories.set(Number(row.id), row);

  const skus = new Map<number, SkuRow[]>();
  for (const row of (skuResult.results || []) as SkuRow[]) {
    const productRows = skus.get(Number(row.product_id)) || [];
    productRows.push(row);
    skus.set(Number(row.product_id), productRows);
  }

  const upstreamProductIds = new Set<number>(
    ((mappingResult.results || []) as Array<{ product_id: number }>).map((row) => Number(row.product_id || 0))
  );
  const autoStock = new Map<number, Map<number, CardSecretStockCounts>>();
  for (const productId of autoProductIds) autoStock.set(productId, new Map());
  for (const row of (stockResult.results || []) as Array<CardSecretStockCounts & { product_id: number; sku_id: number }>) {
    const productStock = autoStock.get(Number(row.product_id)) || new Map<number, CardSecretStockCounts>();
    productStock.set(Number(row.sku_id), {
      total: Number(row.total || 0),
      available: Number(row.available || 0),
      reserved: Number(row.reserved || 0),
      used: Number(row.used || 0)
    });
    autoStock.set(Number(row.product_id), productStock);
  }
  return { categories, skus, upstreamProductIds, autoStock };
}

async function hydrateProduct(
  env: Env,
  product: ProductRow,
  options: {
    publicOnly: boolean;
    resellerContext?: ResellerContext | null;
    includeRelatedPosts?: boolean;
    preload?: ProductHydrationPreload;
  }
): Promise<AnyRecord> {
  const [category, loadedSkus] = options.preload
    ? [options.preload.categories.get(Number(product.category_id || 0)) || null, options.preload.skus.get(product.id) || []]
    : await Promise.all([
      product.category_id ? env.DB.prepare("SELECT * FROM categories WHERE id=?").bind(product.category_id).first<CategoryRow>() : null,
      env.DB.prepare("SELECT * FROM product_skus WHERE product_id=? ORDER BY sort_order ASC, id ASC").bind(product.id).all<SkuRow>()
        .then((result) => result.results || [])
    ]);
  const fulfillmentType = clean(product.fulfillment_type, 40) || "manual";
  const isAutoFulfillment = fulfillmentType === "auto";
  const isUpstreamFulfillment = fulfillmentType === "upstream";
  const skuSource = loadedSkus;
  const usesUpstreamStock = isUpstreamFulfillment && (options.preload
    ? options.preload.upstreamProductIds.has(product.id)
    : await productHasActiveUpstreamMapping(env, product.id));
  const usesCardSecretStock = isAutoFulfillment;
  const autoStockMap = usesCardSecretStock
    ? (options.preload?.autoStock.get(product.id) || await loadCardSecretStockMap(env, product.id))
    : new Map<number, CardSecretStockCounts>();
  let skuRows = skuSource.map((row) => formatSku(row, autoStockMap.get(row.id), usesUpstreamStock));
  let resellerBasePriceAmount = Number(product.price_amount || 0);
  if (options.publicOnly && options.resellerContext) {
    const pricedSkus: AnyRecord[] = [];
    for (const sku of skuSource) {
      const pricing = await resellerPricingForSku(env, options.resellerContext, product, sku);
      if (!pricing.listed) continue;
      const formatted = formatSku(sku, autoStockMap.get(sku.id), usesUpstreamStock);
      formatted.base_price_amount = money(pricing.baseUnitPrice);
      formatted.price_amount = Number(money(pricing.unitPrice));
      formatted.reseller_rule = {
        pricing_mode: pricing.rule.pricing_mode || "inherit",
        is_listed: pricing.rule.is_listed !== false && Number(pricing.rule.is_listed ?? 1) !== 0
      };
      pricedSkus.push(formatted);
    }
    if (!pricedSkus.some((sku) => sku.is_active)) return null as any;
    skuRows = pricedSkus;
  }
  const activeSkuSource = skuSource.filter((sku) => sku.is_active);
  const autoStockSummary = activeSkuSource.reduce(
    (summary, sku) => {
      const counts = autoStockMap.get(sku.id) || { total: 0, available: 0, reserved: 0, used: 0 };
      summary.total += counts.total;
      summary.available += counts.available;
      summary.reserved += counts.reserved;
      summary.used += counts.used;
      return summary;
    },
    { total: 0, available: 0, reserved: 0, used: 0 }
  );
  const stockSummary = usesCardSecretStock
    ? { total: 0, locked: 0, sold: 0 }
    : productStockSummary(product, skuSource);
  const available = usesCardSecretStock
    ? autoStockSummary.available
    : productAvailableStock(product, skuSource);
  const productAutoStockAvailable = usesCardSecretStock
    ? autoStockSummary.available
    : usesUpstreamStock
      ? (available === null ? -1 : available)
      : 0;
  const productAutoStockTotal = usesCardSecretStock
    ? autoStockSummary.total
    : usesUpstreamStock
      ? stockSummary.total
      : 0;
  const productAutoStockLocked = usesCardSecretStock
    ? autoStockSummary.reserved
    : usesUpstreamStock
      ? stockSummary.locked
      : 0;
  const productAutoStockSold = usesCardSecretStock
    ? autoStockSummary.used
    : usesUpstreamStock
      ? stockSummary.sold
      : 0;
  const stockStatus = stockStatusFor(available);
  const relatedPosts = options.publicOnly && options.includeRelatedPosts !== false
    ? await relatedPostsForProduct(env, product.id)
    : [];
  const activeSkuRows = skuRows.filter((sku) => sku.is_active);
  const displayPriceAmount = activeSkuRows.length
    ? Math.min(...activeSkuRows.map((sku) => Number(sku.price_amount || 0)))
    : Number(product.price_amount || 0);
  if (options.publicOnly && options.resellerContext) {
    const activeSource = skuSource.filter((sku) => sku.is_active);
    if (activeSource.length) resellerBasePriceAmount = Math.min(...activeSource.map((sku) => Number(sku.price_amount || 0)));
  }
  return {
    id: product.id,
    category_id: product.category_id || 0,
    slug: product.slug,
    seo_meta: jsonParse(product.seo_meta_json, {}),
    title: jsonParse(product.title_json, {}),
    description: jsonParse(product.description_json, {}),
    content: jsonParse(product.content_json, {}),
    instructions: jsonParse(product.instructions_json, {}),
    price_amount: displayPriceAmount,
    base_price_amount: money(resellerBasePriceAmount),
    cost_price_amount: Number(product.cost_price_amount || 0),
    wholesale_prices: options.publicOnly && options.resellerContext
      ? []
      : parseWholesalePrices(product.wholesale_prices_json).map((tier) => ({
        min_quantity: tier.min_quantity,
        unit_price: money(tier.unit_price)
      })),
    images: jsonParse(product.images_json, []),
    tags: jsonParse(product.tags_json, []),
    purchase_type: product.purchase_type || "guest",
    min_purchase_quantity: product.min_purchase_quantity || 1,
    max_purchase_quantity: product.max_purchase_quantity || 0,
    stock_display_mode: product.stock_display_mode || "exact",
    stock_quantity_hidden: product.stock_display_mode !== "exact",
    fulfillment_type: product.fulfillment_type || "manual",
    manual_form_schema: jsonParse(product.manual_form_schema_json, { fields: [] }),
    manual_stock_total: stockSummary.total,
    manual_stock_locked: stockSummary.locked,
    manual_stock_sold: stockSummary.sold,
    manual_stock_available: available === null ? -1 : available,
    payment_channel_ids: jsonParse(product.payment_channel_ids_json, []),
    is_affiliate_enabled: Boolean(product.is_affiliate_enabled),
    auto_stock_available: productAutoStockAvailable,
    auto_stock_total: productAutoStockTotal,
    auto_stock_locked: productAutoStockLocked,
    auto_stock_sold: productAutoStockSold,
    uses_upstream_stock: usesUpstreamStock,
    is_mapped: usesUpstreamStock,
    is_active: Boolean(product.is_active),
    is_sold_out: stockStatus === "out_of_stock",
    stock_status: stockStatus,
    sort_order: product.sort_order,
    created_at: product.created_at,
    updated_at: product.updated_at,
    category: category ? formatCategory(category) : undefined,
    skus: options.publicOnly ? skuRows.filter((sku) => sku.is_active) : skuRows,
    related_posts: relatedPosts
  };
}

function formatCategory(row: CategoryRow): AnyRecord {
  return {
    id: row.id,
    parent_id: row.parent_id || 0,
    slug: row.slug,
    name: jsonParse(row.name_json, {}),
    icon: row.icon || "",
    sort_order: row.sort_order || 0,
    is_active: Boolean(row.is_active),
    created_at: row.created_at,
    updated_at: row.updated_at
  };
}

function formatSku(row: SkuRow, autoStock?: CardSecretStockCounts, usesUpstreamStock = false): AnyRecord {
  const available = autoStock ? autoStock.available : availableStock(row);
  const normalizedAvailable = available === null ? -1 : available;
  const upstreamStock = usesUpstreamStock ? normalizedAvailable : Number((row as AnyRecord).upstream_stock ?? 0);
  const autoAvailable = autoStock
    ? autoStock.available
    : usesUpstreamStock
      ? normalizedAvailable
      : row.auto_stock_available;
  const autoTotal = autoStock
    ? autoStock.total
    : usesUpstreamStock
      ? (row.manual_stock_total < 0 ? -1 : row.manual_stock_total)
      : row.auto_stock_total;
  return {
    id: row.id,
    product_id: row.product_id,
    sku_code: row.sku_code,
    spec_values: jsonParse(row.spec_values_json, {}),
    price_amount: Number(row.price_amount || 0),
    cost_price_amount: Number(row.cost_price_amount || 0),
    manual_stock_total: row.manual_stock_total,
    manual_stock_locked: row.manual_stock_locked,
    manual_stock_sold: row.manual_stock_sold,
    manual_stock_available: normalizedAvailable,
    auto_stock_available: autoAvailable,
    auto_stock_total: autoTotal,
    upstream_stock: upstreamStock,
    uses_upstream_stock: usesUpstreamStock,
    is_active: Boolean(row.is_active),
    sort_order: row.sort_order,
    stock_status: stockStatusFor(available),
    stock_snapshot_at: row.updated_at,
    stock_quantity_hidden: false,
    created_at: row.created_at,
    updated_at: row.updated_at
  };
}

async function hydrateOrder(
  env: Env,
  order: OrderRow,
  options: { includeChildren?: boolean; includeCost?: boolean } = {}
): Promise<AnyRecord> {
  const includeChildren = options.includeChildren !== false;
  const includeCost = options.includeCost === true;
  if (includeChildren && order.parent_id == null) {
    const results = await env.DB.batch(rootOrderHydrationStatements(env, order.id));
    return formatRootOrderHydration(order, results, includeCost);
  }
  const itemsQuery = order.parent_id == null
    ? env.DB.prepare(
      `SELECT oi.* FROM order_items oi
       JOIN orders item_order ON item_order.id=oi.order_id
       WHERE item_order.id=? OR item_order.parent_id=?
       ORDER BY item_order.id ASC, oi.id ASC`
    ).bind(order.id, order.id).all<OrderItemRow>()
    : env.DB.prepare("SELECT * FROM order_items WHERE order_id=? ORDER BY id ASC").bind(order.id).all<OrderItemRow>();
  const fulfillmentQuery = env.DB.prepare("SELECT * FROM fulfillments WHERE order_id=?").bind(order.id).first<FulfillmentRow>();
  const paymentsQuery = env.DB.prepare(
    `SELECT p.*, pc.name AS channel_name
     FROM payments p LEFT JOIN payment_channels pc ON pc.id=p.channel_id
     WHERE p.order_id=?
     ORDER BY p.id DESC`
  ).bind(order.id).all<PaymentRow>();
  const [itemsResult, fulfillment, paymentsResult] = await Promise.all([
    itemsQuery,
    fulfillmentQuery,
    paymentsQuery
  ]);
  const storedItems = itemsResult.results || [];
  const items = storedItems.map((item) => formatOrderItem(item, includeCost));
  const payments = (paymentsResult.results || []).map(formatPayment);
  const [products, children] = await Promise.all([
    productRowsByIds(env, storedItems.map((item) => Number(item.product_id || 0))),
    Promise.resolve([])
  ]);
  const allowedPaymentChannelIds = productPaymentChannelIntersection(products);
  return formatHydratedOrderRecord(
    order,
    items,
    payments,
    fulfillment || undefined,
    allowedPaymentChannelIds,
    children
  );
}

async function hydrateRootOrders(
  env: Env,
  orders: OrderRow[],
  options: { includeCost?: boolean } = {}
): Promise<AnyRecord[]> {
  if (!orders.length) return [];
  const rootOrders = orders.filter((order) => order.parent_id == null);
  if (!rootOrders.length) {
    return Promise.all(orders.map((order) => hydrateOrder(env, order, { includeChildren: false, ...options })));
  }

  const rootIds = rootOrders.map((order) => Number(order.id));
  const placeholders = rootIds.map(() => "?").join(",");
  const results = await env.DB.batch([
    env.DB.prepare(
      `SELECT oi.*, COALESCE(item_order.parent_id, item_order.id) AS root_order_id
       FROM order_items oi
       JOIN orders item_order ON item_order.id=oi.order_id
       WHERE item_order.id IN (${placeholders}) OR item_order.parent_id IN (${placeholders})
       ORDER BY root_order_id ASC, item_order.id ASC, oi.id ASC`
    ).bind(...rootIds, ...rootIds),
    env.DB.prepare(
      `SELECT f.*, COALESCE(fulfillment_order.parent_id, fulfillment_order.id) AS root_order_id
       FROM fulfillments f
       JOIN orders fulfillment_order ON fulfillment_order.id=f.order_id
       WHERE fulfillment_order.id IN (${placeholders}) OR fulfillment_order.parent_id IN (${placeholders})
       ORDER BY root_order_id ASC, f.order_id ASC, f.id ASC`
    ).bind(...rootIds, ...rootIds),
    env.DB.prepare(
      `SELECT p.*, pc.name AS channel_name,
              COALESCE(payment_order.parent_id, payment_order.id) AS root_order_id
       FROM payments p
       LEFT JOIN payment_channels pc ON pc.id=p.channel_id
       JOIN orders payment_order ON payment_order.id=p.order_id
       WHERE payment_order.id IN (${placeholders}) OR payment_order.parent_id IN (${placeholders})
       ORDER BY root_order_id ASC, p.order_id ASC, p.id DESC`
    ).bind(...rootIds, ...rootIds),
    env.DB.prepare(
      `SELECT child.*, child.parent_id AS root_order_id
       FROM orders child
       WHERE child.parent_id IN (${placeholders})
       ORDER BY child.parent_id ASC, child.id ASC`
    ).bind(...rootIds),
    env.DB.prepare(
      `SELECT DISTINCT COALESCE(item_order.parent_id, item_order.id) AS root_order_id, product.*
       FROM products product
       JOIN order_items oi ON oi.product_id=product.id
       JOIN orders item_order ON item_order.id=oi.order_id
       WHERE item_order.id IN (${placeholders}) OR item_order.parent_id IN (${placeholders})`
    ).bind(...rootIds, ...rootIds)
  ]);

  type RootScoped<T> = T & { root_order_id: number };
  const itemsByRoot = groupRowsByNumber(
    (results[0]?.results || []) as RootScoped<OrderItemRow>[],
    (row) => row.root_order_id
  );
  const fulfillmentsByRoot = groupRowsByNumber(
    (results[1]?.results || []) as RootScoped<FulfillmentRow>[],
    (row) => row.root_order_id
  );
  const paymentsByRoot = groupRowsByNumber(
    (results[2]?.results || []) as RootScoped<PaymentRow>[],
    (row) => row.root_order_id
  );
  const childrenByRoot = groupRowsByNumber(
    (results[3]?.results || []) as RootScoped<OrderRow>[],
    (row) => row.root_order_id
  );
  const productsByRoot = groupRowsByNumber(
    (results[4]?.results || []) as RootScoped<ProductRow>[],
    (row) => row.root_order_id
  );
  const includeCost = options.includeCost === true;
  const hydratedRoots = new Map<number, AnyRecord>();
  for (const order of rootOrders) {
    hydratedRoots.set(order.id, formatRootOrderHydrationRows(
      order,
      itemsByRoot.get(order.id) || [],
      fulfillmentsByRoot.get(order.id) || [],
      paymentsByRoot.get(order.id) || [],
      childrenByRoot.get(order.id) || [],
      productsByRoot.get(order.id) || [],
      includeCost
    ));
  }

  return Promise.all(orders.map((order) => {
    const hydrated = hydratedRoots.get(order.id);
    return hydrated
      ? Promise.resolve(hydrated)
      : hydrateOrder(env, order, { includeChildren: false, ...options });
  }));
}

function rootOrderHydrationStatements(env: Env, orderId: number): Array<ReturnType<D1Database["prepare"]>> {
  return [
    env.DB.prepare(
      `SELECT oi.* FROM order_items oi
       JOIN orders item_order ON item_order.id=oi.order_id
       WHERE item_order.id=? OR item_order.parent_id=?
       ORDER BY item_order.id ASC, oi.id ASC`
    ).bind(orderId, orderId),
    env.DB.prepare(
      `SELECT f.* FROM fulfillments f
       JOIN orders fulfillment_order ON fulfillment_order.id=f.order_id
       WHERE fulfillment_order.id=? OR fulfillment_order.parent_id=?`
    ).bind(orderId, orderId),
    env.DB.prepare(
      `SELECT p.*, pc.name AS channel_name
       FROM payments p
       LEFT JOIN payment_channels pc ON pc.id=p.channel_id
       JOIN orders payment_order ON payment_order.id=p.order_id
       WHERE payment_order.id=? OR payment_order.parent_id=?
       ORDER BY p.order_id ASC, p.id DESC`
    ).bind(orderId, orderId),
    env.DB.prepare("SELECT * FROM orders WHERE parent_id=? ORDER BY id ASC").bind(orderId),
    env.DB.prepare(
      `SELECT DISTINCT p.* FROM products p
       JOIN order_items oi ON oi.product_id=p.id
       JOIN orders item_order ON item_order.id=oi.order_id
       WHERE item_order.id=? OR item_order.parent_id=?`
    ).bind(orderId, orderId)
  ];
}

async function hydrateRootOrderById(env: Env, orderId: number, includeCost = false): Promise<AnyRecord | null> {
  const [orderResult, ...hydrationResults] = await env.DB.batch([
    env.DB.prepare("SELECT * FROM orders WHERE id=? AND parent_id IS NULL").bind(orderId),
    ...rootOrderHydrationStatements(env, orderId)
  ]);
  const order = orderResult.results?.[0] as OrderRow | undefined;
  return order ? formatRootOrderHydration(order, hydrationResults, includeCost) : null;
}

function formatRootOrderHydration(
  order: OrderRow,
  results: D1Result<unknown>[],
  includeCost: boolean
): AnyRecord {
  const [itemsResult, fulfillmentsResult, paymentsResult, childrenResult, productsResult] = results;
  return formatRootOrderHydrationRows(
    order,
    (itemsResult?.results || []) as OrderItemRow[],
    (fulfillmentsResult?.results || []) as FulfillmentRow[],
    (paymentsResult?.results || []) as PaymentRow[],
    (childrenResult?.results || []) as OrderRow[],
    (productsResult?.results || []) as ProductRow[],
    includeCost
  );
}

function formatRootOrderHydrationRows(
  order: OrderRow,
  storedItems: OrderItemRow[],
  fulfillmentRows: FulfillmentRow[],
  paymentRows: PaymentRow[],
  childRows: OrderRow[],
  products: ProductRow[],
  includeCost: boolean
): AnyRecord {
  const itemsByOrder = groupRowsByNumber(storedItems, (item) => item.order_id);
  const fulfillmentsByOrder = new Map(fulfillmentRows.map((row) => [Number(row.order_id), row]));
  const paymentsByOrder = groupRowsByNumber(paymentRows, (payment) => payment.order_id);
  const productsById = new Map(products.map((product) => [Number(product.id), product]));
  const allItems = storedItems.map((item) => formatOrderItem(item, includeCost));
  const parentFulfillment = fulfillmentsByOrder.get(order.id);
  const parentPayments = (paymentsByOrder.get(order.id) || []).map(formatPayment);
  const children = childRows.length
    ? childRows.map((child) => {
        const childStoredItems = itemsByOrder.get(child.id) || [];
        const childProducts = childStoredItems
          .map((item) => productsById.get(Number(item.product_id)))
          .filter((product): product is ProductRow => Boolean(product));
        return formatHydratedOrderRecord(
          child,
          childStoredItems.map((item) => formatOrderItem(item, includeCost)),
          (paymentsByOrder.get(child.id) || []).map(formatPayment),
          fulfillmentsByOrder.get(child.id),
          productPaymentChannelIntersection(childProducts),
          []
        );
      })
    : allItems.length
      ? [{
          ...formatHydratedOrderRecord(
            order,
            allItems,
            parentPayments,
            parentFulfillment,
            productPaymentChannelIntersection(products),
            []
          ),
          id: order.id,
          order_no: `${order.order_no}-01`,
          parent_id: order.id
        }]
      : [];
  return formatHydratedOrderRecord(
    order,
    allItems,
    parentPayments,
    childRows.length ? undefined : parentFulfillment,
    productPaymentChannelIntersection(products),
    children
  );
}

function groupRowsByNumber<T>(rows: T[], key: (row: T) => number): Map<number, T[]> {
  const grouped = new Map<number, T[]>();
  for (const row of rows) {
    const id = Number(key(row) || 0);
    const values = grouped.get(id);
    if (values) values.push(row);
    else grouped.set(id, [row]);
  }
  return grouped;
}

function formatHydratedOrderRecord(
  order: OrderRow,
  items: AnyRecord[],
  payments: AnyRecord[],
  fulfillment: FulfillmentRow | undefined,
  allowedPaymentChannelIds: number[] | null,
  children: AnyRecord[]
): AnyRecord {
  return {
    ...order,
    original_amount: Number(order.original_amount || 0),
    discount_amount: Number(order.discount_amount || 0),
    promotion_discount_amount: Number(order.promotion_discount_amount || 0),
    wholesale_discount_amount: Number(order.wholesale_discount_amount || 0),
    member_discount_amount: Number(order.member_discount_amount || 0),
    total_amount: Number(order.total_amount || 0),
    wallet_paid_amount: Number(order.wallet_paid_amount || 0),
    online_paid_amount: Number(order.online_paid_amount || 0),
    refunded_amount: Number(order.refunded_amount || 0),
    items,
    payments,
    children,
    ...(allowedPaymentChannelIds === null ? {} : { allowed_payment_channel_ids: allowedPaymentChannelIds }),
    fulfillment: children.length ? null : (fulfillment ? formatFulfillment(fulfillment) : null)
  };
}

function formatOrderItem(item: OrderItemRow, includeCost = false): AnyRecord {
  return {
    id: item.id,
    order_id: item.order_id,
    product_id: item.product_id,
    sku_id: item.sku_id,
    title: jsonParse(item.title_json, {}),
    sku_snapshot: jsonParse(item.sku_snapshot_json, {}),
    quantity: item.quantity,
    original_unit_price: Number(item.original_unit_price || 0),
    unit_price: Number(item.unit_price || 0),
    ...(includeCost ? { cost_price: Number(item.cost_price || 0) } : {}),
    original_total_price: Number(item.original_total_price || 0),
    total_price: Number(item.total_price || 0),
    coupon_discount_amount: Number(item.coupon_discount_amount || 0),
    promotion_discount_amount: Number(item.promotion_discount_amount || 0),
    member_discount_amount: Number(item.member_discount_amount || 0),
    wholesale_discount_amount: Number(item.wholesale_discount_amount || 0),
    fulfillment_type: item.fulfillment_type,
    manual_form_schema_snapshot: jsonParse(item.manual_form_schema_snapshot_json, { fields: [] }),
    manual_form_submission: jsonParse(item.manual_form_submission_json, {}),
    created_at: item.created_at
  };
}

function formatOrderRefund(row: OrderRefundRow): AnyRecord {
  return {
    id: row.id,
    order_id: Number(row.order_id || 0),
    order_no: row.order_no || "",
    user_id: Number(row.user_id || 0),
    guest_email: row.guest_email || "",
    guest_locale: row.guest_locale || "zh-CN",
    type: row.type || "manual",
    refund_type_label: row.type || "manual",
    amount: money(Number(row.amount || 0)),
    currency: row.currency || "CNY",
    remark: row.remark || "",
    items: jsonParse(row.items_json || "[]", []),
    wallet_txn_id: row.wallet_txn_id || 0,
    user_email: row.user_email || "",
    user_display_name: row.user_display_name || "",
    created_at: row.created_at,
    updated_at: row.updated_at
  };
}

function formatFulfillment(fulfillment: FulfillmentRow): AnyRecord {
  const presentation = formatFulfillmentPresentation(fulfillment);
  return {
    id: fulfillment.id,
    order_id: fulfillment.order_id,
    type: fulfillment.type,
    status: fulfillment.status,
    content: presentation.payload,
    delivery_data: presentation.deliveryData,
    payload: presentation.payload,
    payload_line_count: presentation.payloadLineCount,
    created_at: fulfillment.created_at,
    updated_at: fulfillment.updated_at
  };
}

function formatFulfillmentPresentation(fulfillment: FulfillmentRow): { deliveryData: AnyRecord; payload: string; payloadLineCount: number } {
  const deliveryData = jsonParse<AnyRecord>(fulfillment.delivery_data_json || "{}", {});
  if (clean(fulfillment.type, 20) !== "auto") {
    return {
      deliveryData,
      payload: fulfillment.payload || "",
      payloadLineCount: Number(fulfillment.payload_line_count || countNonEmptyLines(fulfillment.payload))
    };
  }

  const autoData = autoFulfillmentDataSource(deliveryData);
  const secretLines = autoFulfillmentSecretLines(autoData, fulfillment.payload);
  if (!secretLines.length) {
    const fallbackPayload = stripLegacyAutoPayload(fulfillment.payload).join("\n");
    return {
      deliveryData,
      payload: fallbackPayload,
      payloadLineCount: countNonEmptyLines(fallbackPayload)
    };
  }

  const normalizedDeliveryData = {
    ...autoData,
    entries: secretLines.map((secret, index) => ({
      key: secretLines.length > 1 ? `卡密 ${index + 1}` : "卡密",
      value: secret
    }))
  };
  const payload = secretLines.join("\n");
  return {
    deliveryData: normalizedDeliveryData,
    payload,
    payloadLineCount: secretLines.length
  };
}

function autoFulfillmentDataSource(deliveryData: AnyRecord): AnyRecord {
  const nestedAuto = jsonObject(deliveryData.auto);
  return Object.keys(nestedAuto).length ? nestedAuto : deliveryData;
}

function autoFulfillmentSecretLines(deliveryData: AnyRecord, fallbackPayload = ""): string[] {
  const cardSecrets = Array.isArray(deliveryData.card_secrets) ? deliveryData.card_secrets : [];
  const cardSecretLines = cardSecrets
    .map((row) => cleanDeliveryText(row?.secret, 20000))
    .filter(Boolean);
  if (cardSecretLines.length) return cardSecretLines;

  const entries = Array.isArray(deliveryData.entries) ? deliveryData.entries : [];
  const entryLines = entries
    .map((entry) => stripLegacyAutoSecretValue(entry?.value || entry?.secret || entry))
    .flatMap((value) => splitNonEmptyLines(value));
  if (entryLines.length) return entryLines;

  return stripLegacyAutoPayload(fallbackPayload);
}

function stripLegacyAutoSecretValue(value: unknown): string {
  const text = cleanDeliveryText(value, 20000);
  if (!text) return "";
  const lines = splitNonEmptyLines(text);
  if (lines.length > 1 && looksLikeAutoSecretLabel(lines[0])) {
    return lines.slice(1).join("\n");
  }
  return text.replace(/^卡密\s*[:：]\s*/i, "").trim();
}

function stripLegacyAutoPayload(value: unknown): string[] {
  const text = cleanDeliveryText(value, 20000);
  if (!text) return [];
  const lines = splitNonEmptyLines(text);
  const result: string[] = [];
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    if (looksLikeAutoSecretLabel(line) && index + 1 < lines.length) {
      result.push(lines[index + 1]);
      index += 1;
      continue;
    }
    result.push(line.replace(/^卡密(?:\s*\d+)?\s*[:：]\s*/i, "").trim());
  }
  return result.filter(Boolean);
}

function splitNonEmptyLines(value: unknown): string[] {
  return String(value ?? "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
}

function countNonEmptyLines(value: unknown): number {
  return splitNonEmptyLines(value).length;
}

function looksLikeAutoSecretLabel(value: unknown): boolean {
  const text = String(value ?? "").trim();
  return /^卡密(?:\s*\d+)?\s*[:：]/i.test(text)
    || /\/\s*[^/]+$/.test(text)
    || /\b(DEFAULT|SKU|sku)\b/.test(text);
}

const COMPLIANCE_SETTING_KEY = "compliance.acknowledgement.v1";
const COMPLIANCE_SEGMENT_1 = "我已阅读并理解上述合规声明提醒";
const COMPLIANCE_SEGMENT_2 = "知悉相关法律风险";
const COMPLIANCE_SEGMENT_3 = "并确认自行承担部署运营和收费行为产生的法律责任";
const COMPLIANCE_FULL_TEXT = "我已阅读并理解上述合规声明提醒，知悉相关法律风险，并确认自行承担部署、运营和收费行为产生的法律责任";

async function complianceStatus(env: Env): Promise<AnyRecord> {
  const row = await env.DB.prepare("SELECT value_json FROM settings WHERE key=?")
    .bind(COMPLIANCE_SETTING_KEY)
    .first<{ value_json: string }>();
  const value = jsonObject(jsonParse(row?.value_json || "{}", {}));
  if (value.acknowledged !== true || value.version !== "v1") return { acknowledged: false };
  return {
    acknowledged: true,
    acknowledged_at: clean(value.acknowledged_at, 80),
    acknowledged_by_admin_id: toInt(value.acknowledged_by_admin_id, 0) || undefined,
    acknowledged_by_username: clean(value.acknowledged_by_username, 120),
    version: "v1"
  };
}

async function complianceAcknowledged(env: Env): Promise<boolean> {
  return (await complianceStatus(env)).acknowledged === true;
}

async function apiAdminComplianceStatus(env: Env): Promise<Response> {
  return apiOk(await complianceStatus(env));
}

async function apiAdminAcknowledgeCompliance(
  request: Request,
  env: Env,
  admin: AdminSessionUser
): Promise<Response> {
  if (!admin.is_super) return apiError("compliance.error.super_admin_required", 403);
  const current = await complianceStatus(env);
  if (current.acknowledged) return apiOk({ already_acknowledged: true });
  const body = await readJson(request);
  const segment1 = String(body.segment1 ?? "");
  const segment2 = String(body.segment2 ?? "");
  const segment3 = String(body.segment3 ?? "");
  const segment3Prefix = "并确认自行承担部署";
  const fullText = segment3.startsWith(segment3Prefix)
    ? `${segment1}，${segment2}，${segment3Prefix}、${segment3.slice(segment3Prefix.length)}`
    : "";
  if (
    segment1 !== COMPLIANCE_SEGMENT_1
    || segment2 !== COMPLIANCE_SEGMENT_2
    || segment3 !== COMPLIANCE_SEGMENT_3
    || fullText !== COMPLIANCE_FULL_TEXT
  ) {
    return apiError("compliance.error.text_mismatch", 400);
  }
  const acknowledgedAt = new Date().toISOString();
  const value = {
    acknowledged: true,
    acknowledged_at: acknowledgedAt,
    acknowledged_by_admin_id: admin.id,
    acknowledged_by_username: admin.username,
    acknowledged_text: COMPLIANCE_FULL_TEXT,
    version: "v1",
    client_ip: clientIp(request),
    user_agent: clean(request.headers.get("User-Agent"), 500)
  };
  const result = await env.DB.prepare(
    `INSERT INTO settings (key, value_json, updated_at)
     VALUES (?, ?, CURRENT_TIMESTAMP)
     ON CONFLICT(key) DO UPDATE SET
       value_json=excluded.value_json,
       updated_at=CURRENT_TIMESTAMP
     WHERE COALESCE(json_extract(settings.value_json, '$.acknowledged'), 0) <> 1`
  ).bind(COMPLIANCE_SETTING_KEY, JSON.stringify(value)).run();
  if (Number(result.meta.changes || 0) === 0) return apiOk({ already_acknowledged: true });
  await recordAuthzAudit(env, admin, "compliance.acknowledge", {
    version: "v1",
    acknowledged_at: acknowledgedAt
  });
  return apiOk({ already_acknowledged: false });
}

function adminPathRequiresCompliance(path: string): boolean {
  return path.startsWith("/admin/payment-channels")
    || path.startsWith("/admin/payments")
    || path.startsWith("/admin/reconciliation/")
    || path === "/admin/reconciliation/run"
    || path.startsWith("/admin/affiliates/commissions")
    || path.startsWith("/admin/affiliates/withdraws")
    || path === "/admin/resellers/operations/finance"
    || path.startsWith("/admin/resellers/ledger-entries")
    || path.startsWith("/admin/resellers/balance-accounts")
    || path.startsWith("/admin/resellers/withdraws")
    || /^\/admin\/users\/\d+\/wallet(?:\/|$)/.test(path)
    || path.startsWith("/admin/wallet/recharges");
}

async function canAccessAdminPath(env: Env, admin: AdminSessionUser, method: string, path: string): Promise<boolean> {
  if (method === "OPTIONS") return true;
  if (admin.is_super) return true;
  if (isAdminSelfServicePath(path)) return true;
  const policies = await authzPoliciesForAdmin(env, admin.id);
  return policies.some((policy) => authzPolicyMatches(policy, method, path));
}

function isAdminSelfServicePath(path: string): boolean {
  return path === "/admin/authz/me"
    || path === "/admin/password"
    || path.startsWith("/admin/2fa/")
    || path.startsWith("/admin/compliance/")
    || path.startsWith("/admin/system/version");
}

async function requireAdmin(request: Request, env: Env): Promise<{ ok: true; user: AdminSessionUser } | { ok: false; response: Response }> {
  const auth = request.headers.get("Authorization") || "";
  const token = auth.startsWith("Bearer ") ? auth.slice(7).trim() : "";
  if (!token) return { ok: false, response: apiError("unauthorized", 401) };
  const tokenHash = await sha256Hex(token);
  const row = await env.DB.prepare(
    `SELECT a.id, a.username, a.is_super, s.expires_at
     FROM admin_sessions s JOIN admins a ON a.id=s.admin_id
     WHERE s.token_hash=?`
  ).bind(tokenHash).first<{ id: number; username: string; is_super: number; expires_at: string }>();
  if (!row || new Date(row.expires_at).getTime() <= Date.now()) {
    return { ok: false, response: apiError("unauthorized", 401) };
  }
  return { ok: true, user: { id: row.id, username: row.username, is_super: Number(row.is_super || 0) } };
}

async function ensureDefaultAuthz(env: Env): Promise<void> {
  await env.DB.batch([
    env.DB.prepare("INSERT OR IGNORE INTO authz_roles (role) VALUES ('role:super_admin')"),
    env.DB.prepare("INSERT OR IGNORE INTO authz_policies (role, object, action) VALUES ('role:super_admin', '/*', '*')")
  ]);
}

async function authzRolesForAdmin(env: Env, adminId: number): Promise<string[]> {
  await ensureDefaultAuthz(env);
  const rows = await env.DB.prepare("SELECT role FROM authz_admin_roles WHERE admin_id=? ORDER BY role ASC")
    .bind(adminId)
    .all<{ role: string }>();
  return (rows.results || []).map((row) => row.role);
}

async function authzPoliciesForAdmin(env: Env, adminId: number): Promise<Array<{ subject: string; object: string; action: string }>> {
  await ensureDefaultAuthz(env);
  const rows = await env.DB.prepare(
    `SELECT p.role, p.object, p.action
     FROM authz_admin_roles ar
     JOIN authz_policies p ON p.role=ar.role
     WHERE ar.admin_id=?
     ORDER BY p.role ASC, p.object ASC, p.action ASC`
  ).bind(adminId).all<AuthzPolicyRow>();
  return (rows.results || []).map(formatAuthzPolicy);
}

function formatAuthzPolicy(row: AuthzPolicyRow): { subject: string; object: string; action: string } {
  return {
    subject: row.role,
    object: normalizeAuthzObject(row.object) || "/",
    action: normalizeAuthzAction(row.action) || "GET"
  };
}

function formatAuthzAuditLog(row: AuthzAuditLogRow): AnyRecord {
  return {
    id: row.id,
    operator_admin_id: row.operator_admin_id || 0,
    operator_username: row.operator_username || "",
    target_admin_id: row.target_admin_id || 0,
    target_username: row.target_username || "",
    action: row.action || "",
    role: row.role || "",
    object: row.object || "",
    method: row.method || "",
    request_id: row.request_id || "",
    detail: jsonParse(row.detail_json, {}),
    created_at: row.created_at
  };
}

function normalizeAuthzRole(value: unknown): string {
  const raw = clean(value, 120);
  if (!raw) return "";
  const role = raw.startsWith("role:") ? raw : `role:${raw}`;
  return /^role:[a-zA-Z0-9:_-]{1,100}$/.test(role) ? role : "";
}

function normalizeAdminUsername(value: unknown): string {
  const username = String(value ?? "").trim();
  const length = Array.from(username).length;
  if (length < 3 || length > 64 || /\s/.test(username)) return "";
  return username;
}

function stripRolePrefix(role: string): string {
  return role.replace(/^role:/, "");
}

function normalizeAuthzAction(value: unknown): string {
  const action = clean(value, 20).toUpperCase();
  return ["GET", "POST", "PUT", "PATCH", "DELETE", "*"].includes(action) ? action : "";
}

function normalizeAuthzObject(value: unknown): string {
  const object = clean(value, 300);
  if (!object) return "";
  if (object === "*") return "/*";
  return object.startsWith("/") ? object : `/${object}`;
}

function authzPolicyMatches(policy: { object: string; action: string }, method: string, path: string): boolean {
  const action = normalizeAuthzAction(policy.action);
  if (action !== "*" && action !== method.toUpperCase()) return false;
  const object = normalizeAuthzObject(policy.object);
  if (object === "/*") return true;
  const pattern = `^${escapeRegex(object).replace(/\\\*/g, ".*").replace(/:[^/]+/g, "[^/]+")}$`;
  return new RegExp(pattern).test(path);
}

function escapeRegex(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

async function recordAuthzAudit(
  env: Env,
  operator: AdminSessionUser,
  action: string,
  detail: AnyRecord = {},
  fields: AnyRecord = {}
): Promise<void> {
  await env.DB.prepare(
    `INSERT INTO authz_audit_logs (
       operator_admin_id, operator_username, target_admin_id, target_username,
       action, role, object, method, request_id, detail_json
     ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
  ).bind(
    operator.id,
    operator.username,
    toInt(fields.target_admin_id, 0),
    clean(fields.target_username, 120),
    clean(action, 80),
    clean(fields.role || detail.role, 120),
    clean(fields.object || detail.object, 300),
    clean(fields.method || detail.method, 20),
    randomToken().slice(0, 16),
    JSON.stringify(detail || {})
  ).run();
}

