async function releaseLockedStockForOrder(env: Env, orderId: number): Promise<void> {
  await env.DB.prepare(
    `UPDATE order_manual_stock_locks
     SET status='released', updated_at=CURRENT_TIMESTAMP
     WHERE order_id=? AND status='reserved'`
  ).bind(orderId).run();
}

async function reserveManualStockForOrder(env: Env, orderId: number): Promise<boolean> {
  const rows = await env.DB.prepare(
    `SELECT sku_id, SUM(quantity) AS quantity
     FROM order_items
     WHERE order_id=?
       AND COALESCE(NULLIF(fulfillment_type, ''), 'manual')='manual'
     GROUP BY sku_id`
  ).bind(orderId).all<{ sku_id: number; quantity: number }>();
  const reservations = rows.results || [];
  if (!reservations.length) return true;
  try {
    await env.DB.batch(reservations.map((item) => env.DB.prepare(
      `INSERT INTO order_manual_stock_locks (order_id, sku_id, quantity, status)
       VALUES (?, ?, ?, 'reserved')`
    ).bind(orderId, item.sku_id, item.quantity)));
    return true;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (message.includes("manual_stock_reserve_insufficient") || message.includes("manual_stock_reserve_invalid")) {
      return false;
    }
    throw error;
  }
}

async function reserveFreshCardSecretsForOrder(
  env: Env,
  orderId: number,
  product: ProductRow,
  sku: SkuRow,
  quantity: number
): Promise<CardSecretRow[]> {
  const updated = await env.DB.prepare(
    `UPDATE card_secrets
     SET status='reserved', order_id=?, reserved_at=CURRENT_TIMESTAMP, used_at=NULL, updated_at=CURRENT_TIMESTAMP
     WHERE status='available' AND id IN (
       SELECT id FROM card_secrets
       WHERE product_id=? AND sku_id=? AND status='available'
       ORDER BY id ASC LIMIT ?
     )
     RETURNING *`
  ).bind(orderId, product.id, sku.id, quantity).all<CardSecretRow>();
  const rows = (updated.results || []).sort((left, right) => left.id - right.id);
  if (rows.length !== quantity) {
    await env.DB.prepare(
      `UPDATE card_secrets SET status='available', order_id=NULL, reserved_at=NULL, updated_at=CURRENT_TIMESTAMP
       WHERE order_id=? AND status='reserved'`
    ).bind(orderId).run();
    return [];
  }
  return rows;
}

type OrderProcessingStep = "manual_stock_consumed_at" | "business_effects_completed_at" | "notifications_sent_at";

async function ensureOrderProcessingState(env: Env, orderId: number): Promise<AnyRecord> {
  await env.DB.prepare("INSERT OR IGNORE INTO order_processing_state (order_id) VALUES (?)").bind(orderId).run();
  return await env.DB.prepare("SELECT * FROM order_processing_state WHERE order_id=?")
    .bind(orderId)
    .first<AnyRecord>() || {};
}

async function markOrderProcessingStep(env: Env, orderId: number, step: OrderProcessingStep): Promise<void> {
  await env.DB.prepare(
    `UPDATE order_processing_state SET ${step}=COALESCE(${step}, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP WHERE order_id=?`
  ).bind(orderId).run();
}

async function consumeLockedStockForOrder(env: Env, orderId: number): Promise<void> {
  const processing = await ensureOrderProcessingState(env, orderId);
  if (processing.manual_stock_claimed_at || processing.manual_stock_consumed_at) return;
  await env.DB.prepare(
    `UPDATE order_processing_state
     SET manual_stock_claimed_at=CURRENT_TIMESTAMP,
         manual_stock_consumed_at=CURRENT_TIMESTAMP,
         updated_at=CURRENT_TIMESTAMP
     WHERE order_id=? AND manual_stock_claimed_at IS NULL AND manual_stock_consumed_at IS NULL`
  ).bind(orderId).run();
}

async function reserveCardSecretsForOrder(
  env: Env,
  orderId: number,
  product: ProductRow,
  sku: SkuRow,
  quantity: number
): Promise<CardSecretRow[]> {
  const existing = await env.DB.prepare(
    `SELECT * FROM card_secrets
     WHERE order_id=? AND product_id=? AND sku_id=? AND status IN ('reserved','used')
     ORDER BY id ASC`
  ).bind(orderId, product.id, sku.id).all<CardSecretRow>();
  if ((existing.results || []).length >= quantity) return (existing.results || []).slice(0, quantity);

  const missing = quantity - (existing.results || []).length;
  const candidates = await env.DB.prepare(
    `SELECT * FROM card_secrets
     WHERE product_id=? AND sku_id=? AND status='available'
     ORDER BY id ASC LIMIT ?`
  ).bind(product.id, sku.id, missing).all<CardSecretRow>();
  const ids = (candidates.results || []).map((row) => row.id);
  if (ids.length !== missing) return [];

  const placeholders = ids.map(() => "?").join(",");
  const updated = await env.DB.prepare(
    `UPDATE card_secrets
     SET status='reserved', order_id=?, reserved_at=CURRENT_TIMESTAMP, used_at=NULL, updated_at=CURRENT_TIMESTAMP
     WHERE status='available' AND id IN (${placeholders})`
  ).bind(orderId, ...ids).run();
  if (Number(updated.meta.changes || 0) !== ids.length) {
    await env.DB.prepare(
      `UPDATE card_secrets SET status='available', order_id=NULL, reserved_at=NULL, updated_at=CURRENT_TIMESTAMP
       WHERE order_id=? AND status='reserved' AND id IN (${placeholders})`
    ).bind(orderId, ...ids).run();
    return [];
  }
  const rows = await env.DB.prepare(
    `SELECT * FROM card_secrets
     WHERE order_id=? AND product_id=? AND sku_id=? AND status IN ('reserved','used')
     ORDER BY id ASC LIMIT ?`
  ).bind(orderId, product.id, sku.id, quantity).all<CardSecretRow>();
  return rows.results || [];
}

async function releaseCardSecretsForOrder(env: Env, orderId: number): Promise<void> {
  await env.DB.prepare(
    `UPDATE card_secrets
     SET status='available', order_id=NULL, reserved_at=NULL, used_at=NULL, updated_at=CURRENT_TIMESTAMP
     WHERE order_id=? AND status='reserved'`
  ).bind(orderId).run();
}

async function orderPaymentExpireMinutes(env: Env): Promise<number> {
  const config = await setting(env, "order_config", { payment_expire_minutes: 15 });
  return clampInteger(config.payment_expire_minutes, 1, 10080, 15);
}

function defaultOrderRiskControlConfig(): OrderRiskControlConfig {
  return {
    enabled: false,
    max_pending_orders_per_user: 3,
    max_pending_orders_per_ip: 5,
    max_pending_orders_per_guest_email: 2,
    order_rate_limit: {
      enabled: false,
      window_seconds: 60,
      max_requests: 5,
      block_seconds: 120
    },
    ip_blacklist: [],
    email_blacklist: []
  };
}

function normalizeOrderRiskControlConfig(value: unknown): OrderRiskControlConfig {
  const fallback = defaultOrderRiskControlConfig();
  const input = cloneJsonRecord(value);
  const rateInput = jsonObject(input.order_rate_limit);
  return {
    enabled: input.enabled === true,
    max_pending_orders_per_user: boundedIntegerOrFallback(
      input.max_pending_orders_per_user,
      0,
      100,
      fallback.max_pending_orders_per_user
    ),
    max_pending_orders_per_ip: boundedIntegerOrFallback(
      input.max_pending_orders_per_ip,
      0,
      100,
      fallback.max_pending_orders_per_ip
    ),
    max_pending_orders_per_guest_email: boundedIntegerOrFallback(
      input.max_pending_orders_per_guest_email,
      0,
      100,
      fallback.max_pending_orders_per_guest_email
    ),
    order_rate_limit: {
      enabled: rateInput.enabled === true,
      window_seconds: boundedIntegerOrFallback(
        rateInput.window_seconds,
        10,
        3600,
        fallback.order_rate_limit.window_seconds
      ),
      max_requests: boundedIntegerOrFallback(
        rateInput.max_requests,
        1,
        100,
        fallback.order_rate_limit.max_requests
      ),
      block_seconds: boundedIntegerOrFallback(
        rateInput.block_seconds,
        0,
        86400,
        fallback.order_rate_limit.block_seconds
      )
    },
    ip_blacklist: normalizeIpBlacklist(input.ip_blacklist),
    email_blacklist: normalizeStringList(input.email_blacklist)
      .map((email) => email.toLowerCase())
  };
}

async function orderRiskControlConfig(env: Env): Promise<OrderRiskControlConfig> {
  return normalizeOrderRiskControlConfig(await setting(env, "order_risk_control_config", defaultOrderRiskControlConfig()));
}

async function checkOrderRiskControl(env: Env, input: OrderRiskCheckInput): Promise<OrderRiskCheckResult> {
  let config: OrderRiskControlConfig;
  try {
    config = await orderRiskControlConfig(env);
  } catch (error) {
    console.warn("order risk config unavailable", error);
    return { ok: true };
  }
  if (!config.enabled) return { ok: true };

  if (!input.skipIpCheck && input.clientIp && isIpBlacklisted(input.clientIp, config.ip_blacklist)) {
    return { ok: false, response: apiError("您的 IP 已被限制下单，请联系客服", 403) };
  }
  if (input.isGuest && input.guestEmail) {
    const normalizedEmail = input.guestEmail.trim().toLowerCase();
    if (config.email_blacklist.includes(normalizedEmail)) {
      return { ok: false, response: apiError("该邮箱已被限制下单，请联系客服", 403) };
    }
  }

  const tooManyPending = await exceedsPendingOrderLimit(env, input, config);
  if (tooManyPending) {
    return { ok: false, response: apiError("待支付订单过多，请先完成或取消已有订单后再下单", 429) };
  }

  if (!config.order_rate_limit.enabled) return { ok: true };
  const rate = config.order_rate_limit;
  try {
    if (!input.skipIpCheck && input.clientIp) {
      const ipLimit = await consumeFixedWindowRateLimit(
        env,
        `risk:order:ip:${input.clientIp}`,
        rate.window_seconds,
        rate.max_requests,
        rate.block_seconds
      );
      if (!ipLimit.allowed) {
        return { ok: false, response: apiErrorWithRetryAfter("下单过于频繁，请稍后再试", ipLimit.retryAfter) };
      }
    }
    if (input.userId > 0) {
      const userLimit = await consumeFixedWindowRateLimit(
        env,
        `risk:order:user:${input.userId}`,
        rate.window_seconds,
        rate.max_requests,
        rate.block_seconds
      );
      if (!userLimit.allowed) {
        return { ok: false, response: apiErrorWithRetryAfter("下单过于频繁，请稍后再试", userLimit.retryAfter) };
      }
    }
  } catch (error) {
    console.warn("order risk rate limit unavailable", error);
  }
  return { ok: true };
}

async function exceedsPendingOrderLimit(
  env: Env,
  input: OrderRiskCheckInput,
  config: OrderRiskControlConfig
): Promise<boolean> {
  const checks: Array<{ enabled: boolean; sql: string; value: unknown; limit: number }> = [
    {
      enabled: input.userId > 0 && config.max_pending_orders_per_user > 0,
      sql: "SELECT COUNT(*) AS count FROM orders WHERE user_id=? AND parent_id IS NULL AND status='pending_payment'",
      value: input.userId,
      limit: config.max_pending_orders_per_user
    },
    {
      enabled: !input.skipIpCheck && !!input.clientIp && config.max_pending_orders_per_ip > 0,
      sql: "SELECT COUNT(*) AS count FROM orders WHERE client_ip=? AND parent_id IS NULL AND status='pending_payment'",
      value: input.clientIp,
      limit: config.max_pending_orders_per_ip
    },
    {
      enabled: input.isGuest && !!input.guestEmail && config.max_pending_orders_per_guest_email > 0,
      sql: "SELECT COUNT(*) AS count FROM orders WHERE lower(guest_email)=? AND parent_id IS NULL AND status='pending_payment'",
      value: input.guestEmail.toLowerCase(),
      limit: config.max_pending_orders_per_guest_email
    }
  ];
  const enabledChecks = checks.filter((check) => check.enabled);
  if (!enabledChecks.length) return false;
  try {
    const results = await env.DB.batch(
      enabledChecks.map((check) => env.DB.prepare(check.sql).bind(check.value))
    );
    return results.some((result, index) => {
      const row = result.results?.[0] as { count?: number } | undefined;
      return Number(row?.count || 0) >= enabledChecks[index].limit;
    });
  } catch (error) {
    console.warn("pending order risk check unavailable", error);
  }
  return false;
}

async function consumeFixedWindowRateLimit(
  env: Env,
  counterKey: string,
  windowSeconds: number,
  maxRequests: number,
  blockSeconds: number
): Promise<RateLimitResult> {
  const window = clampInteger(windowSeconds, 1, 86400, 60);
  const maximum = clampInteger(maxRequests, 1, 10000, 60);
  const block = clampInteger(blockSeconds, 0, 86400, 0);
  const now = Math.floor(Date.now() / 1000);
  const row = await env.DB.prepare(
    `INSERT INTO rate_limit_counters (counter_key, window_started_at, request_count, blocked_until, updated_at)
     VALUES (?, ?, 1, 0, ?)
     ON CONFLICT(counter_key) DO UPDATE SET
       window_started_at=CASE
         WHEN (rate_limit_counters.blocked_until > 0 AND rate_limit_counters.blocked_until <= excluded.updated_at)
           OR rate_limit_counters.window_started_at + ${window} <= excluded.updated_at
         THEN excluded.updated_at
         ELSE rate_limit_counters.window_started_at
       END,
       request_count=CASE
         WHEN (rate_limit_counters.blocked_until > 0 AND rate_limit_counters.blocked_until <= excluded.updated_at)
           OR rate_limit_counters.window_started_at + ${window} <= excluded.updated_at
         THEN 1
         ELSE rate_limit_counters.request_count + 1
       END,
       blocked_until=CASE
         WHEN rate_limit_counters.blocked_until > excluded.updated_at THEN rate_limit_counters.blocked_until
         WHEN (rate_limit_counters.blocked_until > 0 AND rate_limit_counters.blocked_until <= excluded.updated_at)
           OR rate_limit_counters.window_started_at + ${window} <= excluded.updated_at
         THEN 0
         WHEN rate_limit_counters.request_count + 1 > ${maximum} AND ${block} > 0
         THEN excluded.updated_at + ${block}
         ELSE 0
       END,
       updated_at=excluded.updated_at
     RETURNING window_started_at, request_count, blocked_until`
  ).bind(clean(counterKey, 500), now, now).first<{
    window_started_at: number;
    request_count: number;
    blocked_until: number;
  }>();
  if (!row) throw new Error("rate_limit_counter_unavailable");
  const blockedUntil = Number(row.blocked_until || 0);
  const requestCount = Number(row.request_count || 0);
  if (blockedUntil > now || requestCount > maximum) {
    const retryAt = blockedUntil > now
      ? blockedUntil
      : Number(row.window_started_at || now) + window;
    return { allowed: false, retryAfter: Math.max(1, retryAt - now) };
  }
  return { allowed: true, retryAfter: 0 };
}

function normalizeStringList(value: unknown): string[] {
  const source = Array.isArray(value)
    ? value
    : typeof value === "string"
      ? value.split(/\r?\n/)
      : [];
  return source.map((item) => clean(item, 255)).filter(Boolean);
}

function normalizeIpBlacklist(value: unknown): string[] {
  return normalizeStringList(value).filter((entry) => isValidIpOrCidr(entry));
}

function boundedIntegerOrFallback(value: unknown, min: number, max: number, fallback: number): number {
  if (value === null || value === undefined || value === "") return fallback;
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed < min || parsed > max) return fallback;
  return parsed;
}

type ParsedIpAddress = { bits: 32 | 128; value: bigint };

function parseIpAddress(value: string): ParsedIpAddress | null {
  let input = clean(value, 100).toLowerCase();
  if (input.startsWith("[") && input.endsWith("]")) input = input.slice(1, -1);
  input = input.split("%")[0];
  if (!input) return null;

  if (!input.includes(":")) {
    const parts = input.split(".");
    if (parts.length !== 4) return null;
    let result = 0n;
    for (const part of parts) {
      if (!/^\d{1,3}$/.test(part)) return null;
      const octet = Number(part);
      if (octet < 0 || octet > 255) return null;
      result = (result << 8n) | BigInt(octet);
    }
    return { bits: 32, value: result };
  }

  if (input.includes(".")) {
    const lastColon = input.lastIndexOf(":");
    const ipv4 = parseIpAddress(input.slice(lastColon + 1));
    if (!ipv4 || ipv4.bits !== 32) return null;
    const high = Number((ipv4.value >> 16n) & 0xffffn).toString(16);
    const low = Number(ipv4.value & 0xffffn).toString(16);
    input = `${input.slice(0, lastColon)}:${high}:${low}`;
  }
  if ((input.match(/::/g) || []).length > 1) return null;
  const compressed = input.includes("::");
  const [headText, tailText = ""] = input.split("::");
  const head = headText ? headText.split(":") : [];
  const tail = tailText ? tailText.split(":") : [];
  if ([...head, ...tail].some((part) => !/^[0-9a-f]{1,4}$/.test(part))) return null;
  const missing = 8 - head.length - tail.length;
  if ((compressed && missing < 1) || (!compressed && missing !== 0)) return null;
  const groups = compressed ? [...head, ...Array(missing).fill("0"), ...tail] : head;
  if (groups.length !== 8) return null;
  let result = 0n;
  for (const group of groups) result = (result << 16n) | BigInt(`0x${group}`);
  return { bits: 128, value: result };
}

function parseIpNetwork(value: string): { address: ParsedIpAddress; prefix: number } | null {
  const parts = clean(value, 120).split("/");
  if (parts.length > 2) return null;
  const address = parseIpAddress(parts[0]);
  if (!address) return null;
  const prefix = parts.length === 1 ? address.bits : Number(parts[1]);
  if (!Number.isInteger(prefix) || prefix < 0 || prefix > address.bits) return null;
  return { address, prefix };
}

function isValidIpOrCidr(value: string): boolean {
  return parseIpNetwork(value) !== null;
}

function isIpBlacklisted(clientIpValue: string, blacklist: string[]): boolean {
  const client = parseIpAddress(clientIpValue);
  if (!client) return false;
  for (const entry of blacklist) {
    const network = parseIpNetwork(entry);
    if (!network || network.address.bits !== client.bits) continue;
    const shift = BigInt(client.bits - network.prefix);
    if ((client.value >> shift) === (network.address.value >> shift)) return true;
  }
  return false;
}

async function cancelExpiredPendingOrders(env: Env): Promise<number> {
  const now = dashboardDbDate(new Date());
  const rows = await env.DB.prepare(
    `SELECT DISTINCT o.id AS order_id
     FROM orders o
     LEFT JOIN order_maintenance_state oms ON oms.order_id=o.id
     WHERE o.expires_at IS NOT NULL
       AND o.parent_id IS NULL
       AND ${dashboardSqlDate("o.expires_at")} <= datetime(?)
       AND (
         o.status='pending_payment'
         OR (o.status='canceled' AND oms.expiry_cleanup_completed_at IS NULL)
       )
     ORDER BY o.id ASC
     LIMIT 200`
  ).bind(now).all<{ order_id: number }>();
  const orderIds = Array.from(new Set((rows.results || []).map((row) => Number(row.order_id || 0)).filter((id) => id > 0)));
  if (!orderIds.length) return 0;

  let canceled = 0;
  for (const orderId of orderIds) {
    try {
      if (await cancelExpiredPendingOrder(env, orderId, now)) canceled += 1;
    } catch (error) {
      console.warn(`expired order cleanup failed for order ${orderId}`, error);
    }
  }
  return canceled;
}

async function cancelExpiredPendingOrder(env: Env, orderId: number, now = dashboardDbDate(new Date())): Promise<boolean> {
  const result = await env.DB.prepare(
    `UPDATE orders
     SET status='canceled',
         canceled_at=COALESCE(canceled_at, CURRENT_TIMESTAMP),
         updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND status='pending_payment'
       AND expires_at IS NOT NULL
       AND ${dashboardSqlDate("expires_at")} <= datetime(?)`
  ).bind(orderId, now).run();
  const order = await env.DB.prepare("SELECT status FROM orders WHERE id=?")
    .bind(orderId)
    .first<{ status: string }>();
  if (order?.status !== "canceled") return false;

  await env.DB.batch([
    env.DB.prepare(
      `UPDATE orders SET status='canceled', canceled_at=COALESCE(canceled_at, CURRENT_TIMESTAMP),
       updated_at=CURRENT_TIMESTAMP WHERE parent_id=? AND status='pending_payment'`
    ).bind(orderId),
    env.DB.prepare("INSERT OR IGNORE INTO order_maintenance_state (order_id) VALUES (?)").bind(orderId)
  ]);
  await cancelOrderTreeAndRelease(env, orderId);
  await env.DB.prepare(
    `UPDATE order_maintenance_state
     SET expiry_cleanup_completed_at=COALESCE(expiry_cleanup_completed_at, CURRENT_TIMESTAMP),
         updated_at=CURRENT_TIMESTAMP
     WHERE order_id=?`
  ).bind(orderId).run();
  return Number(result.meta.changes || 0) === 1;
}

async function consumeCardSecretsForOrder(
  env: Env,
  orderId: number,
  product: ProductRow,
  sku: SkuRow,
  quantity: number
): Promise<CardSecretRow[]> {
  const reserved = await env.DB.prepare(
    `SELECT *
     FROM card_secrets
     WHERE order_id=? AND product_id=? AND sku_id=? AND status IN ('reserved','used')
     ORDER BY id ASC
     LIMIT ?`
  ).bind(orderId, product.id, sku.id, quantity).all<CardSecretRow>();
  let rows = reserved.results || [];
  if (rows.length < quantity) {
    rows = await reserveCardSecretsForOrder(env, orderId, product, sku, quantity);
  }
  if (rows.length !== quantity) return [];
  const ids = rows.map((row) => row.id);

  let changed = 0;
  for (const chunk of chunkNumbers(ids, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(
      `UPDATE card_secrets
       SET status='used',
           order_id=?,
           reserved_at=CURRENT_TIMESTAMP,
           used_at=CURRENT_TIMESTAMP,
           updated_at=CURRENT_TIMESTAMP
        WHERE order_id=? AND status='reserved' AND id IN (${placeholders})`
    ).bind(orderId, orderId, ...chunk).run();
    changed += Number(result.meta.changes || 0);
  }

  const freshRows = await cardSecretsByIds(env, ids);
  const consumed = freshRows.filter((row) => row.order_id === orderId && row.status === "used");
  return changed <= quantity && consumed.length === quantity ? consumed : [];
}

async function createAutoFulfillment(
  env: Env,
  orderId: number,
  rows: Array<{ product: ProductRow; sku: SkuRow; secret: CardSecretRow }>
): Promise<void> {
  if (!rows.length) return;
  const entries = rows.map((row, index) => {
    return {
      key: rows.length > 1 ? `卡密 ${index + 1}` : "卡密",
      value: row.secret.secret
    };
  });
  const payload = rows.map((row) => row.secret.secret).join("\n");
  const deliveryData = {
    entries,
    card_secrets: rows.map((row) => ({
      id: row.secret.id,
      product_id: row.product.id,
      sku_id: row.sku.id,
      secret: row.secret.secret
    }))
  };
  await upsertFulfillmentComponent(env, orderId, "auto", 0, "auto", deliveryData, payload);
  await rebuildOrderFulfillment(env, orderId);
}

async function upsertFulfillmentComponent(
  env: Env,
  orderId: number,
  sourceType: string,
  sourceId: number,
  fulfillmentType: string,
  deliveryData: AnyRecord,
  payload: string
): Promise<void> {
  await env.DB.prepare(
    `INSERT INTO fulfillment_components (
       order_id, source_type, source_id, fulfillment_type, delivery_data_json, payload
     ) VALUES (?, ?, ?, ?, ?, ?)
     ON CONFLICT(order_id, source_type, source_id) DO UPDATE SET
       fulfillment_type=excluded.fulfillment_type,
       delivery_data_json=excluded.delivery_data_json,
       payload=excluded.payload,
       updated_at=CURRENT_TIMESTAMP`
  ).bind(
    orderId,
    clean(sourceType, 40),
    Math.max(0, sourceId),
    clean(fulfillmentType, 40) || "manual",
    JSON.stringify(deliveryData),
    cleanDeliveryText(payload, 20000)
  ).run();
}

async function rebuildOrderFulfillment(env: Env, orderId: number): Promise<void> {
  const result = await env.DB.prepare(
    `SELECT source_type, source_id, fulfillment_type, delivery_data_json, payload
     FROM fulfillment_components
     WHERE order_id=? AND payload<>''
     ORDER BY CASE source_type WHEN 'auto' THEN 1 WHEN 'upstream' THEN 2 WHEN 'manual' THEN 3 ELSE 4 END,
              source_id ASC, id ASC`
  ).bind(orderId).all<AnyRecord>();
  const components = result.results || [];
  if (!components.length) return;
  const payload = components.map((row) => cleanDeliveryText(row.payload, 20000)).filter(Boolean).join("\n");
  const auto = components.find((row) => row.source_type === "auto");
  const manual = components.find((row) => row.source_type === "manual");
  const upstream = components.filter((row) => row.source_type === "upstream");
  const deliveryData: AnyRecord = {
    components: components.map((row) => ({
      source_type: row.source_type,
      source_id: Number(row.source_id || 0),
      type: row.fulfillment_type,
      delivery_data: jsonParse(row.delivery_data_json || "{}", {})
    }))
  };
  if (auto) deliveryData.auto = jsonParse(auto.delivery_data_json || "{}", {});
  if (manual) deliveryData.manual = jsonParse(manual.delivery_data_json || "{}", {});
  if (upstream.length) {
    deliveryData.upstream = upstream.map((row) => ({
      source_id: Number(row.source_id || 0),
      ...jsonObject(jsonParse(row.delivery_data_json || "{}", {}))
    }));
  }
  const type = manual ? "manual" : upstream.length ? "upstream" : auto ? "auto" : clean(components[0]?.fulfillment_type, 40) || "manual";
  await env.DB.prepare(
    `INSERT INTO fulfillments (order_id, type, status, content, delivery_data_json, payload, payload_line_count)
     VALUES (?, ?, 'delivered', ?, ?, ?, ?)
     ON CONFLICT(order_id) DO UPDATE SET
       type=excluded.type,
       status='delivered',
       content=excluded.content,
       delivery_data_json=excluded.delivery_data_json,
       payload=excluded.payload,
       payload_line_count=excluded.payload_line_count,
       updated_at=CURRENT_TIMESTAMP`
  ).bind(orderId, type, payload, JSON.stringify(deliveryData), payload, countNonEmptyLines(payload)).run();
}

async function refreshOrderFulfillmentStatus(env: Env, orderId: number): Promise<string> {
  const results = await env.DB.batch([
    env.DB.prepare("SELECT status, parent_id FROM orders WHERE id=?").bind(orderId),
    env.DB.prepare(
      `SELECT
         COUNT(*) AS total_count,
         SUM(CASE WHEN COALESCE(NULLIF(fulfillment_type, ''), 'manual')='auto' THEN 1 ELSE 0 END) AS auto_count,
         SUM(CASE WHEN COALESCE(NULLIF(fulfillment_type, ''), 'manual')='manual' THEN 1 ELSE 0 END) AS manual_count,
         SUM(CASE WHEN COALESCE(NULLIF(fulfillment_type, ''), 'manual')='upstream' THEN 1 ELSE 0 END) AS upstream_count
       FROM order_items WHERE order_id=?`
    ).bind(orderId),
    env.DB.prepare(
      `SELECT
         SUM(CASE WHEN source_type='auto' THEN 1 ELSE 0 END) AS auto_count,
         SUM(CASE WHEN source_type='manual' THEN 1 ELSE 0 END) AS manual_count,
         COUNT(*) AS total_count
       FROM fulfillment_components WHERE order_id=? AND payload<>''`
    ).bind(orderId),
    env.DB.prepare(
      `SELECT COUNT(*) AS total_count,
              SUM(CASE WHEN status='fulfilled' THEN 1 ELSE 0 END) AS fulfilled_count
       FROM procurement_orders WHERE local_order_id=?`
    ).bind(orderId)
  ]);
  const order = results[0].results?.[0] as { status: string; parent_id: number | null } | undefined;
  if (!order) return "";
  const itemCounts = results[1].results?.[0] as {
    total_count?: number;
    auto_count?: number;
    manual_count?: number;
    upstream_count?: number;
  } | undefined;
  const componentCounts = results[2].results?.[0] as {
    auto_count?: number;
    manual_count?: number;
    total_count?: number;
  } | undefined;
  const procurementCounts = results[3].results?.[0] as {
    total_count?: number;
    fulfilled_count?: number;
  } | undefined;

  const totalItems = Number(itemCounts?.total_count || 0);
  if (!totalItems) return order.status;
  const autoRequired = Number(itemCounts?.auto_count || 0);
  const manualRequired = Number(itemCounts?.manual_count || 0);
  const upstreamRequired = Number(itemCounts?.upstream_count || 0);
  const autoComplete = autoRequired === 0 || Number(componentCounts?.auto_count || 0) > 0;
  const manualComplete = manualRequired === 0 || Number(componentCounts?.manual_count || 0) > 0;
  const procurementTotal = Number(procurementCounts?.total_count || 0);
  const procurementFulfilled = Number(procurementCounts?.fulfilled_count || 0);
  const upstreamComplete = upstreamRequired === 0
    || (procurementTotal >= upstreamRequired && procurementFulfilled === procurementTotal);
  const anyDelivered = Number(componentCounts?.total_count || 0) > 0 || procurementFulfilled > 0;
  const allAuto = autoRequired === totalItems;
  const target = autoComplete && manualComplete && upstreamComplete
    ? (allAuto ? "completed" : "delivered")
    : anyDelivered
      ? "partially_delivered"
      : "fulfilling";
  if (order.status === target || ["completed", "partially_refunded", "refunded", "canceled"].includes(order.status)) {
    if (order.parent_id) await syncParentOrderStatus(env, order.parent_id);
    return order.status;
  }
  const updated = await env.DB.prepare(
    `UPDATE orders SET status=?, updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND status IN ('paid','fulfilling','partially_delivered','delivered')`
  ).bind(target, orderId).run();
  if (Number(updated.meta.changes || 0) === 1) {
    if (order.parent_id) {
      await syncParentOrderStatus(env, order.parent_id);
    } else if (["delivered", "completed"].includes(target)) {
      await sendOrderLifecycleEmail(env, orderId, target);
    }
  }
  return Number(updated.meta.changes || 0) === 1 ? target : order.status;
}

async function setting(env: Env, key: string, fallback: AnyRecord): Promise<AnyRecord> {
  const cacheable = CACHEABLE_SETTING_KEYS.has(key);
  const cached = cacheable ? settingCache.get(key) : undefined;
  if (cached && cached.expiresAt > Date.now()) {
    return cached.raw === null ? fallback : jsonParse(cached.raw, fallback);
  }
  const row = await env.DB.prepare("SELECT value_json FROM settings WHERE key=?").bind(key).first<{ value_json: string }>();
  if (cacheable) {
    settingCache.set(key, { raw: row?.value_json ?? null, expiresAt: Date.now() + SETTING_CACHE_TTL_MS });
  }
  return row ? jsonParse(row.value_json, fallback) : fallback;
}

async function runtimeFlag(env: Env, key: string): Promise<boolean> {
  const cached = CACHEABLE_SETTING_KEYS.has(key) ? settingCache.get(key) : undefined;
  if (cached && cached.expiresAt > Date.now()) {
    return cached.raw === null ? false : jsonParse<boolean>(cached.raw, false) === true;
  }
  const row = await env.DB.prepare("SELECT value_json FROM settings WHERE key=?").bind(key).first<{ value_json: string }>();
  if (CACHEABLE_SETTING_KEYS.has(key)) {
    settingCache.set(key, { raw: row?.value_json ?? null, expiresAt: Date.now() + SETTING_CACHE_TTL_MS });
  }
  return row ? jsonParse<boolean>(row.value_json, false) === true : false;
}

async function upsertSetting(env: Env, key: string, value: unknown): Promise<void> {
  await env.DB.prepare(
    "INSERT INTO settings (key, value_json) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value_json=excluded.value_json, updated_at=CURRENT_TIMESTAMP"
  ).bind(key, JSON.stringify(value ?? {})).run();
  settingCache.delete(key);
  if (PUBLIC_CONFIG_SETTING_KEYS.has(key)) publicConfigCache.clear();
}

function sanitizeSettingValue(key: string, value: unknown): unknown {
  if (key === "smtp") return sanitizeSMTPSettings(value, defaultSMTPSettings());
  if (key === "telegram_auth") return sanitizeTelegramAuthSettings(value, defaultTelegramAuthSettings());
  if (key === "dashboard_config") return normalizeDashboardConfig(cloneJsonRecord(value));
  if (key === "order_risk_control_config") return normalizeOrderRiskControlConfig(value);
  if (key === "callback_routes_config") return normalizeCallbackRoutesSetting(value);
  if (key === "site_config") {
    const config = cloneJsonRecord(value);
    const legal = jsonObject(config.legal);
    if (Object.keys(legal).length) {
      legal.terms = sanitizeLocalizedHtml(legal.terms);
      legal.privacy = sanitizeLocalizedHtml(legal.privacy);
      config.legal = legal;
    }
    const announcement = jsonObject(config.announcement);
    if (Object.keys(announcement).length) {
      announcement.content = sanitizeLocalizedHtml(announcement.content);
      config.announcement = announcement;
    }
    return config;
  }
  if (key === "home_announcement") {
    const announcement = cloneJsonRecord(value);
    announcement.enabled = announcement.enabled === true;
    const type = clean(announcement.type, 20);
    announcement.type = ["normal", "info", "warning"].includes(type) ? type : "normal";
    announcement.title = normalizeLocalizedText(announcement.title, "");
    announcement.content = sanitizeLocalizedHtml(announcement.content);
    announcement.start_at = normalizeOptionalDateTime(announcement.start_at);
    announcement.end_at = normalizeOptionalDateTime(announcement.end_at);
    announcement.version = clean(announcement.version, 100) || `home-${Date.now().toString(36)}`;
    return announcement;
  }
  return value ?? {};
}

type CallbackRouteTarget = "none" | "blocked" | "payment" | "dujiaopay" | "paypal" | "stripe" | "upstream";

const CALLBACK_ROUTE_DEFAULTS = {
  payment_callback: "/api/v1/payments/callback",
  dujiaopay_webhook: "/api/v1/payments/webhook/dujiaopay",
  paypal_webhook: "/api/v1/payments/webhook/paypal",
  stripe_webhook: "/api/v1/payments/webhook/stripe",
  upstream_callback: "/api/v1/upstream/callback"
} as const;

function normalizeCallbackRoutesSetting(value: unknown): AnyRecord {
  const input = jsonObject(value);
  const output: AnyRecord = {};
  const seen = new Set<string>();
  for (const key of Object.keys(CALLBACK_ROUTE_DEFAULTS) as Array<keyof typeof CALLBACK_ROUTE_DEFAULTS>) {
    const route = normalizeCallbackRoutePath(input[key]);
    output[key] = route && !seen.has(route) ? route : "";
    if (output[key]) seen.add(output[key]);
  }
  return output;
}

function normalizeCallbackRoutePath(value: unknown): string {
  let path = clean(value, 500);
  if (!path) return "";
  path = path.split(/[?#]/, 1)[0].replace(/\/+$/, "");
  if (!path.startsWith("/api/")) return "";
  const withSlash = `${path}/`;
  const reserved = [
    "/api/v1/public/",
    "/api/v1/admin/",
    "/api/v1/auth/",
    "/api/v1/guest/",
    "/api/v1/channel/",
    "/api/v1/upstream/api/",
    "/api/v1/user/"
  ];
  if (reserved.some((prefix) => withSlash.startsWith(prefix) || prefix.startsWith(withSlash))) return "";
  return path;
}

async function resolveCallbackRoute(env: Env, rawPath: string): Promise<CallbackRouteTarget> {
  const path = rawPath.replace(/\/+$/, "") || "/";
  const routes = normalizeCallbackRoutesSetting(await setting(env, "callback_routes_config", {}));
  const targets: Array<[keyof typeof CALLBACK_ROUTE_DEFAULTS, Exclude<CallbackRouteTarget, "none" | "blocked">]> = [
    ["payment_callback", "payment"],
    ["dujiaopay_webhook", "dujiaopay"],
    ["paypal_webhook", "paypal"],
    ["stripe_webhook", "stripe"],
    ["upstream_callback", "upstream"]
  ];
  for (const [key, target] of targets) {
    if (routes[key] && routes[key] === path) return target;
  }
  for (const [key] of targets) {
    if (routes[key] && CALLBACK_ROUTE_DEFAULTS[key] === path) return "blocked";
  }
  return "none";
}

function cloneJsonRecord(value: unknown): AnyRecord {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
  try {
    return JSON.parse(JSON.stringify(value)) as AnyRecord;
  } catch {
    return { ...(value as AnyRecord) };
  }
}

async function count(env: Env, sql: string, params: unknown[]): Promise<number> {
  const row = await env.DB.prepare(sql).bind(...params).first<{ count: number }>();
  return Number(row?.count || 0);
}

function apiOk(data: unknown, page?: AnyRecord): Response {
  const payload: AnyRecord = { status_code: 0, msg: "ok", data };
  if (page) payload.pagination = page;
  return new Response(JSON.stringify(payload), { headers: JSON_HEADERS });
}

function apiError(message: string, status = 400): Response {
  return new Response(JSON.stringify({ status_code: status, msg: message, data: null }), {
    status,
    headers: JSON_HEADERS
  });
}

function apiErrorWithRetryAfter(message: string, retryAfter: number): Response {
  const response = apiError(message, 429);
  response.headers.set("Retry-After", String(Math.max(1, retryAfter)));
  return response;
}

function databaseErrorIncludes(error: unknown, marker: string): boolean {
  const message = error instanceof Error ? error.message : String(error || "");
  return message.includes(marker);
}

async function readJson(request: Request): Promise<AnyRecord> {
  const contentLength = Number(request.headers.get("Content-Length") || 0);
  const maxBytes = 2 * 1024 * 1024;
  if (contentLength > maxBytes) throw new ApiRequestError(413, "请求内容过大");
  const text = await request.text();
  if (new TextEncoder().encode(text).byteLength > maxBytes) throw new ApiRequestError(413, "请求内容过大");
  if (!text.trim()) return {};
  try {
    const parsed = JSON.parse(text);
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed as AnyRecord : {};
  } catch {
    throw new ApiRequestError(400, "JSON 格式不正确");
  }
}

function paging(url: URL): { page: number; size: number; offset: number } {
  const page = Math.max(1, toInt(url.searchParams.get("page"), 1));
  const size = Math.min(100, Math.max(1, pageSize(url)));
  return { page, size, offset: (page - 1) * size };
}

function pageSize(url: URL): number {
  return toInt(url.searchParams.get("page_size"), 20);
}

function paginationFromTotal(url: URL, total: number): AnyRecord {
  const { page, size } = paging(url);
  return pagination(page, size, total);
}

function pagination(page: number, size: number, total: number): AnyRecord {
  return { page, page_size: size, total, total_page: Math.ceil(total / size) };
}

function clean(value: unknown, max = 255): string {
  return String(value ?? "").trim().slice(0, max);
}

function clampInteger(value: unknown, min: number, max: number, fallback: number): number {
  const parsed = Number.parseInt(String(value ?? ""), 10);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.min(max, Math.max(min, parsed));
}

function escapeHtml(value: unknown): string {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function textToHtml(value: unknown): string {
  return escapeHtml(value).replace(/\r?\n/g, "<br>");
}

function timingSafeEqualHex(a: string, b: string): boolean {
  if (a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}

function toInt(value: unknown, fallback: number): number {
  const parsed = Number.parseInt(String(value ?? ""), 10);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function numberValue(value: unknown, fallback: number): number {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function isHttpUrl(value: string): boolean {
  try {
    const url = new URL(value);
    return url.protocol === "http:" || url.protocol === "https:";
  } catch {
    return false;
  }
}

function normalizeNumberListJson(value: unknown, fallback: number[]): string {
  let raw: unknown = value;
  if (typeof value === "string") {
    try {
      raw = JSON.parse(value);
    } catch {
      raw = value.split(",");
    }
  }
  const list = Array.isArray(raw)
    ? raw.map((item) => Number(item)).filter((item) => Number.isFinite(item) && item > 0)
    : [];
  return JSON.stringify(list.length ? list.slice(0, 10) : fallback);
}

function boolInt(value: unknown, fallback: boolean): number {
  if (value === undefined || value === null || value === "") return fallback ? 1 : 0;
  if (typeof value === "boolean") return value ? 1 : 0;
  return ["1", "true", "yes", "on"].includes(String(value).toLowerCase()) ? 1 : 0;
}

function stockValue(value: unknown): number {
  const raw = String(value ?? "").trim();
  if (!raw || raw === "-1" || raw.toLowerCase() === "unlimited") return -1;
  return Math.max(0, toInt(raw, 0));
}

function aggregateSkuStock(skus: AnyRecord[]): number {
  const active = skus.filter((sku) => sku.is_active !== false);
  if (active.some((sku) => stockValue(sku.manual_stock_total) === -1)) return -1;
  return active.reduce((sum, sku) => sum + stockValue(sku.manual_stock_total), 0);
}

function availableStock(row: { manual_stock_total: number; manual_stock_locked: number; manual_stock_sold: number }): number | null {
  if (row.manual_stock_total < 0) return null;
  return Math.max(0, row.manual_stock_total);
}

function hasStock(sku: SkuRow, quantity: number): boolean {
  const available = availableStock(sku);
  return available === null || available >= quantity;
}

function productAvailableStock(product: ProductRow, skus: SkuRow[]): number | null {
  const active = skus.filter((sku) => sku.is_active);
  if (active.length) {
    if (active.some((sku) => sku.manual_stock_total < 0)) return null;
    return active.reduce((sum, sku) => sum + (availableStock(sku) || 0), 0);
  }
  return availableStock(product);
}

function productStockSummary(product: ProductRow, skus: SkuRow[]): { total: number; locked: number; sold: number } {
  const active = skus.filter((sku) => sku.is_active);
  if (!active.length) {
    return {
      total: product.manual_stock_total,
      locked: product.manual_stock_locked,
      sold: product.manual_stock_sold
    };
  }
  return {
    total: active.some((sku) => sku.manual_stock_total < 0)
      ? -1
      : active.reduce((sum, sku) => sum + sku.manual_stock_total, 0),
    locked: active.reduce((sum, sku) => sum + sku.manual_stock_locked, 0),
    sold: active.reduce((sum, sku) => sum + sku.manual_stock_sold, 0)
  };
}

function stockStatusFor(available: number | null): string {
  if (available === null) return "unlimited";
  if (available <= 0) return "out_of_stock";
  if (available <= 5) return "low_stock";
  return "in_stock";
}

function normalizeLocalized(value: unknown, fallback: string): AnyRecord {
  if (value && typeof value === "object" && !Array.isArray(value)) {
    const input = value as AnyRecord;
    return {
      "zh-CN": clean(input["zh-CN"] || input.zh || input.cn || fallback, 500),
      "zh-TW": clean(input["zh-TW"] || input["zh-CN"] || fallback, 500),
      "en-US": clean(input["en-US"] || input["zh-CN"] || fallback, 500)
    };
  }
  return { "zh-CN": clean(value || fallback, 500), "zh-TW": clean(value || fallback, 500), "en-US": clean(value || fallback, 500) };
}

function localizedFirst(value: AnyRecord): string {
  return clean(value["zh-CN"] || value["zh-TW"] || value["en-US"] || "item", 120);
}

