function normalizeEmail(value: unknown): string {
  const email = clean(value, 160).toLowerCase();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? email : "";
}

async function getUserById(env: Env, id: number): Promise<UserRow | null> {
  const row = await env.DB.prepare(
    `SELECT u.*, COALESCE(w.balance, 0) AS wallet_balance
     FROM users u LEFT JOIN user_wallets w ON w.user_id=u.id
     WHERE u.id=?`
  ).bind(id).first<UserRow>();
  return row || null;
}

async function createUserSession(env: Env, userId: number): Promise<{ token: string; expiresAt: string }> {
  const token = randomToken();
  const tokenHash = await sha256Hex(token);
  const expiresAt = new Date(Date.now() + 30 * 24 * 3600 * 1000).toISOString();
  await env.DB.prepare("INSERT INTO user_sessions (user_id, token_hash, expires_at) VALUES (?, ?, ?)")
    .bind(userId, tokenHash, expiresAt)
    .run();
  return { token, expiresAt };
}

async function createUserLoginChallenge(env: Env, userId: number): Promise<{ token: string; expiresAt: string }> {
  const token = randomToken();
  const tokenHash = await sha256Hex(token);
  const now = new Date().toISOString();
  const expiresAt = new Date(Date.now() + ADMIN_2FA_LOGIN_TTL_MS).toISOString();
  await env.DB.prepare("DELETE FROM user_login_challenges WHERE user_id=? OR expires_at <= ?")
    .bind(userId, now)
    .run();
  await env.DB.prepare("INSERT INTO user_login_challenges (user_id, token_hash, expires_at) VALUES (?, ?, ?)")
    .bind(userId, tokenHash, expiresAt)
    .run();
  return { token, expiresAt };
}

async function userRecoveryCodeHash(userId: number, code: string): Promise<string> {
  return sha256Hex(`user-recovery:${userId}:${normalizeRecoveryCode(code)}`);
}

async function replaceUserRecoveryCodes(env: Env, userId: number): Promise<string[]> {
  const codes = Array.from({ length: ADMIN_RECOVERY_CODE_COUNT }, () => makeRecoveryCode());
  await env.DB.prepare("DELETE FROM user_recovery_codes WHERE user_id=?").bind(userId).run();
  for (const code of codes) {
    await env.DB.prepare("INSERT INTO user_recovery_codes (user_id, code_hash) VALUES (?, ?)")
      .bind(userId, await userRecoveryCodeHash(userId, code))
      .run();
  }
  return codes;
}

async function consumeUserRecoveryCode(env: Env, userId: number, code: string): Promise<boolean> {
  const normalized = normalizeRecoveryCode(code);
  if (!normalized) return false;
  const hash = await userRecoveryCodeHash(userId, normalized);
  const result = await env.DB.prepare(
    "UPDATE user_recovery_codes SET used_at=CURRENT_TIMESTAMP WHERE user_id=? AND code_hash=? AND used_at IS NULL"
  ).bind(userId, hash).run();
  return Boolean(result.meta.changes);
}

async function requireUser(request: Request, env: Env): Promise<{ ok: true; user: UserRow } | { ok: false; response: Response }> {
  const auth = request.headers.get("Authorization") || "";
  const token = auth.startsWith("Bearer ") ? auth.slice(7).trim() : "";
  if (!token) return { ok: false, response: apiError("unauthorized", 401) };
  const tokenHash = await sha256Hex(token);
  const row = await env.DB.prepare(
    `SELECT u.*, s.expires_at AS session_expires_at, COALESCE(w.balance, 0) AS wallet_balance
     FROM user_sessions s
     JOIN users u ON u.id=s.user_id
     LEFT JOIN user_wallets w ON w.user_id=u.id
     WHERE s.token_hash=?`
  ).bind(tokenHash).first<UserRow & { session_expires_at: string }>();
  if (!row || new Date(row.session_expires_at).getTime() <= Date.now()) {
    return { ok: false, response: apiError("unauthorized", 401) };
  }
  if (row.status !== "active") {
    return { ok: false, response: apiError("账号已被禁用", 403) };
  }
  return { ok: true, user: row };
}

async function ensureWallet(env: Env, userId: number): Promise<WalletRow> {
  let wallet = await env.DB.prepare("SELECT * FROM user_wallets WHERE user_id=?").bind(userId).first<WalletRow>();
  if (wallet) return wallet;
  await env.DB.prepare("INSERT OR IGNORE INTO user_wallets (user_id, balance, currency) VALUES (?, 0, 'CNY')")
    .bind(userId)
    .run();
  wallet = await env.DB.prepare("SELECT * FROM user_wallets WHERE user_id=?").bind(userId).first<WalletRow>();
  if (!wallet) throw new Error("wallet_create_failed");
  return wallet;
}

async function adjustWalletBalance(
  env: Env,
  userId: number,
  amount: number,
  direction: "in" | "out",
  meta: {
    type: string;
    orderId?: number | null;
    reference?: string;
    remark?: string;
    relatedType?: string;
    relatedId?: number | null;
  },
  options: { walletReady?: boolean } = {}
): Promise<WalletTransactionRow | null> {
  if (!options.walletReady) await ensureWallet(env, userId);
  const amountCents = moneyToCents(Number(amount || 0));
  if (amountCents <= 0) return null;
  const delta = centsToMoney(amountCents);
  if (await runtimeFlag(env, "atomic_wallet_adjustments_enabled")) {
    return atomicWalletBalanceAdjustment(env, userId, delta, direction, meta);
  }
  const existing = await idempotentWalletTransaction(env, userId, meta);
  if (existing) return existing;
  const balanceUpdate = direction === "out"
    ? await env.DB.prepare(
      "UPDATE user_wallets SET balance=ROUND(balance-?, 2), updated_at=CURRENT_TIMESTAMP WHERE user_id=? AND balance>=?"
    ).bind(money(delta), userId, money(delta)).run()
    : await env.DB.prepare(
      "UPDATE user_wallets SET balance=ROUND(balance+?, 2), updated_at=CURRENT_TIMESTAMP WHERE user_id=?"
    ).bind(money(delta), userId).run();
  if (Number(balanceUpdate.meta.changes || 0) !== 1) return null;

  const wallet = await env.DB.prepare("SELECT * FROM user_wallets WHERE user_id=?").bind(userId).first<WalletRow>();
  if (!wallet) throw new Error("wallet_update_failed");
  const afterCents = moneyToCents(Number(wallet.balance || 0));
  const beforeCents = direction === "out" ? afterCents + amountCents : afterCents - amountCents;
  try {
    const result = await env.DB.prepare(
      `INSERT INTO wallet_transactions (
        user_id, order_id, type, direction, amount, balance_before, balance_after,
        currency, reference, remark, related_type, related_id
      ) VALUES (?, ?, ?, ?, ?, ?, ?, 'CNY', ?, ?, ?, ?)`
    ).bind(
      userId,
      meta.orderId ?? null,
      clean(meta.type, 40) || "adjust",
      direction,
      money(delta),
      money(centsToMoney(beforeCents)),
      money(centsToMoney(afterCents)),
      clean(meta.reference, 120),
      clean(meta.remark, 500),
      clean(meta.relatedType, 40),
      meta.relatedId ?? null
    ).run();
    return env.DB.prepare("SELECT * FROM wallet_transactions WHERE id=?")
      .bind(Number(result.meta.last_row_id))
      .first<WalletTransactionRow>();
  } catch (error) {
    const reverseSql = direction === "out"
      ? "UPDATE user_wallets SET balance=ROUND(balance+?, 2), updated_at=CURRENT_TIMESTAMP WHERE user_id=?"
      : "UPDATE user_wallets SET balance=ROUND(balance-?, 2), updated_at=CURRENT_TIMESTAMP WHERE user_id=?";
    await env.DB.prepare(reverseSql).bind(money(delta), userId).run();
    const raced = await idempotentWalletTransaction(env, userId, meta);
    if (raced) return raced;
    throw error;
  }
}

async function atomicWalletBalanceAdjustment(
  env: Env,
  userId: number,
  amount: number,
  direction: "in" | "out",
  meta: {
    type: string;
    orderId?: number | null;
    reference?: string;
    remark?: string;
    relatedType?: string;
    relatedId?: number | null;
  }
): Promise<WalletTransactionRow | null> {
  const type = clean(meta.type, 40) || "adjust";
  const reference = clean(meta.reference, 120);
  const relatedType = clean(meta.relatedType, 40);
  const idempotencyKey = walletAdjustmentIdempotencyKey(userId, type, meta, reference, relatedType);
  let adjustmentId = 0;
  try {
    const result = await env.DB.prepare(
      `INSERT INTO wallet_adjustments (
         idempotency_key, user_id, order_id, type, direction, amount, currency,
         reference, remark, related_type, related_id
       ) VALUES (?, ?, ?, ?, ?, ?, 'CNY', ?, ?, ?, ?)`
    ).bind(
      idempotencyKey,
      userId,
      meta.orderId ?? null,
      type,
      direction,
      money(amount),
      reference,
      clean(meta.remark, 500),
      relatedType,
      meta.relatedId ?? null
    ).run();
    adjustmentId = Number(result.meta.last_row_id || 0);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (message.includes("wallet_adjustment_insufficient")) return null;
    if (message.includes("wallet_adjustment_invalid")) return null;
    const raced = await idempotentWalletTransaction(env, userId, meta);
    if (raced) return raced;
    if (/unique constraint failed.*wallet_adjustments\.idempotency_key/i.test(message)) {
      const existing = await walletTransactionByAdjustmentKey(env, idempotencyKey);
      if (existing) return existing;
    }
    throw error;
  }
  const transaction = await env.DB.prepare(
    `SELECT wt.* FROM wallet_adjustments wa
     JOIN wallet_transactions wt ON wt.id=wa.wallet_txn_id
     WHERE wa.id=? LIMIT 1`
  ).bind(adjustmentId).first<WalletTransactionRow>();
  if (!transaction) throw new Error("wallet_adjustment_transaction_missing");
  return transaction;
}

async function walletTransactionByAdjustmentKey(env: Env, idempotencyKey: string): Promise<WalletTransactionRow | null> {
  return env.DB.prepare(
    `SELECT wt.* FROM wallet_adjustments wa
     JOIN wallet_transactions wt ON wt.id=wa.wallet_txn_id
     WHERE wa.idempotency_key=? LIMIT 1`
  ).bind(idempotencyKey).first<WalletTransactionRow>();
}

function walletAdjustmentIdempotencyKey(
  userId: number,
  type: string,
  meta: { orderId?: number | null; reference?: string; relatedType?: string; relatedId?: number | null },
  reference: string,
  relatedType: string
): string {
  if (type === "order_payment" && meta.orderId) return `order-payment:${userId}:${meta.orderId}`;
  if (type === "recharge" && relatedType === "wallet_recharge" && meta.relatedId) {
    return `wallet-recharge:${meta.relatedId}`;
  }
  if (type === "order_refund" && meta.orderId && reference) {
    return `order-refund:${userId}:${meta.orderId}:${reference}`;
  }
  if (type === "gift_card" && relatedType === "gift_card" && meta.relatedId) {
    return `gift-card:${meta.relatedId}`;
  }
  if (reference) return `${type}:${userId}:${reference}`;
  return `${type}:${userId}:${randomToken()}`;
}

async function idempotentWalletTransaction(
  env: Env,
  userId: number,
  meta: {
    type: string;
    orderId?: number | null;
    reference?: string;
    relatedType?: string;
    relatedId?: number | null;
  }
): Promise<WalletTransactionRow | null> {
  const type = clean(meta.type, 40);
  if (type === "order_payment" && meta.orderId) {
    return env.DB.prepare(
      "SELECT * FROM wallet_transactions WHERE user_id=? AND order_id=? AND type='order_payment' LIMIT 1"
    ).bind(userId, meta.orderId).first<WalletTransactionRow>();
  }
  if (type === "recharge" && clean(meta.relatedType, 40) === "wallet_recharge" && meta.relatedId) {
    return env.DB.prepare(
      "SELECT * FROM wallet_transactions WHERE type='recharge' AND related_type='wallet_recharge' AND related_id=? LIMIT 1"
    ).bind(meta.relatedId).first<WalletTransactionRow>();
  }
  if (type === "order_refund" && meta.orderId && clean(meta.reference, 120).endsWith(":cancel")) {
    return env.DB.prepare(
      "SELECT * FROM wallet_transactions WHERE user_id=? AND order_id=? AND type='order_refund' AND reference=? LIMIT 1"
    ).bind(userId, meta.orderId, clean(meta.reference, 120)).first<WalletTransactionRow>();
  }
  if (type === "gift_card" && clean(meta.relatedType, 40) === "gift_card" && meta.relatedId) {
    return env.DB.prepare(
      "SELECT * FROM wallet_transactions WHERE type='gift_card' AND related_type='gift_card' AND related_id=? LIMIT 1"
    ).bind(meta.relatedId).first<WalletTransactionRow>();
  }
  return null;
}

async function applyOrderWalletBalance(env: Env, inputOrder: OrderRow): Promise<OrderRow> {
  let order = inputOrder;
  if (order.status !== "pending_payment") throw new ApiRequestError(409, "订单当前状态不能支付");
  if (!order.user_id) throw new ApiRequestError(400, "游客订单不支持余额支付");
  if (moneyToCents(Number(order.wallet_paid_amount || 0)) > 0) return order;

  const [releasedResult, walletResult] = await env.DB.batch([
    env.DB.prepare(
      "SELECT id FROM wallet_transactions WHERE user_id=? AND order_id=? AND type='order_refund' LIMIT 1"
    ).bind(order.user_id, order.id),
    env.DB.prepare("SELECT * FROM user_wallets WHERE user_id=? LIMIT 1").bind(order.user_id)
  ]);
  const released = releasedResult.results?.[0] as { id: number } | undefined;
  if (released) throw new ApiRequestError(409, "该订单的余额已退回，请改用在线支付或重新下单");

  const wallet = (walletResult.results?.[0] as WalletRow | undefined) || await ensureWallet(env, order.user_id);
  const amount = centsToMoney(Math.min(
    moneyToCents(Number(wallet.balance || 0)),
    moneyToCents(Number(order.total_amount || 0))
  ));
  if (moneyToCents(amount) <= 0) return order;

  const transaction = await adjustWalletBalance(env, order.user_id, amount, "out", {
    type: "order_payment",
    orderId: order.id,
    reference: order.order_no,
    remark: `订单余额支付 ${order.order_no}`
  }, { walletReady: true });
  if (!transaction) throw new ApiRequestError(409, "钱包余额不足，请刷新后重试");

  const effectiveAmount = centsToMoney(Math.min(
    moneyToCents(Number(transaction.amount || amount)),
    moneyToCents(Number(order.total_amount || 0))
  ));
  const [orderUpdate] = await env.DB.batch([
    env.DB.prepare(
      `UPDATE orders
       SET wallet_paid_amount=?, online_paid_amount=ROUND(total_amount-?, 2), updated_at=CURRENT_TIMESTAMP
       WHERE id=? AND status='pending_payment' AND wallet_paid_amount=0
       RETURNING *`
    ).bind(money(effectiveAmount), money(effectiveAmount), order.id),
    env.DB.prepare(
      `UPDATE payments
       SET status='expired', expired_at=COALESCE(expired_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP
       WHERE order_id=? AND status IN ('initiated','pending','created','')`
    ).bind(order.id)
  ]);
  order = (orderUpdate.results?.[0] as OrderRow | undefined) || order;
  if (moneyToCents(Number(order.wallet_paid_amount || 0)) <= 0) {
    const refund = await adjustWalletBalance(env, order.user_id, effectiveAmount, "in", {
      type: "order_refund",
      orderId: order.id,
      reference: `${order.order_no}:cancel`,
      remark: `余额扣款未能关联订单，自动退回 ${order.order_no}`
    });
    if (!refund) throw new Error("wallet_release_failed");
    throw new ApiRequestError(409, "余额支付失败，请刷新后重试");
  }
  return order;
}

async function releaseOrderWalletBalance(env: Env, orderId: number, remark = "订单取消退回余额"): Promise<void> {
  const order = await env.DB.prepare("SELECT * FROM orders WHERE id=?").bind(orderId).first<OrderRow>();
  if (!order?.user_id || moneyToCents(Number(order.wallet_paid_amount || 0)) <= 0) return;
  const reference = `${order.order_no}:cancel`;
  const existing = await env.DB.prepare(
    "SELECT id FROM wallet_transactions WHERE user_id=? AND order_id=? AND type='order_refund' AND reference=? LIMIT 1"
  ).bind(order.user_id, order.id, reference).first<{ id: number }>();
  if (!existing) {
    const transaction = await adjustWalletBalance(env, order.user_id, Number(order.wallet_paid_amount || 0), "in", {
      type: "order_refund",
      orderId: order.id,
      reference,
      remark: `${clean(remark, 400) || "订单余额退回"} ${order.order_no}`
    });
    if (!transaction) throw new Error("wallet_release_failed");
  }
  await env.DB.prepare(
    "UPDATE orders SET wallet_paid_amount=0, online_paid_amount=total_amount, updated_at=CURRENT_TIMESTAMP WHERE id=?"
  ).bind(order.id).run();
  await expireActiveOrderPayments(env, order.id);
}

async function expireActiveOrderPayments(env: Env, orderId: number): Promise<void> {
  await env.DB.prepare(
    `UPDATE payments
     SET status='expired', expired_at=COALESCE(expired_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP
     WHERE order_id=? AND status IN ('initiated','pending','created','')`
  ).bind(orderId).run();
}

async function recordUserLogin(env: Env, request: Request, userId: number, email: string, status: string, failReason: string): Promise<void> {
  await env.DB.prepare(
    `INSERT INTO user_login_logs (user_id, email, client_ip, user_agent, login_source, status, fail_reason)
     VALUES (?, ?, ?, ?, 'web', ?, ?)`
  ).bind(
    userId,
    email,
    clientIp(request),
    clean(request.headers.get("User-Agent"), 500),
    status,
    failReason
  ).run();
}

async function recordAdminLogin(env: Env, request: Request, adminId: number, username: string, status: string, failReason: string): Promise<void> {
  try {
    await env.DB.prepare(
      `INSERT INTO admin_login_logs (admin_id, username, client_ip, user_agent, status, fail_reason)
       VALUES (?, ?, ?, ?, ?, ?)`
    ).bind(
      adminId,
      clean(username, 80),
      clientIp(request),
      clean(request.headers.get("User-Agent"), 500),
      status,
      failReason
    ).run();
  } catch (error) {
    console.warn("admin_login_log_failed", error);
  }
}

async function tooManyUserLoginFailures(env: Env, request: Request, email: string): Promise<boolean> {
  try {
    const row = await env.DB.prepare(
      `SELECT COUNT(*) AS count
       FROM user_login_logs
       WHERE status='failed'
         AND created_at >= datetime('now', '-15 minutes')
         AND (email=? OR client_ip=?)`
    ).bind(email, clientIp(request)).first<{ count: number }>();
    return Number(row?.count || 0) >= 10;
  } catch {
    return false;
  }
}

async function tooManyAdminLoginFailures(env: Env, request: Request, username: string): Promise<boolean> {
  try {
    const row = await env.DB.prepare(
      `SELECT COUNT(*) AS count
       FROM admin_login_logs
       WHERE status='failed'
         AND created_at >= datetime('now', '-15 minutes')
         AND (username=? OR client_ip=?)`
    ).bind(clean(username, 80), clientIp(request)).first<{ count: number }>();
    return Number(row?.count || 0) >= 8;
  } catch {
    return false;
  }
}

function clientIp(request: Request): string {
  const forwarded = (request.headers.get("X-Forwarded-For") || "").split(",")[0];
  return clean(request.headers.get("CF-Connecting-IP") || forwarded || "", 80);
}

async function getWalletRechargeByNo(env: Env, rechargeNo: string, userId?: number): Promise<WalletRechargeRow | null> {
  const params: unknown[] = [rechargeNo];
  let where = "wr.recharge_no=?";
  if (userId !== undefined) {
    where += " AND wr.user_id=?";
    params.push(userId);
  }
  const row = await env.DB.prepare(
    `SELECT wr.*, u.email AS user_email, u.display_name AS user_display_name
     FROM wallet_recharges wr LEFT JOIN users u ON u.id=wr.user_id
     WHERE ${where}`
  ).bind(...params).first<WalletRechargeRow>();
  return row || null;
}

async function getWalletRechargeByPaymentId(env: Env, paymentId: number, userId?: number): Promise<WalletRechargeRow | null> {
  const params: unknown[] = [paymentId];
  let where = "wr.payment_id=?";
  if (userId !== undefined) {
    where += " AND wr.user_id=?";
    params.push(userId);
  }
  const row = await env.DB.prepare(
    `SELECT wr.*, u.email AS user_email, u.display_name AS user_display_name
     FROM wallet_recharges wr LEFT JOIN users u ON u.id=wr.user_id
     WHERE ${where}`
  ).bind(...params).first<WalletRechargeRow>();
  return row || null;
}

function paymentChannelTypes(row: PaymentChannelRow): string[] {
  return jsonParse<string[]>(row.payment_types_json || "[]", [])
    .map((item) => clean(item, 40).toLowerCase())
    .filter(Boolean);
}

function isWalletRechargeProviderSupported(row: PaymentChannelRow): boolean {
  const providerType = clean(row.provider_type, 40).toLowerCase();
  return isImplementedPaymentProvider(providerType, row.channel_type);
}

function isPaymentChannelAllowedForWalletRecharge(
  row: PaymentChannelRow,
  user: UserRow | null,
  allowedIds: number[]
): boolean {
  if (!row || !row.is_active) return false;
  if (allowedIds.length > 0 && !allowedIds.includes(row.id)) return false;
  if (!paymentChannelAllowsRole(row, user)) return false;
  if (!paymentChannelAllowsMemberLevel(row, user)) return false;
  if (!paymentChannelAllowsType(row, "wallet")) return false;
  return isWalletRechargeProviderSupported(row);
}

function paymentChannelAcceptsAmount(row: PaymentChannelRow, amount: number): boolean {
  const cents = moneyToCents(amount);
  const minCents = moneyToCents(Number(row.min_amount || 0));
  const maxCents = moneyToCents(Number(row.max_amount || 0));
  if (minCents > 0 && cents < minCents) return false;
  if (maxCents > 0 && cents > maxCents) return false;
  return true;
}

async function availableWalletRechargeChannels(env: Env, amount: number, user: UserRow): Promise<PaymentChannelRow[]> {
  const [channels, wallet] = await Promise.all([
    activePaymentChannels(env),
    walletConfig(env)
  ]);
  return channels
    .filter((row) => isPaymentChannelAllowedForWalletRecharge(row, user, wallet.rechargeChannelIds))
    .filter((row) => !row.hide_amount_out_range || paymentChannelAcceptsAmount(row, amount));
}

async function walletConfig(env: Env): Promise<{ rechargeChannelIds: number[]; walletOnlyPayment: boolean }> {
  const config = jsonObject(await setting(env, "wallet_config", {}));
  return {
    rechargeChannelIds: arrayNumbers(config.recharge_channel_ids),
    walletOnlyPayment: config.wallet_only_payment === true
  };
}

function calculatePaymentChannelFee(channel: PaymentChannelRow, amount: number): { feeRate: number; fixedFee: number; feeAmount: number; payableAmount: number } | null {
  const feeRate = centsToMoney(moneyToCents(Number(channel.fee_rate || 0)));
  const fixedFee = centsToMoney(moneyToCents(Number(channel.fixed_fee || 0)));
  if (feeRate < 0 || feeRate > 100 || fixedFee < 0) return null;
  const amountCents = moneyToCents(amount);
  const feeCents = Math.round(amountCents * feeRate / 100) + moneyToCents(fixedFee);
  const feeAmount = centsToMoney(feeCents);
  return {
    feeRate,
    fixedFee,
    feeAmount,
    payableAmount: centsToMoney(amountCents + feeCents)
  };
}

async function createWalletRechargePayment(
  env: Env,
  input: { user: UserRow; channelId: number; amount: number; remark: string; clientIp: string }
): Promise<{ ok: true; recharge: WalletRechargeRow; payment: PaymentRow; account: WalletRow } | { ok: false; error: string; status: number }> {
  const channel = await env.DB.prepare("SELECT * FROM payment_channels WHERE id=?")
    .bind(input.channelId)
    .first<PaymentChannelRow>();
  if (!channel) return { ok: false, error: "支付渠道不存在", status: 404 };
  const wallet = await walletConfig(env);
  if (!isPaymentChannelAllowedForWalletRecharge(channel, input.user, wallet.rechargeChannelIds)) {
    return { ok: false, error: "该支付渠道不支持钱包充值", status: 400 };
  }
  if (!paymentChannelAcceptsAmount(channel, input.amount)) {
    return { ok: false, error: "充值金额不符合支付渠道限额", status: 400 };
  }
  const fee = calculatePaymentChannelFee(channel, input.amount);
  if (!fee) return { ok: false, error: "支付渠道手续费配置不正确", status: 400 };

  const rechargeNo = makeRechargeNo();
  const paymentNo = makePaymentNo();
  const providerPayload = {
    biz_type: "wallet_recharge",
    recharge_no: rechargeNo,
    user_id: input.user.id,
    client_ip: input.clientIp
  };
  const paymentResult = await env.DB.prepare(
    `INSERT INTO payments (
      payment_no, order_id, user_id, guest_email, channel_id, provider_type, channel_type,
      interaction_mode, amount, payable_amount, fee_rate, fixed_fee, fee_amount, currency,
      status, provider_payload_json
    ) VALUES (?, 0, ?, '', ?, ?, ?, ?, ?, ?, ?, ?, ?, 'CNY', 'pending', ?)`
  ).bind(
    paymentNo,
    input.user.id,
    channel.id,
    channel.provider_type || "epay",
    channel.channel_type || "alipay",
    channel.interaction_mode || "redirect",
    money(fee.payableAmount),
    money(fee.payableAmount),
    money(fee.feeRate),
    money(fee.fixedFee),
    money(fee.feeAmount),
    stringify(providerPayload)
  ).run();
  const paymentId = Number(paymentResult.meta.last_row_id || 0);
  if (!paymentId) return { ok: false, error: "创建支付记录失败", status: 500 };

  await env.DB.prepare(
    `INSERT INTO wallet_recharges (
      recharge_no, user_id, payment_id, channel_id, channel_name, provider_type, channel_type,
      interaction_mode, amount, payable_amount, fee_rate, fee_amount, currency, status, remark
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'CNY', 'pending', ?)`
  ).bind(
    rechargeNo,
    input.user.id,
    paymentId,
    channel.id,
    channel.name || "",
    channel.provider_type || "epay",
    channel.channel_type || "alipay",
    channel.interaction_mode || "redirect",
    money(input.amount),
    money(fee.payableAmount),
    money(fee.feeRate),
    money(fee.feeAmount),
    input.remark || "余额充值"
  ).run();

  let payment = await paymentByIdWithContext(env, paymentId);
  const recharge = await getWalletRechargeByNo(env, rechargeNo, input.user.id);
  if (!payment || !recharge) return { ok: false, error: "创建充值订单失败", status: 500 };

  if (clean(channel.provider_type, 40).toLowerCase() !== "manual") {
    const prepared = await prepareProviderRechargePayment(env, payment, recharge);
    if (!prepared.ok) {
      await env.DB.prepare("UPDATE payments SET status='failed', updated_at=CURRENT_TIMESTAMP WHERE id=?")
        .bind(payment.id)
        .run();
      await env.DB.prepare("UPDATE wallet_recharges SET status='failed', updated_at=CURRENT_TIMESTAMP WHERE id=?")
        .bind(recharge.id)
        .run();
      return { ok: false, error: prepared.error, status: 400 };
    }
    payment = prepared.payment;
  }

  return {
    ok: true,
    recharge: await getWalletRechargeByNo(env, rechargeNo, input.user.id) || recharge,
    payment,
    account: await ensureWallet(env, input.user.id)
  };
}

function formatWalletRechargePaymentPayload(recharge: WalletRechargeRow, payment: PaymentRow | null, account?: WalletRow | null): AnyRecord {
  const formattedPayment = payment ? formatPayment(payment) : null;
  const payload: AnyRecord = {
    recharge: formatWalletRecharge(recharge),
    recharge_no: recharge.recharge_no,
    recharge_status: recharge.status || "pending",
    payment: formattedPayment,
    account: account ? formatWalletAccount(account) : undefined
  };
  if (payment) {
    const providerPayload = jsonObject(jsonParse(payment.provider_payload_json || "{}", {}));
    const crypto = jsonObject(providerPayload.crypto || providerPayload.payment || {});
    payload.payment_id = payment.id;
    payload.provider_type = payment.provider_type || recharge.provider_type;
    payload.channel_type = payment.channel_type || recharge.channel_type;
    payload.interaction_mode = payment.interaction_mode || recharge.interaction_mode;
    payload.pay_url = payment.pay_url || "";
    payload.qr_code = payment.qr_code || "";
    payload.expires_at = payment.expired_at || "";
    payload.status = payment.status || recharge.status || "pending";
    payload.wallet_address = clean(providerPayload.wallet_address || crypto.wallet_address || crypto.address, 500);
    payload.chain_amount = clean(providerPayload.chain_amount || crypto.chain_amount || crypto.amount, 120);
    payload.chain = clean(providerPayload.chain || crypto.chain || crypto.network, 120);
    payload.token_id = clean(providerPayload.token_id || crypto.token_id || crypto.token, 120);
  }
  return payload;
}

async function applyWalletRechargeSuccess(env: Env, payment: PaymentRow, recharge: WalletRechargeRow, providerPayload: AnyRecord): Promise<void> {
  const now = clean(providerPayload.paid_at, 80) || new Date().toISOString();
  await env.DB.prepare(
    `UPDATE payments
     SET status='success',
         provider_trade_no=COALESCE(NULLIF(provider_trade_no, ''), ?),
         provider_ref=COALESCE(NULLIF(provider_ref, ''), ?),
         provider_payload_json=?,
         paid_at=COALESCE(paid_at, NULLIF(?, ''), CURRENT_TIMESTAMP),
         callback_at=COALESCE(callback_at, CURRENT_TIMESTAMP),
         updated_at=CURRENT_TIMESTAMP
     WHERE id=?`
  ).bind(
    clean(providerPayload.trade_no || providerPayload.tradeNo, 120),
    clean(providerPayload.buyer || providerPayload.buyer_id || providerPayload.buyer_email || providerPayload.provider_ref, 200),
    stringify(Object.keys(providerPayload).length ? providerPayload : jsonParse(payment.provider_payload_json || "{}", {})),
    now,
    payment.id
  ).run();

  const current = await getWalletRechargeByPaymentId(env, payment.id) || recharge;
  if (!current) return;
  if (current.status !== "success") {
    await env.DB.prepare(
      `UPDATE wallet_recharges
       SET status='success',
           paid_at=COALESCE(paid_at, ?),
           updated_at=CURRENT_TIMESTAMP
       WHERE id=? AND status<>'success'`
    ).bind(now, current.id).run();
  }

  const existingTxn = await env.DB.prepare(
    "SELECT id FROM wallet_transactions WHERE user_id=? AND related_type='wallet_recharge' AND related_id=? AND type='recharge' LIMIT 1"
  ).bind(current.user_id, current.id).first<{ id: number }>();
  if (!existingTxn) {
    const txn = await adjustWalletBalance(env, current.user_id, Number(current.amount || 0), "in", {
      type: "recharge",
      reference: `recharge:${current.id}:success`,
      remark: current.remark || "在线充值到账",
      relatedType: "wallet_recharge",
      relatedId: current.id
    });
    if (txn) {
      await env.DB.prepare(
        `UPDATE users
         SET total_recharged=(
               SELECT COALESCE(SUM(amount), 0)
               FROM wallet_transactions
               WHERE user_id=? AND type='recharge' AND direction='in'
             ),
             updated_at=CURRENT_TIMESTAMP
         WHERE id=?`
      )
        .bind(current.user_id, current.user_id)
        .run();
      await updateUserMemberLevelForThresholds(env, current.user_id);
    }
  }
}

async function assignDefaultMemberLevel(env: Env, userId: number): Promise<void> {
  if (userId <= 0) return;
  const defaultLevel = await env.DB.prepare(
    "SELECT id FROM member_levels WHERE is_default=1 AND is_active=1 ORDER BY id ASC LIMIT 1"
  ).first<{ id: number }>();
  if (!defaultLevel) return;
  await env.DB.prepare(
    "UPDATE users SET member_level_id=?, updated_at=CURRENT_TIMESTAMP WHERE id=? AND member_level_id=0"
  ).bind(defaultLevel.id, userId).run();
}

async function updateUserMemberLevelForThresholds(env: Env, userId: number): Promise<void> {
  const user = await env.DB.prepare("SELECT id, member_level_id, total_recharged, total_spent FROM users WHERE id=?")
    .bind(userId)
    .first<{ id: number; member_level_id: number; total_recharged: number; total_spent: number }>();
  if (!user) return;
  let currentSortOrder = Number.MIN_SAFE_INTEGER;
  if (Number(user.member_level_id || 0) > 0) {
    const current = await env.DB.prepare("SELECT sort_order FROM member_levels WHERE id=?")
      .bind(user.member_level_id)
      .first<{ sort_order: number }>();
    if (!current) return;
    currentSortOrder = Number(current.sort_order || 0);
  }
  const levels = await env.DB.prepare(
    "SELECT * FROM member_levels WHERE is_active=1 AND sort_order>? ORDER BY sort_order DESC, id ASC"
  ).bind(currentSortOrder).all<MemberLevelRow>();
  const match = (levels.results || []).find((level) => (
    (Number(level.recharge_threshold || 0) > 0
      && Number(user.total_recharged || 0) >= Number(level.recharge_threshold || 0))
    || (Number(level.spend_threshold || 0) > 0
      && Number(user.total_spent || 0) >= Number(level.spend_threshold || 0))
  ));
  if (!match) return;
  await env.DB.prepare(
    "UPDATE users SET member_level_id=?, updated_at=CURRENT_TIMESTAMP WHERE id=? AND member_level_id=?"
  ).bind(match.id, user.id, user.member_level_id).run();
}

async function expireDueWalletRecharges(env: Env): Promise<number> {
  const minutes = await orderPaymentExpireMinutes(env);
  const cutoff = dashboardDbDate(new Date(Date.now() - minutes * 60 * 1000));
  const rows = await env.DB.prepare(
    `SELECT wr.id, wr.payment_id
     FROM wallet_recharges wr
     LEFT JOIN payments p ON p.id=wr.payment_id
     WHERE wr.status='pending'
       AND ${dashboardSqlDate("wr.created_at")} <= datetime(?)
       AND (p.id IS NULL OR p.status IN ('pending', 'created', 'initiated', ''))`
  ).bind(cutoff).all<{ id: number; payment_id: number }>();
  const items = rows.results || [];
  if (!items.length) return 0;
  await env.DB.batch(items.flatMap((item) => {
    const statements = [
      env.DB.prepare("UPDATE wallet_recharges SET status='expired', updated_at=CURRENT_TIMESTAMP WHERE id=? AND status='pending'")
        .bind(item.id)
    ];
    if (Number(item.payment_id || 0) > 0) {
      statements.push(env.DB.prepare(
        "UPDATE payments SET status='expired', expired_at=COALESCE(expired_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP WHERE id=? AND status IN ('pending', 'created', 'initiated', '')"
      ).bind(item.payment_id));
    }
    return statements;
  }));
  return items.length;
}

async function expireWalletRechargeIfDue(env: Env, recharge: WalletRechargeRow): Promise<WalletRechargeRow> {
  if (recharge.status !== "pending") return recharge;
  const minutes = await orderPaymentExpireMinutes(env);
  const cutoff = dashboardDbDate(new Date(Date.now() - minutes * 60 * 1000));
  const expired = await env.DB.prepare(
    `UPDATE wallet_recharges
     SET status='expired', updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND status='pending' AND ${dashboardSqlDate("created_at")} <= datetime(?)
     RETURNING *`
  ).bind(recharge.id, cutoff).first<WalletRechargeRow>();
  if (!expired) return recharge;
  if (Number(recharge.payment_id || 0) > 0) {
    await env.DB.prepare(
      "UPDATE payments SET status='expired', expired_at=COALESCE(expired_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP WHERE id=? AND status IN ('pending', 'created', 'initiated', '')"
    ).bind(recharge.payment_id).run();
  }
  return expired;
}

function makeRechargeNo(): string {
  const stamp = new Date().toISOString().replace(/[-:TZ.]/g, "").slice(0, 14);
  const rand = Math.floor(Math.random() * 900000 + 100000);
  return `WR${stamp}${rand}`;
}

async function activePaymentChannels(env: Env): Promise<PaymentChannelRow[]> {
  if (activePaymentChannelCache && activePaymentChannelCache.expiresAt > Date.now()) {
    return activePaymentChannelCache.rows;
  }
  const rows = await env.DB.prepare(
    "SELECT * FROM payment_channels WHERE is_active=1 ORDER BY sort_order ASC, id ASC"
  ).all<PaymentChannelRow>();
  const activeRows = rows.results || [];
  activePaymentChannelCache = {
    rows: activeRows,
    expiresAt: Date.now() + PAYMENT_CHANNEL_CACHE_TTL_MS
  };
  return activeRows;
}

async function paymentChannelById(env: Env, id: number): Promise<PaymentChannelRow | null> {
  return env.DB.prepare("SELECT * FROM payment_channels WHERE id=?").bind(id).first<PaymentChannelRow>();
}

async function productRowsByIds(env: Env, productIds: number[]): Promise<ProductRow[]> {
  const ids = Array.from(new Set(productIds.filter((id) => Number.isInteger(id) && id > 0)));
  if (!ids.length) return [];
  const rows: ProductRow[] = [];
  for (const chunk of chunkNumbers(ids, 100)) {
    const result = await env.DB.prepare(`SELECT * FROM products WHERE id IN (${chunk.map(() => "?").join(",")})`)
      .bind(...chunk)
      .all<ProductRow>();
    rows.push(...(result.results || []));
  }
  return rows;
}

function productPaymentChannelIntersection(products: ProductRow[]): number[] | null {
  let intersection: Set<number> | null = null;
  let restricted = false;
  for (const product of products) {
    const ids = arrayNumbers(jsonParse(product.payment_channel_ids_json || "[]", []));
    if (!ids.length) continue;
    restricted = true;
    const current = new Set(ids);
    if (intersection === null) {
      intersection = current;
      continue;
    }
    intersection = new Set([...intersection].filter((id) => current.has(id)));
  }
  if (!restricted) return null;
  return [...(intersection || new Set<number>())].sort((a, b) => a - b);
}

function paymentChannelAllowsRole(channel: PaymentChannelRow, user: UserRow | null): boolean {
  const roles = jsonParse<unknown[]>(channel.payment_roles_json || "[]", [])
    .map((role) => clean(role, 30).toLowerCase())
    .filter(Boolean);
  if (!roles.length) return true;
  return user
    ? roles.some((role) => role === "member" || role === "user")
    : roles.includes("guest");
}

function paymentChannelAllowsMemberLevel(channel: PaymentChannelRow, user: UserRow | null): boolean {
  const levelIds = arrayNumbers(jsonParse(channel.member_levels_json || "[]", []));
  if (!levelIds.length) return true;
  return Boolean(user && levelIds.includes(Number(user.member_level_id || 0)));
}

function paymentChannelAllowsType(channel: PaymentChannelRow, paymentType: "order" | "wallet"): boolean {
  const types = jsonParse<unknown[]>(channel.payment_types_json || "[]", [])
    .map((type) => clean(type, 30).toLowerCase())
    .filter(Boolean);
  return !types.length || types.includes(paymentType);
}

async function availableOrderPaymentChannels(
  env: Env,
  products: ProductRow[],
  amount: number,
  user: UserRow | null
): Promise<PaymentChannelRow[]> {
  const [wallet, channels] = await Promise.all([
    walletConfig(env),
    activePaymentChannels(env)
  ]);
  if (wallet.walletOnlyPayment) return [];
  const allowedIds = productPaymentChannelIntersection(products);
  return channels.filter((channel) => {
    const providerType = clean(channel.provider_type, 40).toLowerCase();
    if (!["manual", "wallet"].includes(providerType) && !isImplementedPaymentProvider(providerType, channel.channel_type)) return false;
    if (allowedIds !== null && !allowedIds.includes(channel.id)) return false;
    if (!paymentChannelAllowsRole(channel, user)) return false;
    if (!paymentChannelAllowsMemberLevel(channel, user)) return false;
    if (!paymentChannelAllowsType(channel, "order")) return false;
    if (channel.hide_amount_out_range && !paymentChannelAcceptsAmount(channel, amount)) return false;
    return true;
  });
}

async function validatePaymentChannelForOrder(
  env: Env,
  channel: PaymentChannelRow,
  order: OrderRow,
  amount: number,
  authenticatedUser: UserRow | null,
  productRows: ProductRow[]
): Promise<string> {
  const wallet = await walletConfig(env);
  const user = order.user_id ? authenticatedUser : null;
  if (wallet.walletOnlyPayment) return "站点当前仅支持钱包余额支付";
  if (!channel.is_active) return "支付渠道已停用";
  const providerType = clean(channel.provider_type, 40).toLowerCase();
  if (!["manual", "wallet"].includes(providerType) && !isImplementedPaymentProvider(providerType, channel.channel_type)) {
    return "该支付服务尚未接入 Cloudflare 运行时";
  }
  if (!paymentChannelAcceptsAmount(channel, amount)) return "订单金额不符合支付渠道限额";
  if (!paymentChannelAllowsRole(channel, user)) return "当前账号类型不能使用该支付渠道";
  if (!paymentChannelAllowsMemberLevel(channel, user)) return "当前会员等级不能使用该支付渠道";
  if (!paymentChannelAllowsType(channel, "order")) return "该支付渠道不支持订单支付";
  const allowedIds = productPaymentChannelIntersection(productRows);
  if (allowedIds !== null && !allowedIds.includes(channel.id)) return "订单商品不支持该支付渠道";
  return "";
}

async function createManualPaymentForOrder(
  env: Env,
  input: {
    orderId: number;
    orderNo: string;
    userId: number;
      guestEmail: string;
      channelId: number;
      channel?: PaymentChannelRow;
      amount: number;
    paidAt?: string | null;
    status?: string;
    providerPayload?: AnyRecord;
  }
): Promise<PaymentRow | null> {
  const channel = input.channel || await paymentChannelById(env, input.channelId);
  const feeRate = Number(channel?.fee_rate || 0);
  const fixedFee = Number(channel?.fixed_fee || 0);
  const amount = centsToMoney(moneyToCents(input.amount));
  const feeAmount = centsToMoney(Math.round(moneyToCents(amount) * feeRate / 100) + moneyToCents(fixedFee));
  const payable = centsToMoney(moneyToCents(amount) + moneyToCents(feeAmount));
  const paymentNo = makePaymentNo();
  const status = clean(input.status, 30) || (input.paidAt ? "success" : "pending");
  return env.DB.prepare(
    `INSERT INTO payments (
      payment_no, order_id, user_id, guest_email, channel_id, provider_type, channel_type,
      interaction_mode, amount, payable_amount, fee_rate, fixed_fee, fee_amount, currency,
      status, provider_payload_json, paid_at
    )
    SELECT ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'CNY', ?, ?, ?
    WHERE EXISTS (
      SELECT 1 FROM orders
      WHERE id=? AND parent_id IS NULL AND status='pending_payment'
    )
      AND NOT EXISTS (
        SELECT 1 FROM payments
        WHERE order_id=? AND channel_id=?
          AND status IN ('initiated','pending','created')
          AND (expired_at IS NULL OR expired_at > CURRENT_TIMESTAMP)
      )
    RETURNING *`
  ).bind(
    paymentNo,
    input.orderId,
    input.userId,
    input.guestEmail,
    channel?.id || 1,
    channel?.provider_type || "manual",
    channel?.channel_type || "manual",
    channel?.interaction_mode || "none",
    money(payable),
    money(payable),
    money(feeRate),
    money(fixedFee),
    money(feeAmount),
    status,
    stringify(input.providerPayload || { order_no: input.orderNo, mode: channel?.provider_type || "manual" }),
    input.paidAt || null,
    input.orderId,
    input.orderId,
    channel?.id || input.channelId
  ).first<PaymentRow>();
}

function buildPaymentsWhere(url: URL): { where: string; params: unknown[] } {
  const params: unknown[] = [];
  let where = "WHERE 1=1";
  const paymentId = toInt(url.searchParams.get("payment_id"), 0);
  const status = clean(url.searchParams.get("status"), 30);
  const userId = toInt(url.searchParams.get("user_id"), 0);
  const orderId = toInt(url.searchParams.get("order_id"), 0);
  const channelId = toInt(url.searchParams.get("channel_id"), 0);
  const providerType = clean(url.searchParams.get("provider_type"), 40);
  const createdFrom = clean(url.searchParams.get("created_from"), 40);
  const createdTo = clean(url.searchParams.get("created_to"), 40);
  if (paymentId > 0) {
    where += " AND p.id=?";
    params.push(paymentId);
  }
  if (status && status !== "__all__") {
    where += " AND p.status=?";
    params.push(status);
  }
  if (userId > 0) {
    where += " AND p.user_id=?";
    params.push(userId);
  }
  if (orderId > 0) {
    where += " AND p.order_id=?";
    params.push(orderId);
  }
  if (channelId > 0) {
    where += " AND p.channel_id=?";
    params.push(channelId);
  }
  if (providerType && providerType !== "__all__") {
    where += " AND p.provider_type=?";
    params.push(providerType);
  }
  if (createdFrom) {
    const date = new Date(createdFrom);
    if (!Number.isNaN(date.getTime())) {
      where += ` AND ${dashboardSqlDate("p.created_at")} >= datetime(?)`;
      params.push(dashboardDbDate(date));
    }
  }
  if (createdTo) {
    const date = new Date(createdTo);
    if (!Number.isNaN(date.getTime())) {
      where += ` AND ${dashboardSqlDate("p.created_at")} <= datetime(?)`;
      params.push(dashboardDbDate(date));
    }
  }
  return { where, params };
}

function makePaymentNo(): string {
  const stamp = new Date().toISOString().replace(/[-:TZ.]/g, "").slice(0, 14);
  const rand = Math.floor(Math.random() * 900000 + 100000);
  return `PAY${stamp}${rand}`;
}

function sanitizeLocalizedHtml(value: unknown): AnyRecord {
  const normalized = normalizeLocalizedHtml(value, "");
  const result: AnyRecord = {};
  for (const [key, raw] of Object.entries(normalized)) {
    result[key] = sanitizeHtmlLite(String(raw || ""));
  }
  return result;
}

function normalizeLocalizedHtml(value: unknown, fallback: string): AnyRecord {
  const html = (raw: unknown) => String(raw ?? fallback ?? "").slice(0, 200000);
  if (value && typeof value === "object" && !Array.isArray(value)) {
    const input = value as AnyRecord;
    return {
      "zh-CN": html(input["zh-CN"] ?? input.zh ?? input.cn ?? fallback),
      "zh-TW": html(input["zh-TW"] ?? input["zh-CN"] ?? fallback),
      "en-US": html(input["en-US"] ?? input["zh-CN"] ?? fallback)
    };
  }
  return { "zh-CN": html(value), "zh-TW": html(value), "en-US": html(value) };
}

function sanitizeHtmlLite(value: string): string {
  return value
    .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, "")
    .replace(/\s(srcdoc|formaction)\s*=\s*"[^"]*"/gi, "")
    .replace(/\s(srcdoc|formaction)\s*=\s*'[^']*'/gi, "")
    .replace(/\s(href|src|xlink:href)\s*=\s*"[\s\u0000]*(javascript|vbscript):[^"]*"/gi, " $1=\"#\"")
    .replace(/\s(href|src|xlink:href)\s*=\s*'[\s\u0000]*(javascript|vbscript):[^']*'/gi, " $1=\"#\"")
    .replace(/\sstyle\s*=\s*"[^"]*(expression\s*\(|url\s*\(\s*['\"]?\s*(javascript|vbscript):)[^"]*"/gi, "")
    .replace(/\sstyle\s*=\s*'[^']*(expression\s*\(|url\s*\(\s*['\"]?\s*(javascript|vbscript):)[^']*'/gi, "")
    .replace(/\son[a-z]+\s*=\s*"[^"]*"/gi, "")
    .replace(/\son[a-z]+\s*=\s*'[^']*'/gi, "")
    .replace(/\son[a-z]+\s*=\s*[^\s>]+/gi, "")
    .replace(/javascript:/gi, "");
}

function normalizeStringArray(value: unknown, allowed?: string[]): string[] {
  if (!Array.isArray(value)) return [];
  const allowedSet = allowed ? new Set(allowed) : null;
  return Array.from(new Set(value
    .map((item) => clean(item, 80).toLowerCase())
    .filter((item) => item && (!allowedSet || allowedSet.has(item)))));
}

function normalizeDateString(value: unknown): string {
  const text = clean(value, 80);
  if (!text) return "";
  const date = new Date(text);
  if (Number.isNaN(date.getTime())) return "";
  return date.toISOString();
}

function strictOptionalDateQuery(url: URL, key: string): string {
  const raw = clean(url.searchParams.get(key), 80);
  if (!raw) return "";
  const normalized = normalizeDateString(raw);
  if (!normalized) throw new ApiRequestError(400, `${key} 时间格式不正确`);
  return normalized;
}

function giftCardExportResponse(rows: GiftCardRow[], format: "txt" | "csv"): Response {
  const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
  const filename = `gift-cards-${timestamp}.${format}`;
  const body = format === "csv"
    ? "\uFEFF" + [
      ["id", "code", "name", "amount", "currency", "status", "expires_at", "batch_no", "created_at"].join(","),
      ...rows.map((row) => [
        row.id,
        csvEscape(row.code),
        csvEscape(row.name),
        Number(row.amount || 0),
        csvEscape(row.currency || "CNY"),
        csvEscape(row.status || ""),
        csvEscape(row.expires_at || ""),
        csvEscape(row.batch_no || ""),
        csvEscape(row.created_at || "")
      ].join(","))
    ].join("\n")
    : rows.map((row) => row.code).join("\n");
  return new Response(body, {
    headers: {
      "Content-Type": format === "csv" ? "text/csv; charset=utf-8" : "text/plain; charset=utf-8",
      "Content-Disposition": `attachment; filename="${filename}"`,
      "Cache-Control": "no-store"
    }
  });
}

async function deleteEmptyGiftCardBatches(env: Env): Promise<void> {
  await env.DB.prepare(
    "DELETE FROM gift_card_batches WHERE id NOT IN (SELECT DISTINCT batch_id FROM gift_cards WHERE batch_id IS NOT NULL)"
  ).run();
}

function makeGiftCardBatchNo(): string {
  const stamp = new Date().toISOString().replace(/[-:TZ.]/g, "").slice(0, 14);
  const rand = Math.floor(Math.random() * 9000 + 1000);
  return `GC${stamp}${rand}`;
}

async function makeUniqueGiftCardCode(env: Env): Promise<string> {
  for (let attempt = 0; attempt < 8; attempt += 1) {
    const code = `GC-${randomReadableToken(4)}-${randomReadableToken(4)}-${randomReadableToken(4)}`;
    const existing = await env.DB.prepare("SELECT id FROM gift_cards WHERE code=?").bind(code).first<{ id: number }>();
    if (!existing) return code;
  }
  return `GC-${Date.now()}-${randomReadableToken(6)}`;
}

function makeGiftCardCode(): string {
  return `GC-${randomReadableToken(4)}-${randomReadableToken(4)}-${randomReadableToken(4)}`;
}

function randomBase32Secret(byteLength = 20): string {
  const bytes = new Uint8Array(byteLength);
  crypto.getRandomValues(bytes);
  return bytesToBase32(bytes);
}

function bytesToBase32(bytes: Uint8Array): string {
  let bits = 0;
  let value = 0;
  let output = "";
  for (const byte of bytes) {
    value = (value << 8) | byte;
    bits += 8;
    while (bits >= 5) {
      output += BASE32_ALPHABET[(value >>> (bits - 5)) & 31];
      bits -= 5;
    }
  }
  if (bits > 0) output += BASE32_ALPHABET[(value << (5 - bits)) & 31];
  return output;
}

function base32ToBytes(secret: string): Uint8Array {
  const normalized = clean(secret, 512).toUpperCase().replace(/[\s=]/g, "");
  const bytes: number[] = [];
  let bits = 0;
  let value = 0;
  for (const char of normalized) {
    const index = BASE32_ALPHABET.indexOf(char);
    if (index < 0) continue;
    value = (value << 5) | index;
    bits += 5;
    if (bits >= 8) {
      bytes.push((value >>> (bits - 8)) & 255);
      bits -= 8;
    }
  }
  return new Uint8Array(bytes);
}

async function verifyTotpCode(secret: string, code: string): Promise<boolean> {
  const normalized = clean(code, 20).replace(/\D/g, "");
  if (!/^\d{6}$/.test(normalized)) return false;
  const secretBytes = base32ToBytes(secret);
  if (!secretBytes.length) return false;
  const currentCounter = Math.floor(Date.now() / 1000 / TOTP_STEP_SECONDS);
  for (let offset = -TOTP_WINDOW; offset <= TOTP_WINDOW; offset += 1) {
    const candidate = await hotp(secretBytes, currentCounter + offset);
    if (constantTimeEqual(candidate, normalized)) return true;
  }
  return false;
}

async function hotp(secretBytes: Uint8Array, counter: number): Promise<string> {
  const counterBuffer = new ArrayBuffer(8);
  const view = new DataView(counterBuffer);
  const safeCounter = Math.max(0, Math.floor(counter));
  view.setUint32(0, Math.floor(safeCounter / 0x100000000));
  view.setUint32(4, safeCounter >>> 0);
  const key = await crypto.subtle.importKey(
    "raw",
    secretBytes,
    { name: "HMAC", hash: "SHA-1" },
    false,
    ["sign"]
  );
  const digest = new Uint8Array(await crypto.subtle.sign("HMAC", key, counterBuffer));
  const offset = digest[digest.length - 1] & 0x0f;
  const binary = ((digest[offset] & 0x7f) << 24)
    | ((digest[offset + 1] & 0xff) << 16)
    | ((digest[offset + 2] & 0xff) << 8)
    | (digest[offset + 3] & 0xff);
  return String(binary % 10 ** TOTP_DIGITS).padStart(TOTP_DIGITS, "0");
}

function constantTimeEqual(left: string, right: string): boolean {
  if (left.length !== right.length) return false;
  let mismatch = 0;
  for (let index = 0; index < left.length; index += 1) {
    mismatch |= left.charCodeAt(index) ^ right.charCodeAt(index);
  }
  return mismatch === 0;
}

function normalizeRecoveryCode(value: unknown): string {
  return clean(value, 100).toUpperCase().replace(/[^A-Z0-9]/g, "");
}

function makeRecoveryCode(): string {
  return `${randomReadableToken(4)}-${randomReadableToken(4)}-${randomReadableToken(4)}`;
}

async function recoveryCodeHash(adminId: number, code: string): Promise<string> {
  return sha256Hex(`admin-recovery:${adminId}:${normalizeRecoveryCode(code)}`);
}

async function replaceAdminRecoveryCodes(env: Env, adminId: number): Promise<string[]> {
  const codes = Array.from({ length: ADMIN_RECOVERY_CODE_COUNT }, () => makeRecoveryCode());
  await env.DB.prepare("DELETE FROM admin_recovery_codes WHERE admin_id=?").bind(adminId).run();
  for (const code of codes) {
    await env.DB.prepare("INSERT INTO admin_recovery_codes (admin_id, code_hash) VALUES (?, ?)")
      .bind(adminId, await recoveryCodeHash(adminId, code))
      .run();
  }
  return codes;
}

async function consumeAdminRecoveryCode(env: Env, adminId: number, code: string): Promise<boolean> {
  const normalized = normalizeRecoveryCode(code);
  if (!normalized) return false;
  const hash = await recoveryCodeHash(adminId, normalized);
  const result = await env.DB.prepare(
    "UPDATE admin_recovery_codes SET used_at=CURRENT_TIMESTAMP WHERE admin_id=? AND code_hash=? AND used_at IS NULL"
  ).bind(adminId, hash).run();
  return Boolean(result.meta.changes);
}

async function siteIssuerName(env: Env): Promise<string> {
  const siteConfig = await setting(env, "site_config", {});
  const brand = jsonObject(siteConfig.brand);
  return clean(brand.site_name || localizedConfigText(siteConfig.seo?.title) || "Dujiao Next", 80) || "Dujiao Next";
}

function randomReadableToken(length: number): string {
  const alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  const bytes = new Uint8Array(length);
  crypto.getRandomValues(bytes);
  return [...bytes].map((byte) => alphabet[byte % alphabet.length]).join("");
}

function cardSecretFilterFromUrl(url: URL): AnyRecord {
  return {
    product_id: url.searchParams.get("product_id"),
    sku_id: url.searchParams.get("sku_id"),
    batch_id: url.searchParams.get("batch_id"),
    status: url.searchParams.get("status"),
    secret: url.searchParams.get("secret"),
    batch_no: url.searchParams.get("batch_no")
  };
}

function buildCardSecretWhere(filter: AnyRecord): { where: string; params: unknown[] } {
  const params: unknown[] = [];
  let where = "WHERE 1 = 1";
  const productId = toInt(filter.product_id, 0);
  const skuId = toInt(filter.sku_id, 0);
  const batchId = toInt(filter.batch_id, 0);
  const status = clean(filter.status, 30);
  const secret = clean(filter.secret, 200);
  const batchNo = clean(filter.batch_no, 100);
  if (productId > 0) {
    where += " AND cs.product_id = ?";
    params.push(productId);
  }
  if (skuId > 0) {
    where += " AND cs.sku_id = ?";
    params.push(skuId);
  }
  if (batchId > 0) {
    where += " AND cs.batch_id = ?";
    params.push(batchId);
  }
  if (status && status !== "__all__") {
    if (!isCardSecretStatus(status)) {
      where += " AND 1 = 0";
    } else {
      where += " AND cs.status = ?";
      params.push(status);
    }
  }
  if (secret) {
    where += " AND cs.secret LIKE ?";
    params.push(`%${secret}%`);
  }
  if (batchNo) {
    where += " AND b.batch_no LIKE ?";
    params.push(`%${batchNo}%`);
  }
  return { where, params };
}

function isCardSecretStatus(status: string): boolean {
  return status === "available" || status === "reserved" || status === "used";
}

async function resolveCardSecretTarget(
  env: Env,
  productId: number,
  skuId: number
): Promise<{ ok: true; product: ProductRow; sku: SkuRow } | { ok: false; error: string }> {
  if (!productId) return { ok: false, error: "请选择商品" };
  const product = await env.DB.prepare("SELECT * FROM products WHERE id=?").bind(productId).first<ProductRow>();
  if (!product) return { ok: false, error: "商品不存在" };
  if ((product.fulfillment_type || "manual") !== "auto") {
    return { ok: false, error: "请先将商品发货方式改为自动发货" };
  }
  if (skuId > 0) {
    const sku = await env.DB.prepare("SELECT * FROM product_skus WHERE id=? AND product_id=?").bind(skuId, productId).first<SkuRow>();
    if (!sku) return { ok: false, error: "商品规格不存在" };
    return { ok: true, product, sku };
  }
  const skus = await env.DB.prepare("SELECT * FROM product_skus WHERE product_id=? AND is_active=1 ORDER BY sort_order ASC, id ASC")
    .bind(productId)
    .all<SkuRow>();
  const active = skus.results || [];
  if (active.length === 1) return { ok: true, product, sku: active[0]! };
  if (active.length > 1) return { ok: false, error: "该商品有多个规格，请选择规格" };
  return { ok: false, error: "商品没有可用规格" };
}

function normalizeCardSecretLines(values: unknown[]): string[] {
  const lines: string[] = [];
  for (const item of values) {
    for (const line of String(item ?? "").split(/\r?\n/)) {
      const value = clean(line, 4000);
      if (!value) continue;
      lines.push(value);
      if (lines.length >= 5000) return lines;
    }
  }
  return lines;
}

function parseCardSecretImportText(text: string): string[] {
  const lines = text.replace(/^\uFEFF/, "").split(/\r?\n/);
  const values: string[] = [];
  for (const [index, line] of lines.entries()) {
    const value = clean(firstCsvCell(line), 4000);
    if (!value) continue;
    const normalized = value.toLowerCase();
    if (index === 0 && ["secret", "card_secret", "card secret", "卡密", "内容"].includes(normalized)) continue;
    values.push(value);
  }
  return normalizeCardSecretLines(values);
}

function firstCsvCell(line: string): string {
  const trimmed = String(line || "").trim();
  if (!trimmed) return "";
  if (!trimmed.startsWith("\"")) return trimmed.split(",")[0] || "";
  let value = "";
  for (let index = 1; index < trimmed.length; index += 1) {
    const char = trimmed[index];
    if (char === "\"" && trimmed[index + 1] === "\"") {
      value += "\"";
      index += 1;
      continue;
    }
    if (char === "\"") break;
    value += char;
  }
  return value;
}

async function createCardSecretBatch(
  env: Env,
  input: {
    productId: number;
    skuId: number;
    secrets: string[];
    batchNo?: string;
    source: string;
    note?: string;
    deduplicate: boolean;
  }
): Promise<AnyRecord> {
  const batchNo = clean(input.batchNo, 80) || makeCardSecretBatchNo();
  const duplicateBatch = await env.DB.prepare("SELECT id FROM card_secret_batches WHERE batch_no=? LIMIT 1")
    .bind(batchNo)
    .first<{ id: number }>();
  if (duplicateBatch) throw new ApiRequestError(409, "卡密批次号已存在");

  const candidates: Array<{ secret: string; hash: string }> = [];
  let skipped = 0;
  const seenSecrets = new Set<string>();
  for (const secret of input.secrets) {
    if (input.deduplicate && seenSecrets.has(secret)) {
      skipped += 1;
      continue;
    }
    if (input.deduplicate) seenSecrets.add(secret);
    candidates.push({
      secret,
      hash: await cardSecretHash(input.productId, input.skuId, secret)
    });
  }

  let rows = candidates;
  if (input.deduplicate && candidates.length) {
    const existing = await env.DB.prepare(
      `SELECT DISTINCT secret_hash
       FROM card_secrets
       WHERE product_id=?
         AND sku_id=?
         AND secret_hash IN (SELECT CAST(value AS TEXT) FROM json_each(?))`
    ).bind(
      input.productId,
      input.skuId,
      JSON.stringify(candidates.map((item) => item.hash))
    ).all<{ secret_hash: string }>();
    const existingHashes = new Set((existing.results || []).map((item) => item.secret_hash));
    rows = candidates.filter((item) => !existingHashes.has(item.hash));
    skipped += candidates.length - rows.length;
  }

  const imported = rows.length;
  if (!imported) return { imported, skipped, total: input.secrets.length, batch: null };

  try {
    await env.DB.batch([
      env.DB.prepare(
        `INSERT INTO card_secret_batches (product_id, sku_id, name, batch_no, source, note)
         VALUES (?, ?, ?, ?, ?, ?)`
      ).bind(
        input.productId,
        input.skuId,
        batchNo,
        batchNo,
        clean(input.source, 40) || "manual",
        clean(input.note, 1000)
      ),
      env.DB.prepare(
        `INSERT INTO card_secrets (product_id, sku_id, batch_id, secret, secret_hash, status)
         SELECT ?, ?, b.id, json_extract(j.value, '$.secret'), json_extract(j.value, '$.hash'), 'available'
         FROM json_each(?) AS j
         CROSS JOIN card_secret_batches AS b
         WHERE b.batch_no=?`
      ).bind(input.productId, input.skuId, JSON.stringify(rows), batchNo)
    ]);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (/unique constraint failed.*batch_no/i.test(message)) {
      throw new ApiRequestError(409, "卡密批次号已存在");
    }
    throw error;
  }

  const batch = await env.DB.prepare(
    `SELECT
       b.*,
       COUNT(cs.id) AS total_count,
       COALESCE(SUM(CASE WHEN cs.status='available' THEN 1 ELSE 0 END), 0) AS available_count,
       COALESCE(SUM(CASE WHEN cs.status='reserved' THEN 1 ELSE 0 END), 0) AS reserved_count,
       COALESCE(SUM(CASE WHEN cs.status='used' THEN 1 ELSE 0 END), 0) AS used_count
     FROM card_secret_batches b
     LEFT JOIN card_secrets cs ON cs.batch_id=b.id
     WHERE b.batch_no=?
     GROUP BY b.id`
  ).bind(batchNo).first<CardSecretBatchRow>();
  return {
    imported,
    skipped,
    total: input.secrets.length,
    batch: batch ? formatCardSecretBatch(batch) : null
  };
}

async function cardSecretIdsForScope(env: Env, body: AnyRecord, maxRows: number): Promise<number[]> {
  const explicitIds = arrayNumbers(body.ids);
  if (explicitIds.length) return Array.from(new Set(explicitIds));

  const hasFilter = body.filter && typeof body.filter === "object" && !Array.isArray(body.filter);
  const batchId = toInt(body.batch_id, 0);
  if (!hasFilter && batchId <= 0) return [];
  const filter = hasFilter ? { ...(body.filter as AnyRecord) } : {};
  if (batchId > 0) filter.batch_id = batchId;
  const { where, params } = buildCardSecretWhere(filter);
  const rows = await env.DB.prepare(
    `SELECT cs.id
     FROM card_secrets cs
     LEFT JOIN card_secret_batches b ON b.id=cs.batch_id
     ${where}
     ORDER BY cs.id ASC
     LIMIT ?`
  ).bind(...params, maxRows).all<{ id: number }>();
  return (rows.results || []).map((row) => row.id);
}

async function updateCardSecretStatusByIds(env: Env, ids: number[], status: string): Promise<number> {
  let affected = 0;
  for (const chunk of chunkNumbers(ids, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(
      `UPDATE card_secrets
       SET status=?,
           order_id=CASE WHEN ?='available' THEN NULL ELSE order_id END,
           reserved_at=CASE
             WHEN ?='reserved' AND reserved_at IS NULL THEN CURRENT_TIMESTAMP
             WHEN ?='available' THEN NULL
             ELSE reserved_at
           END,
           used_at=CASE
             WHEN ?='used' AND used_at IS NULL THEN CURRENT_TIMESTAMP
             WHEN ?!='used' THEN NULL
             ELSE used_at
           END,
           updated_at=CURRENT_TIMESTAMP
       WHERE id IN (${placeholders})`
    ).bind(status, status, status, status, status, status, ...chunk).run();
    affected += Number(result.meta.changes || 0);
  }
  return affected;
}

async function cardSecretsByIds(env: Env, ids: number[]): Promise<CardSecretRow[]> {
  const rows: CardSecretRow[] = [];
  for (const chunk of chunkNumbers(ids, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(
      `SELECT cs.*, b.batch_no AS batch_no, b.name AS batch_name, b.source AS batch_source, b.note AS batch_note, b.created_at AS batch_created_at
       FROM card_secrets cs
       LEFT JOIN card_secret_batches b ON b.id=cs.batch_id
       WHERE cs.id IN (${placeholders})`
    ).bind(...chunk).all<CardSecretRow>();
    rows.push(...(result.results || []));
  }
  const order = new Map(ids.map((id, index) => [id, index]));
  return rows.sort((a, b) => (order.get(a.id) ?? 0) - (order.get(b.id) ?? 0));
}

async function claimAvailableCardSecretsForExport(
  env: Env,
  input: { productId: number; skuId: number; batchId: number; limit: number; deleteAfterExport: boolean }
): Promise<CardSecretRow[]> {
  const candidateSql = `
    SELECT id
    FROM card_secrets
    WHERE product_id=? AND status='available'
      AND (?=0 OR sku_id=?)
      AND (?=0 OR batch_id=?)
    ORDER BY id ASC
    LIMIT ?`;
  const statement = input.deleteAfterExport
    ? env.DB.prepare(
      `WITH candidates AS MATERIALIZED (${candidateSql})
       DELETE FROM card_secrets
       WHERE id IN (SELECT id FROM candidates)
         AND (SELECT COUNT(*) FROM candidates)=?
         AND status='available'
       RETURNING *`
    )
    : env.DB.prepare(
      `WITH candidates AS MATERIALIZED (${candidateSql})
       UPDATE card_secrets
       SET status='used', used_at=COALESCE(used_at, CURRENT_TIMESTAMP), updated_at=CURRENT_TIMESTAMP
       WHERE id IN (SELECT id FROM candidates)
         AND (SELECT COUNT(*) FROM candidates)=?
         AND status='available'
       RETURNING *`
    );
  const result = await statement.bind(
    input.productId,
    input.skuId,
    input.skuId,
    input.batchId,
    input.batchId,
    input.limit,
    input.limit
  ).all<CardSecretRow>();
  const rows = result.results || [];
  if (rows.length !== input.limit) return [];
  rows.sort((a, b) => a.id - b.id);
  await hydrateExportedCardSecretBatches(env, rows);
  return rows;
}

async function hydrateExportedCardSecretBatches(env: Env, rows: CardSecretRow[]): Promise<void> {
  const batchIds = Array.from(new Set(rows.map((row) => Number(row.batch_id || 0)).filter((id) => id > 0)));
  if (!batchIds.length) return;
  const batches = new Map<number, CardSecretBatchRow>();
  for (const chunk of chunkNumbers(batchIds, 100)) {
    const placeholders = chunk.map(() => "?").join(",");
    const result = await env.DB.prepare(`SELECT * FROM card_secret_batches WHERE id IN (${placeholders})`)
      .bind(...chunk)
      .all<CardSecretBatchRow>();
    for (const batch of result.results || []) batches.set(batch.id, batch);
  }
  for (const row of rows) {
    const batch = batches.get(Number(row.batch_id || 0));
    if (!batch) continue;
    row.batch_no = batch.batch_no;
    row.batch_name = batch.name;
    row.batch_source = batch.source;
    row.batch_note = batch.note;
    row.batch_created_at = batch.created_at;
  }
}

async function availableCardSecretExportCount(env: Env, productId: number, skuId: number, batchId: number): Promise<number> {
  return count(
    env,
    `SELECT COUNT(*) AS count FROM card_secrets
     WHERE product_id=? AND status='available'
       AND (?=0 OR sku_id=?)
       AND (?=0 OR batch_id=?)`,
    [productId, skuId, skuId, batchId, batchId]
  );
}

function normalizeExportFormat(value: unknown): "txt" | "csv" {
  const format = clean(value, 10).toLowerCase();
  if (format !== "txt" && format !== "csv") throw new ApiRequestError(400, "导出格式不合法");
  return format;
}

function cardSecretExportResponse(rows: CardSecretRow[], format: "txt" | "csv", prefix: string): Response {
  const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
  const filename = `${prefix}-${timestamp}.${format}`;
  const body = format === "csv"
    ? "\uFEFF" + [
      ["id", "secret", "status", "product_id", "sku_id", "batch_id", "batch_no", "order_id", "created_at", "used_at"].join(","),
      ...rows.map((row) => [
        row.id,
        csvEscape(row.secret),
        csvEscape(row.status),
        row.product_id,
        row.sku_id,
        row.batch_id || "",
        csvEscape(row.batch_no || ""),
        row.order_id || "",
        csvEscape(row.created_at || ""),
        csvEscape(row.used_at || "")
      ].join(","))
    ].join("\n")
    : rows.map((row) => row.secret).join("\n");
  return new Response(body, {
    headers: {
      "Content-Type": format === "csv" ? "text/csv; charset=utf-8" : "text/plain; charset=utf-8",
      "Content-Disposition": `attachment; filename="${filename}"`,
      "Cache-Control": "no-store"
    }
  });
}

function csvEscape(value: unknown): string {
  const text = String(value ?? "");
  if (!/[",\r\n]/.test(text)) return text;
  return `"${text.replace(/"/g, "\"\"")}"`;
}

async function deleteEmptyCardSecretBatches(env: Env): Promise<void> {
  await env.DB.prepare(
    "DELETE FROM card_secret_batches WHERE id NOT IN (SELECT DISTINCT batch_id FROM card_secrets WHERE batch_id IS NOT NULL)"
  ).run();
}

async function loadCardSecretStockMap(env: Env, productId: number): Promise<Map<number, CardSecretStockCounts>> {
  const rows = await env.DB.prepare(
    `SELECT
       sku_id,
       COUNT(*) AS total,
       COALESCE(SUM(CASE WHEN status='available' THEN 1 ELSE 0 END), 0) AS available,
       COALESCE(SUM(CASE WHEN status='reserved' THEN 1 ELSE 0 END), 0) AS reserved,
       COALESCE(SUM(CASE WHEN status='used' THEN 1 ELSE 0 END), 0) AS used
     FROM card_secrets
     WHERE product_id=?
     GROUP BY sku_id`
  ).bind(productId).all<CardSecretStockCounts & { sku_id: number }>();
  const map = new Map<number, CardSecretStockCounts>();
  for (const row of rows.results || []) {
    map.set(Number(row.sku_id || 0), {
      total: Number(row.total || 0),
      available: Number(row.available || 0),
      reserved: Number(row.reserved || 0),
      used: Number(row.used || 0)
    });
  }
  return map;
}

async function availableCardSecretCount(env: Env, productId: number, skuId: number): Promise<number> {
  const row = await env.DB.prepare(
    "SELECT COUNT(*) AS count FROM card_secrets WHERE product_id=? AND sku_id=? AND status='available'"
  ).bind(productId, skuId).first<{ count: number }>();
  return Number(row?.count || 0);
}

async function calculateCouponDiscount(
  env: Env,
  rawCode: string,
  items: CalculatedOrderItem[],
  originalAmount: number,
  user?: UserRow,
  memberLevelId = 0
): Promise<{ ok: true; discountAmount: number; coupon: CalculatedCoupon | null } | { ok: false; error: string }> {
  const code = clean(rawCode, 80).toUpperCase();
  if (!code) return { ok: true, discountAmount: 0, coupon: null };
  const coupon = await env.DB.prepare("SELECT * FROM coupons WHERE code=?").bind(code).first<CouponRow>();
  if (!coupon || !coupon.is_active) return { ok: false, error: "优惠券不存在或未启用" };
  const now = Date.now();
  if (coupon.starts_at && new Date(coupon.starts_at).getTime() > now) return { ok: false, error: "优惠券尚未开始" };
  if (coupon.ends_at && new Date(coupon.ends_at).getTime() < now) return { ok: false, error: "优惠券已过期" };
  if (coupon.usage_limit > 0 && coupon.used_count >= coupon.usage_limit) return { ok: false, error: "优惠券已达到使用上限" };
  const paymentRoles = normalizeStringArray(jsonParse(coupon.payment_roles_json, []), ["guest", "member"]);
  if (paymentRoles.length) {
    const role = user ? "member" : "guest";
    if (!paymentRoles.includes(role)) {
      if (paymentRoles.length === 1 && paymentRoles[0] === "guest") return { ok: false, error: "该优惠券限游客使用" };
      if (paymentRoles.length === 1 && paymentRoles[0] === "member") return { ok: false, error: "该优惠券限会员使用" };
      return { ok: false, error: "当前付款角色不可使用该优惠券" };
    }
  }
  const memberLevels = arrayNumbers(jsonParse(coupon.member_levels_json, []));
  if (memberLevels.length && (!memberLevelId || !memberLevels.includes(memberLevelId))) {
    return { ok: false, error: "当前会员等级不可使用该优惠券" };
  }
  if (coupon.per_user_limit > 0 && user?.id) {
    const usedByUser = await count(env, "SELECT COUNT(*) AS count FROM coupon_usages WHERE coupon_id=? AND user_id=?", [coupon.id, user.id]);
    if (usedByUser >= coupon.per_user_limit) return { ok: false, error: "已达到优惠券使用上限" };
  }

  const scopeIds = arrayNumbers(jsonParse(coupon.scope_ref_ids_json, []));
  const scopedItems = items.filter((item) => scopeIds.includes(item.product.id));
  const eligibleItems = scopedItems.filter((item) => !coupon.disabled_wholesale_price || moneyToCents(item.wholesaleDiscountAmount) <= 0);
  if (!eligibleItems.length) {
    if (scopedItems.length && coupon.disabled_wholesale_price) return { ok: false, error: "优惠券不可用于批发价商品" };
    return { ok: false, error: "优惠券不适用于当前商品" };
  }
  const eligibleAmount = eligibleItems.reduce((sum, item) => sum + Math.max(0, item.lineTotal), 0);
  if (coupon.min_amount > 0 && eligibleAmount < coupon.min_amount) return { ok: false, error: "未达到优惠券最低使用金额" };

  let discount = 0;
  if (coupon.type === "percent") {
    discount = eligibleAmount * Math.max(0, Math.min(100, Number(coupon.value || 0))) / 100;
  } else if (coupon.per_item_discount) {
    const eligibleQuantity = eligibleItems.reduce((sum, item) => sum + Math.max(0, item.quantity), 0);
    discount = Number(coupon.value || 0) * eligibleQuantity;
  } else {
    discount = Number(coupon.value || 0);
  }
  if (coupon.max_discount > 0) discount = Math.min(discount, Number(coupon.max_discount || 0));
  discount = Math.min(discount, eligibleAmount, originalAmount);
  const discountCents = Math.max(0, Math.round(discount * 100));
  if (discountCents <= 0) return { ok: true, discountAmount: 0, coupon: null };

  let remaining = discountCents;
  const eligibleTotalCents = eligibleItems.reduce((sum, item) => sum + moneyToCents(Math.max(0, item.lineTotal)), 0);
  eligibleItems.forEach((item, index) => {
    const lineCents = moneyToCents(Math.max(0, item.lineTotal));
    const share = index === eligibleItems.length - 1
      ? remaining
      : Math.min(remaining, Math.floor(discountCents * lineCents / Math.max(1, eligibleTotalCents)));
    item.couponDiscountAmount = centsToMoney(share);
    remaining -= share;
  });

  return {
    ok: true,
    discountAmount: centsToMoney(discountCents),
    coupon: {
      id: coupon.id,
      code: coupon.code,
      type: coupon.type,
      discountAmount: centsToMoney(discountCents),
      productIds: Array.from(new Set(eligibleItems.map((item) => item.product.id)))
    }
  };
}

async function calculatePromotionDiscount(env: Env, items: CalculatedOrderItem[]): Promise<CalculatedPromotion> {
  const now = new Date().toISOString();
  let discountCents = 0;
  const applied: CalculatedPromotion["promotions"] = [];
  for (const item of items) {
    const rows = await env.DB.prepare(
      `SELECT * FROM promotions
       WHERE is_active=1
         AND scope_type='product'
         AND scope_ref_id=?
         AND (starts_at IS NULL OR starts_at='' OR starts_at<=?)
         AND (ends_at IS NULL OR ends_at='' OR ends_at>=?)
       ORDER BY id DESC`
    ).bind(item.product.id, now, now).all<PromotionRow>();
    let best: { row: PromotionRow; cents: number } | null = null;
    for (const row of rows.results || []) {
      if (Number(row.min_amount || 0) > 0 && item.lineTotal < Number(row.min_amount || 0)) continue;
      const lineCents = moneyToCents(item.lineTotal);
      const unitCents = moneyToCents(Number(item.unitPrice || item.sku.price_amount || 0));
      const value = Number(row.value || 0);
      let cents = 0;
      if (row.type === "percent") {
        cents = Math.floor(lineCents * Math.max(0, Math.min(100, value)) / 100);
      } else if (row.type === "fixed") {
        cents = Math.min(lineCents, moneyToCents(value) * item.quantity);
      } else if (row.type === "special_price") {
        cents = Math.max(0, (unitCents - moneyToCents(value)) * item.quantity);
      }
      cents = Math.min(lineCents, Math.max(0, cents));
      if (!best || cents > best.cents) best = { row, cents };
    }
    if (best && best.cents > 0) {
      item.promotionDiscountAmount = centsToMoney(best.cents);
      discountCents += best.cents;
      applied.push({
        id: best.row.id,
        name: best.row.name,
        productId: item.product.id,
        discountAmount: centsToMoney(best.cents)
      });
    }
  }
  return { discountAmount: centsToMoney(discountCents), promotions: applied };
}

async function recordCouponUsage(env: Env, coupon: CalculatedCoupon, orderId: number, guestEmail: string, userId = 0): Promise<void> {
  const existing = await env.DB.prepare("SELECT id FROM coupon_usages WHERE order_id=? LIMIT 1")
    .bind(orderId)
    .first<{ id: number }>();
  if (existing) return;
  try {
    await env.DB.prepare(
      `INSERT INTO coupon_usages (coupon_id, coupon_code, coupon_type, order_id, user_id, guest_email, product_ids_json, discount_amount)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`
    ).bind(
      coupon.id,
      coupon.code,
      coupon.type,
      orderId,
      userId,
      guestEmail,
      JSON.stringify(coupon.productIds),
      money(coupon.discountAmount)
    ).run();
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (message.includes("coupon_usage_limit_reached")) throw new ApiRequestError(409, "优惠券已达到使用上限");
    if (message.includes("coupon_user_limit_reached")) throw new ApiRequestError(409, "该优惠券已达到每人使用上限");
    if (message.includes("coupon_unavailable")) throw new ApiRequestError(409, "优惠券不可用");
    const raced = await env.DB.prepare("SELECT id FROM coupon_usages WHERE order_id=? LIMIT 1")
      .bind(orderId)
      .first<{ id: number }>();
    if (raced) return;
    throw error;
  }
}

async function releaseCouponUsageForOrder(env: Env, orderId: number): Promise<void> {
  await env.DB.prepare("DELETE FROM coupon_usages WHERE order_id=?").bind(orderId).run();
}

function chunkNumbers(values: number[], size: number): number[][] {
  const chunks: number[][] = [];
  for (let index = 0; index < values.length; index += size) {
    chunks.push(values.slice(index, index + size));
  }
  return chunks;
}

function makeCardSecretBatchNo(): string {
  const stamp = new Date().toISOString().replace(/[-:TZ.]/g, "").slice(0, 14);
  const rand = Math.floor(Math.random() * 9000 + 1000);
  return `CS${stamp}${rand}`;
}

function cardSecretHash(productId: number, skuId: number, secret: string): Promise<string> {
  return sha256Hex(`${productId}:${skuId}:${secret}`);
}

function normalizePublicSiteName(config: AnyRecord): void {
  if (!config.brand || typeof config.brand !== "object") config.brand = {};
  const brand = config.brand as AnyRecord;
  const current = clean(brand.site_name, 120);
  const seoTitle = localizedConfigText(config.seo?.title);
  const legacyDefaults = new Set(["蜂蜜发卡商城", "蜂蜜發卡商城", "Faka Store", "Dujiao-Next"]);
  if ((!current || legacyDefaults.has(current)) && seoTitle && !legacyDefaults.has(seoTitle)) {
    brand.site_name = seoTitle;
  }
}

function normalizePublicHomeAnnouncement(value: unknown, nowMs: number): AnyRecord | null {
  const announcement = cloneJsonRecord(value);
  if (announcement.enabled !== true) return null;

  const startAt = clean(announcement.start_at, 80);
  const endAt = clean(announcement.end_at, 80);
  if (isFutureDate(startAt, nowMs) || isPastDate(endAt, nowMs)) return null;

  const title = normalizeLocalizedText(announcement.title, "");
  const content = normalizeLocalizedHtml(announcement.content, "");
  const hasBody = Object.values(title).some((item) => clean(item, 500))
    || Object.values(content).some((item) => clean(item, 5000));
  if (!hasBody) return null;

  const type = clean(announcement.type, 20);
  return {
    enabled: true,
    type: ["normal", "info", "warning"].includes(type) ? type : "normal",
    title,
    content,
    start_at: startAt,
    end_at: endAt,
    version: clean(announcement.version, 100) || `home-${hashString(JSON.stringify({ type, title, content, startAt, endAt }))}`
  };
}

function isFutureDate(value: string, nowMs: number): boolean {
  if (!value) return false;
  const time = Date.parse(value);
  return Number.isFinite(time) && nowMs < time;
}

function isPastDate(value: string, nowMs: number): boolean {
  if (!value) return false;
  const time = Date.parse(value);
  return Number.isFinite(time) && nowMs > time;
}

function normalizeOptionalDateTime(value: unknown): string {
  const text = clean(value, 80);
  if (!text) return "";
  const date = new Date(text);
  return Number.isNaN(date.getTime()) ? "" : date.toISOString();
}

function normalizeLocalizedText(value: unknown, fallback: string): AnyRecord {
  const text = (raw: unknown) => clean(raw ?? fallback, 500);
  if (value && typeof value === "object" && !Array.isArray(value)) {
    const input = value as AnyRecord;
    return {
      "zh-CN": text(input["zh-CN"] ?? input.zh ?? input.cn ?? fallback),
      "zh-TW": text(input["zh-TW"] ?? input["zh-CN"] ?? fallback),
      "en-US": text(input["en-US"] ?? input["zh-CN"] ?? fallback)
    };
  }
  return { "zh-CN": text(value), "zh-TW": text(value), "en-US": text(value) };
}

function hashString(value: string): string {
  let hash = 2166136261;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function localizedConfigText(value: unknown): string {
  if (!value || typeof value !== "object" || Array.isArray(value)) return "";
  const input = value as AnyRecord;
  return clean(input["zh-CN"] || input["zh-TW"] || input["en-US"] || "", 120);
}

function normalizeUploadScene(value: unknown): string {
  const scene = clean(value, 40).toLowerCase().replace(/[^a-z0-9_-]+/g, "-").replace(/^-+|-+$/g, "");
  return scene || "common";
}

function isUploadFile(value: unknown): value is File {
  if (!value || typeof value !== "object") return false;
  const candidate = value as { arrayBuffer?: unknown; name?: unknown; size?: unknown; type?: unknown };
  return typeof candidate.arrayBuffer === "function"
    && typeof candidate.name === "string"
    && typeof candidate.size === "number"
    && (candidate.type === undefined || typeof candidate.type === "string");
}

function normalizeUploadImageType(file: File): { mime: string; ext: string } | null {
  const mime = clean(file.type, 100).toLowerCase();
  if (UPLOAD_MIME_EXTENSIONS[mime]) return { mime, ext: UPLOAD_MIME_EXTENSIONS[mime] };

  const extension = clean(file.name.split(".").pop(), 20).toLowerCase();
  const byExtension: Record<string, string> = {
    jpg: "image/jpeg",
    jpeg: "image/jpeg",
    png: "image/png",
    webp: "image/webp",
    gif: "image/gif",
    avif: "image/avif"
  };
  const inferred = byExtension[extension];
  if (!inferred) return null;
  return { mime: inferred, ext: UPLOAD_MIME_EXTENSIONS[inferred] };
}

function looksLikeAllowedImage(body: ArrayBuffer, mime: string): boolean {
  const bytes = new Uint8Array(body.slice(0, 32));
  if (mime === "image/jpeg") return bytes.length >= 3 && bytes[0] === 0xff && bytes[1] === 0xd8 && bytes[2] === 0xff;
  if (mime === "image/png") {
    const png = [0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a];
    return png.every((value, index) => bytes[index] === value);
  }
  if (mime === "image/gif") {
    const header = asciiFromBytes(bytes.slice(0, 6));
    return header === "GIF87a" || header === "GIF89a";
  }
  if (mime === "image/webp") {
    return asciiFromBytes(bytes.slice(0, 4)) === "RIFF" && asciiFromBytes(bytes.slice(8, 12)) === "WEBP";
  }
  if (mime === "image/avif") {
    const brand = asciiFromBytes(bytes.slice(4, 12));
    return brand.startsWith("ftypavif") || brand.startsWith("ftypavis");
  }
  return false;
}

function asciiFromBytes(bytes: Uint8Array): string {
  return [...bytes].map((byte) => String.fromCharCode(byte)).join("");
}

function slugify(value: string): string {
  const slug = value.toLowerCase().replace(/[^a-z0-9\u4e00-\u9fa5]+/g, "-").replace(/^-+|-+$/g, "");
  return slug || `item-${Date.now()}`;
}

function stringify(value: unknown): string {
  return JSON.stringify(value ?? {});
}

function stringifyArray(value: unknown): string {
  return JSON.stringify(Array.isArray(value) ? value : []);
}

function jsonParse<T>(value: string, fallback: T): T {
  try {
    return JSON.parse(value) as T;
  } catch {
    return fallback;
  }
}

function jsonObject(value: unknown): AnyRecord {
  return value && typeof value === "object" && !Array.isArray(value) ? value as AnyRecord : {};
}

function md5Hex(input: string): string {
  const bytes = new TextEncoder().encode(input);
  const totalLength = (((bytes.length + 8) >> 6) + 1) * 64;
  const buffer = new Uint8Array(totalLength);
  buffer.set(bytes);
  buffer[bytes.length] = 0x80;
  const view = new DataView(buffer.buffer);
  const bitLength = bytes.length * 8;
  view.setUint32(totalLength - 8, bitLength >>> 0, true);
  view.setUint32(totalLength - 4, Math.floor(bitLength / 0x100000000), true);

  let a0 = 0x67452301;
  let b0 = 0xefcdab89;
  let c0 = 0x98badcfe;
  let d0 = 0x10325476;
  const shifts = [
    7, 12, 17, 22, 7, 12, 17, 22, 7, 12, 17, 22, 7, 12, 17, 22,
    5, 9, 14, 20, 5, 9, 14, 20, 5, 9, 14, 20, 5, 9, 14, 20,
    4, 11, 16, 23, 4, 11, 16, 23, 4, 11, 16, 23, 4, 11, 16, 23,
    6, 10, 15, 21, 6, 10, 15, 21, 6, 10, 15, 21, 6, 10, 15, 21
  ];
  const constants = Array.from({ length: 64 }, (_, index) => Math.floor(Math.abs(Math.sin(index + 1)) * 0x100000000) >>> 0);
  const leftRotate = (value: number, bits: number) => ((value << bits) | (value >>> (32 - bits))) >>> 0;

  for (let offset = 0; offset < totalLength; offset += 64) {
    const words = Array.from({ length: 16 }, (_, index) => view.getUint32(offset + index * 4, true));
    let a = a0;
    let b = b0;
    let c = c0;
    let d = d0;
    for (let index = 0; index < 64; index += 1) {
      let f = 0;
      let g = 0;
      if (index < 16) {
        f = (b & c) | (~b & d);
        g = index;
      } else if (index < 32) {
        f = (d & b) | (~d & c);
        g = (5 * index + 1) % 16;
      } else if (index < 48) {
        f = b ^ c ^ d;
        g = (3 * index + 5) % 16;
      } else {
        f = c ^ (b | ~d);
        g = (7 * index) % 16;
      }
      const next = d;
      d = c;
      c = b;
      b = (b + leftRotate((a + f + constants[index] + words[g]) >>> 0, shifts[index])) >>> 0;
      a = next;
    }
    a0 = (a0 + a) >>> 0;
    b0 = (b0 + b) >>> 0;
    c0 = (c0 + c) >>> 0;
    d0 = (d0 + d) >>> 0;
  }

  const out = new Uint8Array(16);
  const outView = new DataView(out.buffer);
  [a0, b0, c0, d0].forEach((value, index) => outView.setUint32(index * 4, value, true));
  return Array.from(out).map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

function arrayNumbers(value: unknown): number[] {
  return Array.isArray(value) ? value.map((item) => Number(item)).filter((item) => Number.isFinite(item) && item > 0) : [];
}

function skuSnapshot(sku: SkuRow): AnyRecord {
  return {
    sku_id: sku.id,
    sku_code: sku.sku_code,
    spec_values: jsonParse(sku.spec_values_json, {})
  };
}

function money(value: number): string {
  return Number(value || 0).toFixed(2);
}

function moneyToCents(value: number): number {
  return Math.max(0, Math.round(Number(value || 0) * 100));
}

function centsToMoney(value: number): number {
  return Number((Math.max(0, Math.round(value)) / 100).toFixed(2));
}

function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

function dateKey(date: Date): string {
  return date.toISOString().slice(0, 10);
}

function makeOrderNo(): string {
  const stamp = new Date().toISOString().replace(/[-:TZ.]/g, "").slice(0, 14);
  const rand = Math.floor(Math.random() * 900000 + 100000);
  return `DJ${stamp}${rand}`;
}

function normalizeFulfillmentDeliveryData(value: unknown): AnyRecord {
  const input = jsonObject(value);
  const entries = Array.isArray(input.entries) ? input.entries.slice(0, 200) : [];
  return {
    note: cleanDeliveryText(input.note, 2000),
    entries: entries
      .map((entry) => ({
        key: cleanDeliveryText(entry?.key, 80),
        value: cleanDeliveryText(entry?.value, 2000)
      }))
      .filter((entry) => entry.key || entry.value)
  };
}

function cleanDeliveryText(value: unknown, max: number): string {
  return clean(value, max).replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, "");
}

function formatDeliveryPayload(data: AnyRecord): string {
  const lines: string[] = [];
  const note = clean(data.note, 1000);
  if (note) lines.push(`备注：${note}`);
  const entries = Array.isArray(data.entries) ? data.entries : [];
  for (const entry of entries) {
    const key = clean(entry?.key, 80);
    const value = clean(entry?.value, 1000);
    if (key || value) lines.push(`${key || "内容"}：${value}`);
  }
  return lines.join("\n");
}

function safeDownloadFilename(value: unknown): string {
  const filename = clean(value, 120).replace(/[^a-zA-Z0-9._-]+/g, "_").replace(/^_+|_+$/g, "");
  return filename || "download";
}

async function sha256Hex(input: string): Promise<string> {
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(input));
  return [...new Uint8Array(digest)].map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

const PASSWORD_HASH_PREFIX = "pbkdf2-sha256";
const PASSWORD_HASH_MAX_ITERATIONS = 100_000;
const PASSWORD_HASH_ITERATIONS = PASSWORD_HASH_MAX_ITERATIONS;

async function hashPassword(password: string, salt: string, iterations = PASSWORD_HASH_ITERATIONS): Promise<string> {
  const key = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password),
    "PBKDF2",
    false,
    ["deriveBits"]
  );
  const bits = await crypto.subtle.deriveBits(
    { name: "PBKDF2", hash: "SHA-256", salt: new TextEncoder().encode(salt), iterations },
    key,
    256
  );
  const digest = [...new Uint8Array(bits)].map((byte) => byte.toString(16).padStart(2, "0")).join("");
  return `${PASSWORD_HASH_PREFIX}$${iterations}$${digest}`;
}

async function verifyPassword(password: string, salt: string, storedHash: string): Promise<{ valid: boolean; needsUpgrade: boolean }> {
  if (storedHash.startsWith(`${PASSWORD_HASH_PREFIX}$`)) {
    const [, rawIterations, digest] = storedHash.split("$");
    const iterations = toInt(rawIterations, 0);
    if (
      iterations < 10_000
      || iterations > PASSWORD_HASH_MAX_ITERATIONS
      || !/^[a-f0-9]{64}$/i.test(digest || "")
    ) return { valid: false, needsUpgrade: false };
    const calculated = await hashPassword(password, salt, iterations);
    return {
      valid: timingSafeEqualHex(calculated, storedHash),
      needsUpgrade: iterations < PASSWORD_HASH_ITERATIONS
    };
  }

  const legacyHash = await sha256Hex(`${salt}:${password}`);
  return {
    valid: timingSafeEqualHex(legacyHash, storedHash),
    needsUpgrade: true
  };
}

async function hmacSha256Hex(secret: string, input: string): Promise<string> {
  const key = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  const digest = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(input));
  return [...new Uint8Array(digest)].map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

async function signDujiaoNext(secret: string, method: string, path: string, timestamp: number, bodyText = ""): Promise<string> {
  const signString = `${method.toUpperCase()}\n${path}\n${timestamp}\n${md5Hex(bodyText)}`;
  return hmacSha256Hex(secret, signString);
}

function randomToken(): string {
  const bytes = new Uint8Array(32);
  crypto.getRandomValues(bytes);
  return [...bytes].map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

function makeApiKey(): string {
  return `fk_${randomToken().slice(0, 32)}`;
}

function makeApiSecret(): string {
  return `fs_${randomToken()}`;
}
